          <div class="row-wrap gap6" style="flex-wrap:nowrap">
            <label class="text-micro" style="min-width:92px;color:var(--tx);font-weight:600" id="st-ai-lbl-banner" title="Host AI: how many banner/title lines to include (smaller prompt = faster).">Banner lines</label>
            <input class="finp" type="number" id="st-ai-banner-max-lines" min="12" max="200" step="4" style="width:72px" value="72">
          </div>
        </div>
        <p class="text-micro text-dim mb8" id="st-ai-gen-tuning-hint" style="margin:0;max-width:640px"></p>
        <div class="st-ai-ollama-only">
          <div class="row-wrap gap8 mb8">
            <div class="row-wrap gap6" style="flex-wrap:nowrap">
              <label class="text-micro" style="min-width:130px;color:var(--tx);font-weight:600" title="Ollama num_thread. Set to your vCPU count on small VMs (e.g. 2). 0 = Ollama default.">CPU threads</label>
              <input class="finp" type="number" id="st-ai-ollama-num-thread" min="0" max="256" step="1" style="width:72px" value="0">
            </div>
            <div class="row-wrap gap6" style="flex-wrap:nowrap">
              <label class="text-micro" style="min-width:72px;color:var(--tx);font-weight:600" title="Ollama num_ctx. Lower = faster CPU prefill; if too small, long host prompts truncate and JSON may fail. 0 = model default.">Ctx tokens</label>
              <input class="finp" type="number" id="st-ai-ollama-num-ctx" min="0" max="131072" step="512" style="width:90px" value="0">
            </div>
          </div>
        </div>
        <div class="row-wrap gap6 mb10">
          <label class="switch-field text-micro" style="color:var(--tx3)">
            <span class="tog"><input type="checkbox" id="st-ai-ambiguous-only" checked><div class="trk"></div><div class="tth"></div></span>
            <span>Only run on ambiguous classification cases</span>
          </label>
        </div>
        <div class="row-wrap gap6 mb8">
          <label class="switch-field text-micro" style="color:var(--tx3)">
            <span class="tog"><input type="checkbox" id="st-ai-suggest-only"><div class="trk"></div><div class="tth"></div></span>
            <span>Suggest-only mode (do not auto-apply category changes)</span>
          </label>
        </div>
        <div class="row-wrap gap6 mb8">
          <label class="switch-field text-micro" style="color:var(--tx3)">
            <span class="tog"><input type="checkbox" id="st-ai-conflict-only" checked><div class="trk"></div><div class="tth"></div></span>
            <span>Run only when AI disagrees with current category</span>
          </label>
        </div>
        <div class="row-wrap gap8 mb10">
          <div class="row-wrap gap6" style="flex-wrap:nowrap">
            <label class="text-micro" style="min-width:130px;color:var(--tx);font-weight:600">Min confidence</label>
            <input class="finp" type="number" id="st-ai-conf-threshold" min="0.50" max="0.99" step="0.01" style="width:90px" value="0.72">
          </div>
          <div class="row-wrap gap6" style="flex-wrap:nowrap">
            <label class="text-micro" style="min-width:120px;color:var(--tx);font-weight:600">Min net↔srv confidence</label>
            <input class="finp" type="number" id="st-ai-conf-threshold-netsrv" min="0.50" max="0.99" step="0.01" style="width:90px" value="0.82">
          </div>
        </div>
        <div class="row-wrap gap6 mb8 st-ai-ollama-only">
          <button type="button" class="tbtn btn-xs" onclick="applyAiPreset('homelab_24')">Preset: /24 homelab</button>
          <button type="button" class="tbtn btn-xs" onclick="applyAiPreset('batch_multi_24')">Preset: multi-/24 batch</button>
        </div>
        <div class="row-wrap gap6">
          <button type="button" class="tbtn btn-xs" onclick="saveAiEnrichmentSettings()">Save AI settings</button>
          <div class="row-wrap gap6 st-ai-ollama-only">
            <button type="button" class="tbtn btn-xs" id="btn-ai-install-ollama" onclick="installOllamaRuntime()">Start/check Ollama</button>
            <button type="button" class="tbtn btn-xs" id="btn-ai-check-updates" onclick="checkAiUpdates()">Check updates</button>
          </div>
        </div>
      </div>
  </div>
  </section>
</div>

</div><!-- .main -->
</div><!-- .shell -->

<div class="toast-wrap" id="toasts"></div>

<div id="st-cred-profile-modal-bg" class="modal-bg z100" style="display:none" role="dialog" aria-modal="true" aria-labelledby="st-cred-profile-modal-title" onclick="if(event.target===this)stCredProfileCloseModal()">
  <div class="modal-card modal-w640" onclick="event.stopPropagation()">
    <div class="modal-title" style="margin-bottom:0" id="st-cred-profile-modal-title">Credential profile</div>
    <button type="button" class="modal-close-x" onclick="stCredProfileCloseModal()" title="Close" aria-label="Close">×</button>
    <input type="hidden" id="st-cred-pf-id" value="">
    <label class="flbl" for="st-cred-pf-name">Display name</label>
    <input class="finp w100 mb10" id="st-cred-pf-name" maxlength="200" autocomplete="off">
    <label class="flbl" for="st-cred-pf-transport">Transport</label>
    <select class="finp w100 mb10" id="st-cred-pf-transport" onchange="stCredProfileSecretTransportChanged()">
      <option value="ssh">ssh</option>
      <option value="snmpv3">snmpv3</option>
      <option value="winrm">winrm</option>
    </select>
    <div id="st-cred-pf-principal-struct" class="mb10">
      <div id="st-cred-pf-principal-ssh" class="hide">
        <label class="flbl" for="st-cred-pf-ssh-user">SSH username</label>
        <input class="finp w100 mb8" id="st-cred-pf-ssh-user" maxlength="256" autocomplete="username" oninput="stCredProfileOnStructuredFieldChange()">
        <label class="flbl" for="st-cred-pf-ssh-notes">Notes (optional)</label>
        <input class="finp w100 mb8" id="st-cred-pf-ssh-notes" maxlength="500" placeholder="Realm, environment, ticket…" oninput="stCredProfileOnStructuredFieldChange()">
        <p class="hint-micro text-dim mb0">SSH listen port is not stored on the profile — use the handshake test port field or each job’s targets.</p>
      </div>
      <div id="st-cred-pf-principal-snmp" class="hide">
        <label class="flbl" for="st-cred-pf-snmp-security-name">SNMPv3 security name</label>
        <input class="finp w100 mb8" id="st-cred-pf-snmp-security-name" maxlength="256" autocomplete="off" oninput="stCredProfileOnStructuredFieldChange()">
        <label class="flbl" for="st-cred-pf-snmp-security-level">Security level</label>
        <select class="finp w100 mb8" id="st-cred-pf-snmp-security-level" onchange="stCredPfSnmpOnLevelChange(); stCredProfileOnStructuredFieldChange()">
          <option value="authPriv">authPriv (auth + privacy)</option>
          <option value="authNoPriv">authNoPriv (auth only)</option>
        </select>
        <label class="flbl" for="st-cred-pf-snmp-auth-proto">Auth protocol</label>
        <select class="finp w100 mb8" id="st-cred-pf-snmp-auth-proto" onchange="stCredProfileOnStructuredFieldChange()">
          <option value="SHA">SHA</option>
          <option value="MD5">MD5</option>
        </select>
        <div id="st-cred-pf-snmp-priv-row">
          <label class="flbl" for="st-cred-pf-snmp-priv-proto">Privacy protocol</label>
          <select class="finp w100 mb8" id="st-cred-pf-snmp-priv-proto" onchange="stCredProfileOnStructuredFieldChange()">
            <option value="AES">AES</option>
            <option value="DES">DES</option>
          </select>
        </div>
        <p class="hint-micro text-dim mb0">SNMPv3 passwords belong in secret material below — never in principal JSON.</p>
      </div>
      <div id="st-cred-pf-principal-winrm" class="hide">
        <label class="flbl" for="st-cred-pf-winrm-principal-user">WinRM username</label>
        <input class="finp w100 mb8" id="st-cred-pf-winrm-principal-user" maxlength="256" autocomplete="username" oninput="stCredProfileOnStructuredFieldChange()">
        <label class="flbl" for="st-cred-pf-winrm-domain">Domain (optional)</label>
        <input class="finp w100 mb8" id="st-cred-pf-winrm-domain" maxlength="256" autocomplete="off" oninput="stCredProfileOnStructuredFieldChange()">
      </div>
    </div>
    <details class="mb10 st-cred-pf-adv-details">
      <summary class="text-secondary cursor-pointer">Advanced principal JSON</summary>
      <p class="hint-micro text-dim mb6">Optional extra keys merged with the fields above (advanced overrides on save). Never put passwords or keys here.</p>
      <textarea class="finp w100 mb0" id="st-cred-pf-principal-adv" rows="4" style="font-family:monospace;font-size:12px" placeholder="{}" onchange="stCredProfileOnStructuredFieldChange()"></textarea>
    </details>
    <p class="hint-micro text-dim mb6" id="st-cred-pf-scope-intro"><strong>Profile scope</strong> is an optional allowlist / usage boundary for operators (scopes, tags, assets). <strong>Job targets</strong> decide which assets are actually checked at run time. If you leave profile scope empty, <strong>no allowlist is configured — jobs may target any asset your job definition and inventory allow</strong> (SurveyTrace does not treat empty profile scope as “deny all”).</p>
    <label class="flbl" for="st-cred-pf-scope-scope-ms">Allowed scopes</label>
    <select class="finp w100 mb8" id="st-cred-pf-scope-scope-ms" multiple size="5" onchange="stCredProfileOnStructuredFieldChange()"></select>
    <label class="flbl" for="st-cred-pf-scope-tags">Tags (comma-separated)</label>
    <input class="finp w100 mb8" id="st-cred-pf-scope-tags" maxlength="2000" placeholder="e.g. prod, linux" oninput="stCredProfileOnStructuredFieldChange()">
    <label class="flbl" for="st-cred-pf-scope-asset-q">Allowed assets</label>
    <div class="row-wrap gap6 mb6">
      <input class="finp" style="flex:1;min-width:160px" id="st-cred-pf-scope-asset-q" maxlength="200" placeholder="Search hostname or IP" autocomplete="off" onkeydown="if(event.key==='Enter'){event.preventDefault();stCredPfScopeAssetSearch();}">
      <button type="button" class="tbtn" onclick="stCredPfScopeAssetSearch()">Search inventory</button>
    </div>
    <div class="mb6" id="st-cred-pf-scope-asset-results"></div>
    <div class="row-wrap gap6 mb8" id="st-cred-pf-scope-asset-chips"></div>
    <details class="mb10 st-cred-pf-adv-details">
      <summary class="text-secondary cursor-pointer">Advanced scope JSON</summary>
      <p class="hint-micro text-dim mb6">Merged after scope/tag/asset selections; advanced keys override duplicates.</p>
      <textarea class="finp w100 mb0" id="st-cred-pf-scope-adv" rows="3" style="font-family:monospace;font-size:12px" placeholder="{}" onchange="stCredProfileOnStructuredFieldChange()"></textarea>
    </details>
    <div class="mb10" id="st-cred-pf-secret-panel" style="border-top:1px solid var(--border-subtle, #2a3340);padding-top:10px">
      <div class="flbl">Secret material (server-side encrypted)</div>
      <p class="hint-micro text-dim mb6" id="st-cred-pf-secret-enc-hint"></p>
      <p class="hint-micro text-dim mb6 hide" id="st-cred-pf-secret-profile-save-hint"></p>
      <p class="hint-micro mb6" id="st-cred-pf-secret-status"></p>
      <div id="st-cred-pf-secret-fields-ssh" class="hide">
        <p class="hint-micro text-dim mb4">Use <strong>either</strong> password <strong>or</strong> private key (not both). Values are never shown again after save.</p>
        <label class="flbl" for="st-cred-pf-ssh-password">SSH password</label>
        <input class="finp w100 mb6" type="password" id="st-cred-pf-ssh-password" autocomplete="new-password" value="" oninput="stCredProfileOnSecretInputsChanged()">
        <label class="flbl" for="st-cred-pf-ssh-private-key">SSH private key (PEM)</label>
        <textarea class="finp w100 mb6" id="st-cred-pf-ssh-private-key" rows="4" style="font-family:monospace;font-size:11px" autocomplete="off" oninput="stCredProfileOnSecretInputsChanged()"></textarea>
        <label class="flbl" for="st-cred-pf-ssh-passphrase">Key passphrase (optional)</label>
        <input class="finp w100 mb6" type="password" id="st-cred-pf-ssh-passphrase" autocomplete="new-password" value="" oninput="stCredProfileOnSecretInputsChanged()">
      </div>
      <div id="st-cred-pf-secret-fields-snmp" class="hide">
        <label class="flbl" for="st-cred-pf-snmpv3-auth">SNMPv3 auth password</label>
        <input class="finp w100 mb6" type="password" id="st-cred-pf-snmpv3-auth" autocomplete="new-password" value="" oninput="stCredProfileOnSecretInputsChanged()">
        <div id="st-cred-pf-snmpv3-priv-secret-row">
          <label class="flbl" for="st-cred-pf-snmpv3-priv">SNMPv3 privacy password</label>
          <input class="finp w100 mb6" type="password" id="st-cred-pf-snmpv3-priv" autocomplete="new-password" value="" oninput="stCredProfileOnSecretInputsChanged()">
        </div>
      </div>
      <div id="st-cred-pf-secret-fields-winrm" class="hide">
        <label class="flbl" for="st-cred-pf-winrm-password">WinRM password</label>
        <input class="finp w100 mb6" type="password" id="st-cred-pf-winrm-password" autocomplete="new-password" value="" oninput="stCredProfileOnSecretInputsChanged()">
      </div>
      <p class="hint-micro text-dim mb6 hide" id="st-cred-pf-secret-action-hint" aria-live="polite"></p>
      <div class="row-wrap gap6 mb6">
        <button type="button" class="btnp" id="st-cred-pf-btn-secret-save" onclick="stCredProfileSubmitSecret()">Set / replace secret</button>
        <button type="button" class="tbtn" id="st-cred-pf-btn-secret-clear" onclick="stCredProfileClearSecret()">Clear secret</button>
      </div>
    </div>
    <div class="mb10 hide" id="st-cred-pf-transport-test-panel" style="border-top:1px solid var(--border-subtle, #2a3340);padding-top:10px">
      <div class="flbl">Transport handshake test</div>
      <p class="hint-micro text-dim mb6">Enter a <strong>target host or IP</strong> for this run only (not saved with the profile). SSH runs <code class="code-accent">true</code> then <code class="code-accent">uname -s</code>; SNMPv3 performs a single GET of <code class="code-accent">sysDescr.0</code>. Requires a stored secret and server-side crypto + Python helpers (<code class="code-accent">paramiko</code>, <code class="code-accent">pysnmp</code>).</p>
      <label class="flbl" for="st-cred-pf-test-host">Target host / IP</label>
      <input class="finp w100 mb6" id="st-cred-pf-test-host" autocomplete="off" placeholder="e.g. 10.0.0.12" oninput="stCredProfileOnTestTargetInput()">
      <label class="flbl" for="st-cred-pf-test-port">Port (0 = default: 22 SSH / 161 SNMP)</label>
      <input class="finp w100 mb6" id="st-cred-pf-test-port" type="number" min="0" max="65535" value="0" oninput="stCredProfileOnTestTargetInput()">
      <p class="hint-micro mb6" id="st-cred-pf-handshake-status" aria-live="polite"></p>
      <p class="hint-micro text-dim mb6" id="st-cred-pf-test-readiness" aria-live="polite"></p>
      <div class="row-wrap gap6 mb6">
        <button type="button" class="btnp" id="st-cred-pf-btn-transport-test" onclick="stCredProfileRunTransportTest()">Run handshake test</button>
        <span class="hint-micro text-dim hide" id="st-cred-pf-test-progress">Testing…</span>
      </div>
      <div id="st-cred-pf-handshake-panel" class="st-cred-pf-handshake-panel st-cred-pf-handshake-panel--idle" aria-live="polite">
        <div class="st-cred-pf-handshake-panel-title">Handshake result</div>
        <div id="st-cred-pf-handshake-panel-body" class="hint-micro text-dim mb0">Status: not run. Run a test to see outcome here (toasts are optional; this panel stays until you close the modal, change secret/profile, or run again).</div>
      </div>
    </div>
    <div class="mb10 hide" id="st-cred-pf-next-steps" style="border-top:1px solid var(--border-subtle, #2a3340);padding-top:10px">
      <div class="flbl">What to do next</div>
      <ol class="hint-micro text-dim mt4 mb8" style="padding-left:1.25rem">
        <li>Run a transport handshake against a host (above).</li>
        <li>Create a credentialed check job that references this profile.</li>
        <li>Select plugins that match the transport (SSH vs SNMPv3).</li>
        <li>Pick targets (explicit assets or scopes).</li>
        <li>Run the job now or rely on your scheduler/worker queue.</li>
      </ol>
      <div class="row-wrap gap6">
        <button type="button" class="btnp" id="st-cred-pf-btn-create-job" onclick="stCredProfileCreateJobFromModal()">Create job using this profile</button>
      </div>
    </div>
    <label class="switch-field mb10">
      <span class="tog"><input type="checkbox" id="st-cred-pf-enabled" checked><div class="trk"></div><div class="tth"></div></span>
      <span class="text-secondary">Profile enabled</span>
    </label>
    <div class="row-wrap gap6">
      <button type="button" class="btnp" onclick="stCredProfileSave()">Save</button>
      <button type="button" class="tbtn" onclick="stCredProfileCloseModal()">Cancel</button>
    </div>
    <p class="hint-micro text-dim mt8 mb0" id="st-cred-pf-modal-hint"></p>
  </div>
</div>

<div id="st-cc-job-modal-bg" class="modal-bg z100" style="display:none" role="dialog" aria-modal="true" onclick="if(event.target===this)stCcJobCloseModal()">
  <div class="modal-card modal-w640" onclick="event.stopPropagation()">
    <div class="modal-title">Credentialed check job</div>
    <button type="button" class="modal-close-x" onclick="stCcJobCloseModal()" title="Close" aria-label="Close">×</button>
    <input type="hidden" id="st-cc-job-id" value="">
    <label class="flbl" for="st-cc-job-name">Name</label>
    <input class="finp w100 mb8" id="st-cc-job-name" maxlength="200" autocomplete="off">
    <label class="flbl" for="st-cc-job-desc">Description</label>
    <textarea class="finp w100 mb8" id="st-cc-job-desc" rows="2" maxlength="8000"></textarea>
    <label class="flbl" for="st-cc-job-profile">Credential profile</label>
    <select class="finp w100 mb8" id="st-cc-job-profile" onchange="stCcJobOnProfileChange()"></select>
    <p class="hint-micro text-dim mb8">Profiles define where credentials <strong>may</strong> be used (allowlist). This job chooses what targets <strong>will</strong> run now.</p>
    <label class="flbl" for="st-cc-job-target-mode">Target mode</label>
    <select class="finp w100 mb8" id="st-cc-job-target-mode" onchange="stCcJobSyncTargetHints()">
      <option value="assets">Explicit assets</option>
      <option value="scope">Scopes → assets with matching scope_id</option>
    </select>
    <p class="hint-micro text-dim mb4" id="st-cc-job-target-hint"></p>
    <div id="st-cc-job-target-scope-panel" class="hide">
      <label class="flbl" for="st-cc-job-scope-ms">Scopes</label>
      <select class="finp w100 mb8" id="st-cc-job-scope-ms" multiple size="5" onchange="stCcJobOnTargetStructuredChange()"></select>
    </div>
    <div id="st-cc-job-target-assets-panel">
      <label class="flbl" for="st-cc-job-asset-q">Assets</label>
      <div class="row-wrap gap6 mb6">
        <input class="finp" style="flex:1;min-width:160px" id="st-cc-job-asset-q" maxlength="200" placeholder="Search hostname or IP" autocomplete="off" onkeydown="if(event.key==='Enter'){event.preventDefault();stCcJobAssetSearch();}">
        <button type="button" class="tbtn" onclick="stCcJobAssetSearch()">Search inventory</button>
      </div>
      <div class="mb6" id="st-cc-job-asset-results"></div>
      <div class="row-wrap gap6 mb8" id="st-cc-job-asset-chips"></div>
      <details class="mb8"><summary class="text-secondary cursor-pointer">Paste comma-separated asset IDs</summary>
        <input class="finp w100 mono-sm mb0" id="st-cc-job-target-ids" autocomplete="off" placeholder="e.g. 12, 34, 56" oninput="stCcJobOnTargetStructuredChange()">
      </details>
    </div>
    <div class="flbl mb4">Plugins (must match profile transport)</div>
    <div id="st-cc-job-plugins" class="mb8 text-dim hint-micro" style="max-height:140px;overflow:auto;border:1px solid var(--border-subtle,#2a3340);padding:8px;border-radius:6px">Select a profile first.</div>
    <div class="row-wrap gap8 mb8">
      <div style="flex:1">
        <label class="flbl" for="st-cc-job-max-conc">Max concurrency (plugins)</label>
        <input class="finp w100" id="st-cc-job-max-conc" type="number" min="1" max="50" value="4">
      </div>
      <div style="flex:1">
        <label class="flbl" for="st-cc-job-timeout">Timeout (ms)</label>
        <input class="finp w100" id="st-cc-job-timeout" type="number" min="5000" max="3600000" value="600000">
      </div>
    </div>
    <div class="st-cc-job-sched-sec mt8 mb8" style="border-top:1px solid var(--border-subtle,#2a3340);padding-top:10px">
      <div class="text-secondary mb6">Recurring schedule</div>
      <p class="hint-micro text-dim mb6">When enabled, <code class="mono-sm">surveytrace-scheduler</code> runs <code class="mono-sm">credential_schedule_tick.php</code> and may enqueue at most one catch-up run after downtime, then advances <code class="mono-sm">schedule_next_run_at</code> (UTC storage; cron evaluated in the timezone below).</p>
      <label class="switch-field mb8">
        <span class="tog"><input type="checkbox" id="st-cc-job-sched-enabled"><div class="trk"></div><div class="tth"></div></span>
        <span class="text-secondary">Schedule enabled</span>
      </label>
      <label class="flbl" for="st-cc-job-sched-cron">Cron expression</label>
      <input class="finp w100 mb6 mono-sm" id="st-cc-job-sched-cron" maxlength="200" placeholder="@hourly or 0 0 * * *" autocomplete="off">
      <label class="flbl" for="st-cc-job-sched-tz">Timezone (IANA)</label>
      <input class="finp w100 mb6 mono-sm" id="st-cc-job-sched-tz" maxlength="80" placeholder="UTC" autocomplete="off">
      <div class="row-wrap gap8 mb6">
        <div style="flex:1">
          <label class="flbl" for="st-cc-job-sched-max">Max concurrent runs (queue)</label>
          <input class="finp w100" id="st-cc-job-sched-max" type="number" min="1" max="20" value="1">
        </div>
        <div style="flex:1">
          <label class="flbl" for="st-cc-job-run-to">Run timeout (sec)</label>
          <input class="finp w100" id="st-cc-job-run-to" type="number" min="60" max="172800" value="3600">
        </div>
      </div>
      <p class="hint-micro text-dim mb0" id="st-cc-job-sched-readonly"></p>
    </div>
    <label class="switch-field mb10">
      <span class="tog"><input type="checkbox" id="st-cc-job-enabled" checked><div class="trk"></div><div class="tth"></div></span>
      <span class="text-secondary">Job enabled</span>
    </label>
    <div class="row-wrap gap6">
      <button type="button" class="btnp" onclick="stCcJobSave()">Save</button>
      <button type="button" class="tbtn" onclick="stCcJobCloseModal()">Cancel</button>
    </div>
    <p class="hint-micro text-dim mt8 mb0" id="st-cc-job-modal-hint"></p>
  </div>
</div>

<div id="st-cc-run-modal-bg" class="modal-bg z100" style="display:none" role="dialog" aria-modal="true" onclick="if(event.target===this)stCcRunCloseModal()">
  <div class="modal-card modal-w720" onclick="event.stopPropagation()">
    <div class="modal-title">Credentialed check run</div>
    <button type="button" class="modal-close-x" onclick="stCcRunCloseModal()" title="Close" aria-label="Close">×</button>
    <div id="st-cc-run-detail" class="st-cc-run-detail hint-micro text-dim"></div>
    <div class="row-wrap gap6 mt10">
      <button type="button" class="tbtn" id="st-cc-run-btn-cancel" onclick="stCcRunCancelCurrent()">Cancel run</button>
      <button type="button" class="tbtn" onclick="stCcRunCloseModal()">Close</button>
    </div>
  </div>
</div>

<!-- Session login modal -->
<div id="login-bg" class="modal-bg z260">
  <div class="modal-card modal-w360">
    <div class="modal-title">Sign in</div>
    <div class="text-muted mb10" id="login-msg">
      Session authentication required.
    </div>
    <form id="login-form" onsubmit="event.preventDefault();void submitLogin();return false;">
      <div id="login-local-fields">
        <label class="flbl" for="login-user">Username</label>
        <input class="finp w100 mb10" id="login-user" value="admin" autocomplete="username">
        <label class="flbl" for="login-pass">Password</label>
        <input class="finp w100 mb10" id="login-pass" type="password" autocomplete="current-password">
        <div id="login-mfa-step" class="hide">
          <label class="flbl" for="login-verify-code">Verification code</label>
          <input class="finp w100 mb12" id="login-verify-code" placeholder="Authenticator OTP or recovery code" autocomplete="one-time-code">
        </div>
      </div>
      <div class="row-end">
        <button class="tbtn" type="button" onclick="closeLoginModal()">Cancel</button>
        <button class="btnp" type="submit" id="btn-login">Sign in</button>
      </div>
    </form>
    <div id="login-oidc-fields" class="hide mb12">
      <div class="help-line mb10" id="login-sso-msg">Single sign-on is enabled for this deployment.</div>
      <button class="btnp w100 mb8" type="button" id="btn-login-sso" onclick="startSsoLogin()">Sign in with SSO</button>
      <button class="tbtn w100 hide" type="button" id="btn-breakglass-show" onclick="toggleBreakglassLogin(true)">Use emergency local sign-in</button>
      <div class="hint-micro mt6">Emergency local sign-in is for IdP outages only; day-to-day users should sign in through SSO.</div>
    </div>
  </div>
</div>

<!-- Shown if user dismisses login without signing in (session/OIDC); keeps app chrome hidden -->
