<!-- Rescan single host — profile + scan options (matches Scan tab: rates, discovery, scan steps, exclusions, enrichment) -->
<div id="host-rescan-bg" class="modal-bg z220" style="display:none" role="dialog" aria-labelledby="host-rescan-title">
  <div class="modal-card modal-w600" onclick="event.stopPropagation()">
    <div id="host-rescan-title" class="modal-title mb6">Rescan host</div>
    <p class="text-muted mb10" style="line-height:1.45">Choose profile and scan options for this host only. Changing the profile applies the same defaults as the <strong>Scan</strong> tab and schedules. Values load from the Scan tab when you open this dialog; edit here without leaving the host view.</p>
    <p class="mb8">Target: <strong class="mono" id="host-rescan-ip"></strong></p>
    <label class="flbl" for="host-rescan-profile">Scan profile</label>
    <select id="host-rescan-profile" class="finput w100 mb6">
      <option value="iot_safe">IoT Safe — passive-first, no TCP port scan</option>
      <option value="ot_careful">OT Careful — passive-first, strict rate limits</option>
      <option value="standard_inventory">Standard Inventory — common ports, light banners</option>
      <option value="deep_scan">Deep Scan — aggressive -sV on ~60+ listed ports (not 1&ndash;65535)</option>
      <option value="full_tcp">Full TCP — all 65,535 TCP ports + -sV (longest; true full sweep)</option>
    </select>
    <div id="host-rescan-hint" class="hint-micro mb6" style="min-height:2.6em"></div>
    <div id="host-rescan-profile-warn" class="help-box mb8" style="display:none;border-color:var(--amber);color:var(--amber);font-size:0.9em"></div>
    <div id="host-rescan-scroll" class="mb10" style="max-height:min(52vh,520px);overflow-y:auto;padding-right:6px">
      <div class="ct mb4">Rate limiting</div>
      <div class="rr">
        <label class="flbl">Max packets/sec per host</label>
        <div class="rv"><span>1</span><span id="hr-pps-val">5 pps</span><span>50</span></div>
        <input class="rng" type="range" id="hr-pps" min="1" max="50" step="1" value="5" oninput="document.getElementById('hr-pps-val').textContent=this.value+' pps'">
      </div>
      <div class="rr">
        <label class="flbl">Inter-host delay</label>
        <div class="rv"><span>0</span><span id="hr-delay-val">200 ms</span><span>2000</span></div>
        <input class="rng" type="range" id="hr-delay" min="0" max="2000" step="10" value="200" oninput="document.getElementById('hr-delay-val').textContent=this.value+' ms'">
      </div>
      <div class="ct mb4 mt8">Discovery mode</div>
      <div class="tr2">
        <div><div class="tl">Auto</div><div class="tsubl">ARP for same-subnet, ping scan for routed</div></div>
        <label class="chk tr2-check"><input type="radio" class="chk-input" name="hr_scan_mode" id="hr-sm-auto" value="auto" checked aria-label="Discovery mode: Auto — ARP on same subnet, ping scan when routed"></label>
      </div>
      <div class="tr2">
        <div><div class="tl">Routed</div><div class="tsubl">ICMP/TCP ping scan only — no ARP</div></div>
        <label class="chk tr2-check"><input type="radio" class="chk-input" name="hr_scan_mode" id="hr-sm-routed" value="routed" aria-label="Discovery mode: Routed — ICMP/TCP ping only, no ARP"></label>
      </div>
      <div class="tr2">
        <div><div class="tl">Force (-Pn)</div><div class="tsubl warn-text">&#9888; Scan all IPs regardless of ping</div></div>
        <label class="chk tr2-check"><input type="radio" class="chk-input" name="hr_scan_mode" id="hr-sm-force" value="force" aria-label="Discovery mode: Force (-Pn) — treat all targets as up"></label>
      </div>
      <div class="ct mb4 mt8">Scan steps</div>
      <div class="tr2"><div><div class="tl">Passive discovery</div><div class="tsubl">ARP watch, mDNS — zero packets sent</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-passive" checked aria-label="Include passive discovery for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">ICMP sweep</div><div class="tsubl">Ping / ARP sweep</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-icmp" checked aria-label="Include ICMP sweep for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">Port &amp; banner probe</div><div class="tsubl">TCP connect on safe port list</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-banner" checked aria-label="Include port and banner probe for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">Service fingerprinting</div><div class="tsubl">OUI + banner + port profile → CPE</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-fingerprint" checked aria-label="Include service fingerprinting for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">SNMP GET (read-only)</div><div class="tsubl">sysDescr, ifTable — no SET</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-snmp" aria-label="Include SNMP read-only probes for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">OT protocol probes</div><div class="tsubl warn-text">&#9888; Read-only probes</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-ot" aria-label="Include OT protocol probes for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="tr2"><div><div class="tl">CVE correlation</div><div class="tsubl">Match CPE vs local NVD</div></div><label class="tog tog--sm tr2-check"><input type="checkbox" id="hr-ph-cve" checked aria-label="Include CVE correlation for this rescan"><div class="trk"></div><div class="tth"></div></label></div>
      <div class="ct mb4 mt8">Exclusion list (optional)</div>
      <label class="flbl">IPs, CIDRs, ranges, # comments</label>
      <textarea class="finput w100 mb6" id="hr-excl" rows="4" style="min-height:76px" placeholder="192.168.1.254&#10;10.0.0.0/24&#10;# SCADA servers&#10;192.168.10.88-95"></textarea>
      <label class="flbl" for="hr-collector">Collector target</label>
      <select id="hr-collector" class="finput w100 mb6">
        <option value="0">Master scanner (local)</option>
      </select>
      <div class="hint-micro mb8">Route this rescan to a remote collector for local-site ARP/mDNS when the host is on that network (same as the Scan tab).</div>
      <div class="ct mb4 mt8">Network enrichment (this scan)</div>
      <div class="tsubl mb6">Network enrichment uses sources from <strong>Enrichment</strong>. Uncheck to skip a source for this job only; all checked matches the Scan tab default (omit subset in API).</div>
      <div id="host-rescan-enrichment-wrap" data-ready="0"><div class="hint-micro">Loading…</div></div>
    </div>
    <div class="row-end">
      <button type="button" class="tbtn" id="host-rescan-cancel-btn">Cancel</button>
      <button type="button" class="btnp" id="host-rescan-queue-btn">Queue scan</button>
    </div>
  </div>
</div>

<!-- Profile modal -->
<div id="profile-bg" class="modal-bg z220">
  <div class="modal-card modal-w440">
    <div class="modal-title">My profile</div>
    <div class="text-muted mb10">Manage your personal account settings.</div>
    <label class="flbl">Username</label>
    <input class="finp w100 mb8" id="profile-username" readonly>
    <div class="row-wrap mb8">
      <div class="grow">
        <label class="flbl">Role</label>
        <input class="finp w100" id="profile-role" readonly>
      </div>
      <div class="grow">
        <label class="flbl">Auth source</label>
        <input class="finp w100" id="profile-auth-source" readonly>
      </div>
    </div>
    <label class="flbl">Display name</label>
