async function loadDevices(page) {
    devicePage = page;
    const q    = document.getElementById('df-q')?.value    || '';
    const sort = document.getElementById('df-sort')?.value || 'id';
    let order  = 'asc';
    if (sort === 'last_seen' || sort === 'asset_count') {
        order = 'desc';
    }
    document.getElementById('device-tbody').innerHTML =
        '<tr><td colspan="7" class="loading tbl-empty">Loading devices…</td></tr>';

    const url = `/api/devices.php?page=${page}&per_page=50&q=${enc(q)}&sort=${enc(sort)}&order=${order}`;
    const d   = await api(url);
    if (!d) {
        const fsDead = document.getElementById('st-devices-filter-summary');
        if (fsDead) {
            fsDead.textContent = '';
            fsDead.classList.add('hide');
        }
        return;
    }

    const sortLabel = { id: 'ID', asset_count: '# assets', last_seen: 'last activity', primary_mac_norm: 'MAC' };
    const fsEl = document.getElementById('st-devices-filter-summary');
    if (fsEl) {
        const bits = [];
        if (String(q || '').trim()) bits.push('search “' + String(q).trim() + '”');
        if (sort && sort !== 'id') bits.push('sort: ' + (sortLabel[sort] || sort));
        fsEl.textContent = bits.length ? ('Active: ' + bits.join(' · ')) : '';
        fsEl.classList.toggle('hide', !bits.length);
    }

    const filtersActive = !!(String(q || '').trim() || (sort && sort !== 'id'));
    const rowsHtml = (d.devices || []).map((dev) => {
        const mac = dev.primary_mac_norm ? esc(dev.primary_mac_norm) : '—';
        const ips = dev.ip_sample ? esc(dev.ip_sample) : '—';
        const last = dev.last_seen_max ? relTime(dev.last_seen_max) : '—';
        const created = dev.created_at ? relTime(dev.created_at) : '—';
        const ac = parseInt(String(dev.asset_count || 0), 10) || 0;
        const rowMulti = ac > 1 ? ' st-devices-row--multi' : '';
        return `<tr class="st-devices-row${rowMulti}">
          <td class="mono mono-sm tbl-cell-mono tbl-cell-primary"><span class="click-ip" onclick="openDevicePanel(${dev.id})" title="Device detail">${dev.id}</span></td>
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${mac}</td>
          <td class="mono tbl-cell-mono tbl-cell-muted">${dev.asset_count}</td>
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted" style="max-width:240px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${ips}">${ips}</td>
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${last}</td>
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${created}</td>
          <td class="tbl-cell-actions"><button type="button" class="tbtn btn-xs" onclick="viewDeviceAssets(${dev.id})">Assets</button></td>
        </tr>`;
    }).join('');

    let emptyMsg = 'No devices match the current search or sort. Clear the search box or reset sort to ID.';
    if (!rowsHtml) {
        if ((d.total || 0) === 0) {
            if (filtersActive) {
                emptyMsg = 'No devices match the current filters. Try a broader search or sort by ID.';
            } else {
                emptyMsg = 'No logical devices yet. Devices appear when scans correlate IP assets (e.g. shared MAC) or after identity migration — run inventory scans, then refresh.';
            }
        } else {
            emptyMsg = 'No devices on this page.';
        }
    }

    document.getElementById('device-tbody').innerHTML = rowsHtml
        || `<tr><td colspan="7" class="loading tbl-empty st-devices-empty">${emptyMsg}</td></tr>`;

    document.getElementById('dpgn-info').textContent = `Page ${d.page} of ${d.pages} (${d.total} devices)`;
    document.getElementById('dprev').disabled = page <= 1;
    document.getElementById('dnext').disabled = page >= d.pages;
}

function detectServiceHitsFromAsset(asset) {
    const banners = asset.banners || {};
    const httpProbe = String(banners._http || '');
    const ports = asset.open_ports || [];
    return collectDetectedServiceChips(ports, banners, httpProbe);
}

/**
 * Vendor summary display shared by Assets table + host details.
 * Returns a primary label with optional +N suffix and a full-list tooltip.
 * @param {Record<string, unknown>} asset
 * @returns {{label:string, title:string}}
 */
function stVendorSummaryForAsset(asset) {
    const primaryRaw = String(asset && asset.vendor != null ? asset.vendor : '').trim();
    const hitsRaw = detectServiceHitsFromAsset(asset || {});
    /** @type {string[]} */
    const ordered = [];
    const seen = new Set();
    const pushUnique = (v) => {
        const s = String(v || '').trim();
        if (!s) return;
        const k = s.toLowerCase();
        if (seen.has(k)) return;
        seen.add(k);
        ordered.push(s);
    };
    if (primaryRaw) {
        pushUnique(primaryRaw);
    }
    (hitsRaw || []).forEach((h) => pushUnique(h));
    if (!ordered.length) {
        return { label: '—', title: '—' };
    }
    const displayPrimary = ordered[0];
    const extra = Math.max(0, ordered.length - 1);
    return {
        label: displayPrimary + (extra > 0 ? ' +' + String(extra) : ''),
        title: ordered.join(', '),
    };
}

function lifecycleBadgeHtml(asset) {
    const st = String((asset && asset.lifecycle_status) || 'active').toLowerCase();
    const lbl = st === 'retired' ? 'Retired' : st === 'stale' ? 'Stale' : 'Active';
    const cls = st === 'retired' ? 'life-retired' : st === 'stale' ? 'life-stale' : 'life-active';
    const reason = asset && asset.lifecycle_reason ? String(asset.lifecycle_reason) : '';
    const tip = reason ? esc(reason) : esc('Coverage-based lifecycle — see docs');
    return `<span class="life-badge ${cls}" title="${tip}">${esc(lbl)}</span>`;
}

function stToggleAssetZbxColumn() {
    if (!window.__stAssetsZabbixFiltersAvailable) {
        const c = document.getElementById('af-zbx-col');
        if (c) c.checked = false;
        return;
    }
    const th = document.getElementById('af-th-zbx');
    const on = !!document.getElementById('af-zbx-col')?.checked;
    if (th) th.classList.toggle('hide', !on);
    loadAssets(assetPage);
}

function stAssetZabbixCellHtml(a) {
    const mon = a.monitored_by_zabbix === true;
    const av = String(a.zabbix_availability || '').trim();
    const pr = Number(a.zabbix_problem_count || 0);
    const tip = esc(`monitored=${mon ? 'yes' : 'no'} · availability=${av || '—'} · open_problems=${pr}`);
    const dot = mon ? '<span style="color:var(--green)">●</span>' : '<span class="text-dim">○</span>';
    const avs = av ? esc(av) : '<span class="text-dim">—</span>';
    const prs = pr > 0 ? `<span class="status-text">${pr} prb</span>` : '<span class="text-dim">0</span>';
    return `<span class="mono-sm" title="${tip}">${dot} ${avs} · ${prs}</span>`;
}

function stAssetPopulateScopeSelect(sel, opts) {
    opts = opts || {};
    const chooseLabel = opts.chooseLabel != null ? opts.chooseLabel : '— choose scope —';
    if (!sel) {
        return;
    }
    const prev = sel.value;
    sel.innerHTML = '';
    const o0 = document.createElement('option');
    o0.value = '0';
    o0.textContent = chooseLabel;
    sel.appendChild(o0);
    (stScopesForFormsCache || []).forEach((sc) => {
        const o = document.createElement('option');
        o.value = String(sc.id);
        o.textContent = (sc.name || 'Scope #' + sc.id).slice(0, 120);
        sel.appendChild(o);
    });
    if ([...sel.options].some((opt) => opt.value === prev)) {
        sel.value = prev;
    }
}

function stScopesOpenCreateModal() {
    openStCreateScopeModal('scopes');
}

function stAssetsToggleSelectAll(checked) {
    document.querySelectorAll('.af-row-chk').forEach((c) => {
        c.checked = !!checked;
    });
    const head = document.getElementById('af-select-all');
    if (head) {
        head.checked = !!checked;
        head.indeterminate = false;
    }
    stAssetsUpdateBulkBarVisibility();
}

function stAssetsSyncSelectAllCheckbox() {
    const all = document.querySelectorAll('.af-row-chk');
    const n = all.length;
    let c = 0;
    all.forEach((x) => {
        if (x.checked) {
            c++;
        }
    });
    const head = document.getElementById('af-select-all');
    if (!head) {
        return;
    }
    head.checked = n > 0 && c === n;
    head.indeterminate = c > 0 && c < n;
    stAssetsUpdateBulkBarVisibility();
}

function stAssetsSelectedIds() {
    const ids = [];
    document.querySelectorAll('.af-row-chk:checked').forEach((c) => {
        const id = parseInt(String(c.getAttribute('data-aid') || '0'), 10);
        if (id > 0) {
            ids.push(id);
        }
    });
    return ids;
}

function stAssetsUpdateBulkBarVisibility() {
    const bar = document.getElementById('af-bulk-actions-bar');
    const lbl = document.getElementById('af-bulk-selected-label');
    if (!bar || !lbl) {
        return;
    }
    const n = stAssetsSelectedIds().length;
    const can = stRoleCanManageScans() && !!window.__stAssetsScopeColumn;
    if (!can || n === 0) {
        bar.style.display = 'none';
        return;
    }
    bar.style.display = '';
    lbl.textContent = n === 1 ? '1 selected' : n + ' selected';
}

