async function stAssetsOpenBulkSetScopeModal() {
    if (!stRoleCanManageScans() || !window.__stAssetsScopeColumn) {
        return;
    }
    const ids = stAssetsSelectedIds();
    if (!ids.length) {
        return;
    }
    await ensureStScopeSelects(false);
    if (!(stScopesForFormsCache || []).length) {
        const emptyBg = document.getElementById('st-bulk-scope-empty-bg');
        if (emptyBg) {
            emptyBg.style.display = 'flex';
        }
        return;
    }
    const modal = document.getElementById('st-bulk-asset-scope-bg');
    const cnt = document.getElementById('st-bulk-scope-count');
    const sel = document.getElementById('st-bulk-scope-sel');
    const errEl = document.getElementById('st-bulk-scope-err');
    const ck = document.getElementById('st-bulk-scope-confirm');
    if (!modal || !sel) {
        return;
    }
    if (errEl) {
        errEl.textContent = '';
        errEl.style.display = 'none';
    }
    if (ck) {
        ck.checked = false;
    }
    modal.dataset.idsJson = JSON.stringify(ids);
    if (cnt) {
        cnt.textContent = String(ids.length) + ' asset(s) selected.';
    }
    stAssetPopulateScopeSelect(sel, { chooseLabel: '— choose scope —' });
    modal.style.display = 'flex';
}

async function submitStBulkAssetScopeModal() {
    const modal = document.getElementById('st-bulk-asset-scope-bg');
    const sel = document.getElementById('st-bulk-scope-sel');
    const errEl = document.getElementById('st-bulk-scope-err');
    const ck = document.getElementById('st-bulk-scope-confirm');
    if (!modal || !sel) {
        return;
    }
    if (!ck || !ck.checked) {
        if (errEl) {
            errEl.textContent = 'Confirm the checkbox to apply.';
            errEl.style.display = '';
        }
        return;
    }
    if (errEl) {
        errEl.style.display = 'none';
        errEl.textContent = '';
    }
    let ids = [];
    try {
        ids = JSON.parse(modal.dataset.idsJson || '[]');
    } catch (_e) {
        ids = [];
    }
    if (!Array.isArray(ids) || !ids.length) {
        toast('No assets selected.', 'err');
        return;
    }
    const scopePick = parseInt(String(sel.value || '0'), 10) || 0;
    if (scopePick <= 0) {
        if (errEl) {
            errEl.textContent = 'Choose a target scope.';
            errEl.style.display = '';
        }
        return;
    }
    const r = await apiPost('/api/assets.php?action=set_scope_bulk', {
        confirm: true,
        asset_ids: ids,
        scope_id: scopePick,
    });
    if (r && r.ok) {
        const u = r.updated != null ? r.updated : 0;
        const unc = r.unchanged != null ? r.unchanged : 0;
        const m = r.missing != null ? r.missing : 0;
        let msg = `Applied: ${u} asset(s).`;
        if (unc) {
            msg += ` Unchanged (already at target): ${unc}.`;
        }
        if (m) {
            msg += ` Not found: ${m}.`;
        }
        toast(msg, m && !u && !unc ? 'err' : 'ok');
        closeStBulkAssetScopeModal();
        stScopesForFormsCache = null;
        await ensureStScopeSelects(true);
        stAssetsToggleSelectAll(false);
        loadAssets(typeof assetPage === 'number' ? assetPage : 1);
        if (stRoleIsAdmin()) {
            void loadZabbixEnrichmentPanel();
        }
    } else {
        if (errEl) {
            errEl.textContent = (r && r.error) ? r.error : 'Bulk scope update failed';
            errEl.style.display = '';
        } else {
            toast((r && r.error) || 'Bulk scope update failed', 'err');
        }
    }
}

async function stAssetsBulkClearScopeFromBar() {
    if (!stRoleCanManageScans()) {
        toast('Scan editor or admin role required.', 'err');
        return;
    }
    if (!window.__stAssetsScopeColumn) {
        return;
    }
    const ids = stAssetsSelectedIds();
    if (!ids.length) {
        return;
    }
    const ok = await showConfirmModal(`Clear scope for ${ids.length} selected asset(s)?`, {
        title: 'Clear scope',
        okText: 'Clear',
    });
    if (!ok) {
        return;
    }
    const r = await apiPost('/api/assets.php?action=set_scope_bulk', { confirm: true, asset_ids: ids, scope_id: null });
    if (r && r.ok) {
        const u = r.updated != null ? r.updated : 0;
        const unc = r.unchanged != null ? r.unchanged : 0;
        const m = r.missing != null ? r.missing : 0;
        let msg = `Applied: ${u} asset(s).`;
        if (unc) {
            msg += ` Unchanged (already unscoped): ${unc}.`;
        }
        if (m) {
            msg += ` Not found: ${m}.`;
        }
        toast(msg, m && !u && !unc ? 'err' : 'ok');
        stScopesForFormsCache = null;
        await ensureStScopeSelects(true);
        stAssetsToggleSelectAll(false);
        loadAssets(typeof assetPage === 'number' ? assetPage : 1);
        if (stRoleIsAdmin()) {
            void loadZabbixEnrichmentPanel();
        }
    } else {
        toast((r && r.error) || 'Bulk scope clear failed', 'err');
    }
}

function closeStAssetScopeModal() {
    const bg = document.getElementById('st-asset-scope-bg');
    if (bg) {
        bg.style.display = 'none';
    }
    const ck = document.getElementById('st-asset-scope-confirm');
    if (ck) {
        ck.checked = false;
    }
    const sum = document.getElementById('st-asset-scope-summary');
    if (sum) {
        sum.textContent = '';
    }
    const cntHint = document.getElementById('st-asset-scope-count-hint');
    if (cntHint) {
        cntHint.style.display = 'none';
    }
}

function stAssetScopeLabelForId(scopeId) {
    const n = parseInt(String(scopeId || '0'), 10) || 0;
    if (n <= 0) {
        return 'None (unscoped)';
    }
    const sc = (stScopesForFormsCache || []).find((x) => parseInt(String(x.id), 10) === n);
    return sc ? String(sc.name || 'Scope #' + n) : 'Scope #' + n;
}

function stAssetScopeModalSyncLabels() {
    const bg = document.getElementById('st-asset-scope-bg');
    const sel = document.getElementById('st-asset-scope-sel');
    const sum = document.getElementById('st-asset-scope-summary');
    if (!sum || !bg || !sel) {
        return;
    }
    const curL = bg.dataset.currentScopeLabel ? String(bg.dataset.currentScopeLabel) : '—';
    const pick = parseInt(String(sel.value || '0'), 10) || 0;
    const tgt = stAssetScopeLabelForId(pick);
    sum.innerHTML =
        '<strong>Current scope:</strong> ' + esc(curL) + '<br><strong>Target scope:</strong> ' + esc(tgt);
}

/**
 * Single-asset inventory scope modal (Host detail, etc.). Uses `dataset.assetId` / `dataset.ip`;
 * submit sends `asset_ids: [id]` to `set_scope_bulk` — not table selection.
 * @param {number|string} assetId
 * @param {string} ip
 * @param {number|string} currentScopeId
 * @param {{ singleAssetHint?: boolean }} [opts]
 */
async function openStAssetScopeModal(assetId, ip, currentScopeId, opts) {
    if (!stRoleCanManageScans()) {
        toast('Scan editor or admin role required.', 'err');
        return;
    }
    const aid = parseInt(String(assetId != null ? assetId : '0'), 10) || 0;
    if (aid <= 0) {
        toast('Invalid asset.', 'err');
        return;
    }
    await ensureStScopeSelects(false);
    const bg = document.getElementById('st-asset-scope-bg');
    const ipEl = document.getElementById('st-asset-scope-ip');
    const sel = document.getElementById('st-asset-scope-sel');
    const errEl = document.getElementById('st-asset-scope-err');
    if (!bg || !sel) {
        return;
    }
    if (errEl) {
        errEl.textContent = '';
        errEl.style.display = 'none';
    }
    if (ipEl) {
        ipEl.textContent = 'Asset #' + aid + ' · ' + String(ip || '');
    }
    bg.dataset.assetId = String(aid);
    bg.dataset.ip = String(ip || '');
    stAssetPopulateScopeSelect(sel, { chooseLabel: '— none (clear scope) —' });
    const cur = parseInt(String(currentScopeId != null ? currentScopeId : 0), 10) || 0;
    sel.value = cur > 0 && [...sel.options].some((o) => o.value === String(cur)) ? String(cur) : '0';
    bg.dataset.currentScopeLabel = stAssetScopeLabelForId(cur);
    stAssetScopeModalSyncLabels();
    const ck = document.getElementById('st-asset-scope-confirm');
    if (ck) {
        ck.checked = false;
    }
    const cntHint = document.getElementById('st-asset-scope-count-hint');
    if (cntHint) {
        cntHint.style.display = opts && opts.singleAssetHint ? '' : 'none';
    }
    bg.style.display = 'flex';
}

async function submitStAssetScopeModal() {
    const bg = document.getElementById('st-asset-scope-bg');
    const sel = document.getElementById('st-asset-scope-sel');
    const errEl = document.getElementById('st-asset-scope-err');
    const ck = document.getElementById('st-asset-scope-confirm');
    if (!bg || !sel) {
        return;
    }
    if (!ck || !ck.checked) {
        if (errEl) {
            errEl.textContent = 'Confirm the checkbox to apply.';
            errEl.style.display = '';
        }
        return;
    }
    if (errEl) {
        errEl.style.display = 'none';
    }
    const assetId = parseInt(String(bg.dataset.assetId || '0'), 10) || 0;
    const ip = String(bg.dataset.ip || '');
    if (assetId <= 0) {
        toast('Invalid asset', 'err');
        return;
    }
    const scopePick = parseInt(String(sel.value || '0'), 10) || 0;
    const body = { confirm: true, asset_ids: [assetId], scope_id: scopePick > 0 ? scopePick : null };
    const r = await apiPost('/api/assets.php?action=set_scope_bulk', body);
    if (r && r.ok) {
        const u = r.updated != null ? r.updated : 0;
        const unc = r.unchanged != null ? r.unchanged : 0;
        const m = r.missing != null ? r.missing : 0;
        let msg = u > 0 ? `Applied scope to ${u} asset(s).` : 'No database rows changed.';
        if (unc) {
            msg += ` Unchanged (already at target): ${unc}.`;
        }
        if (m) {
            msg += ` Not found: ${m}.`;
        }
        toast(msg, m && !u && !unc ? 'err' : 'ok');
        closeStAssetScopeModal();
        stScopesForFormsCache = null;
        await ensureStScopeSelects(true);
        if (currentTab === 'assets') {
            loadAssets(typeof assetPage === 'number' ? assetPage : 1);
        }
        if (stIsHostPanelOpen()) {
            void openHostPanel(assetId, ip);
        }
        void loadScopesTab();
        if (stRoleIsAdmin()) {
            void loadZabbixEnrichmentPanel();
        }
    } else {
        if (errEl) {
            errEl.textContent = (r && r.error) ? r.error : 'Update failed';
            errEl.style.display = '';
        } else {
            toast((r && r.error) || 'Update failed', 'err');
        }
    }
}

async function loadScopesTab() {
    if (!stRoleCanManageScans()) {
        return;
    }
    const tb = document.getElementById('st-scopes-tbody');
    const err = document.getElementById('st-scopes-err');
    if (!tb) {
        return;
    }
    if (err) {
        err.style.display = 'none';
        err.textContent = '';
    }
    tb.innerHTML = '<tr><td colspan="7" class="loading tbl-empty st-scopes-empty">Loading scopes…</td></tr>';
    const d = await api('/api/scopes.php', { quiet: true });
    if (!d || !d.ok || !Array.isArray(d.scopes)) {
        tb.innerHTML = '<tr><td colspan="7" class="loading tbl-empty st-scopes-empty">Could not load scopes.</td></tr>';
        if (err) {
            err.textContent = (d && d.error) ? d.error : 'API error';
            err.style.display = '';
        }
        return;
    }
    stScopesForFormsCache = d.scopes;
    stScopesMeta.asset_counts = d.asset_counts && typeof d.asset_counts === 'object' ? d.asset_counts : {};
    stScopesMeta.job_counts = d.job_counts && typeof d.job_counts === 'object' ? d.job_counts : {};
    stScopesMeta.schedule_counts = d.schedule_counts && typeof d.schedule_counts === 'object' ? d.schedule_counts : {};
    const ac = stScopesMeta.asset_counts || {};
    const jc = stScopesMeta.job_counts || {};
    const scd = stScopesMeta.schedule_counts || {};
    const rows = d.scopes.map((sc) => {
        const id = parseInt(String(sc.id), 10) || 0;
        const cnt = parseInt(String(ac[String(id)] ?? 0), 10) || 0;
        const jn = parseInt(String(jc[String(id)] ?? 0), 10) || 0;
        const sn = parseInt(String(scd[String(id)] ?? 0), 10) || 0;
        const nm = esc(String(sc.name || '—'));
        const descRaw = sc.description != null && String(sc.description).trim() ? String(sc.description).trim() : '';
        const descTitle = descRaw ? esc(descRaw) : '';
        const descCell = descRaw
            ? `<span class="st-scope-desc-truncate" title="${descTitle}">${esc(descRaw)}</span>`
            : '<span class="text-dim">—</span>';
        const env = esc(String(sc.environment != null && String(sc.environment).trim() ? sc.environment : 'unknown'));
        const rowCls = cnt > 0 || jn > 0 || sn > 0 ? 'st-scopes-row--populated' : 'st-scopes-row--empty';
        const act = stRoleCanManageScans()
            ? `<button type="button" class="tbtn btn-xs" onclick="void stScopesOpenEditModal(${id})">Edit</button> `
                + `<button type="button" class="tbtn btn-xs tbtn--danger-quiet" onclick="void stScopesDelete(${id},${JSON.stringify(String(sc.name || ''))})">Delete</button>`
            : '—';
        return `<tr class="${rowCls}"><td class="tbl-cell-primary"><strong>${nm}</strong> <span class="tbl-cell-muted mono-sm">#${id}</span></td><td class="st-scope-desc-cell tbl-cell-muted">${descCell}</td><td class="tbl-cell-muted">${env}</td><td class="mono tbl-cell-mono tbl-cell-muted">${cnt}</td><td class="mono tbl-cell-mono tbl-cell-muted">${jn}</td><td class="mono tbl-cell-mono tbl-cell-muted">${sn}</td><td class="tbl-cell-actions st-scopes-row-actions">${act}</td></tr>`;
    });
    tb.innerHTML = rows.length
        ? rows.join('')
        : `<tr><td colspan="7" class="loading tbl-empty st-scopes-empty"><div class="st-scopes-empty-inner">${stRoleCanManageScans()
            ? 'Scopes are optional, but useful for grouping inventory and reports. No scopes exist yet — create one with <strong>+ New scope</strong> to organize assets and job-scope reporting.'
            : 'No scopes in catalog yet.'}</div></td></tr>`;
}

function stScopesOpenEditModal(scopeId) {
    if (!stRoleCanManageScans()) {
        return;
    }
    const sid = parseInt(String(scopeId), 10) || 0;
    if (sid <= 0) {
        return;
    }
    const list = stScopesForFormsCache || [];
    const sc = list.find((x) => (parseInt(String(x.id), 10) || 0) === sid);
    if (!sc) {
        toast('Scope not loaded — try Refresh.', 'err');
        void loadScopesTab();
        return;
    }
    const hid = document.getElementById('st-scope-edit-id');
    const nm = document.getElementById('st-scope-edit-name');
    const ds = document.getElementById('st-scope-edit-desc');
    const en = document.getElementById('st-scope-edit-env');
    const er = document.getElementById('st-scope-edit-err');
    if (hid) hid.value = String(sid);
    if (nm) nm.value = String(sc.name || '');
    if (ds) ds.value = sc.description != null ? String(sc.description) : '';
    if (en) {
        const ev = sc.environment != null && String(sc.environment).trim() ? String(sc.environment).trim() : '';
        en.value = ev === 'unknown' ? '' : ev;
    }
    if (er) {
        er.textContent = '';
        er.style.display = 'none';
    }
    const bg = document.getElementById('st-edit-scope-bg');
    if (bg) bg.style.display = 'flex';
    if (nm) nm.focus();
}

function closeStEditScopeModal() {
    const bg = document.getElementById('st-edit-scope-bg');
    if (bg) bg.style.display = 'none';
}

async function submitStEditScope() {
    if (!stRoleCanManageScans()) {
        return;
    }
    const errEl = document.getElementById('st-scope-edit-err');
    if (errEl) {
        errEl.textContent = '';
        errEl.style.display = 'none';
    }
    const scopeId = parseInt(String((document.getElementById('st-scope-edit-id') || {}).value || '0'), 10) || 0;
    if (scopeId <= 0) {
        return;
    }
    const name = String((document.getElementById('st-scope-edit-name') || {}).value || '').trim();
    if (!name) {
        if (errEl) {
            errEl.textContent = 'Name is required';
            errEl.style.display = '';
        }
        return;
    }
    const desc = String((document.getElementById('st-scope-edit-desc') || {}).value || '').trim();
    const envRaw = String((document.getElementById('st-scope-edit-env') || {}).value || '').trim();
    const btn = document.getElementById('st-scope-edit-submit');
    if (btn) btn.disabled = true;
    const r = await apiPost('/api/scopes.php?action=rename', {
        scope_id: scopeId,
        name,
        description: desc,
        environment: envRaw || 'unknown',
    });
    if (btn) btn.disabled = false;
    if (!r || !r.ok) {
        if (errEl) {
            errEl.textContent = (r && r.error) ? r.error : 'Save failed';
            errEl.style.display = '';
        }
        return;
    }
    toast('Scope updated', 'ok');
    closeStEditScopeModal();
        stScopesForFormsCache = null;
        await ensureStScopeSelects(true);
        void loadScopesTab();
        void loadReportingScopeSelector(true);
        if (stRoleIsAdmin()) {
            void loadZabbixEnrichmentPanel();
    }
}

async function stScopesDelete(scopeId, scopeName) {
    if (!stRoleCanManageScans()) {
        return;
    }
    let impactLine = '';
    try {
        const im = await api('/api/scopes.php?action=delete_impact&scope_id=' + encodeURIComponent(String(scopeId)), { quiet: true });
        if (im && im.ok && im.impact) {
            const x = im.impact;
            impactLine =
                '\n\nImpact if you delete:\n'
                + `· ${x.assets != null ? x.assets : 0} asset(s) will become unscoped\n`
                + `· ${x.jobs != null ? x.jobs : 0} scan job row(s) will have job scope cleared\n`
                + `· ${x.schedules != null ? x.schedules : 0} schedule(s) will have default scope cleared\n`
                + `· ${x.baselines != null ? x.baselines : 0} scope baseline row(s) removed with the scope\n`
                + `· ${x.zabbix_rules != null ? x.zabbix_rules : 0} Zabbix scope map rule(s) removed\n\n`
                + 'Historical scan snapshots are not rewritten; reporting still keys off each job’s scope at run time.';
        }
    } catch (_e) {
        impactLine = '\n\n(Could not load exact counts — impact still applies.)\n\n';
    }
    const ok = await showConfirmModal(
        `Delete scope "${scopeName}" (#${scopeId})?`
            + impactLine
            + 'This cannot be undone.',
        { title: 'Delete scope', okText: 'Delete' }
    );
    if (!ok) {
        return;
    }
    const r = await apiPost('/api/scopes.php?action=delete', { scope_id: scopeId, confirm: true });
    if (r && r.ok) {
        toast('Scope deleted', 'ok');
        stScopesForFormsCache = null;
        await ensureStScopeSelects(true);
        void loadScopesTab();
        void loadReportingScopeSelector(true);
        if (stRoleIsAdmin()) {
            void loadZabbixEnrichmentPanel();
        }
    } else {
        toast((r && r.error) || 'Delete failed', 'err');
    }
}

function stAssetsZabbixFilterSummaryLabel() {
    const bits = [];
    const zm = document.getElementById('af-zbx-monitored')?.value || '';
    if (zm === '1') {
        bits.push('monitored');
    } else if (zm === '0') {
        bits.push('not monitored');
    }
    if (document.getElementById('af-zbx-unavail')?.checked) {
        bits.push('unavailable');
    }
    if (document.getElementById('af-zbx-problems')?.checked) {
        bits.push('problems');
    }
    if ((document.getElementById('af-zbx-group')?.value || '').trim()) {
        bits.push('group');
    }
    if ((document.getElementById('af-zbx-tag')?.value || '').trim()) {
        bits.push('tag');
    }
    if (!bits.length) {
        return 'Zabbix';
    }
    return 'Zabbix (' + bits.join(', ') + ')';
}

function stAssetsScopeFilterActiveCount() {
    const sel = document.getElementById('af-scope-filter');
    if (!window.__stAssetsScopeColumn || !sel || sel.style.display === 'none') {
        return 0;
    }
    return sel.value !== '' ? 1 : 0;
}

function stAssetsUpdateScopeDisclosureButtonLabel() {
    const btn = document.getElementById('af-scope-disclosure-btn');
    if (!btn) {
        return;
    }
    if (btn.disabled) {
        btn.textContent = 'Scope filters (unavailable)';
        return;
    }
    const n = stAssetsScopeFilterActiveCount();
    btn.textContent = n ? ('Scope filters (' + String(n) + ' active)') : 'Scope filters';
}

function stAssetsSyncScopeDisclosureState() {
    const panel = document.getElementById('af-scope-panel');
    const btn = document.getElementById('af-scope-disclosure-btn');
    if (!panel || !btn || btn.disabled) {
        return;
    }
    const sel = document.getElementById('af-scope-filter');
    let open = !!(sel && sel.style.display !== 'none' && sel.value !== '');
    if (!open) {
        try {
            open = localStorage.getItem('st_assets_scope_filters_open') === '1';
        } catch (_e) {
            open = false;
        }
    }
    panel.classList.toggle('hide', !open);
    btn.setAttribute('aria-expanded', open ? 'true' : 'false');
    stAssetsUpdateScopeDisclosureButtonLabel();
}

function stAssetsScopeDisclosureToggle() {
    const panel = document.getElementById('af-scope-panel');
    const btn = document.getElementById('af-scope-disclosure-btn');
    if (!panel || !btn || btn.disabled) {
        return;
    }
    const willOpen = panel.classList.contains('hide');
    panel.classList.toggle('hide', !willOpen);
    btn.setAttribute('aria-expanded', willOpen ? 'true' : 'false');
    try {
        localStorage.setItem('st_assets_scope_filters_open', willOpen ? '1' : '0');
    } catch (_e) {}
    stAssetsUpdateScopeDisclosureButtonLabel();
}

function stAssetsOnScopeFilterChange() {
    stAssetsUpdateScopeDisclosureButtonLabel();
    stAssetsSyncScopeDisclosureState();
    void loadAssets(1);
}

function stAssetsExpandFilterPanel(which, doScroll) {
    if (which === 'ai') {
        if (!window.__stAiFiltersToolbarAvailable) {
            return;
        }
        const wrap = document.getElementById('af-ai-filters-wrap');
        const panel = document.getElementById('af-ai-filters-panel');
        const btn = document.getElementById('af-ai-filters-disclosure-btn');
        if (!panel || !btn) {
            return;
        }
        if (wrap) {
            wrap.style.display = '';
        }
        panel.classList.remove('hide');
        btn.setAttribute('aria-expanded', 'true');
        try {
            localStorage.setItem('st_assets_ai_filters_open', '1');
        } catch (_e) {}
        stAssetsUpdateAiFiltersButtonLabel();
        if (doScroll && wrap) {
            wrap.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
        }
        return;
    }
    if (which === 'zbx') {
        if (!window.__stAssetsZabbixFiltersAvailable) {
            return;
        }
        const sec = document.getElementById('af-zbx-section');
        const panel = document.getElementById('af-zbx-panel');
        const btn = document.getElementById('af-zbx-disclosure-btn');
        if (!panel || !btn) {
            return;
        }
        if (sec) {
            sec.style.display = '';
        }
        panel.classList.remove('hide');
        btn.setAttribute('aria-expanded', 'true');
        try {
            localStorage.setItem('st_assets_zbx_filters_open', '1');
        } catch (_e) {}
        stAssetsUpdateZabbixDisclosureButtonLabel();
        if (doScroll && sec) {
            sec.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
        }
        return;
    }
    if (which === 'scope') {
        const btn = document.getElementById('af-scope-disclosure-btn');
        const panel = document.getElementById('af-scope-panel');
        if (!btn || btn.disabled || !panel) {
            return;
        }
        panel.classList.remove('hide');
        btn.setAttribute('aria-expanded', 'true');
        try {
            localStorage.setItem('st_assets_scope_filters_open', '1');
        } catch (_e) {}
        stAssetsUpdateScopeDisclosureButtonLabel();
        if (doScroll) {
            document.getElementById('af-scope-section')?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
        }
    }
}

function stAssetsSummarySegmentClick(which) {
    const w = String(which || '');
    if (w !== 'ai' && w !== 'zbx' && w !== 'scope') {
        return;
    }
    stAssetsExpandFilterPanel(w, true);
}

function stAssetsRenderFilterSummary() {
    const bar = document.getElementById('af-filter-summary-bar');
    if (!bar) {
        return;
    }
    const parts = [];
    const sf = document.getElementById('af-scope-filter');
    const scopeOn = window.__stAssetsScopeColumn && sf && sf.style.display !== 'none' && sf.value !== '';
    if (scopeOn) {
        const opt = sf.options[sf.selectedIndex];
        const raw = opt ? String(opt.textContent || '').trim() : '';
        const nameOnly = raw.replace(/\s*\([^)]*\)\s*$/, '').trim() || raw || 'Scope';
        parts.push({ key: 'scope', label: 'Scope=' + nameOnly.slice(0, 48) });
    }
    if (window.__stAiNeedsReviewFilterAvailable && document.getElementById('af-ai-review')?.checked) {
        parts.push({ key: 'ai', label: 'Needs AI review' });
    }
    if (window.__stAiSummaryFilterAvailable && document.getElementById('af-ai-summary')?.checked) {
        parts.push({ key: 'ai', label: 'Has host summary' });
    }
    if (window.__stAssetsZabbixFiltersAvailable && stAssetsZabbixFilterActiveDims() > 0) {
        parts.push({ key: 'zbx', label: stAssetsZabbixFilterSummaryLabel() });
    }
    let html = '<span class="af-sum-lbl">Showing:</span> ';
    if (assetDeviceFilter > 0) {
        html += '<span class="af-sum-seg af-sum-seg--dim">Device #' + esc(String(assetDeviceFilter)) + '</span>';
    }
    if (!parts.length) {
        if (assetDeviceFilter > 0) {
            html += ' <span class="text-dim">·</span> <span class="text-dim">no extra list filters</span>';
        } else {
            html += '<span class="text-dim">no extra list filters</span>';
        }
    } else {
        if (assetDeviceFilter > 0) {
            html += ' <span class="text-dim">·</span> ';
        }
        for (let i = 0; i < parts.length; i++) {
            if (i) {
                html += ' <span class="text-dim">·</span> ';
            }
            const p = parts[i];
            const segKey = p.key === 'scope' || p.key === 'zbx' || p.key === 'ai' ? p.key : 'ai';
            html += '<button type="button" class="af-sum-seg" onclick="stAssetsSummarySegmentClick(\'' + segKey + '\')">' + esc(p.label) + '</button>';
        }
    }
    bar.innerHTML = html;
}

function stAssetsFillScopeFilter(d) {
    const sel = document.getElementById('af-scope-filter');
    const hint = document.getElementById('af-scope-unavailable-hint');
    const btn = document.getElementById('af-scope-disclosure-btn');
    if (!sel) {
        return;
    }
    if (!d || !d.assets_scope_column || !Array.isArray(d.asset_scope_filter_options)) {
        sel.innerHTML = '<option value="">All scopes</option>';
        sel.value = '';
        sel.style.display = 'none';
        if (hint) {
            hint.classList.remove('hide');
        }
        if (btn) {
            btn.disabled = true;
            btn.setAttribute('aria-disabled', 'true');
            btn.title = 'Inventory scope filter requires the assets.scope_id column and scope catalog (migrations / Scopes tab).';
        }
        const panel = document.getElementById('af-scope-panel');
        if (panel) {
            panel.classList.add('hide');
        }
        if (btn) {
            btn.setAttribute('aria-expanded', 'false');
        }
        try {
            localStorage.removeItem('st_assets_scope_filters_open');
        } catch (_e) {}
        stAssetsUpdateScopeDisclosureButtonLabel();
        return;
    }
    if (hint) {
        hint.classList.add('hide');
    }
    if (btn) {
        btn.disabled = false;
        btn.removeAttribute('aria-disabled');
        btn.title = 'Filter by inventory scope (assets.scope_id). Distinct from Reports job scope.';
    }
    const prev = sel.value;
    sel.innerHTML = '<option value="">All scopes</option>';
    const un = d.unscoped_asset_count != null ? Number(d.unscoped_asset_count) : 0;
    const o0 = document.createElement('option');
    o0.value = '0';
    o0.textContent = 'Unscoped (' + String(un) + ')';
    sel.appendChild(o0);
    (d.asset_scope_filter_options || []).forEach((s) => {
        const id = parseInt(String(s.id || '0'), 10);
        if (!id) {
            return;
        }
        const op = document.createElement('option');
        op.value = String(id);
        const nm = String(s.name || 'Scope #' + id).slice(0, 80);
        const c = s.asset_count != null ? Number(s.asset_count) : 0;
        op.textContent = nm + ' (' + String(c) + ')';
        sel.appendChild(op);
    });
    const ok = new Set(['', '0']);
    (d.asset_scope_filter_options || []).forEach((s) => {
        const id = parseInt(String(s.id || '0'), 10);
        if (id > 0) {
            ok.add(String(id));
        }
    });
    if (prev && ok.has(prev)) {
        sel.value = prev;
    } else {
        sel.value = '';
    }
    sel.style.display = '';
    stAssetsSyncScopeDisclosureState();
    stAssetsUpdateScopeDisclosureButtonLabel();
}

/** Trusted assertion display threshold (medium+); matches api/lib_reconciliation.php trusted operational preference. */
function stTrustedMeetsOperationalUiPref(conf) {
    const c = String(conf || '').toLowerCase();
    return c === 'medium' || c === 'high' || c === 'authoritative';
}
/** Prefer reconciled hostname in tables when API exposes trusted_hostname + confidence. */
function stAssetDisplayHostnameFromRow(a) {
    if (!a) return '—';
    const t = a.trusted_hostname != null && String(a.trusted_hostname).trim()
        && stTrustedMeetsOperationalUiPref(a.trusted_hostname_confidence)
        ? String(a.trusted_hostname).trim() : '';
    if (t) return t;
    const h = a.hostname != null ? String(a.hostname).trim() : '';
    return h || '—';
}
function stAssetTrustedHostnameChipHtml(a, tip) {
    if (!a || !a.trusted_hostname || !String(a.trusted_hostname).trim()) return '';
    if (!stTrustedMeetsOperationalUiPref(a.trusted_hostname_confidence)) return '';
    const tv = String(a.trusted_hostname).trim();
    const hv = a.hostname != null ? String(a.hostname).trim() : '';
    if (hv && hv.toLowerCase() === tv.toLowerCase()) return '';
    const t = tip || 'Reconciled canonical hostname (medium+ confidence). Stored hostname may differ.';
    return ` <span class="hp-chip st-trusted-pref-chip" title="${esc(t)}">Trusted</span>`;
}

async function loadAssets(page) {
    const tbody = document.getElementById('asset-tbody');
    if (!tbody) {
        return;
    }
    refreshBadges();
    assetPage = page;
    const q    = document.getElementById('af-q')?.value    || '';
    const cat  = document.getElementById('af-cat')?.value  || '';
    const sev  = document.getElementById('af-sev')?.value  || '';
    const sort = document.getElementById('af-sort')?.value || assetSort;
    const aiReview = !!window.__stAiNeedsReviewFilterAvailable && !!document.getElementById('af-ai-review')?.checked;
    const aiSummaryOn = !!window.__stAiSummaryFilterAvailable && !!document.getElementById('af-ai-summary')?.checked;
    const zbxOkForQuery = !!window.__stAssetsZabbixFiltersAvailable;
    const zbxColBefore = zbxOkForQuery && !!document.getElementById('af-zbx-col')?.checked;
    const thZbx = document.getElementById('af-th-zbx');
    if (thZbx) thZbx.classList.toggle('hide', !zbxColBefore);
    const showRowChk = stRoleCanManageScans();
    const listColsLoading = zbxColBefore ? (showRowChk ? 14 : 13) : (showRowChk ? 13 : 12);
    const zMon = zbxOkForQuery ? (document.getElementById('af-zbx-monitored')?.value || '') : '';
    const zUn = zbxOkForQuery && document.getElementById('af-zbx-unavail')?.checked ? '1' : '';
    const zPr = zbxOkForQuery && document.getElementById('af-zbx-problems')?.checked ? '1' : '';
    const zGr = zbxOkForQuery ? (document.getElementById('af-zbx-group')?.value || '').trim() : '';
    const zTg = zbxOkForQuery ? (document.getElementById('af-zbx-tag')?.value || '').trim() : '';
    let zbxQ = '';
    if (zbxOkForQuery) {
        if (zMon === '0' || zMon === '1') zbxQ += `&zabbix_monitored=${enc(zMon)}`;
        if (zUn) zbxQ += '&zabbix_unavailable=1';
        if (zPr) zbxQ += '&zabbix_has_problems=1';
        if (zGr) zbxQ += `&zabbix_group=${enc(zGr)}`;
        if (zTg) zbxQ += `&zabbix_tag=${enc(zTg)}`;
    }

    // Show loading state immediately
    tbody.innerHTML =
        `<tr><td colspan="${listColsLoading}" class="loading tbl-empty">Loading assets…</td></tr>`;
    stAssetsUpdateBulkBarVisibility();

    const b = document.getElementById('af-device-banner');
    const idEl = document.getElementById('af-device-banner-id');
    if (assetDeviceFilter > 0 && b && idEl) {
        idEl.textContent = String(assetDeviceFilter);
        b.classList.remove('hide');
    } else if (b) {
        b.classList.add('hide');
        if (idEl) idEl.textContent = '';
    }

    const devQ = assetDeviceFilter > 0 ? `&device_id=${encodeURIComponent(String(assetDeviceFilter))}` : '';
    const aiQ = aiReview ? '&ai_review=1' : '';
    const aiSumQ = aiSummaryOn ? '&ai_summary=1' : '';
    const life = document.getElementById('af-life')?.value || '';
    const lifeQ = life ? `&lifecycle_status=${enc(life)}` : '';
    const sfEl = document.getElementById('af-scope-filter');
    const scopeQ = (window.__stAssetsScopeColumn && sfEl && sfEl.style.display !== 'none' && sfEl.value !== '')
        ? `&scope_id=${encodeURIComponent(sfEl.value)}`
        : '';
    const url = `/api/assets.php?page=${page}&per_page=50&q=${enc(q)}&category=${enc(cat)}&severity=${enc(sev)}&sort=${sort}&order=${assetOrder}${devQ}${aiQ}${aiSumQ}${lifeQ}${scopeQ}${zbxQ}`;
    const d   = await api(url);
    if (!d) return;

    stAssetsApplyZabbixFromServer(!!d.zabbix_filters_available);
    stAssetsApplyAiFiltersFromServer(d);

    try {
        window.__stAssetsScopeColumn = !!d.assets_scope_column;
    } catch (_e) {}
    stAssetsFillScopeFilter(d);
    const headChk = document.getElementById('af-select-all');
    if (headChk) {
        headChk.checked = false;
        headChk.indeterminate = false;
    }

    const zbxColRender = !!window.__stAssetsZabbixFiltersAvailable && !!document.getElementById('af-zbx-col')?.checked;
    if (thZbx) thZbx.classList.toggle('hide', !zbxColRender);
    const listCols = zbxColRender ? (showRowChk ? 14 : 13) : (showRowChk ? 13 : 12);
    const zbxTd = (a) => (zbxColRender ? `<td class="mono-sm tbl-cell-mono tbl-cell-muted">${stAssetZabbixCellHtml(a)}</td>` : '');
    const chkTd = showRowChk
        ? (a) =>
              `<td onclick="event.stopPropagation()"><input type="checkbox" class="af-row-chk chk-input" data-aid="${a.id}" onchange="stAssetsSyncSelectAllCheckbox()" aria-label="Select ${esc(a.ip)}"></td>`
        : () => '';
    const scopeTip = 'Inventory scope; reporting uses scan job scope for historical snapshots.';
    const scopeCell = (a) =>
        `<td class="mono-sm tbl-cell-mono tbl-cell-muted" title="${esc(scopeTip)}">${esc(a.scope_name != null && String(a.scope_name).trim() ? String(a.scope_name) : '—')}</td>`;
    tbody.innerHTML = (d.assets || []).map(a => {
        const ports = (a.open_ports || []).slice(0,6).map(p => `<span class="pt">${Number(p)}</span>`).join('');
        const more  = a.open_ports && a.open_ports.length > 6 ? `<span class="pt">+${a.open_ports.length-6}</span>` : '';
        const vendorSummary = stVendorSummaryForAsset(a);
        let vendorCell = `<span title="${esc(vendorSummary.title)}">${esc(vendorSummary.label)}</span>`;
        vendorCell += a.model ? '<span class="text-secondary"> ' + esc(a.model) + '</span>' : '';
        const editBtn = stRoleCanManageScans()
            ? `<button type="button" class="tbtn btn-xs" onclick="openReclassify(${a.id},'${esc(a.ip)}','${esc(a.hostname||'')}','${esc(a.category)}','${esc(a.vendor||'')}','${esc(a.notes||'')}','${esc(a.owner||'')}','${esc(a.business_unit||'')}','${esc(a.criticality||'medium')}','${esc(a.environment||'unknown')}',${Number(a.hostname_locked||0)},${Number(a.category_locked||0)},${Number(a.vendor_locked||0)})">&#9998;</button>`
            : '';
        return `<tr>
          ${chkTd(a)}
          <td class="mono mono-sm tbl-cell-mono tbl-cell-primary click-ip" onclick="openHostPanel(${a.id},'${esc(a.ip)}')" title="View host detail">${esc(a.ip)}</td>
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${a.device_id != null && a.device_id !== '' ? `<span class="click-ip" onclick="event.stopPropagation();openDevicePanel(${a.device_id})" title="Device overview">${esc(String(a.device_id))}</span>` : '—'}</td>
          <td class="tbl-cell-primary">${esc(stAssetDisplayHostnameFromRow(a))}${stAssetTrustedHostnameChipHtml(a)}</td>
          <td><span class="cat ${esc(a.category||'unk')}">${esc(a.category||'unk')}</span></td>
          <td style="white-space:nowrap">${lifecycleBadgeHtml(a)}</td>
          <td class="tbl-cell-primary" style="font-size:12px">${vendorCell}</td>
          <td class="tbl-cell-muted"><div class="pts">${ports}${more}</div></td>
          <td class="mono tbl-cell-mono tbl-cell-muted">${a.open_findings||0}</td>
          <td><span class="sev ${sevClass(a.top_cvss)}">${a.top_cvss?a.top_cvss:'—'}</span></td>
          ${zbxTd(a)}
          ${scopeCell(a)}
          <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${relTime(a.last_seen)}</td>
          <td class="tbl-cell-actions">
            <button type="button" class="tbtn btn-xs" onclick="openHostPanel(${a.id},'${esc(a.ip)}')">Details</button>
            ${editBtn}
          </td>
        </tr>`;
    }).join('') || `<tr><td colspan="${listCols}" class="loading tbl-empty">No assets match the current filters.</td></tr>`;

    const apgn = document.getElementById('apgn-info');
    if (apgn) {
        apgn.textContent =
        assetDeviceFilter > 0
            ? `Page ${d.page} of ${d.pages} (${d.total} assets for device ${assetDeviceFilter})`
            : `Page ${d.page} of ${d.pages} (${d.total} assets)`;
    }
    const aprev = document.getElementById('aprev');
    const anext = document.getElementById('anext');
    if (aprev) aprev.disabled = page <= 1;
    if (anext) anext.disabled = page >= d.pages;
    stAssetsUpdateBulkBarVisibility();
    try {
    stAssetsRenderFilterSummary();
    } catch (e) {
        console.error('stAssetsRenderFilterSummary', e);
    }
}

// --------------------------------------------------------------------------
// CVE triage display (used by Vulnerabilities tab + host panel)
// --------------------------------------------------------------------------
function findingTriageMethodLabel(m) {
    const k = String(m || '');
    const map = {
        nmap_port_cpe: 'nmap CPE',
        asset_fingerprint_cpe: 'host CPE',
        collector_ingest: 'collector',
        unknown: '—',
    };
    return map[k] || (k ? k.slice(0, 18) : '—');
}

function findingEvidenceTitle(f) {
    const ev = (f && f.evidence && typeof f.evidence === 'object') ? f.evidence : {};
    const bits = [];
    if (ev.matched_cpe) bits.push('Matched CPE: ' + String(ev.matched_cpe));
    if (ev.cpe_origin) bits.push('Origin: ' + String(ev.cpe_origin));
    if (ev.rationale) bits.push(String(ev.rationale));
    return bits.join('\n');
}

function findingConfidenceChipClass(conf) {
    const c = String(conf || 'low').toLowerCase();
    if (c === 'authoritative') return 'conf-chip conf-high';
    if (c === 'high') return 'conf-chip conf-high';
    if (c === 'medium') return 'conf-chip conf-med';
    if (c === 'unknown') return 'conf-chip conf-low';
    return 'conf-chip conf-low';
}

/** Subtle provenance chip for reconciliation evidence tables (matches `source_tier` from API). */
function stEvidenceSourceTierHtml(tier) {
    const t = String(tier || 'other').toLowerCase();
    const map = {
        authenticated: { abbr: 'Auth', title: 'Authenticated credentialed evidence' },
        unauthenticated: { abbr: 'Scan', title: 'Unauthenticated scan / network inference' },
        monitoring: { abbr: 'Mon', title: 'Monitoring inventory (e.g. Zabbix)' },
        enrichment: { abbr: 'Enrich', title: 'Enrichment or operator-supplied context' },
        other: { abbr: '', title: '' },
    };
    const m = map[t] || map.other;
    if (!m.abbr) return '';
    return `<span class="st-ev-src st-ev-src--${esc(t)}" title="${esc(m.title)}">${esc(m.abbr)}</span>`;
}

function stHostCredentialedChecksHtml(assetData) {
    if (!assetData) return '';
    const s = assetData.credential_check_host_summary;
    if (!s || s.tables_ready !== true) return '';
    const hasPkg = s.package_inventory_summary && (
        (s.package_inventory_summary.package_count != null && Number(s.package_inventory_summary.package_count) >= 0)
        || (s.package_inventory_summary.package_manager != null && String(s.package_inventory_summary.package_manager).trim() !== '')
    );
    const snmp = s.snmp_identity_summary;
    const hasSnmp = snmp && (
        (snmp.sys_name != null && String(snmp.sys_name).trim() !== '')
        || (snmp.vendor_hint != null && String(snmp.vendor_hint).trim() !== '')
        || (snmp.name_hint != null && String(snmp.name_hint).trim() !== '')
    );
    if (!s.has_activity && !hasPkg && !hasSnmp && !s.os_trust_note) return '';

    const ls = s.last_successful_run;
    const lastSucc = ls && ls.run_id
        ? `Run #${esc(String(ls.run_id))} · ${esc(ls.job_name || '—')} · ${esc(localTime(ls.finished_at || ''))}`
        : '<span class="text-dim">—</span>';
    const pluginsEx = ls && Array.isArray(ls.plugins_executed) && ls.plugins_executed.length
        ? ls.plugins_executed.map((p) => `<span class="mono-sm">${esc(String(p))}</span>`).join(' ')
        : '<span class="text-dim">—</span>';
    const lt = s.last_target_touch;
    const lastState = lt
        ? `<span class="mono-sm">${esc(lt.target_status || '')}</span> · run <span class="mono-sm">${esc(lt.run_status || '')}</span>${lt.error_code ? ` · <span class="mono-sm">${esc(String(lt.error_code))}</span>` : ''}`
        : '<span class="text-dim">—</span>';

    let pkgBlock = '';
    if (s.package_inventory_summary) {
        const p = s.package_inventory_summary;
        const bits = [];
        if (p.package_manager) bits.push(esc(String(p.package_manager)));
        if (p.package_count != null) bits.push(`${esc(String(p.package_count))} packages`);
        if (p.partial) bits.push('<span class="st-cc-pill st-cc-pill--warn">partial</span>');
        if (p.truncated) bits.push('<span class="st-cc-pill st-cc-pill--warn">truncated</span>');
        if (bits.length) {
            pkgBlock = `<div><span class="text-dim">Package inventory (summary)</span><div class="row-wrap gap4">${bits.join(' · ')}</div></div>`;
        }
    }

    let snmpBlock = '';
    if (hasSnmp) {
        const n = s.snmp_identity_summary;
        const bits = [];
        if (n.sys_name) bits.push(`sysName <span class="mono-sm">${esc(String(n.sys_name))}</span>`);
        if (n.vendor_hint) bits.push(esc(String(n.vendor_hint)));
        if (n.name_hint) bits.push(esc(String(n.name_hint)));
        if (n.partial) bits.push('<span class="st-cc-pill st-cc-pill--warn">partial</span>');
        snmpBlock = `<div><span class="text-dim">SNMP identity (summary)</span><div class="row-wrap gap4">${bits.join(' · ')}</div></div>`;
    }

    const recent = Array.isArray(s.recent_runs) ? s.recent_runs : [];
    const recentBlock = recent.length
        ? `<details class="st-host-cc-recent mt8"><summary class="text-micro st-host-cc-recent-sum">View recent runs</summary>
            <ul class="st-host-cc-recent-list text-micro text-dim mt4 mb0 pl18">${recent.map((r) =>
            `<li><span class="mono-sm">#${esc(String(r.run_id))}</span> · ${esc(r.run_status || '')} · target ${esc(r.target_status || '')} · ${esc(r.job_name || '')}</li>`
        ).join('')}</ul>
           </details>`
        : '';

    const trustNote = s.os_trust_note
        ? `<p class="hint-micro text-dim mt6 mb0 st-host-cc-trust">${esc(String(s.os_trust_note))}</p>`
        : '';

    const adminRuns = stRoleIsAdmin()
        ? `<div class="mt8"><button type="button" class="tbtn btn-xs" onclick="stGoToCredentialedRunsSettings()">Open credentialed runs in Settings</button></div>`
        : '';

    return `<section class="host-section st-host-subsection st-host-cc-summary" aria-label="Credentialed checks">
      <h3 class="host-section-heading">Credentialed checks</h3>
      <div class="host-inner-surface st-host-cc-inner">
        <div class="st-host-cc-grid text-micro">
          <div><span class="text-dim">Last successful target completion</span><div>${lastSucc}</div></div>
          <div><span class="text-dim">Plugins observed on that run</span><div class="row-wrap gap4">${pluginsEx}</div></div>
          <div><span class="text-dim">Latest target touch</span><div>${lastState}</div></div>
          ${pkgBlock}
          ${snmpBlock}
        </div>
        <p class="hint-micro text-dim mt6 mb0">Package names are summarized here; full lists stay in bounded run results (not in this modal).</p>
        ${trustNote}
        ${recentBlock}
        ${adminRuns}
      </div>
    </section>`;
}

function stGoToCredentialedRunsSettings() {
    goTab('settings');
    hiNav('nsettings');
    setTimeout(() => {
        const el = document.getElementById('st-cred-jobs-card');
        if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
        if (stRoleIsAdmin()) void stCcLoadJobsAndRuns();
    }, 80);
}

function stHostReconciliationEvidenceDetailHtml(rd) {
    if (!rd || rd.tables_ready !== true) return '';
    const obs = Array.isArray(rd.observations) ? rd.observations : [];
    const runs = Array.isArray(rd.recent_runs) ? rd.recent_runs : [];
    const asrc = Array.isArray(rd.assertion_sources) ? rd.assertion_sources : [];
    const ast = rd.assertion && typeof rd.assertion === 'object' ? rd.assertion : null;
    const sw = rd.software_observed && typeof rd.software_observed === 'object' ? rd.software_observed : null;
    const sir = rd.software_inventory_rows && typeof rd.software_inventory_rows === 'object' ? rd.software_inventory_rows : null;
    const swCount = sw ? (parseInt(String(sw.observation_count || 0), 10) || 0) : 0;
    const sirCount = sir ? (parseInt(String(sir.active_count || 0), 10) || 0) : 0;
    const swPrev = sw && Array.isArray(sw.preview) ? sw.preview : [];
    const sirPrev = sir && Array.isArray(sir.preview) ? sir.preview : [];
    if (!obs.length && !runs.length && !asrc.length && !ast && swCount === 0 && sirCount === 0) return '';
    const astHead = ast
        ? `<div class="text-micro text-dim mb6 st-host-evidence-astmeta">Stored assertion <span class="mono-sm">${esc(String(ast.value_label || ast.value_slug || ''))}</span>${ast.reconciled_at ? ` · reconciled ${esc(localTime(ast.reconciled_at))}` : ''}${ast.version != null ? ` · v${esc(String(ast.version))}` : ''}</div>`
        : '';
    const asrcRows = asrc.map((a) => {
        const nm = a.normalized_value != null && String(a.normalized_value).trim() ? esc(String(a.normalized_value)) : '\u2014';
        const tierH = stEvidenceSourceTierHtml(a.source_tier);
        const dn = esc(String(a.display_name || '\u2014'));
        const ot = esc(String(a.observation_type || ''));
        const c = esc(String(a.contribution || ''));
        const w = a.weight_note != null && String(a.weight_note).trim() ? esc(String(a.weight_note)) : '\u2014';
        const oref = a.observation_source_ref ? `<span class="mono-sm">${esc(String(a.observation_source_ref))}</span>` : '\u2014';
        const oat = a.observation_observed_at ? esc(localTime(String(a.observation_observed_at))) : '\u2014';
        return `<tr><td>${tierH}${tierH ? ' ' : ''}${dn}</td><td class="mono-sm">${ot}</td><td>${oref}</td><td class="text-dim">${oat}</td><td class="mono-sm">${nm}</td><td>${c}</td><td class="text-dim">${w}</td></tr>`;
    }).join('');
    const asrcBlock = asrc.length
        ? `<div class="text-micro text-dim mt8 mb4">How the belief was built (assertion sources)</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Source</th><th>Type</th><th>Plugin / ref</th><th>Observed</th><th>Normalized</th><th>Role</th><th>Note</th></tr></thead><tbody>${asrcRows}</tbody></table></div>`
        : '';
    const obsRows = obs.map((o) => {
        const raw = o.raw_value != null && String(o.raw_value).trim() ? esc(String(o.raw_value)) : '\u2014';
        const norm = o.normalized_value != null && String(o.normalized_value).trim() ? esc(String(o.normalized_value)) : '\u2014';
        const when = o.observed_at ? esc(localTime(o.observed_at)) : '\u2014';
        const tierH = stEvidenceSourceTierHtml(o.source_tier);
        const src = esc([o.display_name || '', o.source_type || ''].filter(Boolean).join(' · ') || '\u2014');
        const ref = o.source_object_ref ? `<span class="mono-sm">${esc(String(o.source_object_ref))}</span>` : '\u2014';
        const hint = o.contribution_hint && String(o.contribution_hint).trim()
            ? esc(String(o.contribution_hint))
            : '\u2014';
        return `<tr><td class="mono-sm">${esc(String(o.observation_type || ''))}</td><td>${tierH}${tierH ? ' ' : ''}${src}</td><td>${ref}</td><td class="st-host-evidence-cell-raw">${raw}</td><td class="mono-sm">${norm}</td><td class="text-dim">${when}</td><td class="text-dim">${hint}</td><td>${esc(String(o.confidence_level || '').toUpperCase())}</td></tr>`;
    }).join('');
    const runRows = runs.map((r) => {
        const rawErr = r.error && String(r.error).trim() ? String(r.error) : '';
        const rawSum = r.result_summary && String(r.result_summary).trim() ? String(r.result_summary) : '';
        const err = rawErr ? esc(rawErr) : (rawSum ? esc(rawSum) : '\u2014');
        const fin = r.finished_at ? esc(localTime(r.finished_at)) : '\u2014';
        return `<tr><td class="mono-sm">${esc(String(r.status || ''))}</td><td class="mono-sm">${esc(String(r.slice_key || ''))}</td><td class="text-dim">${fin}</td><td class="st-host-evidence-cell-raw">${err}</td></tr>`;
    }).join('');
    const obsBlock = obs.length
        ? `<div class="text-micro text-dim mt8 mb4">Observations (what sources recorded)</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Type</th><th>Source</th><th>Ref</th><th>Raw</th><th>Normalized</th><th>Observed</th><th>To belief</th><th>Conf.</th></tr></thead><tbody>${obsRows}</tbody></table></div>`
        : '';
    const swPreviewLis = swPrev.map((p) => {
        const lb = p.label != null && String(p.label).trim() ? esc(String(p.label)) : '\u2014';
        return `<li class="text-micro mono-sm">${lb}</li>`;
    }).join('');
    const sirPreviewLis = sirPrev.map((p) => {
        const lb = p.label != null && String(p.label).trim() ? esc(String(p.label)) : '\u2014';
        return `<li class="text-micro mono-sm">${lb}</li>`;
    }).join('');
    const sirBlock = sirCount > 0
        ? `<div class="text-micro text-dim mt8 mb4">Normalized software catalog (<span class="mono-sm">software_inventory*</span>)</div>
          <p class="text-micro mb4">${esc(String(sirCount))} active row(s). Preview (lexicographic sample, max 3):</p>
          ${sirPreviewLis ? `<ul class="st-host-sw-preview mb0">${sirPreviewLis}</ul>` : '<p class="text-micro text-dim mb0">No preview rows returned.</p>'}`
        : '';
    const swBlock = swCount > 0
        ? `<div class="text-micro text-dim mt8 mb4">Legacy software observations (<span class="mono-sm">software_observed</span>)</div>
          <p class="text-micro mb4">${esc(String(swCount))} bounded row(s) from older releases. Preview — max 3:</p>
          ${swPreviewLis ? `<ul class="st-host-sw-preview mb0">${swPreviewLis}</ul>` : '<p class="text-micro text-dim mb0">No preview rows returned.</p>'}`
        : '';
    const runBlock = runs.length
        ? `<div class="text-micro text-dim mt10 mb4">Recent reconciliation attempts (this host)</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Status</th><th>Run key</th><th>Finished</th><th>Error / summary</th></tr></thead><tbody>${runRows}</tbody></table></div>`
        : '';
    return `${astHead}${asrcBlock}${sirBlock}${swBlock}${obsBlock}${runBlock}`;
}

function stHostReconciliationEvidenceHtml(assetData) {
    if (!assetData) return '';
    const rd = assetData.recon_detail && typeof assetData.recon_detail === 'object' ? assetData.recon_detail : null;
    const obsCount = rd && Array.isArray(rd.observations) ? rd.observations.length : 0;
    const swObs = rd && rd.software_observed && typeof rd.software_observed === 'object'
        ? (parseInt(String(rd.software_observed.observation_count || 0), 10) || 0)
        : 0;
    const sirR = rd && rd.software_inventory_rows && typeof rd.software_inventory_rows === 'object' ? rd.software_inventory_rows : null;
    const sirObs = sirR ? (parseInt(String(sirR.active_count || 0), 10) || 0) : 0;
    const asserted = assetData.os_platform_assertion != null ? String(assetData.os_platform_assertion).trim() : '';
    const hasAsserted = asserted.length > 0;
    if (!hasAsserted && (!rd || rd.tables_ready !== true || (obsCount === 0 && swObs === 0 && sirObs === 0))) return '';
    const confRaw = assetData.os_platform_confidence;
    const conf = (confRaw != null && String(confRaw).trim() !== '')
        ? String(confRaw).toLowerCase()
        : (hasAsserted ? 'unknown' : 'low');
    const chipClass = findingConfidenceChipClass(conf);
    const confLabel = conf === 'unknown' ? '\u2014' : conf.toUpperCase();
    const sources = Array.isArray(assetData.os_platform_sources) ? assetData.os_platform_sources : [];
    const srcLine = sources.length ? sources.map((s) => esc(String(s))).join(', ') : '\u2014';
    const expl = assetData.os_platform_explanation != null && String(assetData.os_platform_explanation).trim()
        ? `<p class="text-micro mt6 st-host-evidence-expl">${esc(String(assetData.os_platform_explanation))}</p>`
        : '';
    const rdAst = rd && rd.assertion && typeof rd.assertion === 'object' ? rd.assertion : null;
    const reconAtLine = hasAsserted && rdAst && rdAst.reconciled_at
        ? `<div class="text-micro text-dim mt2">Belief last reconciled \u00b7 ${esc(localTime(rdAst.reconciled_at))}</div>`
        : '';
    const detailInner = stHostReconciliationEvidenceDetailHtml(rd);
    const detailBlock = detailInner
        ? `<details class="st-host-evidence-details mt8"><summary class="text-micro st-host-evidence-sum">View evidence</summary>${detailInner}</details>`
        : '';
    const swLine = swObs > 0 || sirObs > 0
        ? `<div class="text-micro text-dim mt4">Software inventory: <span class="mono-sm">${esc(String(Math.max(swObs, sirObs)))}</span> row hint from ${
            sirObs > 0 ? 'normalized <span class="mono-sm">software_inventory*</span> catalog' : 'legacy <span class="mono-sm">software_observed</span> samples'
        } (bounded preview in evidence).</div>`
        : '';
    const assertRow = hasAsserted
        ? `<div class="st-host-evidence-row">
          <span class="text-dim text-micro">Asserted</span>
          <strong class="mono-sm">${esc(asserted)}</strong>
          <span class="${chipClass}" title="Reconciliation confidence">${esc(confLabel)}</span>
        </div>
        <div class="text-micro text-dim mt4">Contributing sources \u00b7 ${srcLine}</div>
        ${reconAtLine}`
        : `<div class="text-micro text-dim st-host-evidence-pending">No reconciled OS/platform assertion yet. Observations below explain what SurveyTrace has seen; open this host again after scans or Zabbix sync to refresh the belief.</div>`;
    return `<section class="host-section st-host-subsection st-host-evidence" aria-label="Reconciled evidence">
      <h3 class="host-section-heading">Evidence \u2014 OS / platform</h3>
      <div class="host-inner-surface st-host-evidence-inner">
        ${assertRow}
        ${swLine}
        ${expl}
        ${detailBlock}
      </div>
    </section>`;
}

/** Reconciled software_inventory_summary (no CVE signal). Bounded preview via normalized catalog and/or legacy software_observed. */
function stHostSoftwareInventoryHtml(assetData) {
    if (!assetData) return '';
    const rd = assetData.recon_detail && typeof assetData.recon_detail === 'object' ? assetData.recon_detail : null;
    const sw = rd && rd.software_observed && typeof rd.software_observed === 'object' ? rd.software_observed : null;
    const sir = rd && rd.software_inventory_rows && typeof rd.software_inventory_rows === 'object' ? rd.software_inventory_rows : null;
    const swObs = sw && sw.observation_count != null ? (parseInt(String(sw.observation_count), 10) || 0) : 0;
    const normActive = sir && sir.active_count != null ? (parseInt(String(sir.active_count), 10) || 0) : 0;

    const sum = assetData.software_inventory_summary != null && String(assetData.software_inventory_summary).trim()
        ? String(assetData.software_inventory_summary).trim() : '';

    if (!sum && swObs <= 0 && normActive <= 0) return '';

    const mgrRaw = assetData.software_inventory_manager != null ? String(assetData.software_inventory_manager).trim() : '';
    const mgr = mgrRaw || '\u2014';
    const cnt = assetData.software_inventory_count != null ? String(assetData.software_inventory_count) : '\u2014';
    const confRaw = assetData.software_inventory_confidence != null ? String(assetData.software_inventory_confidence).trim().toLowerCase() : '';
    const confLabel = confRaw ? confRaw.toUpperCase() : '\u2014';
    const chipClass = findingConfidenceChipClass(confRaw || 'low');
    const partial = !!assetData.software_inventory_partial;
    const oatRaw = assetData.software_inventory_observed_at != null ? String(assetData.software_inventory_observed_at) : '';
    const oatMs = oatRaw ? Date.parse(oatRaw) : NaN;

    let staleFlag = false;
    if (assetData.software_inventory_stale === true || assetData.software_inventory_stale === 1) {
        staleFlag = true;
    } else if (assetData.software_inventory_stale === false || assetData.software_inventory_stale === 0) {
        staleFlag = false;
    } else {
        staleFlag = Number.isFinite(oatMs) && (Date.now() - oatMs) > 90 * 86400000;
    }

    const oatDisp = oatRaw ? esc(localTime(oatRaw)) : '\u2014';
    const srcLine = assetData.software_inventory_source != null && String(assetData.software_inventory_source).trim()
        ? esc(String(assetData.software_inventory_source).trim())
        : esc('Credentialed SSH package inventory (ssh.linux.package_inventory)');

    const staleBand = assetData.software_inventory_stale_band != null ? String(assetData.software_inventory_stale_band).trim().toLowerCase() : '';
    const obsGap = assetData.software_inventory_observation_gap === true || assetData.software_inventory_observation_gap === 1;
    const badgeParts = [];
    if (partial) {
        badgeParts.push('<span class="hp-chip" title="Truncated, capped, or incomplete inventory signal">Partial / bounded inventory</span>');
    }
    if (staleFlag) {
        const staleHint = staleBand === 'over_180' ? 'Stale evidence (>180d since last observation)' : 'Stale evidence (>90d since last observation)';
        badgeParts.push(`<span class="hp-chip" title="Beyond freshness window — not vulnerability posture">${esc(staleHint)}</span>`);
    }
    if (obsGap) {
        badgeParts.push('<span class="hp-chip" title="Only the package summary observation exists; no normalized rows or snapshot yet">No normalized inventory corroboration</span>');
    }
    const badgeRow = badgeParts.length
        ? `<div class="hp-chips" style="margin-top:6px">${badgeParts.join('')}</div>`
        : '';

    const vin = assetData.vulnerability_inventory && typeof assetData.vulnerability_inventory === 'object'
        ? assetData.vulnerability_inventory
        : null;
    const vinRows = vin && Array.isArray(vin.rows) ? vin.rows : [];
    const vinTot = vin && vin.affected_total != null ? parseInt(String(vin.affected_total), 10) || 0 : 0;
    const vinRollup = vin && vin.risk_rollup && typeof vin.risk_rollup === 'object' ? vin.risk_rollup : null;
    const aidV = assetData.asset && assetData.asset.id != null ? Number(assetData.asset.id) : 0;
    const vinApi =
        vin && vin.tables_ready === true && aidV > 0
            ? `<p class="text-micro text-dim mt4 mb0">Advisory correlation (bounded): <span class="mono-sm">/api/vulnerabilities.php?action=list_for_asset&amp;asset_id=${esc(
                  String(aidV),
              )}</span> \u00b7 Triage API: <span class="mono-sm">/api/vulnerability_triage.php?action=get&amp;asset_vulnerability_id=</span> (viewer+).</p>`
            : '';
    const vinTable =
        vin && vin.tables_ready === true && vinRows.length
            ? `<div class="mt8"><h4 class="text-micro text-dim mb4">Inventory advisory correlation (local rules)</h4>
        <table class="st-table st-table--micro"><thead><tr><th>Advisory</th><th>Sev</th><th>Basis</th><th>Correlation confidence</th><th>Triage</th><th>Priority</th><th>Model score</th><th>Notes</th><th>First seen</th><th>Suppress</th></tr></thead><tbody>${vinRows
                  .map((r) => {
                      const k = r.advisory_key != null ? esc(String(r.advisory_key)) : '\u2014';
                      const sev = r.advisory_severity != null ? esc(String(r.advisory_severity)) : r.severity != null ? esc(String(r.severity)) : '\u2014';
                      const basis =
                          r.correlation_basis_label != null && String(r.correlation_basis_label).trim()
                              ? esc(String(r.correlation_basis_label))
                              : '\u2014';
                      const cconf =
                          r.correlation_confidence != null && String(r.correlation_confidence).trim()
                              ? esc(String(r.correlation_confidence))
                              : '\u2014';
                      const tr = r.triage_state != null && String(r.triage_state).trim() ? esc(String(r.triage_state)) : '<span class="text-dim">new</span>';
                      const triPri =
                          r.triage_priority != null && String(r.triage_priority).trim()
                              ? esc(String(r.triage_priority))
                              : esc(String(r.model_priority != null ? r.model_priority : r.computed_priority || '\u2014'));
                      const modPri = esc(String(r.model_priority != null ? r.model_priority : r.computed_priority || '\u2014'));
                      const modSc = esc(
                          String(r.model_priority_score != null ? r.model_priority_score : r.computed_priority_score ?? '\u2014'),
                      );
                      const srcRaw = r.priority_source != null ? String(r.priority_source).trim().toLowerCase() : '';
                      const isOv = srcRaw === 'analyst_override';
                      const ovBadge = isOv
                          ? '<span class="hp-chip" title="Stored triage band set by analyst; model score column shows deterministic model">Analyst override</span> '
                          : '';
                      const avid = r.asset_vulnerability_id != null ? parseInt(String(r.asset_vulnerability_id), 10) || 0 : 0;
                      const resetBtn =
                          stRoleCanManageScans() && isOv && avid > 0
                              ? ` <button type="button" class="tbtn btn-xs" onclick="stVtResetPriorityToModel(${avid})">Reset to model</button>`
                              : '';
                      const nc = r.notes_count != null ? esc(String(r.notes_count)) : '0';
                      const fs = r.first_seen_at != null ? esc(String(r.first_seen_at)) : '\u2014';
                      let sup = '\u2014';
                      if (r.suppression_reason != null && String(r.suppression_reason).trim()) {
                          sup = esc(String(r.suppression_reason).slice(0, 48));
                          if (r.suppression_expires_at) {
                              sup += ` <span class="text-dim">(\u2264${esc(String(r.suppression_expires_at))})</span>`;
                          }
                      }
                      return `<tr><td class="mono-sm">${k}</td><td>${sev}</td><td class="text-micro">${basis}</td><td class="text-micro">${cconf}</td><td><span class="hp-chip hp-chip--dim">${tr}</span></td><td><span class="hp-chip">${triPri}</span> ${ovBadge}${resetBtn}</td><td class="mono-sm">${modSc} <span class="text-dim text-micro">${modPri}</span></td><td>${nc}</td><td class="text-dim">${fs}</td><td class="text-micro">${sup}</td></tr>`;
                  })
                  .join('')}</tbody></table>
        <p class="text-micro text-dim mt4 mb0">Rows shown here are capped; triage/score are operational hints only (not KEV/exposure). Correlation uses vendor or internal package rules; NVD metadata alone does not prove an installed package is affected. Use triage API for state changes (editor role).</p></div>`
            : vin && vin.tables_ready === true && vinTot > 0
              ? `<p class="text-micro text-dim mt8">This host has <span class="mono-sm">${esc(String(vinTot))}</span> correlated advisory row(s); reload asset detail for the first page of rows.</p>`
              : '';
    const vinRollupHtml = vinRollup && vinRollup.total_affected > 0
        ? `<div class="mt8 mb4 st-host-vuln-rollup" style="display:flex;gap:12px;flex-wrap:wrap;align-items:center">
            <span class="hp-chip hp-chip--${esc(vinRollup.risk_band || 'none')}" title="Risk band">${esc((vinRollup.risk_band || 'none').toUpperCase())}</span>
            <span class="text-micro">Score <strong>${vinRollup.risk_score}</strong></span>
            <span class="text-micro text-dim">C:${vinRollup.critical} H:${vinRollup.high} M:${vinRollup.medium} L:${vinRollup.low}</span>
            <span class="text-micro text-dim">Suppressed:${vinRollup.suppressed} Overrides:${vinRollup.overrides}</span>
            ${vinRollup.oldest_first_seen ? `<span class="text-micro text-dim">Oldest: ${localDate(vinRollup.oldest_first_seen)}</span>` : ''}
          </div>`
        : '';
    const noCveLine = `<p class="text-micro mt6 text-dim">This <strong>software evidence</strong> summary reflects inventory freshness and completeness. Separate <strong>local advisory correlation</strong> (when advisories are imported) matches installed packages using deterministic version rules — not internet exposure, KEV, or ticketing.</p>`;

    const expl = assetData.software_inventory_explanation != null && String(assetData.software_inventory_explanation).trim()
        ? `<p class="text-micro mt6 st-host-evidence-expl">${esc(String(assetData.software_inventory_explanation))}</p>`
        : '';

    const swPrev = sw && Array.isArray(sw.preview) ? sw.preview : [];
    const sirPrev = sir && Array.isArray(sir.preview) ? sir.preview : [];
    const sirPrevLis = sirPrev.map((p) => {
        const lb = p.label != null && String(p.label).trim() ? esc(String(p.label)) : '\u2014';
        return `<li class="text-micro mono-sm">${lb}</li>`;
    }).join('');
    const swPrevLis = swPrev.map((p) => {
        const lb = p.label != null && String(p.label).trim() ? esc(String(p.label)) : '\u2014';
        return `<li class="text-micro mono-sm">${lb}</li>`;
    }).join('');

    const cat = assetData.software_inventory_catalog && typeof assetData.software_inventory_catalog === 'object'
        ? assetData.software_inventory_catalog
        : null;
    const aidSw = assetData.asset && assetData.asset.id != null ? Number(assetData.asset.id) : 0;
    const searchHint =
        cat && cat.tables_ready === true && aidSw > 0
            ? `<p class="text-micro text-dim mt6 mb0">Bounded package search: <span class="mono-sm">/api/software_inventory.php?asset_id=${esc(
                  String(aidSw),
              )}&amp;q=&amp;limit=80</span> (prefix match on normalized names).</p>`
            : '';

    const evidenceParts = [];
    if (sirPrev.length && rd && rd.tables_ready === true) {
        evidenceParts.push(`<ul class="st-host-sw-preview mb0">${sirPrevLis}</ul>`);
        evidenceParts.push('<p class="text-micro text-dim mt6 mb0">Showing up to <span class="mono-sm">3</span> sample rows from the normalized <span class="mono-sm">software_inventory*</span> catalog (active installs). Full lists stay server-side; use the API for bounded search.</p>');
    } else if (normActive > 0) {
        evidenceParts.push(`<p class="text-micro text-dim mb0"><span class="mono-sm">${esc(String(normActive))}</span> active normalized row(s); preview samples omitted in this response.</p>`);
    } else if (swPrev.length && rd && rd.tables_ready === true) {
        evidenceParts.push(`<ul class="st-host-sw-preview mb0">${swPrevLis}</ul>`);
        evidenceParts.push('<p class="text-micro text-dim mt6 mb0">Legacy <span class="mono-sm">software_observed</span> preview (older releases).</p>');
    } else if (swObs > 0) {
        evidenceParts.push(`<p class="text-micro text-dim mb0"><span class="mono-sm">${esc(String(swObs))}</span> legacy <span class="mono-sm">software_observed</span> row(s); preview unavailable.</p>`);
    } else {
        evidenceParts.push('<p class="text-micro text-dim mb0">No bounded preview in this response.</p>');
    }
    if (searchHint) {
        evidenceParts.push(searchHint);
    }

    const evidenceBlock = evidenceParts.length
        ? `<details class="st-host-evidence-details mt8"><summary class="text-micro st-host-evidence-sum">View software evidence</summary>${evidenceParts.join('')}</details>`
        : '';

    if (!sum) {
        return `<section class="host-section st-host-subsection st-host-evidence st-host-sw-inv" aria-label="Software evidence pending reconciliation">
      <h3 class="host-section-heading">Evidence \u2014 Software evidence (bounded inventory)</h3>
      <div class="host-inner-surface st-host-evidence-inner">
        <p class="text-micro text-dim">Bounded <span class="mono-sm">software_observed</span> rows are present (${esc(String(swObs))}), but no reconciled <span class="mono-sm">software_inventory_summary</span> yet. Open this host again after the next credentialed package inventory run, or review trusted-data diagnostics if this persists.</p>
        ${noCveLine}
        ${vinRollupHtml}
        ${vinTable}
        ${vinApi}
        ${evidenceBlock}
      </div>
    </section>`;
    }

    return `<section class="host-section st-host-subsection st-host-evidence st-host-sw-inv" aria-label="Software evidence">
      <h3 class="host-section-heading">Evidence \u2014 Software evidence (bounded inventory)</h3>
      <div class="host-inner-surface st-host-evidence-inner">
        <div class="st-host-evidence-row">
          <span class="text-dim text-micro">Summary belief</span>
          <strong class="mono-sm">${esc(sum)}</strong>
          <span class="${chipClass}" title="Reconciliation confidence from freshness/completeness — not CVE or vulnerability exposure">${esc(confLabel)}</span>
        </div>
        <div class="text-micro text-dim mt4">Source \u00b7 ${srcLine}</div>
        <div class="text-micro text-dim mt2">Package manager \u00b7 <span class="mono-sm">${esc(mgr)}</span> · Observed package count (hint) \u00b7 <span class="mono-sm">${esc(cnt)}</span> · Last evidence \u00b7 ${oatDisp}</div>
        ${badgeRow}
        ${noCveLine}
        ${vinRollupHtml}
        ${vinTable}
        ${vinApi}
        ${expl}
        ${evidenceBlock}
      </div>
    </section>`;
}

function stHostIdentityEvidenceDetailHtml(ird) {
    if (!ird || ird.tables_ready !== true) return '';
    const obs = Array.isArray(ird.observations) ? ird.observations : [];
    const runs = Array.isArray(ird.recent_runs) ? ird.recent_runs : [];
    const sup = new Set(Array.isArray(ird.supporting_observation_ids) ? ird.supporting_observation_ids.map((x) => parseInt(String(x), 10) || 0) : []);
    const con = new Set(Array.isArray(ird.conflicting_observation_ids) ? ird.conflicting_observation_ids.map((x) => parseInt(String(x), 10) || 0) : []);
    const asrc = Array.isArray(ird.assertion_sources) ? ird.assertion_sources : [];
    const ast = ird.assertion && typeof ird.assertion === 'object' ? ird.assertion : null;
    if (!obs.length && !runs.length && !asrc.length && !ast) return '';
    const astHead = ast
        ? `<div class="text-micro text-dim mb6 st-host-evidence-astmeta">Stored belief <span class="mono-sm">${esc(String(ast.value_label || ast.value_slug || ''))}</span>${ast.reconciled_at ? ` · reconciled ${esc(localTime(ast.reconciled_at))}` : ''}${ast.version != null ? ` · v${esc(String(ast.version))}` : ''}</div>`
        : '';
    const asrcRows = asrc.map((a) => {
        const nm = a.normalized_value != null && String(a.normalized_value).trim() ? esc(String(a.normalized_value)) : '\u2014';
        const tierH = stEvidenceSourceTierHtml(a.source_tier);
        const dn = esc(String(a.display_name || '\u2014'));
        const ot = esc(String(a.observation_type || ''));
        const c = esc(String(a.contribution || ''));
        const w = a.weight_note != null && String(a.weight_note).trim() ? esc(String(a.weight_note)) : '\u2014';
        const oref = a.observation_source_ref ? `<span class="mono-sm">${esc(String(a.observation_source_ref))}</span>` : '\u2014';
        const oat = a.observation_observed_at ? esc(localTime(String(a.observation_observed_at))) : '\u2014';
        return `<tr><td>${tierH}${tierH ? ' ' : ''}${dn}</td><td class="mono-sm">${ot}</td><td>${oref}</td><td class="text-dim">${oat}</td><td class="mono-sm">${nm}</td><td>${c}</td><td class="text-dim">${w}</td></tr>`;
    }).join('');
    const asrcBlock = asrc.length
        ? `<div class="text-micro text-dim mt8 mb4">Assertion sources</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Source</th><th>Type</th><th>Plugin / ref</th><th>Observed</th><th>Normalized</th><th>Role</th><th>Note</th></tr></thead><tbody>${asrcRows}</tbody></table></div>`
        : '';
    const obsRowHtml = (o, rowCls) => {
        const raw = o.raw_value != null && String(o.raw_value).trim() ? esc(String(o.raw_value)) : '\u2014';
        const norm = o.normalized_value != null && String(o.normalized_value).trim() ? esc(String(o.normalized_value)) : '\u2014';
        const when = o.observed_at ? esc(localTime(o.observed_at)) : '\u2014';
        const tierH = stEvidenceSourceTierHtml(o.source_tier);
        const src = esc([o.display_name || '', o.source_type || ''].filter(Boolean).join(' · ') || '\u2014');
        const ref = o.source_object_ref ? `<span class="mono-sm">${esc(String(o.source_object_ref))}</span>` : '\u2014';
        const hint = o.contribution_hint && String(o.contribution_hint).trim()
            ? esc(String(o.contribution_hint))
            : '\u2014';
        const cls = rowCls ? ` class="${rowCls}"` : '';
        return `<tr${cls}><td class="mono-sm">${esc(String(o.observation_type || ''))}</td><td>${tierH}${tierH ? ' ' : ''}${src}</td><td>${ref}</td><td class="st-host-evidence-cell-raw">${raw}</td><td class="mono-sm">${norm}</td><td class="text-dim">${when}</td><td class="text-dim">${hint}</td><td>${esc(String(o.confidence_level || '').toUpperCase())}</td></tr>`;
    };
    const supRows = obs.filter((o) => sup.has(parseInt(String(o.id), 10) || 0)).map((o) => obsRowHtml(o, '')).join('');
    const neuRows = obs.filter((o) => !sup.has(parseInt(String(o.id), 10) || 0) && !con.has(parseInt(String(o.id), 10) || 0)).map((o) => obsRowHtml(o, '')).join('');
    const conRows = obs.filter((o) => con.has(parseInt(String(o.id), 10) || 0)).map((o) => obsRowHtml(o, 'st-host-id-evidence-row--conflict')).join('');
    const hasConflictRows = obs.some((o) => con.has(parseInt(String(o.id), 10) || 0));
    const obsBody = [supRows, neuRows, conRows].filter(Boolean).join('');
    const obsBlock = obsBody
        ? `<div class="text-micro text-dim mt8 mb4">Identity observations</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Type</th><th>Source</th><th>Ref</th><th>Raw</th><th>Normalized</th><th>Observed</th><th>To belief</th><th>Conf.</th></tr></thead><tbody>${obsBody}</tbody></table></div>
          ${hasConflictRows ? '<p class="text-micro text-dim mt4 mb0">Rows highlighted for hostname/FQDN disagree with the reconciled short name; they are kept as evidence.</p>' : ''}`
        : '';
    const runRows = runs.map((r) => {
        const rawErr = r.error && String(r.error).trim() ? String(r.error) : '';
        const rawSum = r.result_summary && String(r.result_summary).trim() ? String(r.result_summary) : '';
        const err = rawErr ? esc(rawErr) : (rawSum ? esc(rawSum) : '\u2014');
        const fin = r.finished_at ? esc(localTime(r.finished_at)) : '\u2014';
        return `<tr><td class="mono-sm">${esc(String(r.status || ''))}</td><td class="mono-sm">${esc(String(r.slice_key || ''))}</td><td class="text-dim">${fin}</td><td class="st-host-evidence-cell-raw">${err}</td></tr>`;
    }).join('');
    const runBlock = runs.length
        ? `<div class="text-micro text-dim mt10 mb4">Reconciliation attempts (identity)</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-host-evidence-tbl"><thead><tr><th>Status</th><th>Run key</th><th>Finished</th><th>Error / summary</th></tr></thead><tbody>${runRows}</tbody></table></div>`
        : '';
    return `${astHead}${asrcBlock}${obsBlock}${runBlock}`;
}

function stHostIdentityEvidenceHtml(assetData) {
    if (!assetData) return '';
    const ird = assetData.identity_recon_detail && typeof assetData.identity_recon_detail === 'object' ? assetData.identity_recon_detail : null;
    const obsCount = ird && Array.isArray(ird.observations) ? ird.observations.length : 0;
    const asserted = assetData.canonical_hostname_assertion != null ? String(assetData.canonical_hostname_assertion).trim() : '';
    const hasAsserted = asserted.length > 0;
    if (!hasAsserted && (!ird || ird.tables_ready !== true || obsCount === 0)) return '';
    const confRawId = assetData.canonical_hostname_confidence;
    const conf = (confRawId != null && String(confRawId).trim() !== '')
        ? String(confRawId).toLowerCase()
        : (hasAsserted ? 'unknown' : 'low');
    const chipClass = findingConfidenceChipClass(conf);
    const confLabel = conf === 'unknown' ? '\u2014' : conf.toUpperCase();
    const sources = Array.isArray(assetData.canonical_hostname_sources) ? assetData.canonical_hostname_sources : [];
    const srcLine = sources.length ? sources.map((s) => esc(String(s))).join(', ') : '\u2014';
    const expl = assetData.canonical_hostname_explanation != null && String(assetData.canonical_hostname_explanation).trim()
        ? `<p class="text-micro mt6 st-host-evidence-expl">${esc(String(assetData.canonical_hostname_explanation))}</p>`
        : '';
    const rdAst = ird && ird.assertion && typeof ird.assertion === 'object' ? ird.assertion : null;
    const reconAtLine = hasAsserted && rdAst && rdAst.reconciled_at
        ? `<div class="text-micro text-dim mt2">Belief last reconciled \u00b7 ${esc(localTime(rdAst.reconciled_at))}</div>`
        : '';
    const detailInner = stHostIdentityEvidenceDetailHtml(ird);
    const detailBlock = detailInner
        ? `<details class="st-host-evidence-details mt8"><summary class="text-micro st-host-evidence-sum">View identity evidence</summary>${detailInner}</details>`
        : '';
    const assertRow = hasAsserted
        ? `<div class="st-host-evidence-row">
          <span class="text-dim text-micro">Canonical hostname</span>
          <strong class="mono-sm">${esc(asserted)}</strong>
          <span class="${chipClass}" title="Identity confidence">${esc(confLabel)}</span>
        </div>
        <div class="text-micro text-dim mt4">Contributing sources \u00b7 ${srcLine}</div>
        ${reconAtLine}`
        : `<div class="text-micro text-dim st-host-evidence-pending">No reconciled canonical hostname yet. Observations (scan, Zabbix, operator edits) appear below when present.</div>`;
    return `<section class="host-section st-host-subsection st-host-evidence st-host-identity-evidence" aria-label="Identity evidence">
      <h3 class="host-section-heading">Evidence \u2014 identity</h3>
      <p class="hint-micro text-dim mb6 mt0">Hostname belief only in this release (no automatic asset/device merges).</p>
      <div class="host-inner-surface st-host-evidence-inner">
        ${assertRow}
        ${expl}
        ${detailBlock}
      </div>
    </section>`;
}

function formatHpFindingTriage(f) {
    const rs = f.risk_score != null ? esc(String(f.risk_score)) : '—';
    const conf = esc((f.confidence || 'low').toUpperCase());
    const src = esc(f.provenance_source || 'unknown');
    const meth = esc(findingTriageMethodLabel(f.detection_method));
    const ev = (f.evidence && typeof f.evidence === 'object') ? f.evidence : {};
    const cpe = ev.matched_cpe ? `<span class="mono-sm"> · ${esc(String(ev.matched_cpe))}</span>` : '';
    const tip = esc(findingEvidenceTitle(f).replace(/\n/g, ' '));
    return `<div class="hp-triage mono-sm text-dim mt4" title="${tip}">Score ${rs} · ${conf} · ${meth} · ${src}${cpe}</div>`;
}

// ==========================================================================
// Findings / Vulnerabilities
// ==========================================================================
var vulnDebounce = null;

async function loadFindings(page) {
    refreshBadges();
    // Show loading state immediately
    document.getElementById('vuln-tbody').innerHTML =
        '<tr><td colspan="10" class="loading tbl-empty">Loading vulnerabilities…</td></tr>';

    vulnPage = page;
    const cve  = document.getElementById('vf-cve').value;
    const sev  = document.getElementById('vf-sev').value;
    const cat  = document.getElementById('vf-cat').value;
    const res  = document.getElementById('vf-resolved').value;

    const ip   = document.getElementById('vf-ip')?.value || '';
    const miny = document.getElementById('vf-minyear')?.value || '';
    const conf = document.getElementById('vf-confidence')?.value || '';
    const sort = document.getElementById('vf-sort')?.value || 'cvss';
    const url = `/api/findings.php?page=${page}&per_page=50&cve_id=${enc(cve)}&ip=${enc(ip)}&severity=${enc(sev)}&category=${enc(cat)}&resolved=${res}&min_year=${enc(miny)}&confidence=${enc(conf)}&sort=${enc(sort)}&order=desc`;
    const d   = await api(url);
    if (!d) return;

    const filtersActive = !!(String(cve || '').trim() || String(ip || '').trim() || sev || cat || res !== '0' || miny || conf || (sort && sort !== 'cvss'));
    const fsEl = document.getElementById('st-vuln-filter-summary');
    if (fsEl) {
        const bits = [];
        if (String(cve || '').trim()) bits.push('search “' + String(cve).trim() + '”');
        if (String(ip || '').trim()) bits.push('IP ' + String(ip).trim());
        if (sev) bits.push('severity ' + sev);
        if (cat) bits.push('type ' + cat);
        if (res === '1') bits.push('resolved only');
        if (miny) bits.push('year ≥ ' + miny);
        if (conf) bits.push('confidence ' + conf);
        if (sort && sort !== 'cvss') bits.push('sort ' + sort);
        fsEl.textContent = bits.length ? ('Active filters: ' + bits.join(' · ')) : '';
        fsEl.classList.toggle('hide', !bits.length);
    }

    const rowsHtml = (d.findings || []).map((f) => {
        const sevRow = sevClass(f.cvss);
        const rowExtra = f.resolved ? ' st-vuln-row--resolved' : '';
        return `<tr class="st-vuln-row st-vuln-row--${sevRow}${rowExtra}">
      <td class="mono mono-sm tbl-cell-mono tbl-cell-primary">${esc(f.cve_id)}</td>
      <td class="mono tbl-cell-mono click-ip"
          onclick="filterVulnsByIP('${esc(f.ip)}')"
          title="Filter to this host">${esc(f.ip)}</td>
      <td class="click-ip tbl-cell-primary" style="font-size:12px"
          onclick="filterVulnsByIP('${esc(f.ip)}')"
          title="Filter to this host">${esc(f.hostname||'—')}</td>
      <td><span class="cat ${esc(f.category||'unk')}">${esc(f.category||'unk')}</span></td>
      <td class="tbl-cell-muted" style="font-size:12px;max-width:220px">${esc(f.description||'—')}</td>
      <td><span class="sev ${sevRow}">${f.cvss||'—'}</span></td>
      <td class="mono-sm tbl-cell-mono tbl-cell-muted" style="white-space:nowrap;text-align:right" title="Triage score (0–100, CVSS weighted by detection confidence)">
        <span>${f.risk_score != null ? esc(String(f.risk_score)) : '—'}</span>
        <span class="${findingConfidenceChipClass(f.confidence)}">${esc((f.confidence || 'low').toUpperCase())}</span>
      </td>
      <td class="mono-sm tbl-cell-muted" style="max-width:6.5rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap"
          title="${esc(findingEvidenceTitle(f).replace(/\n/g, ' '))}">${esc(findingTriageMethodLabel(f.detection_method))}</td>
      <td class="mono mono-sm tbl-cell-mono tbl-cell-muted">${localDate(f.published)}</td>
      <td class="tbl-cell-actions">${f.resolved ? '<span class="status-text" style="color:var(--green)">resolved</span>'
          : stRoleCanManageScans()
              ? `<span class="row-wrap" style="gap:4px;justify-content:flex-end"><button type="button" class="tbtn btn-xs" onclick="resolveFinding(${f.id}, this)">Resolve</button><button type="button" class="tbtn btn-xs tbtn--danger-quiet" onclick="acceptFindingRisk(${f.id}, this)">Accept risk</button></span>`
              : '<span class="text-dim">—</span>'}</td>
    </tr>`;
    }).join('');

    let emptyMsg = 'No findings match the current filters. Try clearing IP, search, or widening severity/year.';
    if (!rowsHtml) {
        if ((d.total || 0) === 0) {
            if (filtersActive) {
                emptyMsg = 'No findings match the current filters. Adjust triage controls or clear search/IP.';
            } else if (res === '1') {
                emptyMsg = 'No resolved findings to show.';
            } else {
                emptyMsg = 'No open findings yet. Run scans with CVE correlation enabled, then refresh this tab.';
            }
        } else {
            emptyMsg = 'No findings on this page.';
        }
    }

    // WARNING: innerHTML — row cells must stay escaped via esc() for API fields.
    document.getElementById('vuln-tbody').innerHTML = rowsHtml
        || `<tr><td colspan="10" class="loading tbl-empty st-vuln-empty">${emptyMsg}</td></tr>`;

    document.getElementById('vpgn-info').textContent = `Page ${d.page} of ${d.pages} (${d.total} findings)`;
    document.getElementById('vprev').disabled = page <= 1;
    document.getElementById('vnext').disabled = page >= d.pages;
}

async function resolveFinding(id, btn) {
    if (!stRoleCanManageScans()) return;
    btn.disabled = true;
    const r = await apiPost('/api/findings.php?action=resolve', {action:'resolve', finding_id: id});
    if (r && r.ok) { toast('Finding marked resolved', 'ok'); loadFindings(vulnPage); }
    else { toast('Failed to resolve finding', 'err'); btn.disabled = false; }
}

async function acceptFindingRisk(id, btn) {
    if (!stRoleCanManageScans()) return;
    if (btn) btn.disabled = true;
    const r = await apiPost('/api/findings.php?action=accept_risk', {action: 'accept_risk', finding_id: id});
    if (r && r.ok) {
        toast('Risk accepted — open CVE alerts for this finding are cleared; future scans will not re-open alerts for it while it stays accepted.', 'ok');
        loadFindings(vulnPage);
    } else {
        toast('Failed to accept risk', 'err');
        if (btn) btn.disabled = false;
    }
}

async function unacceptFindingRisk(findingId, assetId, ip) {
    if (!stRoleCanManageScans()) return;
    if (!(await showConfirmModal(
        'Remove accepted-risk status for this CVE? It returns to the open list and change alerts may recur on future scans if the issue is still present.',
        {title: 'Unaccept risk', okText: 'Unaccept risk'}
    ))) return;
    const r = await apiPost('/api/findings.php?action=unresolve', {action: 'unresolve', finding_id: findingId});
    if (r && r.ok) {
        toast('Risk unaccepted — finding is open again', 'ok');
        loadFindings(vulnPage);
        openHostPanel(assetId, ip);
    } else {
        toast((r && r.error) || 'Failed to unaccept risk', 'err');
    }
}

