// ==========================================================================
// Scan control
// ==========================================================================
async function startScan(urgent = false) {
    if (!stRoleCanManageScans()) {
        toast('You do not have permission to queue scans.', 'err');
        return;
    }
    const cidr  = document.getElementById('sc-cidr').value.trim();
    if (!cidr) { toast('Enter a CIDR target', 'err'); return; }

    // Warn on large subnets — /16 is 65k hosts, /8 is 16M
    const cidrs = cidr.split(',').map(c => c.trim());
    for (const c of cidrs) {
        const prefix = parseInt((c.split('/')[1] || '32'));
        if (prefix <= 8) {
            toast('/' + prefix + ' is too broad — maximum allowed is /8', 'err');
            return;
        }
        if (prefix <= 16) {
            const hosts = Math.pow(2, 32 - prefix).toLocaleString();
            const ok = await showConfirmModal(
                `/${prefix} covers ${hosts} hosts and may take hours.\n\nAre you sure you want to scan ${c}?`,
                {title: 'Large scope warning', okText: 'Scan anyway'}
            );
            if (!ok) {
                return;
            }
        }
    }

    const phases = [];
    ['passive','icmp','banner','fingerprint','snmp','ot','cve'].forEach(p => {
        if (document.getElementById('ph-'+p)?.checked) phases.push(p);
    });

    const profileEl = document.querySelector('input[name="scan_profile"]:checked');
    const profileVal  = profileEl ? profileEl.value : 'standard_inventory';

    // Confirmation required for dangerous profiles
    if (['deep_scan', 'full_tcp', 'ot_careful'].includes(profileVal)) {
        const ok = await showConfirmModal(
            `Profile "${profileVal}" generates significant network traffic and requires confirmation.\n\nProceed?`,
            {title: 'High-impact scan profile', okText: 'Proceed'}
        );
        if (!ok) return;
    }

    const modeEl = document.querySelector('input[name="scan_mode"]:checked');
    let scanPriority = parseInt(document.getElementById('sc-priority')?.value || '10', 10);
    if (!Number.isFinite(scanPriority)) scanPriority = 10;
    scanPriority = Math.max(1, Math.min(100, scanPriority));
    if (urgent) scanPriority = 1;
    const body = {
        cidr:        cidr,
        exclusions:  document.getElementById('sc-excl').value,
        phases:      phases,
        rate_pps:    parseInt(document.getElementById('sc-pps').value),
        inter_delay: parseInt(document.getElementById('sc-delay').value),
        label:       document.getElementById('sc-label').value.trim(),
        scan_mode:   modeEl ? modeEl.value : 'auto',
        profile:     profileVal,
        confirmed:   true,
        priority:    scanPriority,
        auto_split_24: !!document.getElementById('sc-auto-split-24')?.checked,
    };
    const collectorId = parseInt(document.getElementById('sc-collector')?.value || '0', 10) || 0;
    if (collectorId > 0) body.collector_id = collectorId;
    const enrSel = scanEnrichmentPayloadField();
    if (enrSel !== undefined) body.enrichment_source_ids = enrSel;
    const scanScopePick = parseInt(String(document.getElementById('sc-scope-id')?.value || '0'), 10) || 0;
    if (scanScopePick > 0) {
        body.scope_id = scanScopePick;
    }

    document.getElementById('btn-start').disabled = true;
    const urgentBtn = document.getElementById('btn-start-urgent');
    if (urgentBtn) urgentBtn.disabled = true;
    const r = await apiPost('/api/scan_start.php', body);
    if (!r) {
        toast('API error starting scan', 'err');
        document.getElementById('btn-start').disabled = false;
        if (urgentBtn) urgentBtn.disabled = false;
        return;
    }
    if (r.error) {
        toast(r.error, 'err');
        document.getElementById('btn-start').disabled = false;
        if (urgentBtn) urgentBtn.disabled = false;
        return;
    }

    activeJobId = r.job_id;
    if ((r.jobs_total || r.jobs_queued || 1) > 1) {
        const nowQ = Number(r.jobs_queued || 0);
        const totalQ = Number(r.jobs_total || nowQ);
        const pendingFeed = Number(r.batch_pending || 0);
        toast(
            'Queued ' + String(nowQ) + ' of ' + String(totalQ) + ' batch jobs'
            + (pendingFeed > 0 ? (' (' + String(pendingFeed) + ' staged for auto-feed)') : '')
            + '. Starting with #' + activeJobId
            + (urgent ? ' [urgent]' : ''),
            'ok'
        );
    } else {
        toast('Scan #' + activeJobId + ' queued' + (urgent ? ' [urgent priority 1]' : ''), 'ok');
    }
    document.getElementById('btn-start').disabled = false;
    if (urgentBtn) urgentBtn.disabled = false;
    document.getElementById('btn-start').textContent = '\u25b6 Queue scan';
    stPendingScanHistoryFocusJobId = Number(activeJobId) || 0;
    goTab('scanhist');
    hiNav('nscanhist');
    await loadScanStatus();
    startPoll(activeJobId);
}

// ---------------------------------------------------------------------------
// Host rescan — modal: profile + scan steps/rates/discovery (Scan tab syncs after queue)
// ---------------------------------------------------------------------------
var hostRescanModalResolve = null;

const HOST_RESCAN_PROFILE_IDS = new Set([
    'iot_safe', 'ot_careful', 'standard_inventory', 'deep_scan', 'full_tcp',
]);

function hostRescanProfileHintText(profile) {
    const p = profile || 'standard_inventory';
    if (p === 'deep_scan') {
        return 'Deep Scan: aggressive -sV on a fixed large port list (~60+ ports), not a 1–65535 sweep. For every TCP port, pick Full TCP.';
    }
    if (p === 'full_tcp') {
        return 'Warning: scans all 65,535 TCP ports with active service detection. Avoid on fragile IoT, cameras, or OT gear unless you accept disruption risk.';
    }
    if (p === 'iot_safe' || p === 'ot_careful') {
        return 'Lower impact: passive-first profile with minimal or no TCP service scanning.';
    }
    return 'Moderate: scans a fixed list of common TCP ports with light service detection.';
}

function applyHostRescanModalRateSlidersForProfile(profile) {
    const rdef = SCHED_PROFILE_RATE_DEFAULTS[profile] || SCHED_PROFILE_RATE_DEFAULTS.standard_inventory;
    const pps = Math.max(1, Math.min(50, rdef.pps));
    const del = Math.max(0, Math.min(2000, rdef.delay));
    const ppsEl = document.getElementById('hr-pps');
    const delEl = document.getElementById('hr-delay');
    const ppsVal = document.getElementById('hr-pps-val');
    const delVal = document.getElementById('hr-delay-val');
    if (ppsEl) ppsEl.value = String(pps);
    if (ppsVal) ppsVal.textContent = pps + ' pps';
    if (delEl) delEl.value = String(del);
    if (delVal) delVal.textContent = del + ' ms';
}

function syncHostRescanModalScanStepBannerOpacity() {
    ['hr-ph-banner', 'hr-ph-fingerprint', 'hr-ph-cve'].forEach(id => {
        const el = document.getElementById(id);
        const tr = el && el.closest('.tr2');
        if (tr) tr.style.opacity = el.checked ? '1' : '0.4';
    });
}

function readScanTabIntoHostRescanModal() {
    ['passive', 'icmp', 'banner', 'fingerprint', 'snmp', 'ot', 'cve'].forEach(p => {
        const src = document.getElementById('ph-' + p);
        const dst = document.getElementById('hr-ph-' + p);
        if (src && dst) dst.checked = src.checked;
    });
    const pps = document.getElementById('sc-pps');
    const del = document.getElementById('sc-delay');
    const hpps = document.getElementById('hr-pps');
    const hdel = document.getElementById('hr-delay');
    const hppsV = document.getElementById('hr-pps-val');
    const hdelV = document.getElementById('hr-delay-val');
    if (pps && hpps) {
        hpps.value = pps.value;
        if (hppsV) hppsV.textContent = hpps.value + ' pps';
    }
    if (del && hdel) {
        hdel.value = del.value;
        if (hdelV) hdelV.textContent = hdel.value + ' ms';
    }
    const mode = document.querySelector('input[name="scan_mode"]:checked');
    const v = mode ? mode.value : 'auto';
    const rid = v === 'routed' ? 'hr-sm-routed' : v === 'force' ? 'hr-sm-force' : 'hr-sm-auto';
    const m = document.getElementById(rid);
    if (m) m.checked = true;
    const exs = document.getElementById('sc-excl');
    const hex = document.getElementById('hr-excl');
    if (exs && hex) hex.value = exs.value;
    const scCol = document.getElementById('sc-collector');
    const hrCol = document.getElementById('hr-collector');
    if (scCol && hrCol) {
        const v = String(scCol.value || '0');
        hrCol.value = [...hrCol.options].some(o => o.value === v) ? v : '0';
    }
}

/** After host-rescan enrichment list is built, mirror checked state from the Scan tab pickers. */
function syncHostRescanEnrichmentFromScanTab() {
    const scanWrap = document.getElementById('scan-enrichment-wrap');
    const hrWrap = document.getElementById('host-rescan-enrichment-wrap');
    if (!scanWrap || scanWrap.dataset.ready !== '1' || !hrWrap || hrWrap.dataset.ready !== '1') return;
    hrWrap.querySelectorAll('input[data-enr-id]:not(:disabled)').forEach(hCb => {
        const id = hCb.dataset.enrId;
        const sCb = scanWrap.querySelector('input[data-enr-id="' + id + '"]');
        if (sCb && !sCb.disabled) hCb.checked = sCb.checked;
    });
}

/** Same preset rules as applyScanTabProfileDefaults, for host-rescan modal controls (hr-*). */
function applyHostRescanModalProfileDefaults(profile) {
    const allowBanner = !['iot_safe', 'ot_careful'].includes(profile);
    ['hr-ph-banner', 'hr-ph-fingerprint', 'hr-ph-cve'].forEach(id => {
        const el = document.getElementById(id);
        if (el) {
            el.checked = allowBanner;
            const tr = el.closest('.tr2');
            if (tr) tr.style.opacity = allowBanner ? '1' : '0.4';
        }
    });
    const passive = document.getElementById('hr-ph-passive');
    const icmp = document.getElementById('hr-ph-icmp');
    if (passive) passive.checked = true;
    if (icmp) icmp.checked = true;
    const snmpEl = document.getElementById('hr-ph-snmp');
    const otEl = document.getElementById('hr-ph-ot');
    if (profile === 'deep_scan' || profile === 'full_tcp') {
        if (snmpEl) snmpEl.checked = true;
        if (otEl) otEl.checked = false;
    } else if (profile === 'ot_careful') {
        if (snmpEl) snmpEl.checked = false;
        if (otEl) otEl.checked = true;
    } else {
        if (snmpEl) snmpEl.checked = false;
        if (otEl) otEl.checked = false;
    }
    applyHostRescanModalRateSlidersForProfile(profile);

    const smForce = document.getElementById('hr-sm-force');
    const smAuto = document.getElementById('hr-sm-auto');
    if (smForce && smAuto && (profile === 'iot_safe' || profile === 'ot_careful') && smForce.checked) {
        smAuto.checked = true;
        toast('Discovery mode set to Auto — this profile does not allow Force (-Pn).', 'ok');
    }
    if (!['iot_safe', 'ot_careful'].includes(profile)) {
        ['hr-ph-banner', 'hr-ph-fingerprint', 'hr-ph-cve'].forEach(id => {
            const el = document.getElementById(id);
            const tr = el && el.closest('.tr2');
            if (tr) tr.style.opacity = '1';
        });
    }
    updateHostRescanHint();
}

function updateHostRescanHint() {
    const sel = document.getElementById('host-rescan-profile');
    const hint = document.getElementById('host-rescan-hint');
    if (!sel || !hint) return;
    hint.textContent = hostRescanProfileHintText(sel.value);
    updateHostRescanProfileWarn(sel.value);
}

function openHostRescanModal(ipTrim) {
    return new Promise((resolve) => {
        const bg = document.getElementById('host-rescan-bg');
        const ipEl = document.getElementById('host-rescan-ip');
        const sel = document.getElementById('host-rescan-profile');
        if (!bg || !ipEl || !sel) {
            resolve(null);
            return;
        }
        if (hostRescanModalResolve) {
            try { hostRescanModalResolve(null); } catch (e) {}
            hostRescanModalResolve = null;
        }
        void (async () => {
            try {
                await loadCollectorsOverview();
                ipEl.textContent = ipTrim;
                const cur = document.querySelector('input[name="scan_profile"]:checked');
                sel.value = cur && HOST_RESCAN_PROFILE_IDS.has(cur.value) ? cur.value : 'standard_inventory';
                readScanTabIntoHostRescanModal();
                syncHostRescanModalScanStepBannerOpacity();
                await refreshScanEnrichmentPicker('host-rescan-enrichment-wrap');
                syncHostRescanEnrichmentFromScanTab();
                updateHostRescanHint();
                hostRescanModalResolve = resolve;
                bg.style.display = 'flex';
            } catch (e) {
                toast('Could not open rescan dialog', 'err');
                resolve(null);
            }
        })();
    });
}

function closeHostRescanModal(result) {
    const bg = document.getElementById('host-rescan-bg');
    if (bg) bg.style.display = 'none';
    const fn = hostRescanModalResolve;
    hostRescanModalResolve = null;
    if (fn) fn(result);
}

function wireHostRescanModalOnce() {
    const bg = document.getElementById('host-rescan-bg');
    if (!bg || bg.dataset.wired === '1') return;
    bg.dataset.wired = '1';
    bg.addEventListener('click', (e) => {
        if (e.target === bg) closeHostRescanModal(null);
    });
    document.getElementById('host-rescan-profile')?.addEventListener('change', function() {
        applyHostRescanModalProfileDefaults(this.value);
    });
    document.getElementById('host-rescan-cancel-btn')?.addEventListener('click', () => closeHostRescanModal(null));
    ['hr-ph-passive', 'hr-ph-icmp', 'hr-ph-banner', 'hr-ph-fingerprint', 'hr-ph-snmp', 'hr-ph-ot', 'hr-ph-cve'].forEach(id => {
        document.getElementById(id)?.addEventListener('change', syncHostRescanModalScanStepBannerOpacity);
    });
    document.getElementById('host-rescan-queue-btn')?.addEventListener('click', () => {
        const s = document.getElementById('host-rescan-profile');
        const profile = s && s.value && HOST_RESCAN_PROFILE_IDS.has(s.value) ? s.value : 'standard_inventory';
        const phases = [];
        ['passive', 'icmp', 'banner', 'fingerprint', 'snmp', 'ot', 'cve'].forEach(p => {
            if (document.getElementById('hr-ph-' + p)?.checked) phases.push(p);
        });
        if (!phases.length) {
            ['passive', 'icmp', 'banner', 'fingerprint', 'cve'].forEach(p => phases.push(p));
        }
        const modeEl = document.querySelector('input[name="hr_scan_mode"]:checked');
        const rate_pps = parseInt(document.getElementById('hr-pps')?.value || '5', 10) || 5;
        const inter_delay = parseInt(document.getElementById('hr-delay')?.value || '200', 10) || 200;
        const hex = document.getElementById('hr-excl');
        const collectorId = parseInt(document.getElementById('hr-collector')?.value || '0', 10) || 0;
        closeHostRescanModal({
            profile,
            phases,
            rate_pps,
            inter_delay,
            scan_mode: modeEl ? modeEl.value : 'auto',
            exclusions: hex ? hex.value : '',
            enrichment_source_ids: hostEnrichmentPayloadField(),
            collector_id: collectorId,
        });
    });
}

/**
 * Queue a single-host scan (/32). Host modal sets profile, scan steps, rates, discovery, exclusions, enrichment; then POSTs.
 * On success, the Scan tab is updated to match. Requires scan_editor or admin (API enforced).
 */
async function queueHostRescan(ip, triggerBtn) {
    const ipTrim = String(ip || '').trim();
    if (!ipTrim) {
        toast('No IP to scan', 'err');
        return;
    }
    if (!stRoleCanManageScans()) {
        toast('Permission denied — scan editor or admin role required', 'err');
        return;
    }

    const choice = await openHostRescanModal(ipTrim);
    if (!choice || !choice.profile) return;

    const profileVal = choice.profile;

    if (['deep_scan', 'full_tcp', 'ot_careful'].includes(profileVal)) {
        const ok = await showConfirmModal(
            `Profile "${profileVal}" generates significant network traffic and requires confirmation.\n\nProceed with rescan of ${ipTrim}?`,
            { title: 'High-impact scan profile', okText: 'Queue scan' }
        );
        if (!ok) return;
    }

    let phases = Array.isArray(choice.phases) && choice.phases.length
        ? choice.phases.slice()
        : [];
    if (!phases.length) {
        ['passive', 'icmp', 'banner', 'fingerprint', 'cve'].forEach(p => phases.push(p));
    }
    const rate_pps = Math.max(1, Math.min(50, parseInt(String(choice.rate_pps ?? '5'), 10) || 5));
    const inter_delay = Math.max(0, Math.min(2000, parseInt(String(choice.inter_delay ?? '200'), 10) || 200));
    const scanModeEff = clampRescanScanModeForProfile(profileVal, choice.scan_mode || 'auto');

    const targetCidr = ipTrim + '/32';
    const hostLabel = 'Host ' + ipTrim;
    const cidrInput = document.getElementById('sc-cidr');
    if (cidrInput) cidrInput.value = targetCidr;
    const labelInput = document.getElementById('sc-label');
    if (labelInput && !String(labelInput.value || '').trim()) labelInput.value = hostLabel;

    const body = {
        cidr: targetCidr,
        exclusions: choice.exclusions !== undefined
            ? choice.exclusions
            : (document.getElementById('sc-excl') ? document.getElementById('sc-excl').value : ''),
        phases,
        rate_pps,
        inter_delay,
        label: hostLabel,
        scan_mode: scanModeEff,
        profile: profileVal,
        confirmed: true,
    };
    if (choice.enrichment_source_ids !== undefined) {
        body.enrichment_source_ids = choice.enrichment_source_ids;
    }
    const collectorId = Math.max(0, parseInt(String(choice.collector_id ?? '0'), 10) || 0);
    if (collectorId > 0) body.collector_id = collectorId;
    const rescanScope = parseInt(String(document.getElementById('sc-scope-id')?.value || '0'), 10) || 0;
    if (rescanScope > 0) body.scope_id = rescanScope;

    const btn = triggerBtn instanceof HTMLElement ? triggerBtn : null;
    const prevText = btn ? btn.textContent : '';
    if (btn) {
        btn.disabled = true;
        btn.textContent = 'Queuing…';
    }
    let r;
    try {
        r = await apiPost('/api/scan_start.php', body);
    } finally {
        if (btn) {
            btn.disabled = false;
            btn.textContent = prevText || '\u8635 Rescan host';
        }
    }
    if (!r) {
        toast('API error starting scan', 'err');
        return;
    }
    if (r.error || r.ok === false) {
        toast(r.error || 'Permission denied', 'err');
        return;
    }
    if (r.job_id == null || r.job_id === '') {
        toast('Scan was not queued (unexpected server response)', 'err');
        return;
    }

    applyRescanChoiceToScanTab({
        profile: profileVal,
        phases,
        rate_pps,
        inter_delay,
        exclusions: choice.exclusions,
        enrichment_source_ids: choice.enrichment_source_ids,
        collector_id: collectorId,
    }, scanModeEff);

    activeJobId = r.job_id;
    showScanRunning(activeJobId);
    toast(
        'Scan #' + r.job_id + ' queued (' + profileVal.replace(/_/g, ' ') + ') for ' + ipTrim + '. Scan tab updated.',
        'ok'
    );
    closeHostPanel();
    stPendingScanHistoryFocusJobId = Number(r.job_id) || 0;
    goTab('scanhist');
    hiNav('nscanhist');
    await loadScanStatus();
    startPoll(r.job_id);
}

async function abortScan() {
    let jobId = activeJobId;
    if (!jobId) {
        const s = await api('/api/scan_status.php?log_limit=1');
        if (s && s.job && ['running','queued'].includes(s.job.status)) {
            jobId = s.job.id;
        }
    }
    if (!jobId) { toast('No active scan to abort', 'err'); return; }
    abortJobById(jobId);
}

function showScanRunning(jobId) {
    document.getElementById('scan-stats').style.display = '';
    setStatusPill('run', 'Scanning…');
}

function startPoll(jobId) {
    clearInterval(pollTimer);
    logSinceId = 0;
    lastScanTerminalToastKey = '';
    pollTimer = setInterval(() => pollJob(jobId), 2500);
}

async function pollJob(jobId) {
    if (pollJobInFlight) return;
    pollJobInFlight = true;
    try {
        const d = await api(`/api/scan_status.php?job_id=${jobId}&since_log_id=${logSinceId}&log_limit=100`, {quiet:true});
        if (!d || !d.job) return;

        const job = d.job;

        // Update scan stats (kept for backward compat)
        document.getElementById('ss-found').textContent   = job.hosts_found || 0;
        document.getElementById('ss-scanned').textContent = job.hosts_scanned || 0;
        const el = job.elapsed_secs || 0;
        document.getElementById('ss-elapsed').textContent = el < 60 ? el+'s' : Math.floor(el/60)+'m '+(el%60)+'s';

        // Update queue panel inline progress
        if (d.history) updateQueuePanel(d.history);

        // Update inline message for running job row
        const msgEl = document.getElementById('qmsg-' + jobId);
        if (msgEl) {
            const lastInfo = (d.log || []).slice().reverse().find(l => l.level === 'INFO');
            if (lastInfo) {
                const pct = job.progress_pct || 0;
                const hf  = job.hosts_found || 0;
                const hs  = job.hosts_scanned || 0;
                msgEl.textContent = (hf > 0 ? hs+'/'+hf+' hosts · '+pct+'% · ' : '') + lastInfo.message.slice(0,60);
            } else if (job.status === 'running' && Number(job.collector_id || 0) > 0 && job.collector_lease) {
                const pct = job.progress_pct || 0;
                const cn = job.collector_name ? String(job.collector_name) : ('#' + job.collector_id);
                const hb = job.collector_lease.last_heartbeat_at ? String(job.collector_lease.last_heartbeat_at) : '—';
                msgEl.textContent = 'Remote on collector ' + esc(cn) + ' · ' + pct + '% · last collector contact ' + esc(hb);
            }
        }

        // Append new log lines to audit log view
        if (d.log && d.log.length) {
            logSinceId = d.log[d.log.length-1].id;
            if (currentTab === 'logs') appendLogRows(d.log);
        }

        if (job.status === 'done' || job.status === 'failed' || job.status === 'aborted') {
            clearInterval(pollTimer);
            activeJobId = null;
            setStatusPill('idle', 'Idle');
            const termKey = String(job.id) + ':' + job.status;
            if (job.status === 'done' && lastScanTerminalToastKey !== termKey) {
                lastScanTerminalToastKey = termKey;
                toast('Scan complete — ' + job.hosts_scanned + ' hosts catalogued', 'ok');
                refreshBadges();
            }
            if (job.status === 'failed' && lastScanTerminalToastKey !== termKey) {
                lastScanTerminalToastKey = termKey;
                toast('Scan failed: ' + (job.error_msg || 'unknown error'), 'err');
            }
            if (job.status === 'aborted' && lastScanTerminalToastKey !== termKey) {
                lastScanTerminalToastKey = termKey;
            }
            loadScanHistory();
            if (currentTab === 'dash') loadDashboard();
            // Check if another job is queued and auto-start polling it
            setTimeout(async () => {
                const next = await api('/api/scan_status.php?log_limit=1', {quiet:true});
                if (next && next.job && next.job.status === 'running') {
                    activeJobId = next.job.id;
                    showScanRunning(activeJobId);
                    startPoll(activeJobId);
                }
            }, 2000);
        } else {
            // Refresh queue panel on each poll so counts stay current
            if (d.history) updateQueuePanel(d.history);
        }
    } finally {
        pollJobInFlight = false;
    }
}

async function loadScanStatus() {
    const d = await api('/api/scan_status.php?log_limit=50', {quiet:true});
    if (!d) return;
    if (d.job) {
        if (d.job.status === 'running' || d.job.status === 'queued') {
            activeJobId = d.job.id;
            showScanRunning(activeJobId);
            startPoll(activeJobId);
        }
    }
    loadScanHistory(d.history);
    refreshScanEnrichmentPicker();
}

/** Per-scan enrichment toggles; returns undefined = default (all enabled), [] = none, else id subset */
function scanEnrichmentPayloadField() {
    const wrap = document.getElementById('scan-enrichment-wrap');
    if (!wrap || wrap.dataset.ready !== '1') return undefined;
    const enabledBoxes = wrap.querySelectorAll('input[data-enr-id]');
    if (!enabledBoxes.length) return undefined;
    const checked = [];
    enabledBoxes.forEach(cb => { if (cb.checked) checked.push(parseInt(cb.dataset.enrId, 10)); });
    if (checked.length === enabledBoxes.length) return undefined;
    return checked;
}

/** Host-rescan modal enrichment; same semantics as scanEnrichmentPayloadField(). */
function hostEnrichmentPayloadField() {
    const wrap = document.getElementById('host-rescan-enrichment-wrap');
    if (!wrap || wrap.dataset.ready !== '1') return undefined;
    const enabledBoxes = wrap.querySelectorAll('input[data-enr-id]:not(:disabled)');
    if (!enabledBoxes.length) return undefined;
    const checked = [];
    enabledBoxes.forEach(cb => { if (cb.checked) checked.push(parseInt(cb.dataset.enrId, 10)); });
    if (checked.length === enabledBoxes.length) return undefined;
    return checked;
}

/** @param {string} [wrapId] Default scan-enrichment-wrap; use host-rescan-enrichment-wrap for rescan modal */
async function refreshScanEnrichmentPicker(wrapId) {
    const wrap = document.getElementById(wrapId || 'scan-enrichment-wrap');
    if (!wrap) return;
    wrap.dataset.ready = '0';
    wrap.innerHTML = '<div class="hint-micro">Loading…</div>';
    let data;
    try {
        data = await api('/api/enrichment.php', {quiet:true});
    } catch (e) {
        wrap.innerHTML = '<div class="hint-micro">Could not load enrichment sources</div>';
        return;
    }
    const srcs = (data && data.sources) ? data.sources : [];
    if (!srcs.length) {
        wrap.innerHTML = '<div class="hint-micro">No sources configured yet — add them under <strong>Enrichment</strong>.</div>';
        wrap.dataset.ready = '1';
        return;
    }
    const parts = [];
    for (const s of srcs) {
        const en = parseInt(s.enabled, 10) === 1;
        const id = parseInt(s.id, 10);
        const label = esc(s.label || s.source_type || '');
        const typ = esc(s.source_type || '');
        if (en) {
            parts.push(`<div class="tr2"><div><div class="tl">${label}</div><div class="tsubl">${typ}</div></div><label class="chk tr2-check"><input type="checkbox" class="chk-input" data-enr-id="${id}" checked aria-label="Include enrichment source for this scan"></label></div>`);
        } else {
            parts.push(`<div class="tr2" style="opacity:0.55"><div><div class="tl">${label}</div><div class="tsubl">${typ} (disabled in Enrichment)</div></div><label class="chk tr2-check"><input type="checkbox" class="chk-input" disabled aria-label="Enrichment source disabled in settings"></label></div>`);
        }
    }
    wrap.innerHTML = parts.join('');
    wrap.dataset.ready = '1';
}

function scanHistSearchQ() {
    const el = document.getElementById('scan-hist-q');
    if (!el) return '';
    return (el.value || '').trim().slice(0, 120);
}

function updateScanHistoryViewButtons() {
    ['active', 'trash', 'all'].forEach((view) => {
        const btn = document.getElementById('scan-view-' + view);
        if (!btn) return;
        btn.classList.toggle('toggle-on', scanHistoryView === view);
        btn.classList.toggle('toggle-off', scanHistoryView !== view);
    });
}

function setScanHistoryView(view) {
    if (!['active', 'trash', 'all'].includes(view)) return;
    if ((view === 'trash' || view === 'all') && !stRoleCanManageScans()) {
        scanHistoryView = 'active';
        updateScanHistoryViewButtons();
        toast('Only scan editors/admins can view Trash', 'err');
        return;
    }
    scanHistoryView = view;
    updateScanHistoryViewButtons();
    void loadScanHistory();
}

async function saveScanTrashRetentionDays() {
    if (!stRoleIsAdmin()) return;
    const input = document.getElementById('scan-trash-retention-days');
    if (!input) return;
    const days = Math.max(1, Math.min(365, parseInt(input.value || String(scanTrashRetentionDays), 10) || 30));
    input.value = String(days);
    const r = await apiPost('/api/settings.php', {scan_trash_retention_days: days});
    if (r && r.ok) {
        scanTrashRetentionDays = days;
        toast('Trash retention updated to ' + days + ' day(s)', 'ok');
    } else {
        toast((r && r.error) || 'Save retention failed', 'err');
    }
}

function stApplyScanHistoryRowHighlight(row) {
    if (!row || !(row instanceof Element)) return;
    try {
        row.scrollIntoView({ block: 'center', behavior: 'smooth' });
    } catch (_e) {
        try {
            row.scrollIntoView();
        } catch (_e2) {}
    }
    row.classList.add('st-scan-hist-row-flash');
    const cleanup = () => {
        try {
            row.classList.remove('st-scan-hist-row-flash');
        } catch (_e) {}
        row.removeEventListener('animationend', cleanup);
    };
    row.addEventListener('animationend', cleanup);
    window.setTimeout(cleanup, 4500);
    const btn = row.querySelector('button[data-scan-action="details"][data-job-id]');
    if (btn && typeof btn.focus === 'function') {
        try {
            btn.focus({ preventScroll: true });
        } catch (_e) {}
    }
}

/** Scroll/highlight the job row when `stPendingScanHistoryFocusJobId` is set (after queue from Scan or host rescan). */
function stFlushPendingScanHistoryFocus() {
    const jid = stPendingScanHistoryFocusJobId;
    if (!jid || jid <= 0) return;
    const sel = 'tr.scan-hist-row[data-job-id="' + String(jid) + '"]';
    const ids = ['queue-tbody', 'queue-tbody-scan', 'scan-hist'];
    let row = null;
    for (let i = 0; i < ids.length; i++) {
        const root = document.getElementById(ids[i]);
        if (!root) continue;
        row = root.querySelector(sel);
        if (row) break;
    }
    stPendingScanHistoryFocusJobId = 0;
    if (row) {
        stApplyScanHistoryRowHighlight(row);
    }
}

function stScanHistChipClass(st) {
    const s = String(st || '').toLowerCase();
    if (s === 'running') return 'scan-hist-chip scan-hist-chip--running';
    if (s === 'queued') return 'scan-hist-chip scan-hist-chip--queued';
    if (s === 'retrying') return 'scan-hist-chip scan-hist-chip--retrying';
    if (s === 'done') return 'scan-hist-chip scan-hist-chip--done';
    if (s === 'failed') return 'scan-hist-chip scan-hist-chip--failed';
    if (s === 'aborted') return 'scan-hist-chip scan-hist-chip--aborted';
    return 'scan-hist-chip scan-hist-chip--default';
}

function stScanHistChipLabel(st) {
    const s = String(st || '').toLowerCase();
    if (s === 'running') return '\u25b6 Running';
    if (s === 'retrying') return 'Retrying';
    if (s === 'queued') return 'Queued';
    if (s === 'done') return 'Completed';
    if (s === 'failed') return 'Failed';
    if (s === 'aborted') return 'Aborted';
    const raw = String(st || '').trim();
    if (!raw) return '\u2014';
    return raw.charAt(0).toUpperCase() + raw.slice(1).toLowerCase();
}

function stCollectorIngestState(job, opts = {}) {
    const j = job && typeof job === 'object' ? job : {};
    if (Number(j.collector_id || 0) <= 0) return null;
    const showApplied = opts && opts.showApplied === false ? false : true;
    const status = String(j.status || '').toLowerCase();
    const subStatus = String(j.collector_submission_status || '').toLowerCase();
    const expected = Number(j.collector_chunks_expected || 0);
    const recv = Number(j.collector_chunks_received || 0);
    const applied = Number(j.collector_chunks_applied || 0);
    const pending = Number(j.collector_ingest_pending_count || 0);
    const failed = Number(j.collector_ingest_failed_count || 0);
    const attempts = Number(j.collector_ingest_attempts || 0);

    const chunkProgressTxt = () => {
        const n = Math.max(recv, applied);
        return expected > 0 ? `${n}/${expected} chunks` : `${n} chunks`;
    };

    // 1) Failed ingest queue rows: terminal job => failed; still running => active retry pressure
    if (failed > 0) {
        if (status === 'failed') {
            return { label: 'Ingest failed', detail: 'see execution record', level: 'err' };
        }
        const det = attempts > 0 ? `attempt ${attempts} · ${chunkProgressTxt()}` : chunkProgressTxt();
        return { label: 'Ingest retrying', detail: det, level: 'warn' };
    }

    // 2) Pending work: retrying only when pending rows exist AND attempts reflect worker pressure
    if (pending > 0 && attempts > 0) {
        return { label: 'Ingest retrying', detail: `attempt ${attempts} · ${chunkProgressTxt()}`, level: 'warn' };
    }
    if (pending > 0) {
        if (recv > 0 || subStatus === 'receiving' || subStatus === 'applied') {
            const chunkTxt = expected > 0 ? `${recv}/${expected} chunks received` : `${recv} chunks received`;
            return { label: 'Awaiting master ingest', detail: chunkTxt, level: 'warn' };
        }
        return { label: 'Running on collector', detail: 'collector execution in progress', level: 'dim' };
    }

    // 3) Terminal jobs with no queue pressure: list rows omit quiet success; detail may show applied
    const terminalSettled = status === 'done' || status === 'aborted';
    const fullyApplied =
        (expected > 0 && applied >= expected && recv > 0) ||
        (expected <= 0 && recv > 0 && applied >= recv) ||
        (expected <= 0 && recv === 0 && applied > 0);
    if (terminalSettled && pending === 0 && failed === 0) {
        if (!showApplied) return null;
        if (fullyApplied || (applied > 0 && recv >= applied)) {
            return {
                label: 'Applied on master',
                detail:
                    expected > 0
                        ? `${applied}/${expected} chunks applied`
                        : applied > 0
                          ? `${applied} chunks applied`
                          : 'collector ingest complete',
                level: 'ok',
            };
        }
        return null;
    }

    // 4) Chunks on master but not fully applied (no pending/failed rows — uncommon)
    if (recv > 0 && applied < recv) {
        const chunkTxt = expected > 0 ? `${recv}/${expected} chunks received` : `${recv} chunks received`;
        return { label: 'Awaiting master ingest', detail: chunkTxt, level: 'warn' };
    }

    if (recv > 0) {
        return {
            label: 'Collector result received',
            detail: expected > 0 ? `${recv}/${expected} chunks received` : `${recv} chunks received`,
            level: 'dim',
        };
    }

    if (status === 'running' || status === 'retrying' || status === 'queued') {
        return { label: 'Running on collector', detail: 'awaiting collector submission', level: 'dim' };
    }

    // collector_ingest_attempts alone is historical (max per queue row); never implies current retry
    return null;
}

function stCollectorIngestBadgeHtml(job, opts = {}) {
    const s = stCollectorIngestState(job, opts);
    if (!s) return '';
    const cls = s.level === 'ok' ? 'hstate-ok' : (s.level === 'err' ? 'hstate-err' : (s.level === 'warn' ? 'hstate-warn' : 'text-dim'));
    return `<div class="text-micro ${cls}" title="${esc(String(s.detail || ''))}">${esc(String(s.label || ''))}${s.detail ? ` · ${esc(String(s.detail))}` : ''}</div>`;
}

function stSyncScanHistStatusFilterButtons() {
    document.querySelectorAll('.st-shsf').forEach((btn) => {
        const on = btn.getAttribute('data-shsf') === stScanHistStatusFilter;
        btn.classList.toggle('toggle-on', on);
        btn.classList.toggle('toggle-off', !on);
    });
}

function stSetScanHistStatusFilter(mode) {
    const ok = { all: 1, running: 1, queued: 1, completed: 1, failed: 1, aborted: 1 };
    if (!ok[mode]) return;
    stScanHistStatusFilter = mode;
    stSyncScanHistStatusFilterButtons();
    stRenderAllScanHistoryUi();
}

function stRenderAllScanHistoryUi() {
    stRenderQueuePanelFromCache();
    stRenderCompletedScanHistFromCache();
}

function stRenderQueuePanelFromCache() {
    const raw = Array.isArray(stScanHistLastQueue) ? stScanHistLastQueue : [];
    const activeJobs = raw.filter((j) => ['queued', 'running', 'retrying'].includes(j.status));
    const f = stScanHistStatusFilter;
    let pool = activeJobs;
    if (f === 'running') {
        pool = activeJobs.filter((j) => ['running', 'retrying'].includes(j.status));
    } else if (f === 'queued') {
        pool = activeJobs.filter((j) => j.status === 'queued');
    } else if (f === 'completed' || f === 'failed' || f === 'aborted') {
        pool = [];
    }
    pool.sort((a, b) => {
        const tier = (s) => (s === 'running' ? 0 : s === 'retrying' ? 1 : 2);
        const d = tier(a.status) - tier(b.status);
        if (d !== 0) return d;
        return (b.id || 0) - (a.id || 0);
    });

    const queueBlocks = [
        {
            wrap: document.getElementById('job-queue'),
            empty: document.getElementById('job-queue-empty'),
            tbody: document.getElementById('queue-tbody'),
        },
        {
            wrap: document.getElementById('job-queue-scan'),
            empty: document.getElementById('job-queue-empty-scan'),
            tbody: document.getElementById('queue-tbody-scan'),
        },
    ].filter((b) => b.wrap && b.empty && b.tbody);

    const setEmptyMsg = (text) => {
        queueBlocks.forEach((b) => {
            if (b.empty) b.empty.textContent = text;
        });
    };

    if (!activeJobs.length) {
        queueBlocks.forEach((b) => {
            b.wrap.style.display = 'none';
            b.empty.style.display = 'block';
            b.tbody.innerHTML = '';
        });
        setEmptyMsg('No jobs queued or running right now.');
        const ss = document.getElementById('scan-stats');
        if (ss) ss.style.display = 'none';
        return;
    }

    if (!pool.length) {
        queueBlocks.forEach((b) => {
            b.wrap.style.display = 'none';
            b.empty.style.display = 'block';
            b.tbody.innerHTML = '';
        });
        setEmptyMsg('No matching jobs for this filter. Try \u201cAll\u201d or another status.');
        const hasRun = activeJobs.some((x) => x.status === 'running' || x.status === 'retrying');
        const ss = document.getElementById('scan-stats');
        if (ss) ss.style.display = hasRun ? '' : 'none';
        return;
    }

    queueBlocks.forEach((b) => {
        b.wrap.style.display = 'block';
        b.empty.style.display = 'none';
    });

    const rowsHtml = pool.map((j) => {
        const pct = j.progress_pct || 0;
        const isRun = j.status === 'running';
        const batchMeta = (Number(j.batch_total || 0) > 1 && Number(j.batch_index || 0) > 0)
            ? `<div class="text-micro text-dim">batch ${esc(String(j.batch_index))}/${esc(String(j.batch_total))}</div>`
            : '';
        const msgEl = isRun ? `
            <div class="text-micro scan-hist-qmsg" id="qmsg-${j.id}">
              ${j.hosts_found > 0 ? j.hosts_scanned + '/' + j.hosts_found + ' hosts \u00b7 ' + pct + '%' : 'Starting\u2026'}
            </div>
            <div class="track scan-hist-track">
              <div class="fill" style="width:${pct}%"></div>
            </div>` : '';
        const profPlain = j.profile ? j.profile.replace(/_/g, ' ') : '\u2014';
        const prof = esc(profPlain);
        const started = localTime(j.created_at, { hour: '2-digit', minute: '2-digit' });
        const elapsed = isRun && j.elapsed_secs != null ? fmtDuration(j.elapsed_secs) : '';
        const metaPlain = 'Profile ' + profPlain + ' \u00b7 Started ' + started + (elapsed ? ' \u00b7 Elapsed ' + elapsed : '');
        const metaLine = `<div class="text-micro scan-hist-inline-meta">${esc(metaPlain)}</div>`;
        const ingestLine = stCollectorIngestBadgeHtml(j, { showApplied: false });
        const rowCls = 'scan-hist-row' + (isRun ? ' scan-hist-row--active' : '');
        return `<tr class="${rowCls}" data-job-id="${j.id}" data-status="${esc(j.status)}" title="Open scan details">
          <td class="mono scan-hist-cell-id"><button type="button" class="tbtn text-micro" data-scan-action="details" data-job-id="${j.id}">#${j.id}</button></td>
          <td class="scan-hist-cell-primary">
            <button type="button" class="tbtn scan-hist-primary-btn" data-scan-action="details" data-job-id="${j.id}">${esc(j.label || '\u2014')}</button>
            ${batchMeta}
            <div class="mono-sm scan-hist-target-sub">${esc(j.target_cidr || '')}</div>
            <div class="text-micro text-dim">source: ${j.collector_id ? esc(j.collector_name || ('collector #' + j.collector_id)) : 'master'}</div>
            ${ingestLine}
            ${metaLine}
          </td>
          <td class="text-micro scan-hist-cell-muted">${prof}</td>
          <td>
            <span class="${stScanHistChipClass(j.status)}">${stScanHistChipLabel(j.status)}</span>
            ${msgEl}
          </td>
          <td class="mono font10 scan-hist-cell-muted">${j.priority || 10}</td>
          <td class="mono font10 scan-hist-cell-muted">${started}</td>
          <td class="nowrap-cell tbl-cell-actions">
            ${isRun
                ? `<button type="button" class="btnd btn-xxs" data-scan-action="abort" data-job-id="${j.id}">\u25a0 Abort</button>`
              : `<button type="button" class="tbtn btn-xxs danger" data-scan-action="cancel" data-job-id="${j.id}">Cancel</button>`}
            ${!isRun
                ? `<button type="button" class="tbtn btn-xxs" data-scan-action="set-priority" data-job-id="${j.id}" data-current-priority="${j.priority || 10}">Set priority</button>`
              : ''}
          </td>
        </tr>`;
    }).join('');
    queueBlocks.forEach((b) => {
        b.tbody.innerHTML = rowsHtml;
    });
}

function stRenderCompletedScanHistFromCache() {
    const tbody = document.getElementById('scan-hist');
    if (!tbody) return;
    const q = scanHistSearchQ();
    const f = stScanHistStatusFilter;
    let rows = (stScanHistLastCompleted || []).slice().filter((j) => !['queued', 'running', 'retrying'].includes(j.status));
    if (f === 'running' || f === 'queued') {
        rows = [];
    } else if (f === 'completed') {
        rows = rows.filter((j) => String(j.status || '').toLowerCase() === 'done');
    } else if (f === 'failed') {
        rows = rows.filter((j) => String(j.status || '').toLowerCase() === 'failed');
    } else if (f === 'aborted') {
        rows = rows.filter((j) => String(j.status || '').toLowerCase() === 'aborted');
    }
    rows.sort((a, b) => {
        const da = String(a.finished_at || a.created_at || '');
        const db = String(b.finished_at || b.created_at || '');
        const c = db.localeCompare(da);
        if (c !== 0) return c;
        return (b.id || 0) - (a.id || 0);
    });

    let emptyMsg;
    if (q && !rows.length) {
        emptyMsg = 'No scans match this search.';
    } else if (!rows.length && f === 'aborted') {
        emptyMsg = 'No aborted scans in this list.';
    } else if (!rows.length && (f === 'running' || f === 'queued' || f === 'completed' || f === 'failed')) {
        emptyMsg = 'No matching jobs for this filter.';
    } else if (!rows.length) {
        emptyMsg = 'No finished scans in this list yet. Queued and running jobs appear in the job queue above.';
    } else {
        emptyMsg = '';
    }

    const canRerun = (st) => ['done', 'aborted', 'failed'].includes(st);
    const canManage = stRoleCanManageScans();
    const canTrash = (j) => canManage && ['done', 'aborted', 'failed'].includes(j.status) && !j.deleted_at;
    const canRestore = (j) => canManage && !!j.deleted_at;
    const canPurge = (j) => !!j.deleted_at && stRoleIsAdmin();
    const aiStat = (j) => {
        const s = j && j.summary && typeof j.summary === 'object' ? j.summary : null;
        const a = s ? Number(s.ai_enrichment_attempts || 0) : 0;
        const p = s ? Number(s.ai_enrichment_applied || 0) : 0;
        if (!a && !p) return '<span class="text-dim">\u2014</span>';
        return `<span class="mono">${a}/${p}</span>`;
    };

    if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="9" class="loading tbl-empty scan-hist-empty">' + emptyMsg + '</td></tr>';
        return;
    }

    tbody.innerHTML = rows.map((j) => {
        const rowCls = 'scan-hist-row';
        const err = j.status === 'failed' && j.error_msg
            ? `<div class="text-micro scan-hist-err-hint" title="${esc(j.error_msg)}">${esc((j.error_msg || '').slice(0, 52))}</div>`
            : '';
        const prof = j.profile ? esc(j.profile.replace(/_/g, ' ')) : '\u2014';
        const fin = localDate(j.finished_at);
        const started = j.created_at ? localTime(j.created_at, { hour: '2-digit', minute: '2-digit' }) : '\u2014';
        const metaLine = `<div class="text-micro scan-hist-inline-meta">Started ${esc(started)} \u00b7 Finished ${esc(fin)} \u00b7 Profile ${prof}</div>`;
        const ingestLine = stCollectorIngestBadgeHtml(j, { showApplied: false });
        return `<tr class="${rowCls}" data-job-id="${j.id}" data-status="${esc(j.status)}" title="Open scan details">
      <td class="mono scan-hist-cell-id"><button type="button" class="tbtn text-micro" data-scan-action="details" data-job-id="${j.id}">#${j.id}</button></td>
      <td class="scan-hist-cell-primary">
        <button type="button" class="tbtn scan-hist-primary-btn" data-scan-action="details" data-job-id="${j.id}">${esc(j.label || '\u2014')}</button>
        ${j.retry_count > 0 ? ` <span class="text-micro scan-hist-retry-hint">retry ${j.retry_count}</span>` : ''}
        <div class="mono-sm scan-hist-target-sub">${esc(j.target_cidr || '')}</div>
        <div class="text-micro text-dim">source: ${j.collector_id ? esc(j.collector_name || ('collector #' + j.collector_id)) : 'master'}</div>
        ${ingestLine}
        ${metaLine}
      </td>
      <td><span class="${stScanHistChipClass(j.status)}">${stScanHistChipLabel(j.status)}</span>${err}</td>
      <td class="text-micro scan-hist-cell-muted">${prof}</td>
      <td class="mono scan-hist-cell-muted">${j.hosts_scanned || 0}/${j.hosts_found || 0}</td>
      <td class="mono scan-hist-cell-muted" title="AI attempted/applied">${aiStat(j)}</td>
      <td class="mono font10 scan-hist-cell-muted">${fmtDuration(j.duration_secs)}</td>
      <td class="mono font10 scan-hist-cell-muted">${fin}</td>
      <td class="nowrap-cell tbl-cell-actions">
        <button type="button" class="tbtn text-micro" data-scan-action="details" data-job-id="${j.id}">Details</button>
        ${canRerun(j.status) && !j.deleted_at && canManage ? `<button type="button" class="tbtn text-micro" data-scan-action="rerun" data-job-id="${j.id}">Re-run</button>` : ''}
        ${canTrash(j) ? `<button type="button" class="tbtn text-micro tbtn--danger-quiet" data-scan-action="delete" data-job-id="${j.id}">Move to trash</button>` : ''}
        ${canRestore(j) ? `<button type="button" class="tbtn text-micro" data-scan-action="restore" data-job-id="${j.id}">Restore</button>` : ''}
        ${canPurge(j) ? `<button type="button" class="tbtn text-micro tbtn--danger-quiet" data-scan-action="purge" data-job-id="${j.id}">Delete permanently</button>` : ''}
      </td>
    </tr>`;
    }).join('');
}

async function loadScanHistory(history) {
    updateScanHistoryViewButtons();
    if (!stRoleCanManageScans() && scanHistoryView !== 'active') {
        scanHistoryView = 'active';
        updateScanHistoryViewButtons();
    }
    let queueHistory = history;
    if (!queueHistory) {
        const d = await api('/api/scan_status.php?log_limit=1', {quiet:true});
        queueHistory = d ? d.history : [];
    }

    const q = scanHistSearchQ();
    const view = scanHistoryView;
    const sourceFilter = scanSourceFilterValue();
    let completedRows;
    if (q) {
        const hd = await api('/api/scan_history.php?limit=200&view=' + encodeURIComponent(view) + '&q=' + encodeURIComponent(q), {quiet:true});
        completedRows = (hd && hd.history) ? hd.history : [];
    } else {
        if (view === 'active') {
            completedRows = (queueHistory || []).filter((j) => !['queued', 'running', 'retrying'].includes(j.status));
        } else {
            const hd = await api('/api/scan_history.php?limit=200&view=' + encodeURIComponent(view), {quiet:true});
            completedRows = (hd && hd.history) ? hd.history : [];
        }
    }
    if (sourceFilter === 'master') {
        completedRows = (completedRows || []).filter((j) => Number(j.collector_id || 0) === 0);
    } else if (sourceFilter === 'collector') {
        completedRows = (completedRows || []).filter((j) => Number(j.collector_id || 0) > 0);
    }

    stScanHistLastQueue = (queueHistory || []).slice();
    stScanHistLastCompleted = (completedRows || []).slice();
    stSyncScanHistStatusFilterButtons();
    stRenderAllScanHistoryUi();
    bindScanHistoryDelegates();
    stFlushPendingScanHistoryFocus();
}

// ==========================================================================
// Job queue panel
// ==========================================================================
function updateQueuePanel(history) {
    if (Array.isArray(history)) {
        stScanHistLastQueue = history.slice();
    }
    stRenderQueuePanelFromCache();
}

function handleScanHistoryTableClick(ev) {
    const t = ev.target instanceof Element ? ev.target : null;
    if (!t) return;

    const btn = t.closest('button[data-scan-action][data-job-id]');
    if (btn) {
        const jid = parseInt(btn.getAttribute('data-job-id') || '0', 10);
        if (jid <= 0) return;
        const action = btn.getAttribute('data-scan-action') || '';
        if (action === 'details') { void openScanHistDetail(jid); return; }
        if (action === 'rerun')   { void rerunScanJob(jid); return; }
        if (action === 'delete')  { void deleteScanJob(jid); return; }
        if (action === 'restore') { void restoreScanJob(jid); return; }
        if (action === 'purge')   { void purgeScanJob(jid); return; }
        if (action === 'abort')   { void abortJobById(jid); return; }
        if (action === 'cancel')  { void cancelJob(jid); return; }
        if (action === 'set-priority') {
            const cur = parseInt(btn.getAttribute('data-current-priority') || '10', 10) || 10;
            void setQueuedJobPriority(jid, cur);
            return;
        }
        return;
    }

    if (t.closest('a,input,label,select,textarea')) return;
    const row = t.closest('tr.scan-hist-row[data-job-id]');
    if (!row) return;
    const jid = parseInt(row.getAttribute('data-job-id') || '0', 10);
    if (jid > 0) void openScanHistDetail(jid);
}

function bindScanHistoryDelegates() {
    ['scan-hist', 'queue-tbody', 'queue-tbody-scan'].forEach((id) => {
        const tbody = document.getElementById(id);
        if (!tbody) return;
        if (tbody.dataset.scanDelegatesBound === '1') return;
        tbody.addEventListener('click', handleScanHistoryTableClick);
        tbody.dataset.scanDelegatesBound = '1';
    });
}
bindScanHistoryDelegates();
(function wireStScanHistStatusFiltersOnce() {
    const wrap = document.getElementById('st-shsf-wrap');
    if (!wrap || wrap.dataset.bound === '1') return;
    wrap.addEventListener('click', (ev) => {
        const b = ev.target && ev.target.closest ? ev.target.closest('button[data-shsf]') : null;
        if (!b || !wrap.contains(b)) return;
        const m = b.getAttribute('data-shsf');
        if (m) stSetScanHistStatusFilter(m);
    });
    wrap.dataset.bound = '1';
})();
wireHostRescanModalOnce();

async function refreshScanHistAiSummary() {
    const btn = document.getElementById('scan-hist-detail-refresh-ai');
    const jobId = parseInt(btn?.dataset.jobId || '0', 10);
    if (!jobId || !stRoleCanManageScans()) return;
    const cmpSel = document.getElementById('scan-hist-compare-select');
    const cmp = cmpSel ? parseInt(String(cmpSel.value || '0'), 10) || 0 : 0;
    const scope = typeof currentCompareScope === 'function' ? currentCompareScope() : 'any';
    const prev = btn ? btn.textContent : '';
    if (btn) {
        btn.disabled = true;
        btn.textContent = 'Refreshing…';
    }
    const r = await apiPost('/api/ai_actions.php', { action: 'refresh_scan_summary', job_id: jobId });
    if (btn) {
        btn.disabled = false;
        btn.textContent = prev || 'Refresh AI summary';
    }
    if (!r) return;
    if (r.ok) {
        toast('Scan AI summary updated', 'ok');
        await openScanHistDetail(jobId, cmp > 0 ? cmp : 0, scope, true);
        return;
    }
    toast(
        (r.error || 'Refresh failed')
            + (r.detail ? ': ' + r.detail : '')
            + (r.hint ? ' — ' + r.hint : ''),
        'err'
    );
}

function hpAiEnvelopeBody(env) {
    if (!env || typeof env !== 'object') return '<div class="hp-empty st-host-empty">No AI summary yet. Generate one when you want a quick narrative (verify against findings and ports).</div>';
    const st = String(env.status || '');
    const det = env.detail != null ? String(env.detail) : '';
    if (st === 'failed' || st === 'skipped') {
        return `<div class="hp-empty st-host-empty">${
            st === 'failed' ? 'Generation failed' : 'Skipped'
        }${det ? ` — ${esc(det)}` : ''}</div>`;
    }
    const doc = env.doc && typeof env.doc === 'object' ? env.doc : null;
    if (!doc) return '<div class="hp-empty st-host-empty">Summary payload empty — try regenerating.</div>';
    return '';
}

function hpAiExplainDocHtml(doc) {
    const ov = doc.overview ? `<div class="summary-line hp-ai-overview-clamp" style="margin-top:6px">${esc(String(doc.overview))}</div>` : '';
    const roles = Array.isArray(doc.likely_roles) && doc.likely_roles.length
        ? `<div class="summary-line mt6"><b>Likely roles</b><ul class="hp-ai-ul">${doc.likely_roles.map(x => `<li>${esc(String(x))}</li>`).join('')}</ul></div>`
        : '';
    const tips = Array.isArray(doc.hardening_tips) && doc.hardening_tips.length
        ? `<div class="summary-line mt6"><b>Hardening ideas</b><ul class="hp-ai-ul">${doc.hardening_tips.map(x => `<li>${esc(String(x))}</li>`).join('')}</ul></div>`
        : '';
    const qs = Array.isArray(doc.owner_questions) && doc.owner_questions.length
        ? `<div class="summary-line mt6"><b>Ask the owner</b><ul class="hp-ai-ul">${doc.owner_questions.map(x => `<li>${esc(String(x))}</li>`).join('')}</ul></div>`
        : '';
    if (!ov && !roles && !tips && !qs) return '<div class="hp-empty st-host-empty">Model returned an empty structure — regenerate or rely on raw inventory above.</div>';
    return ov + roles + tips + qs;
}

function renderHpAiOperatorSection(a, assetId, ip) {
    const ex = a.ai_host_explain && typeof a.ai_host_explain === 'object' ? a.ai_host_explain : null;
    const can = stRoleCanManageScans();

    let exInner = hpAiEnvelopeBody(ex);
    if (ex && String(ex.status || '') === 'ok' && ex.doc) exInner = hpAiExplainDocHtml(ex.doc);

    const exBtns = can
        ? `<div class="row-wrap gap6 mt6">
            <button type="button" class="tbtn btn-xs" data-st-ai-action="explain" data-asset-id="${assetId}" data-ip="${esc(String(ip || ''))}" data-force="${ex ? '1' : '0'}">${ex ? 'Regenerate' : 'Generate'} host summary</button>
          </div>`
        : '<div class="hint-micro mt6">Scan editor or admin role required to run AI.</div>';

    const tsEx = ex && ex.ts ? `<span class="text-micro text-dim"> · ${esc(String(ex.ts))}</span>` : '';

    return `
      <div class="hp-head">AI host summary <span class="text-dim">(suggestions only — verify before acting)</span></div>
      <p class="hint-micro" style="margin:4px 0 10px">AI output may be wrong; use open ports, banners, and the findings list above as source of truth.</p>
      <div class="hp-block hp-ai-col" style="margin-bottom:0">
        <div class="text-micro" style="font-weight:600;margin-bottom:4px">Summary${tsEx}</div>
        ${exInner}
        ${exBtns}
      </div>`;
}

/** POST explain_host in flight for this asset id (0 = none). Survives closing the host panel so reopening can show Running again. */
let stAiHostExplainInflightAssetId = 0;

function syncHostPanelExplainBusyUi() {
    const panel = document.getElementById('host-panel');
    if (!panel) return;
    const openAid = parseInt(panel.dataset.hpAssetId || '0', 10);
    const inflight = stAiHostExplainInflightAssetId;
    const busy = inflight > 0 && inflight === openAid;
    panel.querySelectorAll('button[data-st-ai-action="explain"]').forEach((b) => {
        if (busy) {
            if (b.dataset.stAiSavedHtml === undefined) {
                b.dataset.stAiSavedHtml = b.innerHTML;
            }
            b.disabled = true;
            b.setAttribute('aria-busy', 'true');
            b.innerHTML = '<span class="hp-ai-spin" aria-hidden="true"></span> Running…';
        } else {
            b.disabled = false;
            b.removeAttribute('aria-busy');
            if (b.dataset.stAiSavedHtml !== undefined) {
                b.innerHTML = b.dataset.stAiSavedHtml;
                delete b.dataset.stAiSavedHtml;
            }
        }
    });
}

async function runAiHostExplain(assetId, ip, force) {
    if (!stRoleCanManageScans()) {
        toast('Permission denied — scan editor or admin role required', 'err');
        return;
    }
    if (stAiHostExplainInflightAssetId !== 0) {
        if (stAiHostExplainInflightAssetId === assetId) {
            toast('Host summary is still generating for this host.', 'ok');
        } else {
            toast('Another host summary is still running; wait for it to finish.', 'ok');
        }
        return;
    }
    stAiHostExplainInflightAssetId = assetId;
    syncHostPanelExplainBusyUi();
    try {
        toast('Generating AI host summary (may take up to a few minutes)…', 'ok');
        const r = await apiPost('/api/ai_actions.php', {
            action: 'explain_host',
            asset_id: assetId,
            force: !!force,
        });
        if (!r) return;
        if (r.ok) {
            toast(r.cached ? 'Showing cached host summary' : 'Host summary ready', 'ok');
            await openHostPanel(assetId, ip);
            return;
        }
        toast(
            (r.error || 'Host summary failed')
                + (r.detail ? ': ' + r.detail : '')
                + (r.hint ? ' — ' + r.hint : ''),
            'err'
        );
        await openHostPanel(assetId, ip);
    } finally {
        stAiHostExplainInflightAssetId = 0;
        syncHostPanelExplainBusyUi();
    }
}

function bindScanDetailAssetDelegates() {
    const tbody = document.getElementById('scan-hist-detail-assets');
    if (!tbody || tbody.dataset.scanAssetDelegatesBound === '1') return;
    tbody.addEventListener('click', (ev) => {
        const t = ev.target instanceof Element ? ev.target : null;
        if (!t) return;
        const row = t.closest('tr.scan-hist-asset-row[data-asset-id]');
        if (!row) return;
        const aid = parseInt(row.getAttribute('data-asset-id') || '0', 10);
        const didRaw = row.getAttribute('data-device-id');
        const did = didRaw && didRaw !== 'null' ? parseInt(didRaw, 10) : 0;
        const ip = row.getAttribute('data-ip') || '';
        openScanHistAssetNav(aid, did > 0 ? did : null, ip);
    });
    tbody.dataset.scanAssetDelegatesBound = '1';
}
bindScanDetailAssetDelegates();

/**
 * Host panel AI buttons must not use inline onclick calling async top-level functions —
 * those names are not guaranteed to exist on `window`, so clicks can fail silently.
 */
function bindHostPanelAiDelegatesOnce() {
    const panel = document.getElementById('host-panel');
    if (!panel || panel.dataset.stHostDelegates === '1') return;
    panel.addEventListener('click', (ev) => {
        const el = ev.target;
        const btn = el && el.closest ? el.closest('button[data-st-ai-action]') : null;
        if (!btn || !panel.contains(btn)) return;
        const action = btn.getAttribute('data-st-ai-action') || '';
        if (action !== 'explain') return;
        ev.preventDefault();
        const assetId = parseInt(btn.getAttribute('data-asset-id') || '0', 10);
        const ip = btn.getAttribute('data-ip') || '';
        const force = btn.getAttribute('data-force') === '1';
        if (!assetId) return;
        void runAiHostExplain(assetId, ip, force);
    });
    panel.addEventListener('keydown', (ev) => {
        const list = ev.target && ev.target.closest ? ev.target.closest('.host-tablist') : null;
        if (!list || !panel.contains(list)) return;
        stHostTablistKeydown(ev, list);
    });
    panel.dataset.stHostDelegates = '1';
}
bindHostPanelAiDelegatesOnce();

// ==========================================================================
// Job queue management
// ==========================================================================
async function abortJobById(id) {
    if (!(await showConfirmModal(
        'Abort job #' + id + '? The scan will stop after the current batch.',
        {title: 'Abort scan job', okText: 'Abort'}
    ))) return;
    const r = await apiPost('/api/scan_abort.php', {job_id: id});
    if (r && r.ok) {
        toast('Job #' + id + ' aborted', 'ok');
        clearInterval(pollTimer);
        activeJobId = null;
        setStatusPill('idle', 'Idle');
        loadScanHistory();
    } else {
        toast((r && r.error) || 'Abort failed', 'err');
    }
}

async function cancelJob(id) {
    if (!(await showConfirmModal(
        'Cancel job #' + id + '?',
        {title: 'Cancel queued job', okText: 'Cancel job'}
    ))) return;
    const r = await apiPost('/api/scan_abort.php', {job_id: id});
    if (r && r.ok) { toast('Job #' + id + ' cancelled', 'ok'); loadScanHistory(); }
    else toast((r && r.error) || 'Cancel failed', 'err');
}

async function setQueuedJobPriority(jobId, currentPriority) {
    const raw = await showPromptModal(
        '1 = highest priority in the queue, 100 = lowest.',
        {
            title: 'Set queue priority',
            label: 'Priority (1–100)',
            defaultValue: String(currentPriority || 10),
            okText: 'Set priority',
            inputType: 'number',
            inputMin: 1,
            inputMax: 100,
            placeholder: String(currentPriority || 10),
        }
    );
    if (raw == null) return;
    const nextPriority = parseInt(String(raw).trim(), 10);
    if (!Number.isFinite(nextPriority) || nextPriority < 1 || nextPriority > 100) {
        toast('Priority must be an integer between 1 and 100', 'err');
        return;
    }
    if (nextPriority === (currentPriority || 10)) return;
    const r = await apiPost('/api/scan_priority.php', { job_id: jobId, priority: nextPriority });
    if (!r) {
        toast('Failed to update priority', 'err');
        return;
    }
    if (r.error || r.ok === false) {
        toast(r.error || 'Failed to update priority', 'err');
        return;
    }
    toast('Job #' + jobId + ' priority updated to ' + String(nextPriority), 'ok');
    loadScanHistory();
}

async function rerunScanJob(id) {
    if (!stRoleCanManageScans()) {
        toast('You do not have permission to start scans.', 'err');
        return;
    }
    const r = await apiPost('/api/scan_start.php', {retry_job_id: id});
    if (r && r.job_id) {
        closeScanHistDetailModal(false);
        toast('New job #' + r.job_id + ' queued with the same target and options', 'ok');
        loadScanHistory();
    } else {
        toast((r && r.error) || 'Re-run failed', 'err');
    }
}

async function deleteScanJob(id) {
    const jid = parseInt(String(id), 10);
    if (!jid) return;
    const ok = await showConfirmModal(
        `Move scan #${jid} to Trash?\n\nIt can be restored until the retention period expires.`,
        {title: 'Move scan to trash', okText: 'Move to trash'}
    );
    if (!ok) return;
    const r = await apiPost('/api/scan_delete.php', {job_id: jid, action: 'trash'});
    if (r && r.ok) {
        const delBtn = document.getElementById('scan-hist-detail-delete');
        const openId = delBtn ? parseInt(delBtn.dataset.jobId || '0', 10) : 0;
        if (openId === jid) closeScanHistDetailModal(false);
        toast('Scan #' + jid + ' moved to trash', 'ok');
        loadScanHistory();
    } else {
        toast((r && r.error) || 'Move to trash failed', 'err');
    }
}

async function restoreScanJob(id) {
    const jid = parseInt(String(id), 10);
    if (!jid) return;
    const r = await apiPost('/api/scan_delete.php', {job_id: jid, action: 'restore'});
    if (r && r.ok) {
        toast('Scan #' + jid + ' restored', 'ok');
        loadScanHistory();
    } else {
        toast((r && r.error) || 'Restore failed', 'err');
    }
}

async function purgeScanJob(id) {
    const jid = parseInt(String(id), 10);
    if (!jid) return;
    const ok = await showConfirmModal(
        `Delete scan #${jid} permanently?\n\nThis permanently removes the job and saved run evidence.`,
        {title: 'Permanent delete', okText: 'Delete permanently'}
    );
    if (!ok) return;
    const r = await apiPost('/api/scan_delete.php', {job_id: jid, action: 'purge'});
    if (r && r.ok) {
        const delBtn = document.getElementById('scan-hist-detail-delete');
        const openId = delBtn ? parseInt(delBtn.dataset.jobId || '0', 10) : 0;
        if (openId === jid) closeScanHistDetailModal(false);
        toast('Scan #' + jid + ' permanently deleted', 'ok');
        loadScanHistory();
    } else {
        toast((r && r.error) || 'Permanent delete failed', 'err');
    }
}

function scanHistoryPrimaryAction(id) {
    const btn = document.getElementById('scan-hist-detail-delete');
    const action = btn ? (btn.dataset.action || 'trash') : 'trash';
    if (action === 'restore') return restoreScanJob(id);
    if (action === 'purge') return purgeScanJob(id);
    return deleteScanJob(id);
}

function closeScanHistDetailModal(restoreDevice = true) {
    const bg = document.getElementById('scan-hist-detail-bg');
    if (bg) bg.style.display = 'none';
    const hint = document.getElementById('scan-hist-detail-assets-hint');
    if (hint) hint.style.display = 'none';
    if (restoreDevice && scanDetailReturnDeviceId > 0) {
        const did = scanDetailReturnDeviceId;
        scanDetailReturnDeviceId = 0;
        goTab('devices');
        hiNav('ndevices');
        setTimeout(() => { void openDevicePanel(did); }, 0);
    }
}

/** From scan detail modal: prefer Devices when `device_id` is set, else host panel (asset by IP). */
function openScanHistAssetNav(assetId, deviceId, ip) {
    const aid = parseInt(String(assetId), 10);
    const did = deviceId != null && deviceId !== '' ? parseInt(String(deviceId), 10) : 0;
    closeScanHistDetailModal(false);
    scanDetailReturnDeviceId = 0;
    if (did > 0) {
        goTab('devices');
        hiNav('ndevices');
        void openDevicePanel(did);
        return;
    }
    if (aid > 0 && ip) {
        goTab('assets');
        hiNav('nassets');
        void openHostPanel(aid, ip);
    }
}

function renderScanSummary(summary) {
    if (!summary || typeof summary !== 'object') {
        return '<span class="summary-empty">No summary snapshot recorded for this run.</span>';
    }
    const topPorts = Array.isArray(summary.top_ports) ? summary.top_ports : [];
    const cats = summary.categories && typeof summary.categories === 'object'
        ? Object.entries(summary.categories).map(([k,v]) => `${k}:${v}`).join(', ')
        : '';
    const portText = topPorts.length
        ? topPorts.slice(0, 6).map(p => `${p.port}(${p.hosts})`).join(', ')
        : '—';
    let aiSummaryRaw = summary.ai_summary;
    if (typeof aiSummaryRaw === 'string' && aiSummaryRaw.trim()) {
        try {
            aiSummaryRaw = JSON.parse(aiSummaryRaw);
        } catch (e) {
            aiSummaryRaw = null;
        }
    }
    const aiSummary = aiSummaryRaw && typeof aiSummaryRaw === 'object' ? aiSummaryRaw : null;
    const aiReasonCounts = summary.ai_reason_counts && typeof summary.ai_reason_counts === 'object'
        ? Object.entries(summary.ai_reason_counts).map(([k,v]) => `${k}:${v}`).join(', ')
        : '';
    const aiOverview = aiSummary && aiSummary.overview ? String(aiSummary.overview) : '';
    const aiConcerns = aiSummary && Array.isArray(aiSummary.concerns) ? aiSummary.concerns : [];
    const aiNext = aiSummary && Array.isArray(aiSummary.next_steps) ? aiSummary.next_steps : [];
    const aiStatus = summary.ai_scan_summary_status != null ? String(summary.ai_scan_summary_status) : '';
    const aiDetail = summary.ai_scan_summary_detail != null ? String(summary.ai_scan_summary_detail) : '';
    const aiStatusBlock = (aiStatus || aiDetail) && (!aiSummary || (!aiOverview && !aiConcerns.length && !aiNext.length))
        ? `<div class="summary-line" style="margin-top:8px"><b>AI run summary</b> <span class="text-dim">(${esc(aiStatus || '—')})</span></div>
           ${aiDetail ? `<div class="summary-line text-dim">${esc(aiDetail)}</div>` : ''}`
        : '';
    const aiBlock = aiSummary ? `
      <div class="summary-line" style="margin-top:8px"><b>AI run summary</b></div>
      ${aiOverview ? `<div class="summary-line">${esc(aiOverview)}</div>` : ''}
      ${aiConcerns.length ? `<div class="summary-line">Concerns: ${esc(aiConcerns.join(' | '))}</div>` : ''}
      ${aiNext.length ? `<div class="summary-line">Next checks: ${esc(aiNext.join(' | '))}</div>` : ''}
    ` : '';
    return `
      <div>Profile: <b>${esc(summary.profile || '—')}</b> &nbsp;|&nbsp; Mode: <b>${esc(summary.scan_mode || '—')}</b></div>
      <div class="summary-line">Assets catalogued: <b>${summary.assets_catalogued || 0}</b> &nbsp;|&nbsp; Open ports observed: <b>${summary.open_ports_total || 0}</b></div>
      <div class="summary-line">Top ports: <span class="mono">${esc(portText)}</span></div>
      <div class="summary-line">Categories: <span class="mono">${esc(cats || '—')}</span></div>
      <div class="summary-line">AI enrichment: attempted <b>${summary.ai_enrichment_attempts || 0}</b> &nbsp;|&nbsp; applied <b>${summary.ai_enrichment_applied || 0}</b></div>
      ${aiReasonCounts ? `<div class="summary-line">AI gate/skip reasons: <span class="mono">${esc(aiReasonCounts)}</span></div>` : ''}
      ${aiBlock || aiStatusBlock}
    `;
}

function renderScanDiff(diff) {
    if (!diff || !diff.compared_job) return '';
    const cj = diff.compared_job || {};
    const h = diff.hosts || {};
    const p = diff.ports || {};
    const c = diff.cves || {};
    const addHosts = Array.isArray(h.added) ? h.added : [];
    const remHosts = Array.isArray(h.removed) ? h.removed : [];
    const newCves = Array.isArray(c.new_open) ? c.new_open : [];
    const resCves = Array.isArray(c.resolved) ? c.resolved : [];
    const addPorts = Array.isArray(p.added_ports) ? p.added_ports : [];
    const remPorts = Array.isArray(p.removed_ports) ? p.removed_ports : [];
    return `
      <div><strong>Diff vs scan #${esc(cj.id || '—')}</strong> (${esc(cj.label || 'untitled')})</div>
      <div class="summary-line">Hosts: <b>${h.current || 0}</b> now vs <b>${h.previous || 0}</b> prior &nbsp;|&nbsp; +${addHosts.length} / -${remHosts.length}</div>
      <div class="summary-line">Ports: +<b>${p.added || 0}</b> / -<b>${p.removed || 0}</b> host-port pairs</div>
      ${(addPorts.length || remPorts.length) ? `<div class="summary-line">Ports changed: ${addPorts.length ? `+ ${esc(addPorts.join(', '))}` : ''}${remPorts.length ? `${addPorts.length ? ' &nbsp;|&nbsp; ' : ''}- ${esc(remPorts.join(', '))}` : ''}</div>` : ''}
      <div class="summary-line">Open CVEs: <b>${c.open_current || 0}</b> now vs <b>${c.open_previous || 0}</b> prior &nbsp;|&nbsp; new <b>${newCves.length}</b> / resolved <b>${resCves.length}</b></div>
      ${(addHosts.length || remHosts.length) ? `<div class="summary-line">Hosts changed: ${addHosts.length ? `+ ${esc(addHosts.slice(0, 8).join(', '))}` : ''}${remHosts.length ? `${addHosts.length ? ' &nbsp;|&nbsp; ' : ''}- ${esc(remHosts.slice(0, 8).join(', '))}` : ''}</div>` : ''}
      ${(newCves.length || resCves.length) ? `<div class="summary-line">CVEs changed: ${newCves.length ? `+ ${esc(newCves.slice(0, 6).join(', '))}` : ''}${resCves.length ? `${newCves.length ? ' &nbsp;|&nbsp; ' : ''}resolved ${esc(resCves.slice(0, 6).join(', '))}` : ''}</div>` : ''}
    `;
}

function currentCompareScope() {
    const sameTarget = !!document.getElementById('scan-hist-compare-same-target')?.checked;
    const sameProfile = !!document.getElementById('scan-hist-compare-same-profile')?.checked;
    if (sameTarget && sameProfile) return 'both';
    if (sameTarget) return 'target';
    if (sameProfile) return 'profile';
    return 'any';
}

function applyCompareScope(scope) {
    const sameTarget = document.getElementById('scan-hist-compare-same-target');
    const sameProfile = document.getElementById('scan-hist-compare-same-profile');
    if (sameTarget) sameTarget.checked = (scope === 'target' || scope === 'both');
    if (sameProfile) sameProfile.checked = (scope === 'profile' || scope === 'both');
}

function renderCompareOptions(jobId, job, options, selectedCompareId, scope) {
    const sel = document.getElementById('scan-hist-compare-select');
    const btn = document.getElementById('scan-hist-compare-btn');
    const sameTargetEl = document.getElementById('scan-hist-compare-same-target');
    const sameProfileEl = document.getElementById('scan-hist-compare-same-profile');
    if (!sel || !btn) return;
    applyCompareScope(scope || 'any');
    const opts = Array.isArray(options) ? options : [];
    const filtered = opts.filter(o => {
        if (!job || typeof job !== 'object') return true;
        const needsTarget = !!sameTargetEl?.checked;
        const needsProfile = !!sameProfileEl?.checked;
        if (needsTarget && String(o.target_cidr || '') !== String(job.target_cidr || '')) return false;
        if (needsProfile) {
            if (String(o.profile || '') !== String(job.profile || '')) return false;
            if (String(o.scan_mode || '') !== String(job.scan_mode || '')) return false;
        }
        return true;
    });
    const current = parseInt(String(selectedCompareId || 0), 10);
    sel.innerHTML = ['<option value="">Previous completed run (auto)</option>']
        .concat(filtered.map(o => {
            const id = parseInt(o.id, 10);
            const label = esc(o.label || 'untitled');
            const tgt = esc(o.target_cidr || '');
            const fin = esc(localDate(o.finished_at));
            const tag = id === current ? ' selected' : '';
            return `<option value="${id}"${tag}>#${id} · ${label} · ${tgt} · ${fin}</option>`;
        })).join('');
    const runCompare = () => {
        const cmp = parseInt(sel.value || '0', 10);
        void openScanHistDetail(jobId, cmp > 0 ? cmp : 0, currentCompareScope());
    };
    btn.onclick = runCompare;
    sel.onchange = runCompare;
    if (sameTargetEl) sameTargetEl.onchange = runCompare;
    if (sameProfileEl) sameProfileEl.onchange = runCompare;
}

function stScanHistDetailGoAssets() {
    closeScanHistDetailModal(false);
    goTab('assets');
    hiNav('nassets');
}

function stScanHistDetailGoReport() {
    closeScanHistDetailModal(false);
    goTab('report');
    hiNav('nreport');
}

function stScanHistDetailStatCardsHtml(j) {
    const assetsVal = String(j.hosts_found != null ? Number(j.hosts_found) : 0);
    const assetsLabel = 'Assets found';
    const dur = fmtDuration(j.duration_secs || 0);
    const src = j.collector_id ? String(j.collector_name || ('Collector #' + j.collector_id)) : 'Master';
    const collectorIngest = (() => {
        if (Number(j.collector_id || 0) <= 0) return '';
        const expected = Number(j.collector_chunks_expected || 0);
        const recv = Number(j.collector_chunks_received || 0);
        const applied = Number(j.collector_chunks_applied || 0);
        const attempts = Number(j.collector_ingest_attempts || 0);
        const pending = Number(j.collector_ingest_pending_count || 0);
        const failed = Number(j.collector_ingest_failed_count || 0);
        const err = String(j.collector_ingest_error || '').trim();
        const chunksTxt = expected > 0 ? `${recv}/${expected} received · ${applied}/${expected} applied` : `${recv} received · ${applied} applied`;
        const histAttemptsTxt = `max ingest attempts (historical): ${attempts}`;
        return `<div class="text-micro text-dim mt6">Collector ingest: ${esc(chunksTxt)} · pending ${esc(String(pending))} · failed ${esc(String(failed))} · ${esc(histAttemptsTxt)}${err ? `</div><div class="text-micro hstate-err mt4">Latest ingest error: ${esc(err.slice(0, 220))}` : ''}</div>`;
    })();
    return `<div class="scan-hist-detail-stat-grid">
      <div class="scan-hist-detail-stat"><div class="scan-hist-detail-stat-label">${esc(assetsLabel)}</div><div class="scan-hist-detail-stat-val">${esc(assetsVal)}</div></div>
      <div class="scan-hist-detail-stat"><div class="scan-hist-detail-stat-label">Duration</div><div class="scan-hist-detail-stat-val">${esc(dur)}</div></div>
      <div class="scan-hist-detail-stat"><div class="scan-hist-detail-stat-label">Source</div><div class="scan-hist-detail-stat-val mono-sm">${esc(src)}</div></div>
    </div>${collectorIngest}`;
}

function stScanHistFailureReasonLabel(code) {
    const c = String(code || '').trim().toLowerCase();
    if (!c) return '';
    const map = {
        max_retries_exceeded: 'Exceeded automatic retry limit',
        database_locked: 'Database was temporarily locked',
        dependency_missing: 'A required dependency was missing',
    };
    return map[c] || c;
}

function stScanHistDetailProgressHtml(j) {
    const phases = Array.isArray(j.phases) && j.phases.length ? esc(j.phases.join(', ')) : '\u2014';
    const scanned = j.hosts_scanned != null ? j.hosts_scanned : 0;
    const found = j.hosts_found != null ? j.hosts_found : 0;
    const st = String(j.status || '').toLowerCase();
    let err = '';
    const msg = j.error_msg != null && String(j.error_msg).trim() ? String(j.error_msg) : '';
    const fr = j.failure_reason != null && String(j.failure_reason).trim() ? String(j.failure_reason) : '';
    const frLabel = stScanHistFailureReasonLabel(fr);
    if ((st === 'failed' || st === 'aborted' || st === 'retrying') && (msg || fr)) {
        const bits = [];
        if (frLabel) bits.push(`<div class="text-micro text-dim mt2"><strong>Reason</strong> \u2014 ${esc(frLabel)}</div>`);
        if (msg) bits.push(`<div class="mt2"><strong>Message</strong> \u2014 ${esc(msg)}</div>`);
        err = `<div class="scan-hist-detail-callout scan-hist-detail-callout--err mt6"><strong>${st === 'retrying' ? 'Retry' : 'Issue'}</strong>${bits.join('')}</div>`;
    } else if (st === 'done' && msg) {
        err = `<div class="scan-hist-detail-callout scan-hist-detail-callout--warn mt6"><strong>Note</strong> \u2014 ${esc(msg)}</div>`;
    }
    let phaseBox = '';
    const pp = j.phase_status_parsed && typeof j.phase_status_parsed === 'object' ? j.phase_status_parsed : null;
    if (pp && Object.keys(pp).length) {
        const lines = Object.keys(pp).slice(0, 12).map((k) => {
            const v = pp[k];
            const vs = typeof v === 'object' ? JSON.stringify(v).slice(0, 120) : String(v);
            return `<div class="mono-sm text-dim">${esc(k)}: ${esc(vs)}</div>`;
        });
        phaseBox = `<div class="mt6 text-micro"><strong>Phase status</strong> (bounded)</div><div class="mt2">${lines.join('')}</div>`;
    }
    const trashed = j.deleted_at ? `<div class="text-micro text-dim mt4">Trashed ${esc(localTime(j.deleted_at))}</div>` : '';
    const batch = Number(j.batch_total || 0) > 1
        ? `<div class="text-micro text-dim mt4">Batch ${esc(String(j.batch_index || 0))} / ${esc(String(j.batch_total))}</div>`
        : '';
    const hints = Array.isArray(j.diagnostic_hints) ? j.diagnostic_hints : [];
    const hintBlock = hints.length
        ? `<div class="scan-hist-detail-callout mt6"><strong>Diagnostics</strong><ul class="mb0 mt4" style="padding-left:1.1rem">${hints.map((h) => `<li class="text-micro">${esc(String(h))}</li>`).join('')}</ul></div>`
        : '';
    return `<div class="scan-hist-detail-meta-grid text-micro">
      <div><span class="text-dim">Profile</span> <span class="text-primary">${esc(String((j.profile || '').replace(/_/g, ' ') || '\u2014'))}</span></div>
      <div><span class="text-dim">Mode</span> <span class="text-primary">${esc(String(j.scan_mode || '\u2014'))}</span></div>
      <div><span class="text-dim">Hosts scanned</span> <b>${esc(String(scanned))}</b> <span class="text-dim">/</span> <span class="text-dim">found</span> <b>${esc(String(found))}</b></div>
      <div><span class="text-dim">Steps run</span> <span class="mono-sm">${phases}</span></div>
    </div>${batch}${trashed}${err}${phaseBox}${hintBlock}`;
}

function stScanHistDetailHeaderSubHtml(j) {
    const chip = `<span class="${stScanHistChipClass(j.status)}">${esc(stScanHistChipLabel(j.status))}</span>`;
    const tgt = `<span class="mono-sm">${esc(j.target_cidr || '\u2014')}</span>`;
    let scopeLine = '';
    if (j.scope_id != null && Number(j.scope_id) > 0) {
        scopeLine = `<div class="scan-hist-detail-hd-row text-micro text-dim">Scope <span class="mono-sm">#${esc(String(j.scope_id))}</span></div>`;
    }
    const start = j.started_at ? esc(localTime(j.started_at)) : '\u2014';
    const fin = j.finished_at ? esc(localTime(j.finished_at)) : '\u2014';
    const times = `<div class="scan-hist-detail-hd-row text-micro"><span class="text-dim">Started</span> ${start} <span class="text-dim">\u00b7</span> <span class="text-dim">Finished</span> ${fin}</div>`;
    const ingest = stCollectorIngestState(j);
    const ingestLine = ingest
        ? `<div class="scan-hist-detail-hd-row text-micro ${ingest.level === 'ok' ? 'hstate-ok' : (ingest.level === 'err' ? 'hstate-err' : (ingest.level === 'warn' ? 'hstate-warn' : 'text-dim'))}"><span class="text-dim">Collector ingest</span> ${esc(String(ingest.label || ''))}${ingest.detail ? ` \u00b7 ${esc(String(ingest.detail))}` : ''}</div>`
        : '';
    return `<div class="scan-hist-detail-hd-id text-micro text-dim mono-sm">#${esc(String(j.id))}</div>
      <div class="scan-hist-detail-hd-chips">${chip}</div>
      <div class="scan-hist-detail-hd-row scan-hist-detail-hd-target"><span class="text-dim text-micro">Target</span> ${tgt}</div>
      ${scopeLine}
      ${ingestLine}
      ${times}`;
}

function stScanHistDetailLogHtml(j, logTail) {
    const lines = Array.isArray(logTail) ? logTail : [];
    const rows = lines.length
        ? lines.map((r) => {
            const ts = esc((r.ts || '').split(' ')[1] || r.ts || '');
            const lv = esc(String(r.level || ''));
            const ip = r.ip ? '<b>' + esc(String(r.ip)) + '</b> ' : '';
            const m = esc(String(r.message || ''));
            return `<tr><td class="mono font10 scan-hist-detail-log-ts">${ts}</td><td class="font10"><span class="scan-hist-detail-log-lv">${lv}</span></td><td class="font11 scan-hist-detail-log-msg">${ip}${m}</td></tr>`;
        }).join('')
        : `<tr><td colspan="3" class="loading scan-hist-empty">No log lines returned for this job.</td></tr>`;
    const rawBits = {
        phases: j.phases,
        profile: j.profile,
        scan_mode: j.scan_mode,
        error_msg: j.error_msg || null,
        failure_reason: j.failure_reason || null,
        phase_status: j.phase_status || null,
        collector_submission_status: j.collector_submission_status || null,
        collector_chunks_expected: Number(j.collector_chunks_expected || 0),
        collector_chunks_received: Number(j.collector_chunks_received || 0),
        collector_chunks_applied: Number(j.collector_chunks_applied || 0),
        collector_ingest_pending_count: Number(j.collector_ingest_pending_count || 0),
        collector_ingest_failed_count: Number(j.collector_ingest_failed_count || 0),
        collector_ingest_attempts: Number(j.collector_ingest_attempts || 0),
        collector_ingest_error: j.collector_ingest_error || null,
        collector_ingest_oldest_pending_at: j.collector_ingest_oldest_pending_at || null,
    };
    let rawPre = '';
    try {
        const rawStr = JSON.stringify(rawBits, null, 2);
        if (rawStr.length < 120000) {
            rawPre = '<details class="scan-hist-detail-disclosure inner-log-raw mt8"><summary class="scan-hist-detail-disclosure-sum text-micro">Raw job fields (JSON)</summary><pre class="scan-hist-detail-raw-pre" tabindex="0">' + esc(rawStr) + '</pre></details>';
        } else {
            rawPre = '<p class="hint-micro text-dim mt6">Raw job JSON omitted (too large for inline display).</p>';
        }
    } catch (_e) {
        rawPre = '';
    }
    return '<div class="tbl-wrap tbl-scan-hist"><table class="tbl scan-hist-detail-log-tbl"><thead><tr><th>Time</th><th>Lvl</th><th>Message</th></tr></thead><tbody>' + rows + '</tbody></table></div>' + rawPre;
}

async function openScanHistDetail(id, compareToId = 0, compareScope = 'any', triedAutoCompare = false) {
    const bg = document.getElementById('scan-hist-detail-bg');
    const title = document.getElementById('scan-hist-detail-title');
    const headerSub = document.getElementById('scan-hist-detail-header-sub');
    const stats = document.getElementById('scan-hist-detail-stats');
    const progress = document.getElementById('scan-hist-detail-progress');
    const sum = document.getElementById('scan-hist-detail-summary');
    const diff = document.getElementById('scan-hist-detail-diff');
    const diffWrap = document.getElementById('scan-hist-detail-diff-wrap');
    const tbody = document.getElementById('scan-hist-detail-assets');
    const logEl = document.getElementById('scan-hist-detail-log');
    if (!bg || !title || !headerSub || !stats || !progress || !sum || !diff || !tbody || !logEl) return;
    // Modal is declared near tab markup; ensure it is attached to body so it
    // can render even when its original tab container is hidden.
    if (bg.parentElement !== document.body) {
        document.body.appendChild(bg);
    }
    bg.style.display = 'flex';
    const sumDet = document.getElementById('scan-hist-detail-summary-details');
    if (sumDet) sumDet.open = false;
    const logDet = document.getElementById('scan-hist-detail-log-details');
    if (logDet) logDet.open = false;
    const rerunBtn = document.getElementById('scan-hist-detail-rerun');
    if (rerunBtn) { rerunBtn.style.display = 'none'; rerunBtn.dataset.jobId = ''; }
    const delBtn = document.getElementById('scan-hist-detail-delete');
    if (delBtn) { delBtn.style.display = 'none'; delBtn.dataset.jobId = ''; delBtn.dataset.action = 'trash'; }
    const hint0 = document.getElementById('scan-hist-detail-assets-hint');
    if (hint0) hint0.style.display = 'none';
    title.textContent = 'Loading…';
    headerSub.innerHTML = '';
    stats.innerHTML = '';
    progress.innerHTML = '';
    logEl.innerHTML = '';
    sum.innerHTML = '';
    diff.innerHTML = '';
    if (diffWrap) diffWrap.style.display = 'none';
    tbody.innerHTML = '<tr><td colspan="4" class="loading tbl-empty">Loading assets…</td></tr>';

    const cmpQ = compareToId > 0 ? '&compare_to=' + encodeURIComponent(String(compareToId)) : '';
    const scopeQ = '&compare_scope=' + encodeURIComponent(compareScope || 'any');
    const d = await api('/api/scan_history.php?id=' + encodeURIComponent(id) + cmpQ + scopeQ, {quiet:true});
    if (!d || !d.job) {
        title.textContent = 'Scan detail';
        headerSub.innerHTML = '<p class="text-dim">Could not load scan details.</p>';
        stats.innerHTML = '';
        progress.innerHTML = '';
        logEl.innerHTML = '';
        diff.innerHTML = '';
        if (diffWrap) diffWrap.style.display = 'none';
        tbody.innerHTML = '<tr><td colspan="4" class="loading tbl-empty">Could not load assets for this scan.</td></tr>';
        return;
    }

    const j = d.job;
    const isTrashed = !!j.deleted_at;
    const stNorm = String(j.status || '').toLowerCase();
    if (rerunBtn) {
        rerunBtn.dataset.jobId = String(j.id);
        const showRerun = stRoleCanManageScans() && !isTrashed && ['done', 'aborted', 'failed'].includes(stNorm);
        rerunBtn.style.display = showRerun ? '' : 'none';
    }
    if (delBtn) {
        delBtn.dataset.jobId = String(j.id);
        delBtn.dataset.action = isTrashed ? (stRoleIsAdmin() ? 'purge' : 'restore') : 'trash';
        delBtn.textContent = isTrashed ? (stRoleIsAdmin() ? 'Delete permanently' : 'Restore') : 'Move to trash';
        delBtn.style.color = isTrashed && stRoleIsAdmin() ? 'var(--red)' : '';
        delBtn.style.display = (stRoleCanManageScans() && ['done', 'aborted', 'failed'].includes(stNorm)) ? '' : 'none';
    }
    const aiRefBtn = document.getElementById('scan-hist-detail-refresh-ai');
    if (aiRefBtn) {
        aiRefBtn.dataset.jobId = String(j.id);
        aiRefBtn.style.display = (!isTrashed && stNorm === 'done' && stRoleCanManageScans()) ? '' : 'none';
    }
    const labelTrim = j.label != null && String(j.label).trim() ? String(j.label).trim() : '';
    title.textContent = labelTrim || ('Scan #' + j.id);
    headerSub.innerHTML = stScanHistDetailHeaderSubHtml(j);
    stats.innerHTML = stScanHistDetailStatCardsHtml(j);
    progress.innerHTML = stScanHistDetailProgressHtml(j);
    logEl.innerHTML = stScanHistDetailLogHtml(j, d.log_tail);
    renderCompareOptions(j.id, j, d.compare_options || [], compareToId, d.compare_scope || compareScope || 'any');
    sum.innerHTML = renderScanSummary(j.summary);
    const diffHtml = renderScanDiff(d.compare);
    diff.innerHTML = diffHtml;
    if (diffWrap) diffWrap.style.display = diffHtml.trim() !== '' ? '' : 'none';
    if (!d.compare && !triedAutoCompare) {
        const opts = Array.isArray(d.compare_options) ? d.compare_options : [];
        const auto = opts.find(o => Number(o.id) > 0);
        if (auto) {
            await openScanHistDetail(id, Number(auto.id), d.compare_scope || compareScope || 'any', true);
            return;
        }
    }

    const assets = Array.isArray(d.assets) ? d.assets : [];
    const hint = document.getElementById('scan-hist-detail-assets-hint');
    if (!assets.length) {
        if (hint) hint.style.display = 'none';
        tbody.innerHTML = '<tr><td colspan="4" class="loading tbl-empty scan-hist-empty">No assets available for this run. Older runs can be empty because inventory rows keep only the most recent <code class="code-accent">last_scan_id</code> per asset.</td></tr>';
        return;
    }
    if (hint) hint.style.display = 'block';
    tbody.innerHTML = assets.map((a) => {
        const ports = Array.isArray(a.open_ports) && a.open_ports.length
            ? a.open_ports.join(', ')
            : '—';
        const did = a.device_id != null && a.device_id !== '' ? parseInt(String(a.device_id), 10) : 0;
        const tip = did > 0 ? 'Open device #' + did : 'Open host at ' + (a.ip || '');
        const ipAttr = esc(String(a.ip || ''));
        const devAttr = did > 0 ? String(did) : 'null';
        const hn = esc(a.hostname || '—');
        return `<tr class="scan-hist-asset-row scan-hist-detail-asset-row" style="cursor:pointer" title="${esc(tip)}" data-asset-id="${a.id}" data-device-id="${devAttr}" data-ip="${ipAttr}">
          <td class="mono tbl-cell-mono scan-hist-detail-asset-ip tbl-cell-primary">${esc(a.ip || '')}</td>
          <td class="scan-hist-detail-asset-host tbl-cell-primary">${hn}</td>
          <td><span class="chip">${esc((a.category || 'unk').toUpperCase())}</span></td>
          <td class="mono tbl-cell-mono scan-hist-detail-asset-muted font11 tbl-cell-muted">${esc(ports)}</td>
        </tr>`;
    }).join('');
}

// ==========================================================================
// Audit log
// ==========================================================================
async function loadLog() {
    const d = await api('/api/scan_status.php?log_limit=200');
    if (!d) return;
    allLogRows = d.log || [];
    if (d.log && d.log.length) logSinceId = d.log[d.log.length-1].id;
    renderLog();
}

function appendLogRows(rows) {
    allLogRows = allLogRows.concat(rows);
    if (allLogRows.length > 2000) allLogRows = allLogRows.slice(-2000);
    renderLog();
}

function renderLog() {
    filterLog();
}

function filterLog() {
    const q   = (document.getElementById('lf-q')?.value || '').toLowerCase();
    const lvl = document.getElementById('lf-level')?.value || '';
    const filtered = allLogRows.filter(r =>
        (!lvl || r.level === lvl) &&
        (!q   || (r.message||'').toLowerCase().includes(q) || (r.ip||'').includes(q))
    );
    const wrap = document.getElementById('log-wrap');
    wrap.innerHTML = filtered.map(r => {
      const lvlCls = r.level === 'ERR' ? 'st-audit-row--err' : (r.level === 'WARN' ? 'st-audit-row--warn' : '');
      return `<div class="lr ${lvlCls}">
      <span class="lts">${(r.ts||'').split(' ')[1]||r.ts||''}</span>
      <span class="llv ${r.level}">${r.level}</span>
      <span class="lm">${r.ip ? '<b>'+esc(r.ip)+'</b> ' : ''}${esc(r.message||'')}</span>
    </div>`;
    }).join('') || '<div class="loading st-audit-empty">No log entries match current filters</div>';
    if (autoscroll) wrap.scrollTop = wrap.scrollHeight;
}

function toggleAutoscroll() {
    autoscroll = !autoscroll;
    document.getElementById('btn-autoscroll').textContent = 'Auto-scroll: ' + (autoscroll ? 'ON' : 'OFF');
}

// ==========================================================================
// Status pill
// ==========================================================================
function setStatusPill(state, text) {
    const pill = document.getElementById('status-pill');
    if (!pill) return;
    const scanning = state === 'run';
    pill.className = 'pill' + (scanning ? ' run' : state === 'err' ? ' err' : '') + (scanning ? ' pill--to-scan-hist' : '');
    document.getElementById('status-txt').textContent = text;
    document.getElementById('logodot').classList.toggle('active', scanning);
    pill.disabled = !scanning;
    pill.setAttribute('aria-disabled', scanning ? 'false' : 'true');
    if (scanning) pill.setAttribute('aria-label', 'View scan history');
    else pill.removeAttribute('aria-label');
}

/** When the header pill shows an active scan, navigate to Scan history (all roles that can open the tab). */
function stStatusPillNavToHistory() {
    const pill = document.getElementById('status-pill');
    if (!pill || pill.disabled) return;
    goTab('scanhist');
    hiNav('nscanhist');
}

function updateStatusPill(lastScan) {
    if (lastScan && (lastScan.status === 'running' || lastScan.status === 'queued')) {
        setStatusPill('run', 'Scanning…');
        if (!pollTimer && lastScan.id) startPoll(lastScan.id);
    } else {
        setStatusPill('idle', 'Idle');
    }
}

// ==========================================================================
// Helpers
// ==========================================================================
// SECURITY: Many code paths assign API-derived strings via innerHTML. Any interpolated text MUST go through esc().
// WARNING: innerHTML requires escaped content; use textContent when HTML structure is not required.
function esc(s) {
    if (s === null || s === undefined) return '';
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function enc(s) { return encodeURIComponent(s || ''); }

function sevClass(cvss) {
    const v = parseFloat(cvss);
    if (isNaN(v) || v === 0) return 'none';
    if (v >= 9) return 'critical';
    if (v >= 7) return 'high';
    if (v >= 4) return 'medium';
    return 'low';
}

function relTime(ts) {
    if (!ts) return '—';
    // SQLite stores UTC without 'Z' suffix — add it so JS parses correctly
    const normalized = ts.includes('T') ? ts : ts.replace(' ', 'T') + 'Z';
    const secs = Math.floor((Date.now() - new Date(normalized)) / 1000);
    if (secs < 0)      return 'just now';
    if (secs < 120)    return secs + 's ago';
    if (secs < 3600)   return Math.floor(secs/60) + 'm ago';
    if (secs < 86400)  return Math.floor(secs/3600) + 'h ago';
    return Math.floor(secs/86400) + 'd ago';
}

function localTime(ts, opts) {
    // Convert a UTC DB timestamp to the user's local time for display
    if (!ts) return '—';
    const normalized = ts.includes('T') ? ts : ts.replace(' ', 'T') + 'Z';
    const d = new Date(normalized);
    if (isNaN(d)) return ts;
    return d.toLocaleString([], opts || {
        month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
    });
}

function localDate(ts) {
    // Date only, no time
    if (!ts) return '—';
    const normalized = ts.includes('T') ? ts : ts.replace(' ', 'T') + 'Z';
    const d = new Date(normalized);
    if (isNaN(d)) return ts;
    return d.toLocaleDateString([], {year:'numeric', month:'short', day:'numeric'});
}

function fmtDuration(secs) {
    if (!secs) return '—';
    if (secs < 60)   return secs + 's';
    if (secs < 3600) return Math.floor(secs/60) + 'm ' + (secs%60) + 's';
    return Math.floor(secs/3600) + 'h ' + Math.floor((secs%3600)/60) + 'm';
}

function stFmtUtcTs(ts) {
    if (!ts) return '—';
    const s = String(ts);
    const normalized = s.includes('T') ? s : (s.replace(' ', 'T') + 'Z');
    const d = new Date(normalized);
    if (isNaN(d)) return s;
    return d.toLocaleString([], { year:'numeric', month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' });
}

/** Wall duration from API `duration_ms` (cred runs, etc.). */
function stFmtDurationMs(ms) {
    const n = ms != null ? parseInt(String(ms), 10) : NaN;
    if (!Number.isFinite(n) || n < 0) return '—';
    if (n < 1000) return n + 'ms';
    if (n < 60000) return (n / 1000).toFixed(1) + 's';
    const m = Math.floor(n / 60000);
    const s = Math.round((n % 60000) / 1000);
    return m + 'm ' + s + 's';
}

/** Clipboard API when allowed; else textarea + execCommand (HTTP, Safari, some modal contexts). */
async function stCopyTextToClipboard(text) {
    const t = String(text || '');
    if (!t) return false;
    try {
        if (navigator.clipboard && window.isSecureContext) {
            await navigator.clipboard.writeText(t);
            return true;
        }
    } catch (_) { /* fall through */ }
    try {
        const ta = document.createElement('textarea');
        ta.value = t;
        ta.setAttribute('readonly', '');
        ta.setAttribute('aria-hidden', 'true');
        ta.style.cssText = 'position:fixed;top:0;left:0;width:1px;height:1px;padding:0;margin:0;border:none;opacity:0;pointer-events:none;';
        document.body.appendChild(ta);
        ta.focus();
        ta.select();
        ta.setSelectionRange(0, t.length);
        const ok = document.execCommand('copy');
        document.body.removeChild(ta);
        return ok;
    } catch (_) {
        return false;
    }
}

function toast(msg, type) {
    const w = document.getElementById('toasts');
    const d = document.createElement('div');
    d.className = 'toast ' + (type || 'ok');
    d.textContent = msg;
    w.appendChild(d);
    setTimeout(() => d.remove(), 4000);
}

function showConfirmModal(message, opts) {
    const o = opts || {};
    const bg = document.getElementById('confirm-bg');
    const titleEl = document.getElementById('confirm-title');
    const msgEl = document.getElementById('confirm-msg');
    const okBtn = document.getElementById('confirm-ok-btn');
    const cancelBtn = document.getElementById('confirm-cancel-btn');
    if (!bg || !titleEl || !msgEl || !okBtn || !cancelBtn) return Promise.resolve(false);
    if (confirmResolve) {
        try { confirmResolve(false); } catch (e) {}
        confirmResolve = null;
    }
    titleEl.textContent = o.title || 'Confirm action';
    msgEl.textContent = String(message || '');
    okBtn.textContent = o.okText || 'Confirm';
    cancelBtn.textContent = o.cancelText || 'Cancel';
    bg.style.display = 'flex';
    return new Promise(resolve => {
        confirmResolve = resolve;
    });
}

function closeConfirmModal(accepted) {
    const bg = document.getElementById('confirm-bg');
    if (bg) bg.style.display = 'none';
    if (confirmResolve) {
        const r = confirmResolve;
        confirmResolve = null;
        r(!!accepted);
    }
}

/**
 * App-styled prompt (replaces window.prompt for normal UI).
 * @param {string} message
 * @param {{title?: string, label?: string, defaultValue?: string, okText?: string, cancelText?: string, placeholder?: string, inputMode?: string}} [opts]
 * @returns {Promise<string|null>}
 */
function showPromptModal(message, opts) {
    const o = opts || {};
    const bg = document.getElementById('st-prompt-bg');
    const titleEl = document.getElementById('st-prompt-title');
    const msgEl = document.getElementById('st-prompt-msg');
    const labEl = document.getElementById('st-prompt-input-label');
    const inp = document.getElementById('st-prompt-input');
    const okBtn = document.getElementById('st-prompt-ok-btn');
    const cancelBtn = document.getElementById('st-prompt-cancel-btn');
    if (!bg || !titleEl || !msgEl || !labEl || !inp || !okBtn || !cancelBtn) return Promise.resolve(null);
    if (promptResolve) {
        try { promptResolve(null); } catch (e) {}
        promptResolve = null;
    }
    titleEl.textContent = o.title || 'Enter value';
    msgEl.textContent = String(message || '');
    labEl.textContent = o.label || 'Value';
    inp.value = o.defaultValue != null ? String(o.defaultValue) : '';
    inp.placeholder = o.placeholder || '';
    inp.type = o.inputType || 'text';
    if (inp.type === 'number') {
        if (o.inputMin != null) inp.min = String(o.inputMin);
        else inp.removeAttribute('min');
        if (o.inputMax != null) inp.max = String(o.inputMax);
        else inp.removeAttribute('max');
    } else {
        inp.removeAttribute('min');
        inp.removeAttribute('max');
    }
    okBtn.textContent = o.okText || 'OK';
    cancelBtn.textContent = o.cancelText || 'Cancel';
    bg.style.display = 'flex';
    requestAnimationFrame(() => {
        inp.focus();
        try { inp.select(); } catch (e) {}
    });
    return new Promise((resolve) => {
        promptResolve = resolve;
    });
}

function closeStPromptModal(accepted) {
    const bg = document.getElementById('st-prompt-bg');
    const inp = document.getElementById('st-prompt-input');
    if (bg) bg.style.display = 'none';
    if (!promptResolve) return;
    const r = promptResolve;
    promptResolve = null;
    r(accepted ? String(inp && inp.value != null ? inp.value : '') : null);
}

/** @returns {Promise<string|null>} resolved value, or null if cancelled */
function openCollectorRangesModal(initialValue) {
    const bg = document.getElementById('collector-ranges-bg');
    const ta = document.getElementById('collector-ranges-input');
    if (!bg || !ta) return Promise.resolve(null);
    if (collectorRangesResolve) {
        try { collectorRangesResolve(null); } catch (e) {}
        collectorRangesResolve = null;
    }
    ta.value = String(initialValue || '');
    bg.style.display = 'flex';
    requestAnimationFrame(() => {
        ta.focus();
        try { ta.setSelectionRange(0, ta.value.length); } catch (e) {}
    });
    return new Promise(resolve => { collectorRangesResolve = resolve; });
}

function closeCollectorRangesModal(submit) {
    const bg = document.getElementById('collector-ranges-bg');
    const ta = document.getElementById('collector-ranges-input');
    if (bg) bg.style.display = 'none';
    if (!collectorRangesResolve) return;
    const r = collectorRangesResolve;
    collectorRangesResolve = null;
    r(submit && ta ? String(ta.value || '') : null);
}

function openCollectorInstallTokenRevealModal(token, opts) {
    const o = opts || {};
    const bg = document.getElementById('collector-install-token-reveal-bg');
    const ta = document.getElementById('collector-install-token-reveal-value');
    const titleEl = document.getElementById('collector-install-token-reveal-title');
    const hintEl = document.getElementById('collector-install-token-reveal-hint');
    if (!bg || !ta) return;
    if (titleEl) titleEl.textContent = o.title || 'Install token';
    if (hintEl) {
        hintEl.textContent = o.hint || (
            'Copy this token now and keep it somewhere safe. Closing clears it from the page; SurveyTrace does not show the install token again—use Generate install token again if you need a new one.'
        );
    }
    ta.value = String(token || '');
    bg.style.display = 'flex';
    requestAnimationFrame(() => {
        ta.focus();
        try { ta.setSelectionRange(0, ta.value.length); } catch (e) {}
    });
}

function closeCollectorInstallTokenRevealModal() {
    const bg = document.getElementById('collector-install-token-reveal-bg');
    const ta = document.getElementById('collector-install-token-reveal-value');
    const hintEl = document.getElementById('collector-install-token-reveal-hint');
    if (ta) ta.value = '';
    if (hintEl) hintEl.textContent = '';
    if (bg) bg.style.display = 'none';
}

async function copyCollectorInstallTokenReveal() {
    const ta = document.getElementById('collector-install-token-reveal-value');
    const token = String(ta && ta.value ? ta.value : '').trim();
    if (!token) {
        toast('Nothing to copy', 'err');
        return;
    }
    if (await stCopyTextToClipboard(token)) toast('Copied to clipboard', 'ok');
    else toast('Copy failed — select the text and copy manually', 'err');
}

document.getElementById('collector-ranges-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closeCollectorRangesModal(false);
});
document.getElementById('profile-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closeProfileModal();
});
document.getElementById('mfa-disable-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closeMfaDisableModal();
});
document.getElementById('pw-change-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closePasswordChangeModal();
});
document.getElementById('user-pw-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closeUserPasswordModal();
});
document.getElementById('ai-install-help-bg')?.addEventListener('click', function(e) {
    if (e.target === this) closeAiInstallHelpModal();
});

