    const aiConfThresholdNetSrv = document.getElementById('st-ai-conf-threshold-netsrv');
    if (aiConfThresholdNetSrv) aiConfThresholdNetSrv.value = String(Math.max(0.5, Math.min(0.99, Number(d.ai_conf_threshold_net_srv || 0.82))));
    const aiRuntime = d.ai_runtime || {};
    const aiRtEl = document.getElementById('st-ai-runtime-status');
    if (aiRtEl) {
        const ver = aiRuntime.version ? String(aiRuntime.version) : 'n/a';
        aiRtEl.textContent = `Runtime: installed=${!!aiRuntime.installed} · running=${!!aiRuntime.running} · version=${ver}`;
    }
    const aiModelsEl = document.getElementById('st-ai-models-status');
    if (aiModelsEl) {
        const models = Array.isArray(aiRuntime.models) ? aiRuntime.models : [];
        const rec = String(aiRuntime.compact_recommended_model || 'phi3:mini');
        aiModelsEl.textContent = `Models: ${models.length ? models.join(', ') : 'none installed'} · compact recommended: ${rec}`;
    }
    const updEl = document.getElementById('st-ai-update-status');
    if (updEl) {
        const upd = aiRuntime.update || {};
        const mupd = aiRuntime.model_update || {};
        if (!aiRuntime.installed) {
            updEl.classList.add('hide');
            updEl.innerHTML = '';
        } else if (upd && upd.known) {
            if (upd.update_available) {
                updEl.classList.remove('hide');
                updEl.innerHTML = `Update available: local <code class="code-accent">${esc(String(upd.local_version || ''))}</code> → latest <code class="code-accent">${esc(String(upd.latest_version || ''))}</code>. Run on server shell: <code class="code-accent" id="st-ai-update-cmd">${esc(String(upd.shell_update_command || ''))}</code> <button type="button" class="tbtn btn-xs" onclick="copyAiUpdateCommand()">Copy update command</button>`;
            } else {
                updEl.classList.remove('hide');
                updEl.textContent = `Ollama is up to date (version ${String(upd.local_version || 'unknown')}).`;
            }
        } else {
            updEl.classList.remove('hide');
            updEl.textContent = 'Could not determine Ollama update status right now.';
        }
        if (mupd && (mupd.configured_model || aiRuntime.installed)) {
            const modelName = String(mupd.configured_model || document.getElementById('st-ai-model')?.value || 'phi3:mini');
            const modelCmd = String(mupd.shell_update_command || '');
            const modelDetail = String(mupd.detail || '');
            const modelLine = `<br>Model check (${esc(modelName)}): ${mupd.installed ? 'installed' : 'missing'}${modelDetail ? ` — ${esc(modelDetail)}` : ''}${modelCmd ? `. Refresh command: <code class="code-accent" id="st-ai-model-update-cmd">${esc(modelCmd)}</code> <button type="button" class="tbtn btn-xs" onclick="copyAiModelUpdateCommand()">Copy model command</button>` : ''}`;
            updEl.innerHTML = (updEl.innerHTML || esc(updEl.textContent || '')) + modelLine;
        }
    }
    const installHint = document.getElementById('st-ai-install-hint');
    if (installHint) {
        if (aiRuntime.installed) installHint.classList.add('hide');
        else installHint.classList.remove('hide');
    }
    const installBtn = document.getElementById('btn-ai-install-ollama');
    if (installBtn) installBtn.style.display = aiRuntime.installed ? 'none' : '';
    syncAiProviderUi();
    updateScanHistoryViewButtons();
    await loadCollectorsOverview();
    await loadAuthUsers();
    updateMfaActionButtons();
}

function openAiInstallHelpModal() {
    const bg = document.getElementById('ai-install-help-bg');
    if (!bg) return;
    bg.style.display = 'flex';
}

function closeAiInstallHelpModal() {
    const bg = document.getElementById('ai-install-help-bg');
    if (!bg) return;
    bg.style.display = 'none';
}

async function copyAiInstallHelp() {
    const el = document.getElementById('ai-install-help-text');
    if (!el) return;
    const txt = el.textContent || '';
    if (await stCopyTextToClipboard(txt)) toast('Commands copied', 'ok');
    else toast('Could not copy commands', 'err');
}

window.__stCredPfAssetPick = window.__stCredPfAssetPick || [];
window.__stCcJobAssetPick = window.__stCcJobAssetPick || [];

function stCredNormalizeEncryptionStatus(encRaw) {
    const src = encRaw && typeof encRaw === 'object' && !Array.isArray(encRaw) ? { ...encRaw } : {};
    const availRaw = src.available;
    const available = availRaw === true || availRaw === 1 || availRaw === '1' || String(availRaw).toLowerCase() === 'true';
    const preferredAlg = src.preferred_alg || src.preferredAlg || src.alg || '';
    src.available = !!available;
    src.preferred_alg = String(preferredAlg || '');
    return src;
}

function stCredEncryptionAvailable() {
    const enc = stCredNormalizeEncryptionStatus(window.__stCredEncryption || {});
    return !!enc.available;
}

async function stCredRefreshEncryptionFromServer() {
    const prevOk =
        window.__stCredEncryption &&
        typeof window.__stCredEncryption === 'object' &&
        !Array.isArray(window.__stCredEncryption)
            ? stCredNormalizeEncryptionStatus(window.__stCredEncryption)
            : null;
    let r = null;
    try {
        r = await api('/api/credential_profiles.php', { quiet: true });
    } catch (e) {
        r = null;
    }
    if (r && r.ok && r.encryption && typeof r.encryption === 'object' && !Array.isArray(r.encryption)) {
        window.__stCredEncryption = stCredNormalizeEncryptionStatus(r.encryption);
        return true;
    }
    if (!window.__stCredEncryption || typeof window.__stCredEncryption !== 'object' || Array.isArray(window.__stCredEncryption)) {
        window.__stCredEncryption = prevOk || {};
    }
    return false;
}

function stCredProfileSavedId() {
    const hid = document.getElementById('st-cred-pf-id');
    const n = hid && hid.value ? parseInt(String(hid.value), 10) : 0;
    return !Number.isNaN(n) && n > 0 ? n : 0;
}

function stCredProfileCurrentId() {
    return stCredProfileSavedId();
}

function stCredProfileBuildUiState(p) {
    const tr = document.getElementById('st-cred-pf-transport');
    const hostEl = document.getElementById('st-cred-pf-test-host');
    const t = tr ? String(tr.value || 'ssh') : 'ssh';
    const host = hostEl ? String(hostEl.value || '').trim() : '';
    const profile = stCredProfileNormalizeProfilePayload(p || window.__stCredProfileModalPayload || null);
    const editId = (() => {
        const fromHidden = stCredProfileSavedId();
        const fromProfile = profile && profile.id ? Number(profile.id) : 0;
        return fromHidden > 0 ? fromHidden : (!Number.isNaN(fromProfile) && fromProfile > 0 ? fromProfile : 0);
    })();
    const encryptionAvailable = stCredEncryptionAvailable();
    const hasStoredSecret = stCredProfileHasStoredSecret(profile);
    const secretPeek = stCredProfilePeekSecretMaterialOk();
    const hs = window.__stCredHandshakeResult;
    const testingHandshake = !!(hs && hs.phase === 'testing');
    const supportsHandshake = t !== 'winrm';
    const canSetSecret = !!(editId >= 1 && encryptionAvailable && secretPeek.ok);
    const canClearSecret = !!(editId >= 1 && encryptionAvailable && hasStoredSecret);
    const canRunTest = !!(editId >= 1 && encryptionAvailable && hasStoredSecret && host !== '' && supportsHandshake && !testingHandshake);
    let testReason = 'Ready to test.';
    if (editId < 1) testReason = 'Save profile first.';
    else if (!encryptionAvailable) testReason = 'Credential encryption is not configured.';
    else if (!hasStoredSecret) testReason = 'Store a secret first.';
    else if (host === '') testReason = 'Enter a target host.';
    else if (!supportsHandshake) testReason = 'Transport does not support handshake tests.';
    else if (testingHandshake) testReason = 'Testing...';
    return {
        profile,
        transport: t,
        editId,
        host,
        hostOk: host !== '',
        encryptionAvailable,
        hasStoredSecret,
        supportsHandshake,
        secretPeek,
        testingHandshake,
        canSetSecret,
        canClearSecret,
        canRunTest,
        testReason,
    };
}

function stCredProfileReadinessLine(st) {
    const yesNo = (v) => (v ? 'yes' : 'no');
    return [
        'Test readiness:',
        'profile id ' + yesNo(st.editId >= 1),
        'encryption ' + yesNo(st.encryptionAvailable),
        'stored secret ' + yesNo(st.hasStoredSecret),
        'target host ' + yesNo(st.hostOk),
        'transport supported ' + yesNo(st.supportsHandshake),
        'currently testing ' + yesNo(st.testingHandshake),
        'reason: ' + st.testReason,
    ].join(' | ');
}

window.stCredProfileDebugState = function stCredProfileDebugState() {
    const st = stCredProfileBuildUiState(window.__stCredProfileModalPayload || null);
    return {
        currentProfileId: st.editId,
        transport: st.transport,
        encryptionAvailable: st.encryptionAvailable,
        hasSecret: st.hasStoredSecret,
        targetHost: st.host,
        supported: st.supportsHandshake,
        currentlyTesting: st.testingHandshake,
        canSetSecret: st.canSetSecret,
        canClearSecret: st.canClearSecret,
        canRunTest: st.canRunTest,
        reason: st.testReason,
    };
};

/** @returns {{ ok: boolean, reason: string }} */
function stCredProfilePeekSecretMaterialOk() {
    const got = stCredProfileCollectSecretMaterial();
    if (got.error) return { ok: false, reason: String(got.error) };
    if (got.material && typeof got.material === 'object' && Object.keys(got.material).length > 0) return { ok: true, reason: '' };
    return { ok: false, reason: 'Enter a password or private key.' };
}

function stCredProfileOnSecretInputsChanged() {
    stCredProfileSyncSecretPanel(window.__stCredProfileModalPayload || null);
    stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload || null);
}

async function stCredAssetsQuickSearch(qRaw, limit) {
    const q = String(qRaw || '').trim();
    if (!q) return { rows: [], err: 'empty' };
    if (q.length < 2 && !/^\d+$/.test(q)) return { rows: [], err: 'short' };
    const lim = Math.max(1, Math.min(50, parseInt(String(limit || 20), 10) || 20));
    const url = '/api/assets.php?q=' + encodeURIComponent(q) + '&per_page=' + encodeURIComponent(String(lim)) + '&page=1';
    let r = null;
    try {
        const resp = await fetch(url, { credentials: 'same-origin' });
        if (!resp.ok) {
            if (resp.status === 401) handleAuthRequired();
            return { rows: [], err: 'http', message: 'Inventory search unavailable (HTTP ' + resp.status + ').' };
        }
        r = await resp.json();
    } catch (e) {
        return { rows: [], err: 'network', message: 'Could not reach inventory search (sign in or check network).' };
    }
    if (!r || r.ok === false) {
        return { rows: [], err: 'http', message: (r && r.error) ? String(r.error) : 'Inventory search unavailable.' };
    }
    const rows = (Array.isArray(r.assets) ? r.assets : []).map((a) => ({
        id: Number(a && a.id),
        hostname: a && a.hostname ? String(a.hostname) : '',
        ip: a && a.ip ? String(a.ip) : '',
        category: a && a.category ? String(a.category) : '',
        scope_name: a && a.scope_name ? String(a.scope_name) : '',
        label: (a && a.hostname ? String(a.hostname) : '—') + ' (' + (a && a.ip ? String(a.ip) : '—') + ') [' + String((a && a.id) || '') + ']',
    })).filter((a) => Number.isFinite(a.id) && a.id > 0);
    return { rows, err: null };
}

function stCredAssetSearchResultRowHtml(a, onclickName) {
    const id = Number(a.id);
    const ip = esc(String(a.ip || ''));
    const hn = esc(String(a.hostname || '').trim() || '—');
    const cat = a.category ? esc(String(a.category)) : '';
    const sc = a.scope_name ? esc(String(a.scope_name)) : '';
    const dev = a.device_id != null && String(a.device_id) !== '' ? `<span class="text-dim mono-sm">dev ${esc(String(a.device_id))}</span>` : '';
    const meta = [cat, sc].filter(Boolean).join(' · ');
    const metaHtml = meta ? `<span class="text-dim hint-micro">${meta}</span>` : '';
    return `<div class="st-cred-asset-hit row-wrap gap8 align-center mb6" style="flex-wrap:wrap">
      <div style="flex:1;min-width:140px">
        <div class="mono-sm">${hn}</div>
        <div class="hint-micro text-dim">IP ${ip || '—'} · id ${esc(String(id))}</div>
        ${metaHtml ? `<div class="mt2">${metaHtml}</div>` : ''}
      </div>
      <div class="row-wrap gap4 align-center">${dev}<button type="button" class="tbtn btn-xs" onclick="${onclickName}(${id})">Add</button></div>
    </div>`;
}

function stCredProfileHasStoredSecret(p) {
    if (!p || typeof p !== 'object') return false;
    if (p.has_secret === true || p.has_secret === 1) return true;
    if (String(p.secret_status || '').toLowerCase() === 'stored') return true;
    if (p.secret_envelope && typeof p.secret_envelope === 'object' && p.secret_envelope.stored === true) return true;
    return false;
}

function stCredProfileNormalizeProfilePayload(p) {
    if (!p || typeof p !== 'object') return p;
    const out = { ...p };
    out.has_secret = stCredProfileHasStoredSecret(out);
    return out;
}

async function stCredEnsureScopesCatalog() {
    if (window.__stCredScopesCatalogLoaded) return;
    let r = null;
    try {
        r = await api('/api/scopes.php', { quiet: true });
    } catch (e) {
        r = null;
    }
    if (r && r.ok && Array.isArray(r.scopes)) {
        window.__stCredScopesCatalog = r.scopes;
    } else {
        window.__stCredScopesCatalog = [];
    }
    window.__stCredScopesCatalogLoaded = true;
}

function stCredPfFillScopeMultiselect(selEl, selectedIds) {
    const scopes = Array.isArray(window.__stCredScopesCatalog) ? window.__stCredScopesCatalog : [];
    const want = new Set((selectedIds || []).map((x) => Number(x)).filter((n) => n > 0));
    if (!selEl) return;
    selEl.innerHTML = scopes
        .map((s) => {
            const id = Number(s.id);
            const sel = want.has(id) ? ' selected' : '';
            return `<option value="${id}"${sel}>${esc(String(s.name || ''))}</option>`;
        })
        .join('');
}

function stCredPfParseTags(raw) {
    return String(raw || '')
        .split(/[,;\n]+/)
        .map((s) => s.trim())
        .filter(Boolean);
}

function stCredPrincipalExtraKeys(transport, full) {
    const extra = { ...(full || {}) };
    const t = String(transport || 'ssh');
    if (t === 'ssh') {
        delete extra.username;
        delete extra.notes;
        delete extra.realm;
    } else if (t === 'snmpv3') {
        ['securityName', 'security_name', 'username', 'authProtocol', 'auth_protocol', 'privProtocol', 'priv_protocol', 'securityLevel', 'security_level'].forEach((k) => {
            delete extra[k];
        });
    } else if (t === 'winrm') {
        delete extra.username;
        delete extra.domain;
    }
    return extra;
}

function stCredScopeExtraKeys(sj) {
    const extra = { ...(sj || {}) };
    delete extra.scope_ids;
    delete extra.asset_ids;
    delete extra.tags;
    return extra;
}

function stCredPfSnmpOnLevelChange() {
    const lvlEl = document.getElementById('st-cred-pf-snmp-security-level');
    const row = document.getElementById('st-cred-pf-snmp-priv-row');
    const secPriv = document.getElementById('st-cred-pf-snmpv3-priv-secret-row');
    const privInp = document.getElementById('st-cred-pf-snmpv3-priv');
    if (!lvlEl) return;
    const v = String(lvlEl.value || 'authPriv');
    const hidePriv = v === 'authNoPriv';
    if (row) row.classList.toggle('hide', hidePriv);
    if (secPriv) secPriv.classList.toggle('hide', hidePriv);
    if (hidePriv && privInp) privInp.value = '';
}

function stCredProfileUpdatePrincipalStructVisibility() {
    const tr = document.getElementById('st-cred-pf-transport');
    const t = tr ? String(tr.value || 'ssh') : 'ssh';
    const ssh = document.getElementById('st-cred-pf-principal-ssh');
    const snmp = document.getElementById('st-cred-pf-principal-snmp');
    const wrm = document.getElementById('st-cred-pf-principal-winrm');
    if (ssh) ssh.classList.toggle('hide', t !== 'ssh');
    if (snmp) snmp.classList.toggle('hide', t !== 'snmpv3');
    if (wrm) wrm.classList.toggle('hide', t !== 'winrm');
    if (t === 'snmpv3') stCredPfSnmpOnLevelChange();
}

function stCredProfileOnStructuredFieldChange() {}

function stCredPfApplyPrincipalToUi(pjRaw, transport) {
    const pj = pjRaw && typeof pjRaw === 'object' ? pjRaw : {};
    const t = String(transport || 'ssh');
    const advEl = document.getElementById('st-cred-pf-principal-adv');
    const extra = stCredPrincipalExtraKeys(t, pj);
    if (advEl) {
        try {
            advEl.value = Object.keys(extra).length ? JSON.stringify(extra, null, 2) : '';
        } catch (e) {
            advEl.value = '{}';
        }
    }
    if (t === 'ssh') {
        const u = document.getElementById('st-cred-pf-ssh-user');
        const n = document.getElementById('st-cred-pf-ssh-notes');
        if (u) u.value = String(pj.username || '').trim();
        if (n) n.value = String(pj.notes || pj.realm || '').trim();
    } else if (t === 'snmpv3') {
        const sn = document.getElementById('st-cred-pf-snmp-security-name');
        const sl = document.getElementById('st-cred-pf-snmp-security-level');
        const ap = document.getElementById('st-cred-pf-snmp-auth-proto');
        const pp = document.getElementById('st-cred-pf-snmp-priv-proto');
        if (sn) sn.value = String(pj.securityName || pj.security_name || pj.username || '').trim();
        const rawSl = String(pj.securityLevel || pj.security_level || 'authPriv').toLowerCase();
        if (sl) sl.value = rawSl.indexOf('nopriv') >= 0 ? 'authNoPriv' : 'authPriv';
        const apv = String(pj.authProtocol || pj.auth_protocol || 'SHA').toUpperCase();
        if (ap) ap.value = apv === 'MD5' ? 'MD5' : 'SHA';
        const ppv = String(pj.privProtocol || pj.priv_protocol || 'AES').toUpperCase();
        if (pp) pp.value = ppv === 'DES' ? 'DES' : 'AES';
        stCredPfSnmpOnLevelChange();
    } else if (t === 'winrm') {
        const u = document.getElementById('st-cred-pf-winrm-principal-user');
        const d = document.getElementById('st-cred-pf-winrm-domain');
        if (u) u.value = String(pj.username || '').trim();
        if (d) d.value = String(pj.domain || '').trim();
    }
}

function stCredPfCollectPrincipalObject(transport) {
    const t = String(transport || 'ssh');
    let base = {};
    if (t === 'ssh') {
        const u = (document.getElementById('st-cred-pf-ssh-user')?.value || '').trim();
        const notes = (document.getElementById('st-cred-pf-ssh-notes')?.value || '').trim();
        if (u) base.username = u;
        if (notes) base.notes = notes;
    } else if (t === 'snmpv3') {
        const sn = (document.getElementById('st-cred-pf-snmp-security-name')?.value || '').trim();
        const sl = document.getElementById('st-cred-pf-snmp-security-level')?.value || 'authPriv';
        const ap = document.getElementById('st-cred-pf-snmp-auth-proto')?.value || 'SHA';
        const pp = document.getElementById('st-cred-pf-snmp-priv-proto')?.value || 'AES';
        if (sn) base.securityName = sn;
        base.securityLevel = sl === 'authNoPriv' ? 'authNoPriv' : 'authPriv';
        base.authProtocol = ap;
        base.privProtocol = sl === 'authNoPriv' ? 'AES' : pp;
    } else if (t === 'winrm') {
        const u = (document.getElementById('st-cred-pf-winrm-principal-user')?.value || '').trim();
        const d = (document.getElementById('st-cred-pf-winrm-domain')?.value || '').trim();
        if (u) base.username = u;
        if (d) base.domain = d;
    }
    const advTa = document.getElementById('st-cred-pf-principal-adv');
    let adv = {};
    if (advTa && String(advTa.value || '').trim()) {
        try {
            const parsed = JSON.parse(String(advTa.value || '{}'));
            if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) adv = parsed;
            else throw new Error('not_object');
        } catch (e) {
            throw new Error('principal_adv_json');
        }
    }
    return { ...base, ...adv };
}

function stCredPfRenderAssetChips(containerId, pick, removeFnName) {
    const box = document.getElementById(containerId);
    if (!box) return;
    if (!pick.length) {
        box.innerHTML = '<span class="hint-micro text-dim">No assets selected.</span>';
        return;
    }
    box.innerHTML = pick
        .map((x) => {
            const id = Number(x.id);
            const lab = esc(String(x.label || '#' + id));
            return `<span class="row-wrap gap4 align-center" style="border:1px solid var(--border-subtle,#2a3340);border-radius:999px;padding:2px 8px;font-size:12px;display:inline-flex"><span class="mono-sm">${lab}</span><button type="button" class="tbtn btn-xs" onclick="${removeFnName}(${id})" aria-label="Remove asset">×</button></span>`;
        })
        .join('');
}

async function stCredPfHydratePickLabels(pick) {
    const need = pick.filter((x) => !x.label || String(x.label).indexOf('Asset #') === 0);
    await Promise.all(
        need.map(async (x) => {
            const id = Number(x.id);
            if (id < 1) return;
            let r = null;
            try {
                r = await api('/api/assets.php?id=' + encodeURIComponent(String(id)), { quiet: true });
            } catch (e1) {
                r = null;
            }
            const a = r && r.asset ? r.asset : null;
            if (a) {
                const ip = a.ip ? String(a.ip) : '';
                const hn = a.hostname ? String(a.hostname) : '';
                x.label = hn || ip ? `${hn || '—'} (${ip || '—'}) [${id}]` : `Asset ${id}`;
            }
        })
    );
}

async function stCredPfScopeAssetSearch() {
    const qEl = document.getElementById('st-cred-pf-scope-asset-q');
    const res = document.getElementById('st-cred-pf-scope-asset-results');
    if (!qEl || !res) return;
    const q = String(qEl.value || '').trim();
    res.innerHTML = '<span class="hint-micro text-dim">Searching…</span>';
    const { rows, err, message } = await stCredAssetsQuickSearch(q, 20);
    if (err === 'empty') {
        res.innerHTML = '<span class="hint-micro text-dim">Enter hostname, IP, MAC, or device id.</span>';
        return;
    }
    if (err === 'short') {
        res.innerHTML = '<span class="hint-micro text-dim">Enter at least 2 characters (or digits only for a short id).</span>';
        return;
    }
    if (err === 'network' || err === 'http') {
        res.innerHTML = '<span class="hint-micro text-dim">' + esc(message || 'Could not reach inventory search (sign in or check network).') + '</span>';
        return;
    }
    if (!rows.length) {
        res.innerHTML = '<span class="hint-micro text-dim">No matches — try another substring or use Advanced scope JSON.</span>';
        return;
    }
    res.innerHTML = rows.map((a) => stCredAssetSearchResultRowHtml(a, 'stCredPfAddAssetPick')).join('');
}

function stCredPfAddAssetPick(assetId) {
    const id = Number(assetId);
    if (id < 1) return;
    window.__stCredPfAssetPick = window.__stCredPfAssetPick || [];
    if (window.__stCredPfAssetPick.some((x) => Number(x.id) === id)) {
        toast('Asset already selected', 'ok');
        return;
    }
    window.__stCredPfAssetPick.push({ id, label: 'Asset #' + id });
    void stCredPfHydratePickLabels(window.__stCredPfAssetPick).then(() => {
        stCredPfRenderAssetChips('st-cred-pf-scope-asset-chips', window.__stCredPfAssetPick, 'stCredPfRemoveAssetPick');
    });
}

function stCredPfRemoveAssetPick(assetId) {
    const id = Number(assetId);
    window.__stCredPfAssetPick = (window.__stCredPfAssetPick || []).filter((x) => Number(x.id) !== id);
    stCredPfRenderAssetChips('st-cred-pf-scope-asset-chips', window.__stCredPfAssetPick, 'stCredPfRemoveAssetPick');
}

function stCredPfApplyScopeToUi(sjRaw) {
    const sj = sjRaw && typeof sjRaw === 'object' ? sjRaw : {};
    const ids = Array.isArray(sj.scope_ids) ? sj.scope_ids.map((x) => Number(x)).filter((n) => n > 0) : [];
    const sel = document.getElementById('st-cred-pf-scope-scope-ms');
    stCredPfFillScopeMultiselect(sel, ids);
    const tagsEl = document.getElementById('st-cred-pf-scope-tags');
    const tags = Array.isArray(sj.tags) ? sj.tags : [];
    if (tagsEl) tagsEl.value = tags.map((x) => String(x)).join(', ');
    window.__stCredPfAssetPick = [];
    const aids = Array.isArray(sj.asset_ids) ? sj.asset_ids.map((x) => Number(x)).filter((n) => n > 0) : [];
    aids.forEach((id) => window.__stCredPfAssetPick.push({ id, label: 'Asset #' + id }));
    void stCredPfHydratePickLabels(window.__stCredPfAssetPick).then(() => {
        stCredPfRenderAssetChips('st-cred-pf-scope-asset-chips', window.__stCredPfAssetPick, 'stCredPfRemoveAssetPick');
    });
    const extra = stCredScopeExtraKeys(sj);
    const advEl = document.getElementById('st-cred-pf-scope-adv');
    if (advEl) {
        try {
            advEl.value = Object.keys(extra).length ? JSON.stringify(extra, null, 2) : '';
        } catch (e) {
            advEl.value = '';
        }
    }
    const qEl = document.getElementById('st-cred-pf-scope-asset-q');
    const res = document.getElementById('st-cred-pf-scope-asset-results');
    if (qEl) qEl.value = '';
    if (res) res.innerHTML = '';
}

function stCredPfCollectScopeObject() {
    const sel = document.getElementById('st-cred-pf-scope-scope-ms');
    const scope_ids = sel ? Array.from(sel.selectedOptions || []).map((o) => parseInt(o.value, 10)).filter((n) => n > 0) : [];
    const tags = stCredPfParseTags(document.getElementById('st-cred-pf-scope-tags')?.value || '');
    const asset_ids = (window.__stCredPfAssetPick || []).map((x) => Number(x.id)).filter((n) => n > 0);
    let obj = { scope_ids, asset_ids, tags };
    const advTa = document.getElementById('st-cred-pf-scope-adv');
    if (advTa && String(advTa.value || '').trim()) {
        try {
            const parsed = JSON.parse(String(advTa.value || '{}'));
            if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
                obj = { ...obj, ...parsed };
            } else throw new Error('bad');
        } catch (e) {
            throw new Error('scope_adv_json');
        }
    }
    return obj;
}

function stCredProfileSyncNextSteps(p) {
    const wrap = document.getElementById('st-cred-pf-next-steps');
    const btn = document.getElementById('st-cred-pf-btn-create-job');
    if (!wrap) return;
    const ok = !!(p && p.id && stCredProfileHasStoredSecret(p) && stCredEncryptionAvailable());
    wrap.classList.toggle('hide', !ok);
    if (btn) {
        btn.dataset.profileId = p && p.id ? String(p.id) : '';
        btn.disabled = !ok;
    }
}

function stCredProfileCreateJobFromModal() {
    const btn = document.getElementById('st-cred-pf-btn-create-job');
    const raw = btn && btn.dataset.profileId ? parseInt(btn.dataset.profileId, 10) : 0;
    if (raw < 1) return;
    stCredProfileCloseModal();
    void stCcJobOpenModal(null, raw);
}

window.__stCredHandshakeResult = null;

function stCredHandshakeEffectivePort(transport, rawPort) {
    const pr = rawPort !== '' && rawPort != null ? parseInt(String(rawPort), 10) : 0;
    const p = !Number.isNaN(pr) && pr >= 0 ? pr : 0;
    const t = String(transport || 'ssh');
    if (p > 0) return p;
    return t === 'snmpv3' ? 161 : 22;
}

function stCredHandshakeSanitizeMessage(msg) {
    let s = String(msg || '').replace(/[\x00-\x08\x0b\x0c\x0e-\x1f]/g, ' ').replace(/\s+/g, ' ').trim();
    if (s.length > 220) s = s.slice(0, 217) + '…';
    return s;
}

function stCredHandshakeCodeHint(code) {
    const c = String(code || '').toLowerCase();
    const map = {
        auth_failed: 'Check username/password/private key.',
        timeout: 'Host did not respond before timeout; verify network/firewall.',
        network_unreachable: 'Verify address and routing.',
        host_key_mismatch: 'Host key changed or policy rejected the host.',
        dependency_missing:
            'App venv is missing Python packages for this transport. On the server: sudo -u surveytrace /opt/surveytrace/venv/bin/python3 -m pip install "paramiko>=3.0" "pysnmp>=4.4" (then retry the handshake).',
        encryption_unavailable: 'Credential encryption key is not available (check /etc/surveytrace/surveytrace.env and sudo helper).',
        decrypt_failed: 'Stored secret could not be decrypted; re-enter the secret.',
        invalid_profile: 'Fix principal/secret/profile configuration, then retry.',
        busy: 'Another test is already running on the server; wait a few seconds and retry.',
        unsupported_transport: 'This transport is not supported for handshake in this release.',
        protocol_error: 'Handshake failed at the protocol layer; check port, service, and server logs.',
        runner_error: 'Test runner crashed or misconfigured; see Result / Message for detail and server logs.',
        ok: '',
    };
    return map[c] || 'Review the error code and server/worker logs.';
}

function stCredHandshakeClearState() {
    window.__stCredHandshakeResult = null;
    stCredHandshakeRenderPanel();
}

function stCredHandshakeMarkStaleIfTargetChanged() {
    const st = window.__stCredHandshakeResult;
    if (!st || st.phase !== 'done') return;
    const tr = document.getElementById('st-cred-pf-transport');
    const t = tr ? String(tr.value || 'ssh') : 'ssh';
    const hostEl = document.getElementById('st-cred-pf-test-host');
    const portEl = document.getElementById('st-cred-pf-test-port');
    const host = hostEl ? String(hostEl.value || '').trim() : '';
    const pr = portEl && portEl.value !== '' ? parseInt(portEl.value, 10) : 0;
    const eff = stCredHandshakeEffectivePort(t, pr);
    const prevHost = String(st.targetHost || '').trim();
    const prevPort = Number(st.port);
    st.stale = host !== prevHost || eff !== prevPort;
    stCredHandshakeRenderPanel();
}

function stCredProfileOnTestTargetInput() {
    stCredHandshakeMarkStaleIfTargetChanged();
    stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload || null);
}

function stCredHandshakeRenderPanel() {
    const wrapPanel = document.getElementById('st-cred-pf-handshake-panel');
    const body = document.getElementById('st-cred-pf-handshake-panel-body');
    if (!wrapPanel || !body) return;
    const st = window.__stCredHandshakeResult;
    if (!st) {
        wrapPanel.className = 'st-cred-pf-handshake-panel st-cred-pf-handshake-panel--idle';
        body.className = 'hint-micro text-dim mb0';
        body.innerHTML =
            'Status: <strong>not run</strong>. Save the profile, set the secret, enter target host/port, then <strong>Run handshake test</strong>. Results stay here until you close the modal, run again, or change profile/secret.';
        return;
    }
    if (st.phase === 'testing') {
        wrapPanel.className = 'st-cred-pf-handshake-panel st-cred-pf-handshake-panel--testing';
        body.className = 'hint-micro mb0';
        body.innerHTML =
            '<p class="mb0"><strong>Testing…</strong> Contacting <span class="mono-sm">' +
            esc(String(st.targetHost || '')) +
            '</span> on port <span class="mono-sm">' +
            esc(String(st.port)) +
            '</span>.</p>';
        return;
    }
    const ok = !!st.success;
    wrapPanel.className =
        'st-cred-pf-handshake-panel ' + (ok ? 'st-cred-pf-handshake-panel--ok' : 'st-cred-pf-handshake-panel--bad');
    body.className = 'hint-micro mb0';
    const statusWord = ok ? 'success' : 'failed';
    const code = esc(String(st.code || '—'));
    const host = esc(String(st.targetHost || '—'));
    const port = esc(String(st.port != null ? st.port : '—'));
    const ts = st.atIso ? esc(localTime(st.atIso)) : '—';
    const dur = st.duration_ms != null && st.duration_ms !== '' ? esc(String(st.duration_ms)) + ' ms' : '—';
    const safeMsg = st.message
        ? `<div class="st-cred-pf-handshake-detail"><strong>Message:</strong> ${esc(stCredHandshakeSanitizeMessage(st.message))}</div>`
        : '';
    const detail =
        st.detail && String(st.detail).trim()
            ? `<div class="st-cred-pf-handshake-detail"><strong>${ok ? 'Result' : 'Detail'}:</strong> ${esc(stCredHandshakeSanitizeMessage(st.detail))}</div>`
            : '';
    const nextHint = !ok
        ? `<div class="st-cred-pf-handshake-detail"><strong>Next step:</strong> ${esc(stCredHandshakeCodeHint(st.code))}</div>`
        : '';
    const stale = st.stale
        ? '<div class="st-cred-pf-handshake-stale">Target host or port changed after this run — this snapshot may not match the fields above.</div>'
        : '';
    body.innerHTML =
        stale +
        '<dl class="st-cred-pf-handshake-dl">' +
        '<dt>Status</dt><dd><strong>' +
        esc(statusWord) +
        '</strong></dd>' +
        '<dt>Target</dt><dd><span class="mono-sm">' +
        host +
        '</span> · port <span class="mono-sm">' +
        port +
        '</span></dd>' +
        '<dt>Time</dt><dd>' +
        ts +
        '</dd>' +
        '<dt>Duration</dt><dd>' +
        dur +
        '</dd>' +
        '<dt>Code</dt><dd class="mono-sm">' +
        code +
        '</dd></dl>' +
        safeMsg +
        detail +
        nextHint;
}

function stCredHandshakeBeginTest(profileId, transport, targetHost, rawPort) {
    const effPort = stCredHandshakeEffectivePort(transport, rawPort);
    window.__stCredHandshakeResult = {
        phase: 'testing',
        profileId,
        transport: String(transport || 'ssh'),
        targetHost: String(targetHost || '').trim(),
        port: effPort,
    };
    stCredHandshakeRenderPanel();
}

function stCredHandshakeFinishFromResponse(r, reqProfileId, reqTransport, targetHost, rawPort) {
    const effPort = stCredHandshakeEffectivePort(reqTransport, rawPort);
    const atIso = new Date().toISOString();
    if (r && r.ok && r.test) {
        const t = r.test;
        const hint = t.hint != null ? String(t.hint) : '';
        const portShown = t.port != null && t.port !== '' ? Number(t.port) : effPort;
        window.__stCredHandshakeResult = {
            phase: 'done',
            ranAt: atIso,
            atIso,
            profileId: reqProfileId,
            transport: String(t.transport || reqTransport || 'ssh'),
            targetHost: String(t.target_host || targetHost || '').trim(),
            port: portShown,
            success: !!t.success,
            code: String(t.code || '—'),
            duration_ms: t.duration_ms,
            message: '',
            detail: hint,
            stale: false,
        };
        stCredHandshakeRenderPanel();
        return;
    }
    const code = r && r.code ? String(r.code) : 'protocol_error';
    const msg = r && r.error ? stCredHandshakeSanitizeMessage(r.error) : 'Test failed';
    window.__stCredHandshakeResult = {
        phase: 'done',
        ranAt: atIso,
        atIso,
        profileId: reqProfileId,
        transport: String(reqTransport || 'ssh'),
        targetHost: String(targetHost || '').trim(),
        port: effPort,
        success: false,
        code,
        duration_ms: null,
        message: msg,
        detail: '',
        stale: false,
    };
    stCredHandshakeRenderPanel();
}

