async function stCcJobAssetSearch() {
    const qEl = document.getElementById('st-cc-job-asset-q');
    const res = document.getElementById('st-cc-job-asset-results');
    if (!qEl || !res) return;
    const q = String(qEl.value || '').trim();
    res.innerHTML = '<span class="hint-micro text-dim">Searching…</span>';
    const { rows, err, message } = await stCredAssetsQuickSearch(q, 20);
    if (err === 'empty') {
        res.innerHTML = '<span class="hint-micro text-dim">Enter hostname, IP, MAC, or device id.</span>';
        return;
    }
    if (err === 'short') {
        res.innerHTML = '<span class="hint-micro text-dim">Enter at least 2 characters (or digits only for a short id).</span>';
        return;
    }
    if (err === 'network' || err === 'http') {
        res.innerHTML = '<span class="hint-micro text-dim">' + esc(message || 'Could not reach inventory search (sign in or check network).') + '</span>';
        return;
    }
    if (!rows.length) {
        res.innerHTML = '<span class="hint-micro text-dim">No matches — try another substring or paste asset IDs below.</span>';
        return;
    }
    res.innerHTML = rows.map((a) => stCredAssetSearchResultRowHtml(a, 'stCcJobAddAssetPick')).join('');
}

function stCcJobAddAssetPick(assetId) {
    const id = Number(assetId);
    if (id < 1) return;
    window.__stCcJobAssetPick = window.__stCcJobAssetPick || [];
    if (window.__stCcJobAssetPick.some((x) => Number(x.id) === id)) {
        toast('Asset already selected', 'ok');
        return;
    }
    window.__stCcJobAssetPick.push({ id, label: 'Asset #' + id });
    void stCredPfHydratePickLabels(window.__stCcJobAssetPick).then(() => {
        stCcJobRenderAssetChips();
        stCcJobSyncTargetIdsInputFromPick();
    });
}

function stCcJobRemoveAssetPick(assetId) {
    const id = Number(assetId);
    window.__stCcJobAssetPick = (window.__stCcJobAssetPick || []).filter((x) => Number(x.id) !== id);
    stCcJobRenderAssetChips();
    stCcJobSyncTargetIdsInputFromPick();
}

