function stCredProfileSecretTransportChanged() {
    stCredHandshakeClearState();
    const trEl = document.getElementById('st-cred-pf-transport');
    const newT = trEl ? String(trEl.value || 'ssh') : 'ssh';
    const oldT = typeof window.__stCredPfLastTransport === 'string' ? window.__stCredPfLastTransport : newT;
    let merged = {};
    try {
        merged = stCredPfCollectPrincipalObject(oldT);
    } catch (e) {
        merged = {};
    }
    stCredProfileClearSecretInputs();
    stCredProfileUpdateSecretFieldVisibility();
    stCredProfileUpdatePrincipalStructVisibility();
    stCredPfApplyPrincipalToUi(merged, newT);
    window.__stCredPfLastTransport = newT;
    stCredProfileSyncSecretPanel(window.__stCredProfileModalPayload || null);
    stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload || null);
}

function stCredProfileSyncTransportTestPanel(p) {
    const panel = document.getElementById('st-cred-pf-transport-test-panel');
    const btn = document.getElementById('st-cred-pf-btn-transport-test');
    const statEl = document.getElementById('st-cred-pf-handshake-status');
    const readyEl = document.getElementById('st-cred-pf-test-readiness');
    const hostEl = document.getElementById('st-cred-pf-test-host');
    if (!panel || !btn) return;
    const st = stCredProfileBuildUiState(p);
    if (readyEl) readyEl.textContent = stCredProfileReadinessLine(st);
    if (!st.supportsHandshake) {
        panel.classList.add('hide');
        btn.disabled = true;
        btn.title = 'WinRM handshake test is not implemented yet';
        if (statEl) statEl.textContent = '';
        return;
    }
    if (st.editId < 1) {
        panel.classList.add('hide');
        btn.disabled = true;
        btn.title = '';
        if (statEl) statEl.textContent = '';
        return;
    }
    panel.classList.remove('hide');
    const encOk = st.encryptionAvailable;
    const secOk = st.hasStoredSecret;
    const hostOk = st.hostOk;
    const stat = st.testReason;
    if (statEl) {
        statEl.textContent = stat;
        statEl.className = 'hint-micro mb6 ' + (st.canRunTest ? 'text-secondary' : 'text-dim');
    }
    const canClick = !!st.canRunTest;
    btn.disabled = !canClick;
    if (st.testingHandshake) {
        btn.title = 'Handshake test is currently running.';
    } else if (!encOk) {
        btn.title = 'Credential encryption is not configured on the server.';
    } else if (!secOk) {
        btn.title = 'Set / replace secret above before testing.';
    } else if (!hostOk) {
        btn.title = 'Target host required.';
    } else {
        btn.title = 'Ready to test.';
    }
}

async function stCredProfileRunTransportTest() {
    const hid = document.getElementById('st-cred-pf-id');
    const hostEl = document.getElementById('st-cred-pf-test-host');
    const portEl = document.getElementById('st-cred-pf-test-port');
    const btn = document.getElementById('st-cred-pf-btn-transport-test');
    const prog = document.getElementById('st-cred-pf-test-progress');
    const hint = document.getElementById('st-cred-pf-modal-hint');
    const tr = document.getElementById('st-cred-pf-transport');
    const transport = tr ? String(tr.value || 'ssh') : 'ssh';
    const id = hid && hid.value ? parseInt(hid.value, 10) : 0;
    const target = (hostEl && hostEl.value) ? hostEl.value.trim() : '';
    const port = portEl && portEl.value !== '' ? parseInt(portEl.value, 10) : 0;
    if (id < 1) return;
    if (!target) {
        toast('Enter target host or IP', 'err');
        return;
    }
    if (btn) btn.disabled = true;
    if (prog) prog.classList.remove('hide');
    if (hint) hint.textContent = '';
    stCredHandshakeBeginTest(id, transport, target, port);
    try {
        const r = await apiPost('/api/credential_profiles.php', { action: 'test', id, target_host: target, port });
        if (r && r.ok && r.test) {
            const ok = !!r.test.success;
            stCredHandshakeFinishFromResponse(r, id, transport, target, port);
            toast(ok ? 'Handshake succeeded' : 'Handshake failed', ok ? 'ok' : 'err');
            if (r.profile) {
                window.__stCredProfileModalPayload = stCredProfileNormalizeProfilePayload(r.profile);
                stCredProfileSyncSecretPanel(window.__stCredProfileModalPayload);
                stCredProfileSyncNextSteps(window.__stCredProfileModalPayload);
                stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload);
            }
            if (r.encryption && typeof r.encryption === 'object') {
                window.__stCredEncryption = stCredNormalizeEncryptionStatus(r.encryption);
            }
            await loadCredentialProfiles();
        } else {
            const err = (r && r.error) ? String(r.error) : 'Test failed';
            if (hint) hint.textContent = err;
            toast(err, 'err');
            const failCode = r && r.code ? String(r.code) : 'protocol_error';
            stCredHandshakeFinishFromResponse(r || { ok: false, error: err, code: failCode }, id, transport, target, port);
            if (r && r.encryption && typeof r.encryption === 'object' && !Array.isArray(r.encryption)) {
                window.__stCredEncryption = stCredNormalizeEncryptionStatus(r.encryption);
            }
        }
    } catch (e) {
        const err = e && e.message ? String(e.message) : 'Transport test request failed';
        if (hint) hint.textContent = err;
        toast(err, 'err');
        stCredHandshakeFinishFromResponse({ ok: false, error: err, code: 'request_failed' }, id, transport, target, port);
    } finally {
        if (prog) prog.classList.add('hide');
        stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload || null);
    }
}


function stCredProfileUpdateSecretFieldVisibility() {
    const tr = document.getElementById('st-cred-pf-transport');
    const t = tr ? String(tr.value || 'ssh') : 'ssh';
    const ssh = document.getElementById('st-cred-pf-secret-fields-ssh');
    const snmp = document.getElementById('st-cred-pf-secret-fields-snmp');
    const wrm = document.getElementById('st-cred-pf-secret-fields-winrm');
    if (ssh) ssh.classList.toggle('hide', t !== 'ssh');
    if (snmp) snmp.classList.toggle('hide', t !== 'snmpv3');
    if (wrm) wrm.classList.toggle('hide', t !== 'winrm');
    if (t === 'snmpv3') stCredPfSnmpOnLevelChange();
}

/** @returns {{ material: object }|{ error: string }} */
function stCredProfileCollectSecretMaterial() {
    const tr = document.getElementById('st-cred-pf-transport');
    const t = tr ? String(tr.value || 'ssh') : 'ssh';
    if (t === 'ssh') {
        const pw = (document.getElementById('st-cred-pf-ssh-password')?.value || '').trim();
        const pk = (document.getElementById('st-cred-pf-ssh-private-key')?.value || '').trim();
        const pp = (document.getElementById('st-cred-pf-ssh-passphrase')?.value || '').trim();
        if (pw !== '' && pk !== '') {
            return { error: 'Enter either an SSH password or a private key, not both.' };
        }
        const material = {};
        if (pw !== '') material.password = pw;
        if (pk !== '') {
            material.private_key = pk;
            if (pp !== '') material.passphrase = pp;
        }
        if (Object.keys(material).length === 0) {
            return { error: 'Enter an SSH password or private key.' };
        }
        return { material };
    }
    if (t === 'snmpv3') {
        const a = (document.getElementById('st-cred-pf-snmpv3-auth')?.value || '').trim();
        const p = (document.getElementById('st-cred-pf-snmpv3-priv')?.value || '').trim();
        if (a === '' && p === '') {
            return { error: 'Enter at least one of SNMPv3 auth password or privacy password.' };
        }
        const material = {};
        if (a !== '') material.auth_password = a;
        if (p !== '') material.priv_password = p;
        return { material };
    }
    if (t === 'winrm') {
        const pw = (document.getElementById('st-cred-pf-winrm-password')?.value || '').trim();
        if (pw === '') {
            return { error: 'Enter WinRM password.' };
        }
        return { material: { password: pw } };
    }
    return { error: 'Unknown transport.' };
}

function stCredProfileSyncSecretPanel(p) {
    const encHint = document.getElementById('st-cred-pf-secret-enc-hint');
    const saveHint = document.getElementById('st-cred-pf-secret-profile-save-hint');
    const statusEl = document.getElementById('st-cred-pf-secret-status');
    const actHint = document.getElementById('st-cred-pf-secret-action-hint');
    const btnSave = document.getElementById('st-cred-pf-btn-secret-save');
    const btnClear = document.getElementById('st-cred-pf-btn-secret-clear');
    const ui = stCredProfileBuildUiState(p);
    const avail = ui.encryptionAvailable;
    const editId = ui.editId;
    const hasSec = ui.hasStoredSecret;
    const peek = ui.secretPeek;
    p = ui.profile;
    if (encHint) {
        encHint.textContent = avail
            ? 'Secrets are encrypted at rest. They are never returned by the API. Credentialed checks use the stored envelope server-side.'
            : 'Credential encryption is not configured on this server (helper cannot load the key from /etc/surveytrace/surveytrace.env, or sudo helper is unavailable). Save profile metadata now; you cannot store secrets until encryption is working.';
    }
    if (saveHint) {
        if (editId < 1) {
            saveHint.textContent = 'Save profile before storing a secret.';
            saveHint.classList.remove('hide');
        } else {
            saveHint.textContent = '';
            saveHint.classList.add('hide');
        }
    }
    if (statusEl) {
        if (editId < 1) {
            statusEl.textContent = '';
            statusEl.className = 'hint-micro text-dim mb6';
        } else if (hasSec) {
            const alg = p.secret_envelope && p.secret_envelope.alg ? String(p.secret_envelope.alg) : '';
            statusEl.textContent = 'Secret on file: yes' + (alg ? ' (envelope ' + alg + ')' : '') + '.';
            statusEl.className = 'hint-micro mb6';
        } else {
            statusEl.textContent = 'No secret stored for this profile yet.';
            statusEl.className = 'hint-micro text-dim mb6';
        }
    }
    let saveReason = '';
    if (editId < 1) saveReason = 'Save profile before storing a secret.';
    else if (!avail) saveReason = 'Credential encryption is not configured.';
    else if (!peek.ok) saveReason = peek.reason || 'Enter a password or private key.';
    if (actHint) {
        if (saveReason) {
            actHint.textContent = saveReason;
            actHint.classList.remove('hide');
        } else {
            actHint.textContent = '';
            actHint.classList.add('hide');
        }
    }
    if (btnSave) {
        const canSave = !!(avail && editId >= 1 && peek.ok);
        btnSave.disabled = !canSave;
        btnSave.title = saveReason || '';
    }
    if (btnClear) {
        let clrReason = '';
        if (editId < 1) clrReason = 'Save profile before storing a secret.';
        else if (!hasSec) clrReason = 'No stored secret.';
        else if (!avail) clrReason = 'Credential encryption is not configured.';
        const canClear = !!(avail && editId >= 1 && hasSec);
        btnClear.disabled = !canClear;
        btnClear.title = clrReason || '';
    }
}

/** @param {{ encryptionSnapshot?: object }|null|undefined} opts */
async function stCredProfileOpenModal(p, opts) {
    const snap = opts && opts.encryptionSnapshot && typeof opts.encryptionSnapshot === 'object' && !Array.isArray(opts.encryptionSnapshot)
        ? opts.encryptionSnapshot
        : null;
    if (snap) {
        window.__stCredEncryption = stCredNormalizeEncryptionStatus(snap);
    } else {
        await stCredRefreshEncryptionFromServer();
    }
    await stCredEnsureScopesCatalog();
    const bg = document.getElementById('st-cred-profile-modal-bg');
    const title = document.getElementById('st-cred-profile-modal-title');
    const hid = document.getElementById('st-cred-pf-id');
    const nm = document.getElementById('st-cred-pf-name');
    const tr = document.getElementById('st-cred-pf-transport');
    const en = document.getElementById('st-cred-pf-enabled');
    const hint = document.getElementById('st-cred-pf-modal-hint');
    if (!bg || !title || !hid || !nm || !tr || !en) return;
    stCredProfileClearSecretInputs();
    p = stCredProfileNormalizeProfilePayload(p || null);
    window.__stCredPfAssetPick = [];
    const newPid = p && p.id ? Number(p.id) : 0;
    const lastOpened = window.__stCredProfileModalLastOpenedId;
    if (!p || !p.id) {
        stCredHandshakeClearState();
        window.__stCredProfileModalLastOpenedId = null;
        title.textContent = 'New credential profile';
        hid.value = '';
        nm.value = '';
        tr.value = 'ssh';
        en.checked = true;
        if (hint) {
            hint.textContent =
                'Save profile metadata first (name + transport + principal fields). Then set an encrypted secret, enter a target host, and run a handshake test. Empty scope selections here only record intent — jobs choose execution targets separately.';
        }
        stCredPfApplyPrincipalToUi({}, 'ssh');
        stCredPfApplyScopeToUi({ scope_ids: [], asset_ids: [], tags: [] });
        const th0 = document.getElementById('st-cred-pf-test-host');
        const tp0 = document.getElementById('st-cred-pf-test-port');
        if (th0) th0.value = '';
        if (tp0) tp0.value = '0';
    } else {
        if (lastOpened && lastOpened !== newPid) {
            stCredHandshakeClearState();
            const thSw = document.getElementById('st-cred-pf-test-host');
            const tpSw = document.getElementById('st-cred-pf-test-port');
            if (thSw) thSw.value = '';
            if (tpSw) tpSw.value = '0';
        }
        title.textContent = 'Edit credential profile';
        hid.value = String(p.id || '');
        nm.value = p.name || '';
        tr.value = p.transport || 'ssh';
        en.checked = !!p.enabled;
        if (hint) hint.textContent = '';
        const pj = p.principal_json && typeof p.principal_json === 'object' ? p.principal_json : {};
        stCredPfApplyPrincipalToUi(pj, String(tr.value || 'ssh'));
        const sj = p.scope_json && typeof p.scope_json === 'object' ? p.scope_json : {};
        stCredPfApplyScopeToUi(sj);
    }
    stCredProfileUpdatePrincipalStructVisibility();
    stCredProfileUpdateSecretFieldVisibility();
    stCredProfileSyncSecretPanel(p);
    window.__stCredProfileModalPayload = p || null;
    window.__stCredPfLastTransport = String(tr.value || 'ssh');
    stCredProfileSyncNextSteps(window.__stCredProfileModalPayload);
    stCredProfileSyncTransportTestPanel(window.__stCredProfileModalPayload);
    window.__stCredProfileModalLastOpenedId = newPid > 0 ? newPid : null;
    stCredHandshakeMarkStaleIfTargetChanged();
    stCredHandshakeRenderPanel();
    bg.style.display = 'flex';
}

async function stCredProfileOpenModalById(id) {
    const r = await api('/api/credential_profiles.php?id=' + encodeURIComponent(String(id)));
    if (!r || !r.ok || !r.profile) {
        toast((r && r.error) ? r.error : 'Load failed', 'err');
        return;
    }
    await stCredProfileOpenModal(stCredProfileNormalizeProfilePayload(r.profile), {
        encryptionSnapshot: r.encryption && typeof r.encryption === 'object' ? r.encryption : null,
    });
}

async function stCredProfileSubmitSecret() {
    const hid = document.getElementById('st-cred-pf-id');
    const id = hid && hid.value ? parseInt(hid.value, 10) : 0;
    const hint = document.getElementById('st-cred-pf-modal-hint');
    if (id < 1) {
        toast('Save the profile first', 'err');
        return;
    }
    if (!stCredEncryptionAvailable()) {
        toast('Credential encryption is not configured.', 'err');
        return;
    }
    const got = stCredProfileCollectSecretMaterial();
    if (got.error) {
        if (hint) hint.textContent = got.error;
        toast(got.error, 'err');
        return;
    }
    const r = await apiPost('/api/credential_profiles.php', { action: 'set_secret', id, secret_material: got.material });
    if (r && r.ok) {
        stCredProfileClearSecretInputs();
        if (hint) hint.textContent = '';
        toast('Secret saved (value not shown again)', 'ok');
        stCredHandshakeClearState();
        await stCredProfileOpenModal(stCredProfileNormalizeProfilePayload(r.profile), {
            encryptionSnapshot: r.encryption && typeof r.encryption === 'object' ? r.encryption : null,
        });
        await loadCredentialProfiles();
    } else {
        const err = (r && r.error) ? String(r.error) : 'Save secret failed';
        if (hint) hint.textContent = err;
        toast(err, 'err');
    }
}

async function stCredProfileClearSecret() {
    const hid = document.getElementById('st-cred-pf-id');
    const id = hid && hid.value ? parseInt(hid.value, 10) : 0;
    const hint = document.getElementById('st-cred-pf-modal-hint');
    if (id < 1) return;
    const okClear = await showConfirmModal('Clear the stored secret for this profile? Operators will need to set a new secret before checks can authenticate.', {
        title: 'Clear secret',
        okText: 'Clear secret',
        cancelText: 'Cancel',
    });
    if (!okClear) return;
    const r = await apiPost('/api/credential_profiles.php', { action: 'clear_secret', id });
    if (r && r.ok) {
        stCredProfileClearSecretInputs();
        if (hint) hint.textContent = '';
        toast('Secret cleared', 'ok');
        stCredHandshakeClearState();
        await stCredProfileOpenModal(stCredProfileNormalizeProfilePayload(r.profile), {
            encryptionSnapshot: r.encryption && typeof r.encryption === 'object' ? r.encryption : null,
        });
        await loadCredentialProfiles();
    } else {
        const err = (r && r.error) ? String(r.error) : 'Clear failed';
        if (hint) hint.textContent = err;
        toast(err, 'err');
    }
}

async function stCredProfileSave() {
    const hid = document.getElementById('st-cred-pf-id');
    const nm = document.getElementById('st-cred-pf-name');
    const tr = document.getElementById('st-cred-pf-transport');
    const en = document.getElementById('st-cred-pf-enabled');
    const hint = document.getElementById('st-cred-pf-modal-hint');
    if (!nm || !tr || !en) return;
    await stCredEnsureScopesCatalog();
    let principalObj;
    try {
        principalObj = stCredPfCollectPrincipalObject(tr.value);
    } catch (e) {
        const msg = e && e.message === 'principal_adv_json' ? 'Advanced principal JSON must be a valid object.' : 'Could not read principal fields.';
        if (hint) hint.textContent = msg;
        toast(msg, 'err');
        return;
    }
    let scopeObj;
    try {
        scopeObj = stCredPfCollectScopeObject();
    } catch (e2) {
        const msg = e2 && e2.message === 'scope_adv_json' ? 'Advanced scope JSON must be a valid object.' : 'Could not read scope fields.';
        if (hint) hint.textContent = msg;
        toast(msg, 'err');
        return;
    }
    const id = hid && hid.value ? parseInt(hid.value, 10) : 0;
    const body = id > 0
        ? { action: 'update', id, name: nm.value.trim(), transport: tr.value, principal_json: principalObj, scope_json: scopeObj, enabled: !!en.checked }
        : { action: 'create', name: nm.value.trim(), transport: tr.value, principal_json: principalObj, scope_json: scopeObj, enabled: !!en.checked };
    const r = await apiPost('/api/credential_profiles.php', body);
    if (r && r.ok) {
        toast('Profile saved — set or confirm secret, then run a handshake test.', 'ok');
        stCredHandshakeClearState();
        await stCredProfileOpenModal(stCredProfileNormalizeProfilePayload(r.profile), {
            encryptionSnapshot: r.encryption && typeof r.encryption === 'object' ? r.encryption : null,
        });
        await loadCredentialProfiles();
    } else {
        if (hint) hint.textContent = (r && r.error) ? String(r.error) : 'Save failed';
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

async function stCredProfileToggleEnabled(id, toEnable) {
    const r = await apiPost('/api/credential_profiles.php', { action: 'set_enabled', id, enabled: toEnable === true || toEnable === 'true' });
    if (r && r.ok) {
        toast('Updated', 'ok');
        await loadCredentialProfiles();
    } else {
        toast((r && r.error) ? r.error : 'Update failed', 'err');
    }
}

async function stCredProfileDelete(id) {
    const okDel = await showConfirmModal(
        'Remove this credential profile? If it is referenced by check jobs, it will be archived (hidden from lists) instead of permanently deleted.',
        { title: 'Remove profile', okText: 'Remove', cancelText: 'Cancel' }
    );
    if (!okDel) return;
    const r = await apiPost('/api/credential_profiles.php', { action: 'delete', id });
    if (r && r.ok) {
        if (r.archived) toast('Profile archived (still referenced by jobs)', 'ok');
        else toast('Profile removed', 'ok');
        await loadCredentialProfiles();
    } else {
        toast((r && r.error) ? r.error : 'Remove failed', 'err');
    }
}

var __stCcRunModalId = 0;

function stCcJobCloseModal() {
    const bg = document.getElementById('st-cc-job-modal-bg');
    if (bg) bg.style.display = 'none';
}

function stCcRunCloseModal() {
    const bg = document.getElementById('st-cc-run-modal-bg');
    if (bg) bg.style.display = 'none';
    __stCcRunModalId = 0;
}

function stCcJobSyncTargetHints() {
    const mode = document.getElementById('st-cc-job-target-mode');
    const hint = document.getElementById('st-cc-job-target-hint');
    const sp = document.getElementById('st-cc-job-target-scope-panel');
    const ap = document.getElementById('st-cc-job-target-assets-panel');
    const ids = document.getElementById('st-cc-job-target-ids');
    if (!mode || !hint) return;
    if (mode.value === 'assets') {
        hint.textContent = 'Search inventory and add assets, or paste comma-separated asset IDs. Targets must exist in inventory.';
        if (sp) sp.classList.add('hide');
        if (ap) ap.classList.remove('hide');
        if (ids) ids.placeholder = 'e.g. 12, 34';
    } else {
        hint.textContent = 'Choose one or more scopes by name. At launch, active assets whose scope_id matches are included.';
        if (sp) sp.classList.remove('hide');
        if (ap) ap.classList.add('hide');
    }
}

async function stCcJobOnProfileChange() {
    const sel = document.getElementById('st-cc-job-profile');
    const box = document.getElementById('st-cc-job-plugins');
    if (!sel || !box) return;
    const opt = sel.options[sel.selectedIndex];
    const tr = opt ? String(opt.getAttribute('data-transport') || '') : '';
    box.textContent = 'Loading plugins…';
    if (!tr) {
        box.textContent = 'Select a profile.';
        return;
    }
    const r = await api('/api/credentialed_checks.php?transport=' + encodeURIComponent(tr));
    if (!r || !r.ok || !Array.isArray(r.plugins)) {
        box.textContent = 'Could not load plugins.';
        return;
    }
    const rows = r.plugins
        .map((p) => {
            const k = esc(String(p.plugin_key || ''));
            const v = esc(String(p.version || ''));
            const st = esc(String(p.state || ''));
            return `<label class="row-wrap gap6" style="display:flex;align-items:flex-start;margin-bottom:4px"><input type="checkbox" class="st-cc-pl-cb" data-pk="${k}" data-pv="${v}"><span><span class="mono-sm">${k}</span> <span class="text-dim">@${v}</span> <span class="text-dim">(${st})</span></span></label>`;
        })
        .join('');
    let transportHint = '';
    if (tr === 'ssh') transportHint = 'Only SSH plugins are listed for this profile.';
    else if (tr === 'snmpv3') transportHint = 'Only SNMPv3 plugins are listed for this profile.';
    else if (tr === 'winrm') transportHint = 'WinRM plugins appear here when available for this transport.';
    box.innerHTML =
        (rows || '<span class="text-dim">No plugins for this transport.</span>') +
        (transportHint ? `<p class="hint-micro text-dim mt8 mb0">${esc(transportHint)}</p>` : '');
}

async function stCcJobOpenModal(jobId, presetProfileId) {
    if (!stRoleIsAdmin()) return;
    const bg = document.getElementById('st-cc-job-modal-bg');
    const hid = document.getElementById('st-cc-job-id');
    const nm = document.getElementById('st-cc-job-name');
    const ds = document.getElementById('st-cc-job-desc');
    const pf = document.getElementById('st-cc-job-profile');
    const mode = document.getElementById('st-cc-job-target-mode');
    const ids = document.getElementById('st-cc-job-target-ids');
    const scopeMs = document.getElementById('st-cc-job-scope-ms');
    const mc = document.getElementById('st-cc-job-max-conc');
    const to = document.getElementById('st-cc-job-timeout');
    const en = document.getElementById('st-cc-job-enabled');
    const se = document.getElementById('st-cc-job-sched-enabled');
    const scr = document.getElementById('st-cc-job-sched-cron');
    const stz = document.getElementById('st-cc-job-sched-tz');
    const smx = document.getElementById('st-cc-job-sched-max');
    const rto = document.getElementById('st-cc-job-run-to');
    const sro = document.getElementById('st-cc-job-sched-readonly');
    const hintEl = document.getElementById('st-cc-job-modal-hint');
    const resBox = document.getElementById('st-cc-job-asset-results');
    const qEl = document.getElementById('st-cc-job-asset-q');
    if (!bg || !hid || !nm || !pf || !mode || !ids) return;
    hintEl.textContent = '';
    hid.value = jobId && jobId > 0 ? String(jobId) : '';
    window.__stCcJobAssetPick = [];
    stCcJobRenderAssetChips();
    if (resBox) resBox.innerHTML = '';
    if (qEl) qEl.value = '';
    ids.value = '';
    await stCredEnsureScopesCatalog();
    if (scopeMs) {
        scopeMs.innerHTML = (window.__stCredScopesCatalog || [])
            .map((s) => {
                const sid = Number(s.id);
                return `<option value="${sid}">${esc(String(s.name || ''))}</option>`;
            })
            .join('');
    }
    const pr = await api('/api/credential_profiles.php');
    if (!pr || !pr.ok || !Array.isArray(pr.profiles)) {
        toast('Could not load profiles', 'err');
        return;
    }
    pf.innerHTML = pr.profiles
        .map((p) => {
            const id = Number(p.id);
            return `<option value="${id}" data-transport="${esc(String(p.transport || ''))}">${esc(String(p.name || ''))} (${esc(String(p.transport || ''))})</option>`;
        })
        .join('');
    if (!pf.options.length) {
        toast('Add a credential profile first', 'err');
        return;
    }
    const preset = presetProfileId != null ? Number(presetProfileId) : 0;
    if (preset > 0 && [...pf.options].some((o) => o.value === String(preset))) {
        pf.value = String(preset);
    }
    if (jobId && jobId > 0) {
        const jr = await api('/api/credential_check_jobs.php?id=' + encodeURIComponent(String(jobId)));
        if (!jr || !jr.ok || !jr.job) {
            toast('Could not load job', 'err');
            return;
        }
        const j = jr.job;
        nm.value = String(j.name || '');
        ds.value = String(j.description || '');
        pf.value = String(j.credential_profile_id || '');
        mode.value = j.target_mode === 'scope' ? 'scope' : 'assets';
        let tj = {};
        try {
            tj = j.target_json ? JSON.parse(String(j.target_json)) : {};
        } catch (e1) {
            tj = {};
        }
        stCcJobSyncTargetHints();
        if (mode.value === 'scope' && scopeMs && Array.isArray(tj.scope_ids)) {
            const want = new Set(tj.scope_ids.map((x) => Number(x)).filter((n) => n > 0));
            Array.from(scopeMs.options).forEach((o) => {
                o.selected = want.has(parseInt(o.value, 10));
            });
            ids.value = '';
        } else if (mode.value === 'assets' && Array.isArray(tj.asset_ids)) {
            if (scopeMs) Array.from(scopeMs.options).forEach((o) => { o.selected = false; });
            ids.value = tj.asset_ids.join(', ');
            window.__stCcJobAssetPick = [];
            tj.asset_ids.forEach((aid) => {
                const n = Number(aid);
                if (n > 0) window.__stCcJobAssetPick.push({ id: n, label: 'Asset #' + n });
            });
            void stCredPfHydratePickLabels(window.__stCcJobAssetPick).then(() => {
                stCcJobRenderAssetChips();
                stCcJobSyncTargetIdsInputFromPick();
            });
        } else {
            ids.value = '';
            if (scopeMs) Array.from(scopeMs.options).forEach((o) => { o.selected = false; });
        }
        let pol = {};
        try {
            pol = j.policy_json ? JSON.parse(String(j.policy_json)) : {};
        } catch (e2) {
            pol = {};
        }
        if (mc) mc.value = String(pol.max_concurrency != null ? pol.max_concurrency : 4);
        if (to) to.value = String(pol.timeout_ms != null ? pol.timeout_ms : 600000);
        if (en) en.checked = !!j.enabled;
        if (se) se.checked = !!j.schedule_enabled;
        if (scr) scr.value = j.schedule_cron != null && String(j.schedule_cron).trim() ? String(j.schedule_cron) : '';
        if (stz) stz.value = j.schedule_timezone != null && String(j.schedule_timezone).trim() ? String(j.schedule_timezone) : 'UTC';
        if (smx) smx.value = String(j.schedule_max_concurrency != null ? j.schedule_max_concurrency : 1);
        if (rto) rto.value = String(j.run_timeout_sec != null ? j.run_timeout_sec : 3600);
        if (sro) {
            const nr = j.schedule_next_run_at != null && String(j.schedule_next_run_at).trim() ? esc(String(j.schedule_next_run_at)) + ' UTC' : '—';
            const lr = j.schedule_last_run_at != null && String(j.schedule_last_run_at).trim() ? esc(String(j.schedule_last_run_at)) + ' UTC' : '—';
            const er = j.schedule_last_error != null && String(j.schedule_last_error).trim() ? esc(String(j.schedule_last_error)) : '—';
            sro.innerHTML =
                '<span class="text-dim">Next scheduled:</span> ' +
                nr +
                ' · <span class="text-dim">Last scheduler launch:</span> ' +
                lr +
                ' · <span class="text-dim">Last scheduler error:</span> ' +
                er;
        }
        await stCcJobOnProfileChange();
        let plugs = [];
        try {
            plugs = j.plugin_selection_json ? JSON.parse(String(j.plugin_selection_json)) : [];
        } catch (e3) {
            plugs = [];
        }
        document.querySelectorAll('.st-cc-pl-cb').forEach((cb) => {
            const pk = cb.getAttribute('data-pk');
            const pv = cb.getAttribute('data-pv');
            cb.checked = plugs.some((x) => String(x.plugin_key) === pk && String(x.version || '') === pv);
        });
    } else {
        nm.value = '';
        ds.value = '';
        if (!preset && pf.options.length) pf.selectedIndex = 0;
        mode.value = 'assets';
        if (scopeMs) Array.from(scopeMs.options).forEach((o) => { o.selected = false; });
        if (mc) mc.value = '4';
        if (to) to.value = '600000';
        if (en) en.checked = true;
        if (se) se.checked = false;
        if (scr) scr.value = '';
        if (stz) stz.value = 'UTC';
        if (smx) smx.value = '1';
        if (rto) rto.value = '3600';
        if (sro) sro.textContent = '';
        stCcJobSyncTargetHints();
        await stCcJobOnProfileChange();
    }
    stCcJobSyncTargetHints();
    bg.style.display = 'flex';
}

function stCcParseCommaInts(raw) {
    const out = [];
    String(raw || '')
        .split(/[,;\s]+/)
        .map((s) => s.trim())
        .filter(Boolean)
        .forEach((s) => {
            const n = parseInt(s, 10);
            if (!Number.isNaN(n) && n > 0) out.push(n);
        });
    return out;
}

async function stCcJobSave() {
    const hid = document.getElementById('st-cc-job-id');
    const nm = document.getElementById('st-cc-job-name');
    const ds = document.getElementById('st-cc-job-desc');
    const pf = document.getElementById('st-cc-job-profile');
    const mode = document.getElementById('st-cc-job-target-mode');
    const ids = document.getElementById('st-cc-job-target-ids');
    const mc = document.getElementById('st-cc-job-max-conc');
    const to = document.getElementById('st-cc-job-timeout');
    const en = document.getElementById('st-cc-job-enabled');
    const se = document.getElementById('st-cc-job-sched-enabled');
    const scr = document.getElementById('st-cc-job-sched-cron');
    const stz = document.getElementById('st-cc-job-sched-tz');
    const smx = document.getElementById('st-cc-job-sched-max');
    const rto = document.getElementById('st-cc-job-run-to');
    const hintEl = document.getElementById('st-cc-job-modal-hint');
    const id = hid && hid.value ? parseInt(hid.value, 10) : 0;
    let ints = [];
    if (mode && mode.value === 'scope') {
        const sms = document.getElementById('st-cc-job-scope-ms');
        ints = sms ? Array.from(sms.selectedOptions || []).map((o) => parseInt(o.value, 10)).filter((n) => n > 0) : [];
    } else {
        const fromPick = (window.__stCcJobAssetPick || []).map((x) => Number(x.id)).filter((n) => n > 0);
        ints = fromPick.length ? fromPick : stCcParseCommaInts(ids && ids.value);
    }
    const targetJson =
        mode && mode.value === 'scope' ? { scope_ids: ints } : { asset_ids: ints };
    const selPl = [];
    document.querySelectorAll('.st-cc-pl-cb:checked').forEach((cb) => {
        selPl.push({ plugin_key: cb.getAttribute('data-pk'), version: cb.getAttribute('data-pv') || '' });
    });
    const policy = {
        max_concurrency: mc ? parseInt(mc.value, 10) || 4 : 4,
        timeout_ms: to ? parseInt(to.value, 10) || 600000 : 600000,
    };
    const body = {
        action: id > 0 ? 'update' : 'create',
        name: nm ? nm.value.trim() : '',
        description: ds ? ds.value.trim() : '',
        credential_profile_id: pf ? parseInt(pf.value, 10) || 0 : 0,
        target_mode: mode ? mode.value : 'assets',
        target_json: targetJson,
        plugin_selection_json: selPl,
        policy_json: policy,
        enabled: en ? !!en.checked : true,
        schedule_enabled: se ? !!se.checked : false,
        schedule_cron: scr ? scr.value.trim() : '',
        schedule_timezone: stz && stz.value.trim() ? stz.value.trim() : 'UTC',
        schedule_max_concurrency: smx ? parseInt(smx.value, 10) || 1 : 1,
        run_timeout_sec: rto ? parseInt(rto.value, 10) || 3600 : 3600,
    };
    if (id > 0) body.id = id;
    const r = await apiPost('/api/credential_check_jobs.php', body);
    if (r && r.ok) {
        if (Array.isArray(r.experimental_warnings) && r.experimental_warnings.length) {
            toast('Saved. Note: job references experimental plugin(s).', 'ok');
        } else toast('Job saved', 'ok');
        stCcJobCloseModal();
        await stCcLoadJobsAndRuns();
    } else {
        if (hintEl) hintEl.textContent = (r && r.error) ? String(r.error) : 'Save failed';
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

async function stCcJobDelete(id) {
    const okDel = await showConfirmModal('Delete this credentialed check job? Pending runs may still finish; history stays unless purged separately.', {
        title: 'Delete job',
        okText: 'Delete',
        cancelText: 'Cancel',
    });
    if (!okDel) return;
    const r = await apiPost('/api/credential_check_jobs.php', { action: 'delete', id });
    if (r && r.ok) {
        toast('Job deleted', 'ok');
        await stCcLoadJobsAndRuns();
    } else {
        toast((r && r.error) ? r.error : 'Delete failed', 'err');
    }
}

function stCcRunsListHasActive() {
    const runs = window.__stCcRunsListCache || [];
    return runs.some((u) => {
        const s = String(u.status || '').toLowerCase();
        return s === 'queued' || s === 'resolving_targets' || s === 'ready' || s === 'running';
    });
}

function stCcStopRunPoll() {
    if (window.__stCcPollTimer) {
        clearInterval(window.__stCcPollTimer);
        window.__stCcPollTimer = null;
    }
}

function stCcMaybeStartRunPoll() {
    if (!stRoleIsAdmin()) return;
    stCcStopRunPoll();
    if (!stCcRunsListHasActive()) {
        const h = document.getElementById('st-cc-runs-poll-hint');
        if (h) h.textContent = '';
        return;
    }
    window.__stCcPollTimer = setInterval(function () {
        void stCcPollRunsTick();
    }, 4000);
}

async function stCcPollRunsTick() {
    const hint = document.getElementById('st-cc-runs-poll-hint');
    try {
        if (hint) hint.textContent = 'Refreshing…';
        await stCcLoadJobsAndRuns();
        if (hint) {
            hint.textContent = stCcRunsListHasActive()
                ? 'Auto-refresh every 4s · last ' + new Date().toLocaleTimeString()
                : '';
        }
        const bg = document.getElementById('st-cc-run-modal-bg');
        const rid = __stCcRunModalId;
        const modalOpen = bg && bg.style.display === 'flex' && rid > 0;
        if (modalOpen) {
            await stCcRunOpenModal(rid);
        }
    } catch (e) {
        if (hint) hint.textContent = 'Refresh failed — will retry on next interval';
    }
}

async function stCcLaunchRun(jobId) {
    const tryPost = async (accept) =>
        apiPost('/api/credential_check_runs.php', { action: 'launch', job_id: jobId, accept_experimental: !!accept });
    let r = await tryPost(false);
    if (r && !r.ok && r.experimental_plugins && r.error && String(r.error).indexOf('accept_experimental') >= 0) {
        const okExp = await showConfirmModal('This job uses experimental plugins. Launch anyway?', {
            title: 'Experimental plugins',
            okText: 'Launch',
            cancelText: 'Cancel',
        });
        if (!okExp) return;
        r = await tryPost(true);
    }
    if (r && r.ok) {
        const run = r.run || {};
        const rid = run.id != null ? parseInt(String(run.id), 10) : 0;
        const wjid = run.worker_job_id != null ? parseInt(String(run.worker_job_id), 10) : 0;
        const fb = document.getElementById('st-cc-launch-feedback');
        if (fb) {
            fb.innerHTML =
                '<span class="text-strong">Queued</span> · run <span class="mono-sm">#' +
                esc(String(rid)) +
                '</span>' +
                (wjid > 0 ? ' · worker job <span class="mono-sm">#' + esc(String(wjid)) + '</span>' : '') +
                ' <span class="text-dim">Starting…</span>';
        }
        await stCcLoadJobsAndRuns();
        stCcMaybeStartRunPoll();
        if (rid > 0) {
            void stCcRunOpenModal(rid);
        }
    } else {
        toast((r && r.error) ? r.error : 'Launch failed', 'err');
    }
}

function stCcParseRunSummaryJson(raw) {
    if (raw == null || raw === '') return null;
    try {
        return JSON.parse(String(raw));
    } catch {
        const s = String(raw);
        return { _unparsed: s.length > 480 ? s.slice(0, 480) + '…' : s };
    }
}

function stCcPrettyMaybeJson(raw) {
    const s = String(raw || '');
    if (!s) return '';
    try {
        return JSON.stringify(JSON.parse(s), null, 2);
    } catch {
        return s;
    }
}

function stCcToggleNormPrev(btn) {
    if (!btn || !btn.parentElement) return;
    const wrap = btn.parentElement;
    const pre = wrap.querySelector('.st-cc-prev-full');
    if (!pre) return;
    const open = pre.classList.contains('hide');
    pre.classList.toggle('hide', !open);
    btn.setAttribute('aria-expanded', open ? 'true' : 'false');
    btn.textContent = open ? 'Hide details' : 'View details';
}

function stCcRunStatusBadgeHtml(status, opts) {
    opts = opts && typeof opts === 'object' ? opts : {};
    const ro = String(opts.run_outcome || '');
    const st = String(status || '').toLowerCase();
    let cls = 'st-cc-run-badge';
    let label = String(status || '—');
    if (st === 'completed' && ro === 'partial') {
        cls += ' st-cc-run-badge--warn';
        label = 'completed (partial)';
    } else if (st === 'completed' && ro === 'failed') {
        cls += ' st-cc-run-badge--bad';
        label = 'all plugins failed';
    } else if (st === 'completed') {
        cls += ' st-cc-run-badge--ok';
    } else if (st === 'failed' || st === 'cancelled') {
        cls += ' st-cc-run-badge--bad';
    } else if (st === 'running' || st === 'queued' || st === 'ready' || st === 'resolving_targets') {
        cls += ' st-cc-run-badge--act';
    }
    return `<span class="${cls}">${esc(label)}</span>`;
}

async function stCcRunOpenModal(runId) {
    if (!stRoleIsAdmin() || runId < 1) return;
    __stCcRunModalId = runId;
    window.__stCcRunFetchGen = (window.__stCcRunFetchGen || 0) + 1;
    const fetchGen = window.__stCcRunFetchGen;
    const bg = document.getElementById('st-cc-run-modal-bg');
    const box = document.getElementById('st-cc-run-detail');
    const btn = document.getElementById('st-cc-run-btn-cancel');
    if (!bg || !box) return;
    box.innerHTML = '<p class="text-dim mb0">Loading…</p>';
    bg.style.display = 'flex';
    const dbg = stRoleIsAdmin() ? '&debug=1' : '';
    const r = await api(
        '/api/credential_check_runs.php?id=' + encodeURIComponent(String(runId)) + dbg + '&events=1'
    );
    if (fetchGen !== window.__stCcRunFetchGen) {
        return;
    }
    if (!r || !r.ok || !r.run) {
        box.innerHTML = '<p class="text-dim mb0">Could not load run.</p>';
        if (btn) btn.style.display = 'none';
        return;
    }
    const run = r.run;
    const st = String(run.status || '');
    if (btn) btn.style.display = st === 'queued' || st === 'running' || st === 'resolving_targets' || st === 'ready' ? '' : 'none';
    const tc = run.target_counts || {};
    const rc = run.result_counts || {};
    const dur = stFmtDurationMs(run.duration_ms);
    const partialN = parseInt(String(rc.partial ?? 0), 10) || 0;
    const failN = parseInt(String(rc.failed ?? 0), 10) || 0;
    const planned = Array.isArray(run.job_plugins_planned) ? run.job_plugins_planned : [];
    const plannedLine = planned.length ? planned.map((p) => `<span class="mono-sm">${esc(String(p))}</span>`).join(' ') : '<span class="text-dim">—</span>';
    const sumPub = run.summary_public && typeof run.summary_public === 'object' ? run.summary_public : null;
    const sumKeys = sumPub ? Object.keys(sumPub) : [];
    let sumHtml = '';
    if (sumKeys.length) {
        const rows = sumKeys
            .sort()
            .map((k) => `<tr><td class="text-dim mono-sm">${esc(k)}</td><td class="st-host-evidence-cell-raw">${esc(JSON.stringify(sumPub[k]))}</td></tr>`)
            .join('');
        sumHtml = rows ? `<div class="tbl-wrap tbl-wrap--compact mt6"><table class="tbl tbl--compact st-cc-run-sum-tbl"><tbody>${rows}</tbody></table></div>` : '';
    } else {
        const sumLegacy = stCcParseRunSummaryJson(run.summary_json);
        if (sumLegacy && typeof sumLegacy === 'object' && !sumLegacy._unparsed) {
            const hide = new Set(['slice', 'executor', 'job_id', 'credential_profile_id']);
            const rows = Object.keys(sumLegacy)
                .filter((k) => !hide.has(k))
                .filter((k) => {
                    if (k === 'placeholder_only' && !sumLegacy[k]) return false;
                    if (k === 'plugins_placeholder' && (!Array.isArray(sumLegacy[k]) || sumLegacy[k].length === 0)) return false;
                    return true;
                })
                .sort()
                .map((k) => `<tr><td class="text-dim mono-sm">${esc(k)}</td><td class="st-host-evidence-cell-raw">${esc(JSON.stringify(sumLegacy[k]))}</td></tr>`)
                .join('');
            sumHtml = rows ? `<div class="tbl-wrap tbl-wrap--compact mt6"><table class="tbl tbl--compact st-cc-run-sum-tbl"><tbody>${rows}</tbody></table></div>` : '';
        } else if (sumLegacy && sumLegacy._unparsed) {
            sumHtml = `<p class="hint-micro text-dim mb0 mt6">Summary unavailable as structured fields (${esc(String(sumLegacy._unparsed))}).</p>`;
        }
    }
    const headline = run.run_headline != null && String(run.run_headline).trim()
        ? `<p class="text-strong mb0 mt6">${esc(String(run.run_headline))}</p>`
        : '';
    const errHint =
        failN > 0 || String(st) === 'failed' || String(run.run_outcome || '') === 'failed' || String(run.run_outcome || '') === 'partial'
            ? `<p class="hint-micro st-cc-run-err-hint mt6 mb0">Inspect per-target plugin summaries and bounded normalized previews (no raw stderr or artifact bodies).</p>`
            : '';
    const opNotes = Array.isArray(run.run_operational_notes) ? run.run_operational_notes : [];
    const opNotesHtml = opNotes.length
        ? `<ul class="hint-micro st-cc-run-op-notes mt4 mb0" style="padding-left:1.2rem">${opNotes
              .map((n) => `<li class="mb4">${esc(String(n))}</li>`)
              .join('')}</ul>`
        : '';

    const tlm = run.timeline && Array.isArray(run.timeline) ? run.timeline : [];
    const tlmMeta = run.timeline_meta && typeof run.timeline_meta === 'object' ? run.timeline_meta : null;
    let tlmBlock = '';
    if (tlm.length) {
        const rows = tlm
            .map((ev) => {
                const src = esc(String(ev.source || ''));
                const at = ev.at ? esc(localTime(String(ev.at))) : '—';
                const lbl = esc(String(ev.label || ''));
                const det =
                    ev.detail && typeof ev.detail === 'object' && Object.keys(ev.detail).length
                        ? `<div class="mono-sm text-dim mt2">${esc(JSON.stringify(ev.detail))}</div>`
                        : '';
                const lvl = ev.level ? `<span class="text-dim">[${esc(String(ev.level))}]</span> ` : '';
                return `<li class="mb6"><div class="text-dim mono-sm">${at} · ${src}</div><div>${lvl}${lbl}</div>${det}</li>`;
            })
            .join('');
        const trunc =
            tlmMeta && tlmMeta.truncated
                ? '<p class="hint-micro text-dim mb0">Showing the latest 50 events (merged audit log + worker job events).</p>'
                : '';
        tlmBlock = `<div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Activity timeline</div>${trunc}<ol class="mb0 mt6" style="padding-left:1.2rem">${rows}</ol></div>`;
    } else {
        tlmBlock = `<div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Activity timeline</div><p class="text-dim hint-micro mb0">No timeline entries yet (audit + worker events appear as the run progresses).</p></div>`;
    }

    const tgtRows = (Array.isArray(run.targets) ? run.targets : []).map((t) => {
        const safeErr = t.error_message_safe != null && String(t.error_message_safe).trim()
            ? `<div class="text-dim mono-sm">${esc(String(t.error_message_safe))}</div>`
            : '';
        const ec = t.error_code ? `<span class="mono-sm">${esc(String(t.error_code))}</span>` : '';
        const plugSum = t.plugin_result_summary != null && String(t.plugin_result_summary).trim()
            ? `<span class="mono-sm text-dim">${esc(String(t.plugin_result_summary))}</span>`
            : '<span class="text-dim">—</span>';
        return `<tr>
          <td class="mono-sm">${esc(String(t.id))}</td>
          <td class="mono-sm">${esc(String(t.asset_id))}</td>
          <td class="mono-sm">${esc(String(t.asset_ip || ''))}</td>
          <td>${stCcRunStatusBadgeHtml(t.status)}</td>
          <td>${plugSum}</td>
          <td>${ec}</td>
          <td class="st-host-evidence-cell-raw">${safeErr || '—'}</td>
        </tr>`;
    }).join('');
    const tgtBlock = tgtRows
        ? `<div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-cc-run-detail-tbl"><thead><tr><th>ID</th><th>Asset</th><th>IP</th><th>Status</th><th>Plugins</th><th>Code</th><th>Safe error</th></tr></thead><tbody>${tgtRows}</tbody></table></div>`
        : '<p class="text-dim mb0">No targets.</p>';

    const oneResRow = (x) => {
        const stB = String(x.status || '').toLowerCase() === 'partial'
            ? `${stCcRunStatusBadgeHtml(x.status)} <span class="st-cc-pill st-cc-pill--warn">partial</span>`
            : stCcRunStatusBadgeHtml(x.status);
        const pvRaw = x.normalized_preview != null ? String(x.normalized_preview) : '';
        const pvEsc = pvRaw ? esc(pvRaw) : '—';
        const detAvail = !!x.normalized_detail_available && x.normalized_detail_json != null && String(x.normalized_detail_json).trim() !== '';
        let pvCell = `<span class="mono-sm">${pvEsc}</span>`;
        if (detAvail) {
            const fullEsc = esc(stCcPrettyMaybeJson(String(x.normalized_detail_json)));
            pvCell = `<div class="st-cc-prev-wrap"><div class="mono-sm st-cc-prev-short">${pvEsc}</div>
            <button type="button" class="tbtn btn-xs mt2" aria-expanded="false" onclick="stCcToggleNormPrev(this)">View details</button>
            <pre class="st-cc-prev-full hide mono-sm mt4 text-dim" style="white-space:pre-wrap;max-height:260px;overflow:auto">${fullEsc}</pre></div>`;
        }
        return `<tr>
          <td class="mono-sm">${esc(String(x.plugin_key || ''))}@${esc(String(x.plugin_version || ''))}</td>
          <td>${stB}</td>
          <td class="st-cc-norm-prev">${pvCell}</td>
        </tr>`;
    };
    const rbT = Array.isArray(run.results_by_target) ? run.results_by_target : [];
    let resBlock = '';
    if (rbT.length) {
        resBlock = rbT
            .map((grp) => {
                const host =
                    (grp.asset_hostname && String(grp.asset_hostname).trim()) ||
                    (grp.asset_ip && String(grp.asset_ip).trim()) ||
                    'target ' + String(grp.target_id || '');
                const subRows = (Array.isArray(grp.rows) ? grp.rows : []).map(oneResRow).join('');
                const sumG = grp.plugin_result_summary ? esc(String(grp.plugin_result_summary)) : '';
                const tbl = subRows
                    ? `<table class="tbl tbl--compact st-cc-run-detail-tbl mt4"><thead><tr><th>Plugin</th><th>Status</th><th>Normalized preview</th></tr></thead><tbody>${subRows}</tbody></table>`
                    : '<p class="text-dim hint-micro mb0 mt4">No plugin rows for this target.</p>';
                return `<div class="st-cc-run-target-prev mb10 pb10" style="border-bottom:1px solid var(--border)"><div class="mono-sm">${esc(
                    host,
                )}${sumG ? ` <span class="text-dim">· ${sumG}</span>` : ''}</div>${tbl}</div>`;
            })
            .join('');
    } else {
        const resRows = (Array.isArray(run.results) ? run.results : []).map(oneResRow).join('');
        resBlock = resRows
            ? `<div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-cc-run-detail-tbl"><thead><tr><th>Plugin</th><th>Status</th><th>Normalized preview</th></tr></thead><tbody>${resRows}</tbody></table></div>`
            : '<p class="text-dim mb0">No result rows.</p>';
    }

    const osum = run.observations_summary && typeof run.observations_summary === 'object' ? run.observations_summary : null;
    const otypes = osum && osum.counts_by_type && typeof osum.counts_by_type === 'object' ? osum.counts_by_type : {};
    const typeKeys = Object.keys(otypes).sort();
    const countRows = typeKeys
        .map((t) => `<tr><td class="mono-sm">${esc(t)}</td><td>${esc(String(otypes[t]))}</td></tr>`)
        .join('');
    const invSnaps = osum && Array.isArray(osum.software_inventory_snapshots) ? osum.software_inventory_snapshots : [];
    const snapRows = invSnaps
        .map((s) => {
            const pm = s.package_manager != null ? esc(String(s.package_manager)) : '—';
            const pc = s.package_count != null ? esc(String(s.package_count)) : '—';
            const pa = s.packages_added != null ? esc(String(s.packages_added)) : '—';
            const pr = s.packages_removed != null ? esc(String(s.packages_removed)) : '—';
            const pv = s.packages_changed != null ? esc(String(s.packages_changed)) : '—';
            const ast = s.active_rows_after != null ? esc(String(s.active_rows_after)) : '—';
            const at = s.observed_at ? esc(localTime(String(s.observed_at))) : '—';
            return `<tr><td class="mono-sm">${esc(String(s.asset_id || ''))}</td><td>${pm}</td><td>${pc}</td><td>${pa}</td><td>${pr}</td><td>${pv}</td><td>${ast}</td><td class="text-dim">${at}</td></tr>`;
        })
        .join('');
    const obsNote = osum && osum.software_observed_note ? `<p class="hint-micro text-dim mb6">${esc(String(osum.software_observed_note))}</p>` : '';
    let obsBlock = '';
    if (!typeKeys.length) {
        obsBlock = '<p class="text-dim mb0">No reconciled observations linked to this run (or reconciliation unavailable).</p>';
    } else {
        const tbl = countRows
            ? `<div class="tbl-wrap tbl-wrap--compact mb6"><table class="tbl tbl--compact st-cc-run-detail-tbl"><thead><tr><th>observation_type</th><th>count</th></tr></thead><tbody>${countRows}</tbody></table></div>`
            : '';
        const snapTbl =
            snapRows !== ''
                ? `<div class="text-micro text-dim mt6 mb4">Software inventory snapshots (<span class="mono-sm">software_inventory_snapshot_observed</span>) — diff vs prior active state</div>
            <div class="tbl-wrap tbl-wrap--compact mb6"><table class="tbl tbl--compact st-cc-run-detail-tbl"><thead><tr><th>Asset</th><th>PM</th><th>Count</th><th>+</th><th>−</th><th>~ver</th><th>Active rows</th><th>Observed</th></tr></thead><tbody>${snapRows}</tbody></table></div>`
                : '';
        obsBlock = `${obsNote}${tbl}${snapTbl}`;
    }

    const arts = Array.isArray(run.artifact_summaries) ? run.artifact_summaries : [];
    const artRows = arts.map((a) => {
        const sha = a.sha256 != null ? String(a.sha256) : '';
        const shaShort = sha.length > 14 ? sha.slice(0, 12) + '…' : sha;
        return `<tr>
          <td class="mono-sm">${esc(String(a.id))}</td>
          <td>${esc(String(a.kind || ''))}</td>
          <td class="mono-sm">${esc(shaShort)}</td>
          <td class="text-dim">${a.size_bytes != null ? esc(String(a.size_bytes)) : '—'}</td>
        </tr>`;
    }).join('');
    const artBlock = artRows
        ? `<div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-cc-run-detail-tbl"><thead><tr><th>ID</th><th>Kind</th><th>SHA256</th><th>Bytes</th></tr></thead><tbody>${artRows}</tbody></table></div>`
        : '<p class="text-dim mb0">No artifact rows (or none in cap).</p>';

    const vf = run.vulnerability_inventory_followup && typeof run.vulnerability_inventory_followup === 'object' ? run.vulnerability_inventory_followup : null;
    let vfBlock = '';
    if (vf) {
        const aids = Array.isArray(vf.target_asset_ids) ? vf.target_asset_ids.map((x) => esc(String(x))).join(', ') : '';
        const tblRows = [
            ['Target asset id(s)', aids || '—'],
            ['Package inventory (this run)', vf.had_package_inventory_success ? 'success recorded' : 'no success row'],
            ['Active normalized catalog rows (those assets)', vf.active_normalized_inventory_rows != null ? String(vf.active_normalized_inventory_rows) : '—'],
            ['Vendor_distro package rules (DB)', vf.vendor_distro_package_rule_count != null ? String(vf.vendor_distro_package_rule_count) : '—'],
            ['Ubuntu vendor package rules', vf.ubuntu_vendor_package_rules != null ? String(vf.ubuntu_vendor_package_rules) : '—'],
            ['Ubuntu advisories last DB update', vf.ubuntu_advisories_last_updated_at != null ? esc(localTime(String(vf.ubuntu_advisories_last_updated_at))) : '—'],
            ['Open findings (those assets)', vf.open_affected_findings_on_targets != null ? String(vf.open_affected_findings_on_targets) : '—'],
            ['Correlation jobs queued (those assets)', vf.correlation_jobs_pending_for_targets != null ? String(vf.correlation_jobs_pending_for_targets) : '—'],
        ]
            .map(([k, v]) => `<tr><td class="text-dim tbl-cell-primary">${esc(String(k))}</td><td class="mono-sm">${esc(String(v))}</td></tr>`)
            .join('');
        const hints = Array.isArray(vf.viewer_hints) ? vf.viewer_hints : [];
        const hintUl =
            hints.length > 0
                ? `<ul class="hint-micro text-dim mt6 mb0" style="padding-left:1.2rem">${hints.map((x) => `<li>${esc(String(x))}</li>`).join('')}</ul>`
                : '';
        const sumLine = vf.summary ? `<p class="hint-micro mb6">${esc(String(vf.summary))}</p>` : '';
        vfBlock = `<div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Vulnerability correlation (offline)</div>
          <p class="hint-micro text-dim mb6">SSH inventory is normalized into the software catalog; SurveyTrace then compares each active package row to locally imported vendor advisories (for example Ubuntu OVAL). CVE-level rows appear under <strong>Vulnerabilities</strong> and on each host’s <strong>Vulnerabilities</strong> tab — not inside this run’s plugin previews.</p>
          ${sumLine}
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-cc-run-detail-tbl"><tbody>${tblRows}</tbody></table></div>
          ${hintUl}
          <div class="mt8 row-wrap gap6">
            <button type="button" class="tbtn" onclick="stCcRunCloseModal();goTab('vulns');">Open Vulnerabilities</button>
            <button type="button" class="tbtn tbtn--ghost" onclick="stCcRunCloseModal();goTab('health');">System health</button>
          </div>
        </div>`;
    }

    const wj = run.worker_debug && typeof run.worker_debug === 'object' ? run.worker_debug : null;
    let wjBlock = '';
    if (stRoleIsAdmin() && wj) {
        wjBlock = `<div class="st-cc-run-sec st-cc-run-sec--debug mt10">
          <div class="st-cc-run-sec-title">Admin — worker job</div>
          <div class="tbl-wrap tbl-wrap--compact"><table class="tbl tbl--compact st-cc-run-detail-tbl"><tbody>
            <tr><td class="text-dim">worker_job_id</td><td class="mono-sm">${esc(String(wj.id ?? '—'))}</td></tr>
            <tr><td class="text-dim">status</td><td class="mono-sm">${esc(String(wj.status ?? '—'))}</td></tr>
            <tr><td class="text-dim">attempts / max</td><td class="mono-sm">${esc(String(wj.attempts ?? '—'))} / ${esc(String(wj.max_attempts ?? '—'))}</td></tr>
            <tr><td class="text-dim">next_attempt_at</td><td class="mono-sm">${esc(String(wj.next_attempt_at ?? '—'))}</td></tr>
            <tr><td class="text-dim">leased_at / expires</td><td class="mono-sm">${esc(String(wj.leased_at ?? '—'))} · ${esc(String(wj.lease_expires_at ?? '—'))}</td></tr>
            <tr><td class="text-dim">created / updated / finished</td><td class="mono-sm">${esc(String(wj.created_at ?? '—'))} · ${esc(String(wj.updated_at ?? '—'))} · ${esc(String(wj.finished_at ?? '—'))}</td></tr>
            <tr><td class="text-dim">cancel_requested_at</td><td class="mono-sm">${esc(String(wj.cancel_requested_at ?? '—'))}</td></tr>
            <tr><td class="text-dim">error_code</td><td class="mono-sm">${esc(String(wj.error_code ?? '—'))}</td></tr>
          </tbody></table></div>
        </div>`;
    }

    const retNote = run.retention_note ? `<p class="hint-micro text-dim mt8 mb0">${esc(String(run.retention_note))}</p>` : '';
    const trigSrc = String(run.launch_source || 'manual').toLowerCase() === 'scheduled' ? 'scheduled' : 'manual';
    const trigLine = `<p class="hint-micro text-dim mb0 mt4">Trigger: <span class="mono-sm">${esc(trigSrc)}</span> (manual UI/API vs surveytrace-scheduler)</p>`;

    box.innerHTML = `
      <div class="st-cc-run-head row-wrap gap8 align-center">
        <span class="text-strong">Run #${esc(String(run.id))}</span>
        ${stCcRunStatusBadgeHtml(run.status, { run_outcome: String(run.run_outcome || '') })}
        <span class="text-dim mono-sm">job ${esc(String(run.job_id || '—'))}</span>
        <span class="text-dim">duration ${esc(dur)}</span>
        ${partialN > 0 ? '<span class="st-cc-pill st-cc-pill--warn">partial results</span>' : ''}
      </div>
      ${headline}
      ${trigLine}
      <p class="hint-micro text-dim mb0 mt4">${esc(String(run.job_name || ''))}${run.profile_name != null ? ` · ${esc(String(run.profile_name))}` : ''}${run.profile_transport != null ? ` <span class="mono-sm">(${esc(String(run.profile_transport))})</span>` : ''}</p>
      <p class="hint-micro text-dim mb0 mt4">Planned plugins: ${plannedLine}</p>
      <p class="hint-micro text-dim mb0">Started ${run.started_at ? esc(localTime(String(run.started_at))) : '—'} · Finished ${run.finished_at ? esc(localTime(String(run.finished_at))) : '—'}</p>
      <p class="hint-micro text-dim mb0">Targets: pending ${esc(String(tc.pending ?? 0))} · running ${esc(String(tc.running ?? 0))} · completed ${esc(String(tc.completed ?? 0))} · failed ${esc(String(tc.failed ?? 0))} · skipped ${esc(String(tc.skipped ?? 0))}
        · Results: ok ${esc(String(rc.success ?? 0))} · partial ${esc(String(rc.partial ?? 0))} · failed ${esc(String(rc.failed ?? 0))}</p>
      ${errHint}
      ${opNotesHtml}
      ${sumHtml ? `<div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Run summary</div>${sumHtml}</div>` : ''}
      ${tlmBlock}
      <div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Targets</div>${tgtBlock}</div>
      <div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Normalized previews</div>${resBlock}</div>
      <div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Observations (reconciliation)</div>${obsBlock}</div>
      ${vfBlock}
      <div class="st-cc-run-sec mt10"><div class="st-cc-run-sec-title">Artifact metadata</div>${artBlock}</div>
      ${wjBlock}
      ${retNote}
    `;
}

async function stCcRunCancelCurrent() {
    const id = __stCcRunModalId;
    if (id < 1) return;
    const okCancel = await showConfirmModal('Cancel this run? Targets already completed stay recorded; in-flight work stops when the worker observes cancellation.', {
        title: 'Cancel run',
        okText: 'Cancel run',
        cancelText: 'Keep running',
    });
    if (!okCancel) return;
    const r = await apiPost('/api/credential_check_runs.php', { action: 'cancel', run_id: id });
    if (r && r.ok) {
        const note = r.run && r.run.cancel_note ? String(r.run.cancel_note) : 'Cancelled.';
        toast(note, 'ok');
        await stCcRunOpenModal(id);
        await stCcLoadJobsAndRuns();
    } else {
        toast((r && r.error) ? r.error : 'Cancel failed', 'err');
    }
}

async function stCcRunCancelFromList(runId) {
    const id = parseInt(String(runId), 10);
    if (!stRoleIsAdmin() || id < 1) return;
    const okCancel = await showConfirmModal('Cancel this run? Pending targets stop when the worker observes cancellation; completed targets stay recorded.', {
        title: 'Cancel run',
        okText: 'Cancel run',
        cancelText: 'Keep running',
    });
    if (!okCancel) return;
    const r = await apiPost('/api/credential_check_runs.php', { action: 'cancel', run_id: id });
    if (r && r.ok) {
        const fb = document.getElementById('st-cc-launch-feedback');
        const mode = r.run && r.run.cancel_mode ? String(r.run.cancel_mode) : '';
        const line =
            mode === 'running_inflight'
                ? 'Run #' + esc(String(id)) + ' — cancel sent while <strong>running</strong>; worker will stop in-flight work when it observes cancellation.'
                : 'Run #' + esc(String(id)) + ' — cancelled while <strong>queued / not executing</strong>; pending targets marked skipped.';
        if (fb) {
            fb.innerHTML = '<span class="text-dim">' + line + '</span>';
        }
        await stCcLoadJobsAndRuns();
        if (__stCcRunModalId === id) {
            await stCcRunOpenModal(id);
        }
    } else {
        toast((r && r.error) ? r.error : 'Cancel failed', 'err');
    }
}

function stCcRunsClearFilters() {
    const a = document.getElementById('st-cc-runs-filter-status');
    const b = document.getElementById('st-cc-runs-filter-transport');
    const c = document.getElementById('st-cc-runs-filter-profile');
    const d = document.getElementById('st-cc-runs-filter-plugin');
    if (a) a.value = '';
    if (b) b.value = '';
    if (c) c.value = '0';
    if (d) d.value = '';
    void stCcLoadJobsAndRuns();
}

async function stCcLoadJobsAndRuns() {
    const st = document.getElementById('st-cc-jobs-status');
    const tbJ = document.getElementById('st-cc-jobs-tbody');
    const tbR = document.getElementById('st-cc-runs-tbody');
    const fpSel = document.getElementById('st-cc-runs-filter-profile');
    if (!stRoleIsAdmin() || !tbJ || !tbR) {
        stCcStopRunPoll();
        return;
    }
    if (st) st.textContent = '';
    if (fpSel && fpSel.dataset.loaded !== '1') {
        const pr = await api('/api/credential_profiles.php');
        if (pr && pr.ok && Array.isArray(pr.profiles)) {
            const keep = fpSel.value;
            fpSel.innerHTML = '<option value="0">All profiles</option>' + pr.profiles.map((p) =>
                `<option value="${esc(String(p.id))}">${esc(String(p.name || ''))}</option>`
            ).join('');
            fpSel.value = keep && [...fpSel.options].some((o) => o.value === keep) ? keep : '0';
            fpSel.dataset.loaded = '1';
        }
    }
    const qs = new URLSearchParams();
    qs.set('limit', '80');
    const fSt = document.getElementById('st-cc-runs-filter-status');
    const fTr = document.getElementById('st-cc-runs-filter-transport');
    const fPr = document.getElementById('st-cc-runs-filter-profile');
    const fPl = document.getElementById('st-cc-runs-filter-plugin');
    if (fSt && fSt.value) qs.set('status', fSt.value);
    if (fTr && fTr.value) qs.set('transport', fTr.value);
    if (fPr && fPr.value && fPr.value !== '0') qs.set('profile_id', fPr.value);
    if (fPl && fPl.value.trim()) qs.set('plugin', fPl.value.trim());
    const [rj, rr] = await Promise.all([
        api('/api/credential_check_jobs.php'),
        api('/api/credential_check_runs.php?' + qs.toString()),
    ]);
    if (!rj || !rj.ok) {
        tbJ.innerHTML = '<tr><td colspan="8" class="text-dim">Could not load jobs.</td></tr>';
    } else {
        const jobs = rj.jobs || [];
        window.__stCcJobsCache = jobs;
        stCcRenderOperationalSummary();
        if (!jobs.length) {
            tbJ.innerHTML = '<tr><td colspan="8" class="text-dim">No jobs yet.</td></tr>';
        } else {
            tbJ.innerHTML = jobs
                .map((j) => {
                    const id = Number(j.id);
                    const on = j.enabled ? 'yes' : 'no';
                    const sch = j.schedule_enabled ? esc(String(j.schedule_cron || 'on')) : '—';
                    const nx = j.schedule_next_run_at != null && String(j.schedule_next_run_at).trim()
                        ? esc(String(j.schedule_next_run_at)) + ' <span class="text-dim">UTC</span>'
                        : '—';
                    const lr = j.schedule_last_run_at != null && String(j.schedule_last_run_at).trim()
                        ? esc(String(j.schedule_last_run_at)) + ' <span class="text-dim">UTC</span>'
                        : '—';
                    return `<tr>
            <td>${esc(String(j.name || ''))}</td>
            <td class="text-dim">${esc(String(j.profile_name || ''))} <span class="mono-sm">(${esc(String(j.profile_transport || ''))})</span></td>
            <td class="mono-sm">${esc(String(j.target_mode || ''))}</td>
            <td>${esc(on)}</td>
            <td class="mono-sm">${sch}</td>
            <td class="mono-sm">${nx}</td>
            <td class="mono-sm">${lr}</td>
            <td class="row-wrap gap4" style="white-space:nowrap">
              <button type="button" class="tbtn btn-xs" onclick="stCcJobOpenModal(${id})">Edit</button>
              <button type="button" class="tbtn btn-xs" onclick="stCcLaunchRun(${id})">Run now</button>
              <button type="button" class="tbtn btn-xs" onclick="stCcJobDelete(${id})">Delete</button>
            </td>
          </tr>`;
                })
                .join('');
        }
    }
    if (!rr || !rr.ok) {
        tbR.innerHTML = '<tr><td colspan="12" class="text-dim">Could not load runs.</td></tr>';
    } else {
        const runs = rr.runs || [];
        window.__stCcRunsListCache = runs;
        stCcRenderOperationalSummary();
        if (!runs.length) {
            tbR.innerHTML = '<tr><td colspan="12" class="text-dim">No runs match filters.</td></tr>';
        } else {
            tbR.innerHTML = runs
                .map((u) => {
                    const id = Number(u.id);
                    const wj = u.worker_job_id != null ? esc(String(u.worker_job_id)) : '—';
                    const prof = esc(String(u.profile_name || '—'));
                    const tr = esc(String(u.profile_transport || ''));
                    const profCell =
                        tr !== ''
                            ? `${prof} <span class="mono-sm text-dim">(${tr})</span>`
                            : prof;
                    const plug = esc(String(u.plugin_summary || '—'));
                    const trig = String(u.launch_source || 'manual').toLowerCase() === 'scheduled' ? 'scheduled' : 'manual';
                    const tot = parseInt(String(u.targets_total ?? 0), 10) || 0;
                    const done = parseInt(String(u.targets_completed ?? 0), 10) || 0;
                    const failT = parseInt(String(u.targets_failed ?? 0), 10) || 0;
                    const runT = parseInt(String(u.targets_running ?? 0), 10) || 0;
                    const pend = parseInt(String(u.targets_pending ?? 0), 10) || 0;
                    const succR = parseInt(String(u.result_success_count ?? 0), 10) || 0;
                    const partialR = parseInt(String(u.result_partial_count ?? 0), 10) || 0;
                    const failR = parseInt(String(u.result_failed_count ?? 0), 10) || 0;
                    const dur = stFmtDurationMs(u.duration_ms);
                    const stLow = String(u.status || '').toLowerCase();
                    const ro = String(u.run_outcome || '');
                    const errVis =
                        stLow === 'failed' || ro === 'failed' || failT > 0 || (failR > 0 && succR === 0 && partialR === 0)
                            ? '<span class="st-cc-pill st-cc-pill--bad" title="Target or plugin failures">err</span>'
                            : '';
                    const partVis =
                        (ro === 'partial' || (partialR > 0 && succR > 0) || (failR > 0 && succR + partialR > 0)) && stLow !== 'failed'
                            ? '<span class="st-cc-pill st-cc-pill--warn" title="Mixed plugin outcomes">partial</span>'
                            : '';
                    let tgtExtra = '';
                    if (runT > 0) {
                        tgtExtra += ` <span class="st-cc-pill st-cc-pill--act" title="Target in progress">${runT} active</span>`;
                    }
                    if (pend > 0 && stLow !== 'completed' && stLow !== 'failed' && stLow !== 'cancelled') {
                        tgtExtra += ` <span class="text-dim">${pend} pending</span>`;
                    }
                    const canCancel = stLow === 'queued' || stLow === 'resolving_targets' || stLow === 'ready' || stLow === 'running';
                    const cancelBtn = canCancel
                        ? `<button type="button" class="tbtn btn-xs" onclick="stCcRunCancelFromList(${id})">Cancel</button>`
                        : '';
                    return `<tr>
            <td class="mono-sm">${id}</td>
            <td>${esc(String(u.job_name || ''))}</td>
            <td class="row-wrap">${profCell}</td>
            <td class="mono-sm row-wrap">${plug}</td>
            <td class="row-wrap gap4">${stCcRunStatusBadgeHtml(u.status, { run_outcome: ro })} ${errVis} ${partVis}</td>
            <td class="mono-sm">${esc(trig)}</td>
            <td class="mono-sm">${esc(String(done))}/${esc(String(tot))}${failT > 0 ? ` <span class="text-dim">(${esc(String(failT))} fail)</span>` : ''}${tgtExtra}</td>
            <td class="mono-sm">${esc(dur)}</td>
            <td class="mono-sm">${wj}</td>
            <td class="text-dim mono-sm">${esc(String(u.started_at || ''))}</td>
            <td class="text-dim mono-sm">${u.finished_at ? esc(localTime(String(u.finished_at))) : '—'}</td>
            <td class="row-wrap gap4" style="white-space:nowrap"><button type="button" class="tbtn btn-xs" onclick="stCcRunOpenModal(${id})">Detail</button> ${cancelBtn}</td>
          </tr>`;
                })
                .join('');
        }
    }
    stCcMaybeStartRunPoll();
}

function stCcSummaryTile(label, value, subtext, tone, titleAttr) {
    const t = tone ? ' st-cc-summary-chip--' + tone : '';
    const sub = subtext ? `<div class="st-cc-summary-chip-note">${esc(String(subtext))}</div>` : '';
    const title = titleAttr ? esc(String(titleAttr)) : '';
    return `<div class="st-cc-summary-chip${t}" role="listitem" aria-label="${esc(String(label + ': ' + value))}"${title ? ` title="${title}"` : ''}>
      <div class="st-cc-summary-chip-label">${esc(String(label))}</div>
      <div class="st-cc-summary-chip-value">${esc(String(value))}</div>
      ${sub}
    </div>`;
}

function stCcRenderOperationalSummary() {
    const host = document.getElementById('st-cc-summary-strip');
    if (!host) return;
    const profiles = Array.isArray(window.__stCredProfilesCache) ? window.__stCredProfilesCache : [];
    const jobs = Array.isArray(window.__stCcJobsCache) ? window.__stCcJobsCache : [];
    const hh = window.__stCcOpsHealthCache && typeof window.__stCcOpsHealthCache === 'object' ? window.__stCcOpsHealthCache : {};
    const cc = hh.credential_check_runs && typeof hh.credential_check_runs === 'object' ? hh.credential_check_runs : {};
    const ws = hh.worker_substrate && typeof hh.worker_substrate === 'object' ? hh.worker_substrate : {};
    const maint = hh.maintenance && typeof hh.maintenance === 'object' ? hh.maintenance : {};

    const profilesTotal = profiles.length;
    const profilesSecrets = profiles.filter((p) => !!p && stCredProfileHasStoredSecret(p)).length;
    const jobsTotal = jobs.length;
    const jobsEnabled = jobs.filter((j) => !!j && !!j.enabled).length;
    const completed24 = parseInt(String(cc.completed_recent_24h ?? 0), 10) || 0;
    const failed24 = parseInt(String(cc.failed_recent_24h ?? 0), 10) || 0;
    const partial24 = parseInt(String(cc.partial_results_recent_24h ?? 0), 10) || 0;
    const queuedActive = parseInt(String(cc.queued_or_active ?? 0), 10) || 0;
    const oldestQueuedSec = ws.oldest_queued_age_sec != null ? (parseInt(String(ws.oldest_queued_age_sec), 10) || 0) : 0;
    const longestActiveRunSec =
        cc.longest_active_run_age_sec != null ? parseInt(String(cc.longest_active_run_age_sec), 10) || 0 : 0;
    const staleActive = parseInt(String(cc.stale_active_runs ?? 0), 10) || 0;
    const staleWorkerJobs = parseInt(String(maint.stale_worker_job_candidates ?? 0), 10) || 0;
    const lastOk = cc.last_successful_run_at ? stFmtUtcTs(cc.last_successful_run_at) : '—';

    const empty = profilesTotal === 0 && jobsTotal === 0 && completed24 === 0 && failed24 === 0 && queuedActive === 0;
    if (empty) {
        host.innerHTML = '<p class="hint-micro text-dim mb0">No credentialed-check activity yet. Add a profile, run a handshake test, then queue a job when ready.</p>';
        return;
    }

    const stuckQueued = queuedActive > 0 && oldestQueuedSec >= 10800;
    let queueSub = '—';
    if (queuedActive > 0 && longestActiveRunSec > 0) {
        queueSub = `oldest active run ${fmtDuration(longestActiveRunSec)}`;
    } else if (oldestQueuedSec > 0) {
        queueSub = `oldest queued ${fmtDuration(oldestQueuedSec)}`;
    }
    const runsTone = failed24 > 0 ? 'bad' : partial24 > 0 ? 'warn' : '';
    const runsSub = `${failed24} failed · ${partial24} partial`;
    const profTone = profilesTotal > 0 && profilesSecrets === 0 ? 'warn' : '';
    const queueTone = stuckQueued ? 'bad' : queuedActive > 0 ? 'warn' : '';
    const lastTone = lastOk === '—' ? 'warn' : '';

    const chips = [
        stCcSummaryTile('Profiles', String(profilesTotal), `${profilesSecrets} with secrets`, profTone, ''),
        stCcSummaryTile('Jobs', String(jobsEnabled), `${jobsTotal} total`, '', ''),
        stCcSummaryTile('Runs 24h', String(completed24), runsSub, runsTone, ''),
        stCcSummaryTile('Queue', String(queuedActive), queueSub, queueTone, stuckQueued ? 'Queue age warning at 3h+' : ''),
        stCcSummaryTile('Last success', lastOk, 'credentialed check', lastTone, ''),
    ];
    const states = [];
    if (failed24 > 0) states.push('Failed runs in last 24h');
    if (partial24 > 0) states.push('Partial results observed');
    if (staleActive > 0 || staleWorkerJobs > 0) states.push('Stale run/worker candidates present');
    if (stuckQueued) states.push('Queued work appears stuck');
    const stateLine = states.length
        ? `<p class="hint-micro mb0 st-cc-summary-state"><span class="st-cc-pill st-cc-pill--warn" aria-hidden="true">attention</span> ${esc(states.join(' · '))}</p>`
        : '<p class="hint-micro text-dim mb0 st-cc-summary-state">No active credentialed-check warnings in this snapshot.</p>';
    host.innerHTML = `<div class="st-cc-summary-chips" role="list" aria-label="Credentialed checks operational metrics">${chips.join('')}</div>${stateLine}`;
}

async function stCcLoadOperationalSummary(force) {
    if (!stRoleIsAdmin()) return;
    const now = Date.now();
    const last = parseInt(String(window.__stCcOpsHealthCacheAt || 0), 10) || 0;
    if (!force && window.__stCcOpsHealthCache && (now - last) < 30000) {
        stCcRenderOperationalSummary();
        return;
    }
    try {
        const h = await api('/api/health.php');
        if (h && h.ok) {
            window.__stCcOpsHealthCache = h;
            window.__stCcOpsHealthCacheAt = Date.now();
        }
    } catch (e) {}
    stCcRenderOperationalSummary();
}

async function saveSecurityControlsSettings() {
    let failedWarnMin = parseInt(String(document.getElementById('st-health-worker-failed-warn-min')?.value ?? '1'), 10);
    if (!Number.isFinite(failedWarnMin) || failedWarnMin < 0) failedWarnMin = 1;
    if (failedWarnMin > 1000000) failedWarnMin = 1000000;
    const body = {
        security_health_requires_scan_editor: !!document.getElementById('st-sec-health-scan-editor')?.checked,
        security_export_requires_scan_editor: !!document.getElementById('st-sec-export-scan-editor')?.checked,
        health_worker_substrate_warn_failed_jobs_min: failedWarnMin,
    };
    const r = await apiPost('/api/settings.php', body);
    if (r && r.ok) {
        toast('Security controls updated', 'ok');
        await loadUiSettings();
    } else {
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

async function savePasswordPolicy() {
    const body = {
        password_policy: {
            min_length: Number(document.getElementById('pp-min-len')?.value || 12),
            require_upper: !!document.getElementById('pp-upper')?.checked,
            require_lower: !!document.getElementById('pp-lower')?.checked,
