            require_symbol: !!document.getElementById('pp-symbol')?.checked,
        },
        password_hash_algo: document.getElementById('pp-hash-algo')?.value || 'argon2id',
        login_max_attempts: Number(document.getElementById('pp-max-attempts')?.value || 5),
        login_lockout_minutes: Number(document.getElementById('pp-lockout-min')?.value || 15),
    };
    const r = await apiPost('/api/settings.php', body);
    if (r && r.ok) {
        toast('Password policy updated', 'ok');
        await loadUiSettings();
    } else {
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

async function saveAccessControlSettings() {
    const body = {
        auth_mode: document.getElementById('st-auth-mode')?.value || 'session',
        oidc_enabled: !!document.getElementById('oidc-enabled')?.checked,
        oidc_issuer_url: document.getElementById('oidc-issuer-url')?.value || '',
        oidc_client_id: document.getElementById('oidc-client-id')?.value || '',
        oidc_client_secret: document.getElementById('oidc-client-secret')?.value || '',
        oidc_redirect_uri: document.getElementById('oidc-redirect-uri')?.value || '',
        oidc_role_claim: document.getElementById('oidc-role-claim')?.value || 'groups',
        oidc_role_map: document.getElementById('oidc-role-map')?.value || '',
        sso_role_source: document.getElementById('sso-role-source')?.value || 'surveytrace',
        breakglass_enabled: !!document.getElementById('breakglass-enabled')?.checked,
        breakglass_username: document.getElementById('breakglass-username')?.value || 'admin',
    };
    const r = await apiPost('/api/settings.php', body);
    if (r && r.ok) {
        const sec = document.getElementById('oidc-client-secret');
        if (sec) sec.value = '';
        updateAccessControlModeVisibility();
        toast('Access settings updated', 'ok');
        await initAuthMode();
    } else {
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

/** Optional email for admin user forms: empty string if blank or placeholder junk. */
function stNormalizeAdminUserEmail(raw) {
    const t = String(raw ?? '').trim();
    if (!t) return '';
    const l = t.toLowerCase();
    if (l === 'optional' || l === 'n/a' || l === 'na' || l === 'none') return '';
    return t;
}

async function loadAuthUsers() {
    const tbody = document.getElementById('auth-users-tbody');
    if (!tbody) return;
    const r = await api('/api/auth.php?users=1');
    if (!r || !r.ok) {
        tbody.innerHTML = '<tr><td colspan="7" class="text-dim st-access-empty">Role management unavailable for current account.</td></tr>';
        const liveTbody = document.getElementById('auth-live-tbody');
        if (liveTbody) liveTbody.innerHTML = '<tr><td colspan="5" class="text-dim st-access-empty">Live auth view unavailable for current account.</td></tr>';
        const auditTbody = document.getElementById('auth-audit-tbody');
        if (auditTbody) auditTbody.innerHTML = '<tr><td colspan="5" class="text-dim st-access-empty">Audit log unavailable for current account.</td></tr>';
        return;
    }
    const users = r.users || [];
    tbody.innerHTML = users.length ? users.map(u => {
      const roleCls = u.role === 'admin' ? 'st-access-user-row--admin' : (u.role === 'scan_editor' ? 'st-access-user-row--editor' : 'st-access-user-row--viewer');
      const rowCls = u.disabled ? 'st-access-user-row--disabled' : roleCls;
      return `
      <tr class="${rowCls}">
        <td><input class="finp" id="u-name-${u.id}" value="${esc(u.username)}"></td>
        <td><input class="finp" id="u-dn-${u.id}" value="${esc(u.display_name || '')}" placeholder="Optional"></td>
        <td><input class="finp" id="u-em-${u.id}" value="${esc(u.email || '')}" placeholder="Optional"></td>
        <td>
          <select class="finp" id="u-role-${u.id}">
            <option value="viewer"${u.role==='viewer'?' selected':''}>viewer</option>
            <option value="scan_editor"${u.role==='scan_editor'?' selected':''}>scan_editor</option>
            <option value="admin"${u.role==='admin'?' selected':''}>admin</option>
          </select>
        </td>
        <td class="mono-sm">${u.mfa_enabled ? 'enabled' : 'off'}</td>
        <td style="text-align:center;vertical-align:middle"><label class="tog tog--sm" title="Disabled"><input type="checkbox" id="u-dis-${u.id}" ${u.disabled ? 'checked' : ''}><div class="trk"></div><div class="tth"></div></label></td>
        <td class="tbl-cell-actions">
          <div class="user-row-actions st-access-user-row-actions">
            <button type="button" class="tbtn btn-xs" onclick="saveAuthUserQuick(${u.id})" title="Save account settings without changing password">Save</button>
            <button type="button" class="tbtn btn-xs" onclick="saveAuthUser(${u.id})" title="Set temporary password">Password</button>
            ${u.auth_source === 'local' && u.mfa_enabled ? `<button type="button" class="tbtn btn-xs" onclick="resetUserMfa(${u.id})">Clear MFA</button>` : ''}
            <button type="button" class="tbtn btn-xs st-access-user-action-delete" onclick="deleteAuthUser(${u.id})">Delete</button>
          </div>
        </td>
      </tr>`;
    }).join('')
      : '<tr><td colspan="7" class="text-dim st-access-empty">No local users yet. Create one account to establish local access policy and role ownership.</td></tr>';
    void Promise.allSettled([loadAuthLive(), loadAuthAudit()]);
}

function renderAuditAction(action) {
    const s = String(action || '');
    if (!s) return 'event';
    return s.replace(/^admin\./, '').replace(/^auth\./, '').replace(/_/g, ' ');
}

/** Historical audit TARGET column: user targets stay in target_username; scans use details_json. */
function formatAuditTarget(ev) {
    const tu = (ev.target_username || '').trim();
    if (tu) return tu;
    let d = {};
    try {
        if (ev.details_json && typeof ev.details_json === 'string') {
            d = JSON.parse(ev.details_json);
        }
    } catch (e) {
        d = {};
    }
    const act = String(ev.action || '');
    const prof = d.profile ? String(d.profile).replace(/_/g, ' ') : '';
    if (act === 'scan.job_queued') {
        const parts = [];
        if (d.label) parts.push(String(d.label));
        if (d.target_cidr) parts.push(String(d.target_cidr));
        if (prof) parts.push(prof);
        if (Array.isArray(d.phases) && d.phases.length) parts.push('steps: ' + d.phases.join(', '));
        if (d.job_id != null && d.job_id !== '') parts.push('job #' + d.job_id);
        if (parts.length) return parts.join(' · ').slice(0, 220);
    }
    if (act === 'scan.rerun_queued') {
        const parts = [];
        if (d.target_cidr) parts.push(String(d.target_cidr));
        if (prof) parts.push(prof);
        if (d.label) parts.push(String(d.label));
        if (d.job_id != null) parts.push('job #' + d.job_id);
        if (d.source_job_id != null) parts.push('from #' + d.source_job_id);
        if (parts.length) return parts.join(' · ').slice(0, 220);
    }
    if (act === 'scan.schedule_run_now') {
        const parts = [];
        if (d.schedule_name) parts.push(String(d.schedule_name));
        if (d.target_cidr) parts.push(String(d.target_cidr));
        if (prof) parts.push(prof);
        if (d.job_id != null) parts.push('job #' + d.job_id);
        if (d.schedule_id != null) parts.push('schedule #' + d.schedule_id);
        if (parts.length) return parts.join(' · ').slice(0, 220);
    }
    if (act.indexOf('scan.schedule_') === 0) {
        const parts = [];
        const nm = d.name || d.schedule_name;
        if (nm) parts.push(String(nm));
        if (d.target_cidr) parts.push(String(d.target_cidr));
        if (prof) parts.push(prof);
        if (d.schedule_id != null) parts.push('#' + d.schedule_id);
        if (d.enabled === true || d.enabled === false) parts.push(d.enabled ? 'on' : 'off');
        if (parts.length) return parts.join(' · ').slice(0, 220);
    }
    if (act.startsWith('scan.job_')) {
        const parts = [];
        if (d.job_id != null) parts.push('job #' + d.job_id);
        if (d.target_cidr) parts.push(String(d.target_cidr));
        if (d.label) parts.push(String(d.label));
        if (d.previous_status) parts.push('was ' + d.previous_status);
        if (parts.length) return parts.join(' · ').slice(0, 220);
    }
    if (d.reason || d.summary) {
        const s = d.summary ? String(d.summary) : ('reason: ' + String(d.reason));
        return s.slice(0, 160);
    }
    return '—';
}

async function loadAuthLive() {
    const tbody = document.getElementById('auth-live-tbody');
    if (!tbody) return;
    try {
        const resp = await fetch('/api/auth.php?audit_live=1', { credentials: 'same-origin' });
        const raw = await resp.text();
        let r = null;
        try { r = raw ? JSON.parse(raw) : null; } catch (e) { r = null; }
        if (!resp.ok || !r || !r.ok) {
            const msg = (r && (r.error || r.detail)) ? String(r.error || r.detail) : (`HTTP ${resp.status}`);
            tbody.innerHTML = `<tr><td colspan="5" class="text-dim st-access-empty">Live auth view unavailable (${esc(msg.slice(0, 220))}).</td></tr>`;
            return;
        }
        const rows = Array.isArray(r.live) ? r.live : [];
        if (r.warning) {
            const detail = r.detail ? ` (${String(r.detail).slice(0, 180)})` : '';
            tbody.innerHTML = `<tr><td colspan="5" class="text-dim st-access-empty">Live auth view unavailable${esc(detail)}.</td></tr>`;
            return;
        }
        tbody.innerHTML = rows.length ? rows.map(ev => `
          <tr>
            <td class="mono-sm">${esc(ev.username_norm || '—')}</td>
            <td class="mono-sm">${esc(String(ev.failed_count ?? 0))}</td>
            <td class="mono-sm">${esc(localTime(ev.last_failed_at || ''))}</td>
            <td class="mono-sm">${esc(localTime(ev.locked_until || ''))}</td>
            <td class="mono-sm">${esc(ev.source_ip || '—')}</td>
          </tr>`).join('')
          : '<tr><td colspan="5" class="text-dim st-access-empty">No active sign-in failures or lockouts.</td></tr>';
    } catch (e) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-dim st-access-empty">Live auth view unavailable for current account.</td></tr>';
    }
}

async function loadAuthAudit() {
    const tbody = document.getElementById('auth-audit-tbody');
    if (!tbody) return;
    try {
        const resp = await fetch('/api/auth.php?audit=1&limit=50', { credentials: 'same-origin' });
        const raw = await resp.text();
        let r = null;
        try { r = raw ? JSON.parse(raw) : null; } catch (e) { r = null; }
        if (!resp.ok || !r || !r.ok) {
            const msg = (r && (r.error || r.detail)) ? String(r.error || r.detail) : (`HTTP ${resp.status}`);
            tbody.innerHTML = `<tr><td colspan="5" class="text-dim st-access-empty">Audit log unavailable (${esc(msg.slice(0, 220))}).</td></tr>`;
            return;
        }
        const rows = Array.isArray(r.audit) ? r.audit : [];
        if (r.warning) {
            const detail = r.detail ? ` (${String(r.detail).slice(0, 180)})` : '';
            tbody.innerHTML = `<tr><td colspan="5" class="text-dim st-access-empty">Audit log unavailable${esc(detail)}.</td></tr>`;
            return;
        }
        tbody.innerHTML = rows.length ? rows.map(ev => `
          <tr>
            <td class="mono-sm">${esc(localTime(ev.created_at || ''))}</td>
            <td class="mono-sm">${esc(renderAuditAction(ev.action || ''))}</td>
            <td class="mono-sm">${esc(ev.actor_username || 'system')}</td>
            <td class="mono-sm">${esc(formatAuditTarget(ev))}</td>
            <td class="mono-sm">${esc(ev.source_ip || '—')}</td>
          </tr>`).join('')
          : '<tr><td colspan="5" class="text-dim st-access-empty">No user activity yet.</td></tr>';
    } catch (e) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-dim st-access-empty">Audit log unavailable for current account.</td></tr>';
    }
}

async function deleteAuthUser(id) {
    const username = (document.getElementById(`u-name-${id}`)?.value || '').trim() || `#${id}`;
    const ok = await showConfirmModal(
        `Delete user ${username}? This removes account access and MFA/recovery records.`,
        { title: 'Delete user account', okText: 'Delete user' }
    );
    if (!ok) return;
    const r = await apiPost('/api/auth.php?users=1', { id, delete_user: true });
    if (r && r.ok) {
        toast('User deleted', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : 'Delete failed', 'err');
    }
}

async function saveAuthUser(id) {
    const username = (document.getElementById(`u-name-${id}`)?.value || '').trim();
    const displayName = (document.getElementById(`u-dn-${id}`)?.value || '').trim();
    const email = stNormalizeAdminUserEmail(document.getElementById(`u-em-${id}`)?.value);
    const role = document.getElementById(`u-role-${id}`)?.value || 'viewer';
    const disabled = !!document.getElementById(`u-dis-${id}`)?.checked;
    if (!username) {
        toast('Username is required', 'err');
        return;
    }
    pendingUserSave = { id, username, displayName, email, role, disabled, requirePassword: false };
    openUserPasswordModal(username);
}

async function saveAuthUserQuick(id) {
    const username = (document.getElementById(`u-name-${id}`)?.value || '').trim();
    const displayName = (document.getElementById(`u-dn-${id}`)?.value || '').trim();
    const email = stNormalizeAdminUserEmail(document.getElementById(`u-em-${id}`)?.value);
    const role = document.getElementById(`u-role-${id}`)?.value || 'viewer';
    const disabled = !!document.getElementById(`u-dis-${id}`)?.checked;
    if (!username) {
        toast('Username is required', 'err');
        return;
    }
    const body = {
        id,
        username,
        display_name: displayName,
        email,
        role,
        disabled
    };
    const r = await apiPost('/api/auth.php?users=1', body);
    if (r && r.ok) {
        toast('User updated', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : 'Update failed', 'err');
    }
}

function openUserPasswordModal(username) {
    const bg = document.getElementById('user-pw-bg');
    const msg = document.getElementById('user-pw-msg');
    const pw = document.getElementById('user-pw-new');
    const pwc = document.getElementById('user-pw-confirm');
    const required = !!(pendingUserSave && pendingUserSave.requirePassword);
    if (msg) {
        msg.textContent = required
            ? `Set a temporary password for ${username}. They will be required to change it at first sign-in.`
            : `Set a temporary password for ${username} or leave blank to keep current.`;
    }
    if (pw) pw.value = '';
    if (pwc) pwc.value = '';
    if (pw) pw.placeholder = required ? 'Temporary password' : 'Leave blank to keep current';
    if (pwc) pwc.placeholder = required ? 'Confirm temporary password' : 'Must match temporary password';
    if (bg) bg.style.display = 'flex';
    if (pw) pw.focus();
}

function closeUserPasswordModal() {
    const bg = document.getElementById('user-pw-bg');
    if (bg) bg.style.display = 'none';
    pendingUserSave = null;
}

async function submitAuthUserSave() {
    if (!pendingUserSave) return;
    const body = {
        username: pendingUserSave.username,
        display_name: pendingUserSave.displayName || '',
        email: stNormalizeAdminUserEmail(pendingUserSave.email),
        role: pendingUserSave.role,
        disabled: pendingUserSave.disabled
    };
    if (pendingUserSave.id > 0) body.id = pendingUserSave.id;
    const pwd = document.getElementById('user-pw-new')?.value || '';
    const pwdConfirm = document.getElementById('user-pw-confirm')?.value || '';
    const required = !!pendingUserSave.requirePassword;
    if (required && String(pwd).trim() === '') {
        toast('Temporary password is required', 'err');
        return;
    }
    if (String(pwd).trim() !== '' || String(pwdConfirm).trim() !== '') {
        if (pwd !== pwdConfirm) {
            toast('Temporary password fields do not match', 'err');
            return;
        }
    }
    if (String(pwd).trim() !== '') body.password = String(pwd);
    const r = await apiPost('/api/auth.php?users=1', body);
    if (r && r.ok) {
        const wasCreate = !pendingUserSave.id;
        closeUserPasswordModal();
        if (wasCreate) {
            const un = document.getElementById('new-auth-user');
            if (un) un.value = '';
            const ur = document.getElementById('new-auth-role');
            if (ur) ur.value = 'viewer';
        }
        toast(wasCreate ? 'User created' : 'User updated', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : (pendingUserSave.id ? 'Update failed' : 'Create failed'), 'err');
    }
}

async function createAuthUser() {
    const username = (document.getElementById('new-auth-user')?.value || '').trim();
    const role = document.getElementById('new-auth-role')?.value || 'viewer';
    if (!username) {
        toast('Username is required', 'err');
        return;
    }
    pendingUserSave = { id: 0, username, role, disabled: false, requirePassword: true };
    openUserPasswordModal(username);
}

async function beginMfaSetup() {
    const r = await apiPost('/api/auth.php?mfa_setup=1', {});
    if (!(r && r.ok && r.secret)) {
        toast((r && r.error) ? r.error : 'Could not start MFA setup', 'err');
        return;
    }
    pendingMfaSecret = r.secret;
    pendingMfaOtpUri = String(r.otpauth_uri || '');
    const box = document.getElementById('mfa-setup-box');
    const sec = document.getElementById('mfa-secret');
    const qr = document.getElementById('mfa-qr');
    const qrStatus = document.getElementById('mfa-qr-status');
    const copyBtn = document.getElementById('mfa-copy-uri-btn');
    const recBox = document.getElementById('mfa-recovery-box');
    const recTa = document.getElementById('mfa-recovery-codes');
    if (sec) sec.textContent = pendingMfaSecret;
    if (pendingMfaQrUrl) {
        URL.revokeObjectURL(pendingMfaQrUrl);
        pendingMfaQrUrl = '';
    }
    if (qr) {
        qr.classList.add('hide');
        qr.src = '';
    }
    if (qrStatus) qrStatus.textContent = 'Generating local QR code...';
    if (pendingMfaOtpUri) {
        try {
            const headers = {'Content-Type': 'application/json'};
            if (csrfToken) headers['X-CSRF-Token'] = csrfToken;
            const qrr = await fetch('/api/auth_qr.php', {
                method: 'POST',
                credentials: 'same-origin',
                headers: headers,
                body: JSON.stringify({otpauth_uri: pendingMfaOtpUri})
            });
            const ct = (qrr.headers.get('content-type') || '').toLowerCase();
            if (qrr.ok && ct.includes('image/png')) {
                const blob = await qrr.blob();
                pendingMfaQrUrl = URL.createObjectURL(blob);
                if (qr) {
                    qr.src = pendingMfaQrUrl;
                    qr.classList.remove('hide');
                }
                if (qrStatus) qrStatus.textContent = 'Scan this QR with your authenticator app.';
            } else {
                let msg = 'Local QR generation unavailable; use setup link or manual secret';
                const err = await qrr.json().catch(() => null);
                if (err && err.error) {
                    msg = String(err.error);
                    if (err.detail) {
                        msg += ` (${String(err.detail)})`;
                    }
                }
                else {
                    const raw = await qrr.text().catch(() => '');
                    if (raw && raw.trim()) msg = `QR request failed (HTTP ${qrr.status}): ${raw.replace(/\s+/g, ' ').trim().slice(0, 160)}`;
                    else msg = `QR request failed (HTTP ${qrr.status})`;
                }
                if (qrStatus) qrStatus.textContent = msg;
                toast(msg, 'err');
            }
        } catch (e) {
            const msg = 'Local QR generation unavailable; use setup link or manual secret';
            if (qrStatus) qrStatus.textContent = msg;
            toast(msg, 'err');
        }
    }
    if (copyBtn) {
        copyBtn.onclick = async () => {
            if (!pendingMfaOtpUri) return;
            if (await stCopyTextToClipboard(pendingMfaOtpUri)) toast('Setup link copied', 'ok');
            else toast('Could not copy setup link; use the secret above instead', 'err');
        };
    }
    pendingRecoveryCodes = [];
    if (recTa) recTa.value = '';
    if (recBox) recBox.classList.add('hide');
    if (box) box.classList.remove('hide');
    toast('MFA setup ready. Scan the local QR, or use setup link/manual secret.', 'ok');
}

async function confirmMfaEnable() {
    const otp = (document.getElementById('mfa-enable-otp')?.value || '').trim();
    if (!pendingMfaSecret || !otp) {
        toast('Generate setup secret and enter OTP code', 'err');
        return;
    }
    const r = await apiPost('/api/auth.php?mfa_enable=1', { secret: pendingMfaSecret, otp });
    if (r && r.ok) {
        pendingMfaSecret = '';
        pendingMfaOtpUri = '';
        currentUserMfaEnabled = true;
        updateMfaActionButtons();
        const box = document.getElementById('mfa-setup-box');
        if (box) box.classList.remove('hide');
        const otpEl = document.getElementById('mfa-enable-otp');
        if (otpEl) otpEl.value = '';
        const qr = document.getElementById('mfa-qr');
        if (qr) {
            qr.classList.add('hide');
            qr.src = '';
        }
        if (pendingMfaQrUrl) {
            URL.revokeObjectURL(pendingMfaQrUrl);
            pendingMfaQrUrl = '';
        }
        pendingRecoveryCodes = Array.isArray(r.recovery_codes) ? r.recovery_codes.slice() : [];
        const recBox = document.getElementById('mfa-recovery-box');
        const recTa = document.getElementById('mfa-recovery-codes');
        if (recTa) recTa.value = pendingRecoveryCodes.join('\n');
        if (recBox) recBox.classList.toggle('hide', pendingRecoveryCodes.length === 0);
        toast(pendingRecoveryCodes.length ? 'MFA is now enabled. Save your recovery codes now.' : 'MFA is now enabled', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : 'Could not enable MFA', 'err');
    }
}

async function disableMfaForSelf() {
    const otp = (document.getElementById('mfa-disable-otp')?.value || '').trim();
    const recovery = (document.getElementById('mfa-disable-recovery')?.value || '').trim();
    if (!otp && !recovery) {
        toast('Enter an authenticator code or recovery code', 'err');
        return;
    }
    const body = recovery ? { recovery_code: recovery } : { otp: otp };
    const r = await apiPost('/api/auth.php?mfa_disable=1', body);
    if (r && r.ok) {
        closeMfaDisableModal();
        currentUserMfaEnabled = false;
        updateMfaActionButtons();
        toast('MFA is now disabled', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : 'Could not disable MFA', 'err');
    }
}

function openMfaDisableModal() {
    const bg = document.getElementById('mfa-disable-bg');
    const otp = document.getElementById('mfa-disable-otp');
    const recovery = document.getElementById('mfa-disable-recovery');
    if (otp) otp.value = '';
    if (recovery) recovery.value = '';
    if (bg) bg.style.display = 'flex';
    if (otp) otp.focus();
}

function closeMfaDisableModal() {
    const bg = document.getElementById('mfa-disable-bg');
    if (bg) bg.style.display = 'none';
}

function confirmDisableMfa() {
    disableMfaForSelf();
}

async function resetUserMfa(id) {
    const username = (document.getElementById(`u-name-${id}`)?.value || '').trim() || `#${id}`;
    const displayName = (document.getElementById(`u-dn-${id}`)?.value || '').trim();
    const email = stNormalizeAdminUserEmail(document.getElementById(`u-em-${id}`)?.value);
    const role = document.getElementById(`u-role-${id}`)?.value || 'viewer';
    const disabled = !!document.getElementById(`u-dis-${id}`)?.checked;
    const ok = await showConfirmModal(
        `Clear MFA for ${username}? They will need to enroll MFA again at next sign-in.`,
        { title: 'Clear user MFA', okText: 'Clear MFA' }
    );
    if (!ok) return;
    const r = await apiPost('/api/auth.php?users=1', {
        id,
        username,
        display_name: displayName,
        email: email,
        role,
        disabled,
        reset_mfa: true
    });
    if (r && r.ok) {
        toast('User MFA cleared', 'ok');
        loadAuthUsers();
    } else {
        toast((r && r.error) ? r.error : 'Could not clear user MFA', 'err');
    }
}

function openPasswordChangeModal(required) {
    mustChangePasswordPending = !!required;
    const bg = document.getElementById('pw-change-bg');
    const msg = document.getElementById('pw-change-msg');
    const cur = document.getElementById('pw-change-current');
    const nw = document.getElementById('pw-change-new');
    const cf = document.getElementById('pw-change-confirm');
    if (msg) msg.textContent = required
        ? 'Password update required before continuing. Enter your temporary/current password, then choose a new password.'
        : 'Enter your current password, then choose a new password.';
    if (cur) cur.value = '';
    if (nw) nw.value = '';
    if (cf) cf.value = '';
    if (bg) bg.style.display = 'flex';
    if (cur) cur.focus();
}

function closePasswordChangeModal() {
    if (mustChangePasswordPending) return;
    const bg = document.getElementById('pw-change-bg');
    if (bg) bg.style.display = 'none';
}

async function submitPasswordChange() {
    const currentPassword = document.getElementById('pw-change-current')?.value || '';
    const newPassword = document.getElementById('pw-change-new')?.value || '';
    const confirmPassword = document.getElementById('pw-change-confirm')?.value || '';
    if (!currentPassword || !newPassword || !confirmPassword) {
        toast('Fill in all password fields', 'err');
        return;
    }
    if (newPassword !== confirmPassword) {
        toast('New passwords do not match', 'err');
        return;
    }
    const r = await apiPost('/api/auth.php?password_change=1', {
        current_password: currentPassword,
        new_password: newPassword
    });
    if (r && r.ok) {
        mustChangePasswordPending = false;
        const bg = document.getElementById('pw-change-bg');
        if (bg) bg.style.display = 'none';
        if (currentUser) currentUser.must_change_password = false;
        toast('Password updated successfully', 'ok');
    } else {
        toast((r && r.error) ? r.error : 'Could not change password', 'err');
    }
}

async function copyMfaRecoveryCodes() {
    const text = pendingRecoveryCodes.join('\n');
    if (!text) {
        toast('No recovery codes to copy', 'err');
        return;
    }
    if (await stCopyTextToClipboard(text)) toast('Recovery codes copied', 'ok');
    else toast('Copy failed', 'err');
}

function downloadMfaRecoveryCodesTxt() {
    const text = pendingRecoveryCodes.join('\n');
    if (!text) {
        toast('No recovery codes to download', 'err');
        return;
    }
    const blob = new Blob([text + '\n'], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'surveytrace-mfa-recovery-codes.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

function printMfaRecoveryCodes() {
    const text = pendingRecoveryCodes.join('\n');
    if (!text) {
        toast('No recovery codes to print', 'err');
        return;
    }
    const w = window.open('', '_blank', 'width=640,height=720');
    if (!w) {
        toast('Popup blocked; use Download .txt instead', 'err');
        return;
    }
    const html = `
<!doctype html><html><head><title>SurveyTrace MFA Recovery Codes</title>
<style>body{font-family:ui-monospace,Menlo,Consolas,monospace;padding:24px}h1{font-family:system-ui,sans-serif;font-size:20px}pre{font-size:16px;line-height:1.5}</style>
</head><body><h1>SurveyTrace MFA Recovery Codes</h1><pre>${esc(text)}</pre></body></html>`;
    w.document.open();
    w.document.write(html);
    w.document.close();
    w.focus();
    w.print();
}

/** Show either the paste+Save row or the masked+Remove row (never both). */
function syncNvdKeyFormVisibility(configured) {
    const emptyRow = document.getElementById('st-nvd-api-key-row-empty');
    const setRow = document.getElementById('st-nvd-api-key-row-set');
    const inp = document.getElementById('st-nvd-api-key');
    if (!emptyRow || !setRow) return;
    if (configured) {
        emptyRow.classList.add('hide');
        setRow.classList.remove('hide');
        if (inp) inp.value = '';
    } else {
        setRow.classList.add('hide');
        emptyRow.classList.remove('hide');
        if (inp) inp.value = '';
    }
}

function stIntegrationIsPullType(t) {
    return t === 'prometheus_pull' || t === 'json_events_pull' || t === 'report_summary_pull' || t === 'grafana_infinity_pull';
}

function stIntegrationPullHelpHtml(type) {
    if (type === 'prometheus_pull') {
        return 'Use this token with <code class="code-accent">/api/integrations_metrics.php</code>.';
    }
    if (type === 'json_events_pull') {
        return 'Use this token with <code class="code-accent">/api/integrations_events.php</code>. Good for Splunk scripted or modular inputs.';
    }
    if (type === 'report_summary_pull') {
        return 'Use this token with <code class="code-accent">/api/integrations_dashboard.php</code> (full bundle or <code class="code-accent">?view=…</code> slices) and <code class="code-accent">/api/integrations_report_summary.php</code> only. For Grafana with <code class="code-accent">?view=metrics</code>, JSON metrics/events, or the starter dashboard, create <strong>Grafana Infinity dashboard pull</strong> (<code class="code-accent">grafana_infinity_pull</code>) instead — <code class="code-accent">report_summary_pull</code> tokens are not accepted on <code class="code-accent">/api/integrations_metrics.php?format=json</code> or <code class="code-accent">/api/integrations_events.php?format=json</code>.';
    }
    if (type === 'grafana_infinity_pull') {
        return 'Use this token on the Grafana Infinity datasource (<code class="code-accent">Authorization: Bearer …</code>). Allowed: dashboard (<code class="code-accent">?view=…</code> slices), report summary, <code class="code-accent">/api/integrations_events.php?format=json</code>, <code class="code-accent">/api/integrations_metrics.php?format=json</code>. Not Prometheus text scrape.';
    }
    return '';
}

function stIntegrationsSyncCreateForm() {
    const sel = document.getElementById('st-int-new-type');
    const type = sel ? sel.value : 'webhook';
    const isPull = stIntegrationIsPullType(type);
    const rowEp = document.getElementById('st-int-new-row-endpoint');
    const rowSl = document.getElementById('st-int-new-row-syslog');
    const rowSec = document.getElementById('st-int-new-row-secret');
    const pullHelp = document.getElementById('st-int-new-pull-help');
    const sec = document.getElementById('st-int-new-secret');
    if (rowEp) rowEp.style.display = !isPull && type !== 'syslog' ? '' : 'none';
    if (rowSl) rowSl.style.display = !isPull && type === 'syslog' ? '' : 'none';
    if (rowSec) {
        const showSec = !isPull && (type === 'webhook' || type === 'splunk_hec' || type === 'loki');
        rowSec.style.display = showSec ? '' : 'none';
        if (sec) {
            if (type === 'splunk_hec') sec.placeholder = 'HEC token';
            else if (type === 'loki') sec.placeholder = 'Optional Bearer token for Loki';
            else sec.placeholder = 'Optional HMAC secret';
        }
    }
    if (pullHelp) {
        if (isPull) {
            pullHelp.style.display = '';
            pullHelp.innerHTML = stIntegrationPullHelpHtml(type);
        } else {
            pullHelp.style.display = 'none';
            pullHelp.innerHTML = '';
        }
    }
}

function stIntegrationsSyncEditForm() {
    const sel = document.getElementById('st-int-edit-type');
    const type = sel ? sel.value : 'webhook';
    const isPull = stIntegrationIsPullType(type);
    const rowEp = document.getElementById('st-int-edit-row-endpoint');
    const rowSl = document.getElementById('st-int-edit-row-syslog');
    const rowSec = document.getElementById('st-int-edit-row-secret');
    const pullHelp = document.getElementById('st-int-edit-pull-help');
    if (rowEp) rowEp.style.display = !isPull && type !== 'syslog' ? '' : 'none';
    if (rowSl) rowSl.style.display = !isPull && type === 'syslog' ? '' : 'none';
    if (rowSec) rowSec.style.display = !isPull && (type === 'webhook' || type === 'splunk_hec' || type === 'loki') ? '' : 'none';
    if (pullHelp) {
        if (isPull) {
            pullHelp.style.display = '';
            pullHelp.innerHTML = stIntegrationPullHelpHtml(type);
        } else {
            pullHelp.style.display = 'none';
            pullHelp.innerHTML = '';
        }
    }
}

function stIntegrationRowPushHtml(r) {
    const dest = esc(r.destination_summary || '—');
    const typ = esc(r.type_label || r.type);
    const typTitle = esc(r.type || '');
    const on = r.enabled ? '<span class="st-integrations-on st-integrations-on--enabled">Enabled</span>' : '<span class="st-integrations-on st-integrations-on--disabled">Disabled</span>';
    const auth = r.auth_configured ? '<span class="text-strong">configured</span>' : '<span class="text-dim">—</span>';
    const lt = r.last_test_at ? esc(r.last_test_at) : '—';
    const stRaw = r.last_test_status ? String(r.last_test_status) : '';
    const stCls = /fail|err|timeout/i.test(stRaw) ? 'st-integrations-health--fail' : (/ok|success|200/i.test(stRaw) ? 'st-integrations-health--ok' : 'st-integrations-health--unknown');
    const st = stRaw ? `<span class="${stCls}">${esc(stRaw)}</span>` : '<span class="text-dim">—</span>';
    const rowCls = r.enabled ? 'st-integrations-row--enabled' : 'st-integrations-row--disabled';
    return `<tr class="${rowCls}">
      <td>${esc(r.name)}</td>
      <td title="${typTitle}">${typ}</td>
      <td>Push</td>
      <td>${on}</td>
      <td class="mono-sm" style="max-width:260px;overflow:hidden;text-overflow:ellipsis" title="${dest}">${dest}</td>
      <td class="text-micro">${auth}</td>
      <td class="text-micro">${lt}<br><span class="text-dim">${st}</span></td>
      <td class="text-nowrap">
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationEditOpen(${r.id})">Edit</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationTest(${r.id})">Test</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationSample(${r.id})">Sample</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationToggle(${r.id}, ${r.enabled ? 0 : 1})">${r.enabled ? 'Disable' : 'Enable'}</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationDelete(${r.id})">Delete</button>
      </td>
    </tr>`;
}

function stIntegrationRowPullHtml(r) {
    const dest = esc(r.destination_summary || '—');
    const typ = esc(r.type_label || r.type);
    const typTitle = esc(r.type || '');
    const on = r.enabled ? '<span class="st-integrations-on st-integrations-on--enabled">Enabled</span>' : '<span class="st-integrations-on st-integrations-on--disabled">Disabled</span>';
    const tc = r.token_configured ? '<span class="text-strong">configured</span>' : '<span class="text-dim">not set</span>';
    const created = r.token_created_at ? `<div class="text-dim text-micro">created ${esc(r.token_created_at)}</div>` : '';
    const tokCell = `<div class="text-micro">${tc}</div>${created}
      <button type="button" class="tbtn btn-xxs mt4" onclick="stIntegrationRotateToken(${r.id})">Generate / Rotate token</button>`;
    const used = r.token_last_used_at
        ? esc(r.token_last_used_at) + (r.token_last_used_ip ? ' · ' + esc(r.token_last_used_ip) : '')
        : '—';
    const rowCls = r.enabled ? 'st-integrations-row--enabled' : 'st-integrations-row--disabled';
    return `<tr class="${rowCls}">
      <td>${esc(r.name)}</td>
      <td title="${typTitle}">${typ}</td>
      <td>Pull</td>
      <td>${on}</td>
      <td class="mono-sm text-micro" style="max-width:280px">${dest}</td>
      <td style="vertical-align:top" class="text-micro">${tokCell}</td>
      <td class="text-micro">${used}</td>
      <td class="text-nowrap">
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationEditOpen(${r.id})">Edit</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationToggle(${r.id}, ${r.enabled ? 0 : 1})">${r.enabled ? 'Disable' : 'Enable'}</button>
        <button type="button" class="tbtn btn-xxs" onclick="stIntegrationDelete(${r.id})">Delete</button>
      </td>
    </tr>`;
}

async function loadIntegrationsTab() {
    if (!stRoleIsAdmin()) return;
    const tbPush = document.getElementById('st-int-push-tbody');
    const tbPull = document.getElementById('st-int-pull-tbody');
    const hint = document.getElementById('st-int-pull-hint');
    const loading = '<tr><td colspan="8" class="loading st-integrations-empty">Loading…</td></tr>';
    if (tbPush) tbPush.innerHTML = loading;
    if (tbPull) tbPull.innerHTML = loading;
    const d = await api('/api/integrations.php');
    if (!d || !d.ok) {
        const err = '<tr><td colspan="8" class="st-integrations-empty">Could not load integrations.</td></tr>';
        if (tbPush) tbPush.innerHTML = err;
        if (tbPull) tbPull.innerHTML = err;
        return;
    }
    if (hint) {
        hint.textContent = d.per_integration_pull_token_configured
            ? 'At least one enabled pull integration has a token — each consumer can rotate independently.'
            : 'Add a Pull / API integration and use Generate / Rotate token before calling pull endpoints.';
    }
    window.__stIntegrationsCache = d.integrations || [];
    const rows = window.__stIntegrationsCache;
    const pushRows = rows.filter((r) => !stIntegrationIsPullType(r.type));
    const pullRows = rows.filter((r) => stIntegrationIsPullType(r.type));
    if (tbPush) {
        tbPush.innerHTML = pushRows.length
            ? pushRows.map((r) => stIntegrationRowPushHtml(r)).join('')
            : '<tr><td colspan="8" class="text-dim st-integrations-empty">Push integrations are optional. None configured yet — common first targets are Splunk HEC, syslog, webhook, or Loki.</td></tr>';
    }
    if (tbPull) {
        tbPull.innerHTML = pullRows.length
            ? pullRows.map((r) => stIntegrationRowPullHtml(r)).join('')
            : '<tr><td colspan="8" class="text-dim st-integrations-empty">Pull/API integrations are optional. Add one for Grafana, Prometheus/Alloy, Splunk scripted input, or external dashboard consumers.</td></tr>';
    }
    stIntegrationsSyncCreateForm();
    void loadZabbixIntegrationOnly();
}

function stZabbixFmtCacheStatusMessage(st) {
    if (!st || st.tables_ready === false) {
        return { warn: 'Zabbix tables are not ready (migrations missing).', detail: '' };
    }
    const h = String(st.status_hint || 'ok');
    const detail =
        'Hosts: ' + (st.zabbix_hosts ?? 0)
        + ' · zabbix_host_groups rows: ' + (st.zabbix_host_groups_rows ?? 0)
        + ' · hosts with groups_json: ' + (st.hosts_with_nonempty_groups_json ?? 0)
        + ' · catalog groups: ' + (st.scope_map_catalog_group_count ?? 0);
    if (h === 'no_hosts') {
        return { warn: 'No Zabbix host rows in the local cache — enable the connector and run a sync.', detail };
    }
    if (h === 'no_groups_in_cache') {
        return {
            warn: 'Sync did not store any host groups (empty zabbix_host_groups and no usable groups_json). Check Zabbix API access and run sync again. Advanced: custom group values still work.',
            detail,
        };
    }
    if (h === 'groups_json_unparsed') {
        return {
            warn: 'Hosts have groups_json but no group names could be extracted — possible API shape mismatch. Use Advanced: custom, or report a sample groups_json from the DB.',
            detail,
        };
    }
    if (h === 'group_rows_empty_names') {
        return {
            warn: 'zabbix_host_groups has rows but all group_name values are empty — run a full sync again after upgrading.',
            detail,
        };
    }
    if (h === 'groups_from_json_only') {
        return {
            warn: 'Group dropdown is filled from groups_json (normalized group table is empty). Re-sync to populate zabbix_host_groups.',
            detail,
        };
    }
    if (h === 'tables_missing') {
        return { warn: 'Zabbix tables missing.', detail: '' };
    }
    return { warn: '', detail };
}

function stZabbixApplyCacheStatusHint(z) {
    const row = document.getElementById('zb-enrich-diagnostics-row');
    const wEl = document.getElementById('zb-diagnostics-warn');
    const detBody = document.getElementById('zb-diagnostics-detail');
    const btn = document.getElementById('btn-zb-diagnostics-toggle');
    const panel = document.getElementById('zb-diagnostics-panel');
    if (!row || !wEl || !detBody) {
        return;
    }
    wEl.style.display = 'none';
    wEl.innerHTML = '';
    detBody.textContent = '';
    row.style.display = 'none';
    if (panel) {
        panel.classList.add('hide');
    }
    if (btn) {
        btn.setAttribute('aria-expanded', 'false');
    }
    if (!z || !z.ok || !z.zabbix_cache_status) {
        return;
    }
    const { warn, detail } = stZabbixFmtCacheStatusMessage(z.zabbix_cache_status);
    if (!warn && !detail) {
        return;
    }
    row.style.display = '';
    if (warn) {
        wEl.style.display = '';
        wEl.innerHTML = '<span class="hstate-warn">' + esc(warn) + '</span>';
    }
    if (detail) {
        detBody.textContent = detail;
    }
}

function stZabbixEnrichDiagnosticsToggle() {
    const panel = document.getElementById('zb-diagnostics-panel');
    const btn = document.getElementById('btn-zb-diagnostics-toggle');
    if (!panel || !btn) return;
    const willOpen = panel.classList.contains('hide');
    panel.classList.toggle('hide', !willOpen);
    btn.setAttribute('aria-expanded', willOpen ? 'true' : 'false');
}

function stZabbixOverviewDiagnosticsToggle() {
    const panel = document.getElementById('zb-overview-diagnostics-panel');
    const btn = document.getElementById('btn-zb-overview-diagnostics-toggle');
    if (!panel || !btn) return;
    const willOpen = panel.classList.contains('hide');
    panel.classList.toggle('hide', !willOpen);
