}

const ST_LS_ZB_ENRICH_TOOLS_OPEN = 'st_zabbix_enrich_tools_open';

/** @param {object} zs zabbix_status from GET /api/zabbix.php?status=1 */
function stZabbixFreshnessBadgeClass(zs) {
    const st = zs && zs.freshness_state ? String(zs.freshness_state) : 'never_synced';
    if (st === 'fresh') return 'badge-mini badge-zbx-fresh';
    if (st === 'stale') return 'badge-mini badge-zbx-stale';
    if (st === 'outdated') return 'badge-mini badge-zbx-outdated';
    if (st === 'disabled' || st === 'not_configured') return 'badge-mini badge-zbx-never';
    return 'badge-mini badge-zbx-never';
}

/** @param {object} zs */
function stZabbixFreshnessBadgeLabel(zs) {
    const st = zs && zs.freshness_state ? String(zs.freshness_state) : 'never_synced';
    if (st === 'fresh') return 'Fresh';
    if (st === 'stale') return 'Stale';
    if (st === 'outdated') return 'Outdated';
    if (st === 'disabled') return 'Disabled';
    if (st === 'not_configured') return 'Not configured';
    return 'Never synced';
}

/** @param {number|null|undefined} sec */
function stZabbixFormatAgeSeconds(sec) {
    if (sec == null || !Number.isFinite(Number(sec))) return '—';
    const s = Number(sec);
    if (s < 75) return 'just now';
    const m = Math.floor(s / 60);
    if (m < 120) return String(m) + ' minute' + (m === 1 ? '' : 's') + ' ago';
    const h = Math.floor(m / 60);
    return String(h) + ' hour' + (h === 1 ? '' : 's') + ' ago';
}

/** @param {object} zs */
function stZabbixLastSyncLineHtml(zs) {
    if (!zs || zs.last_sync == null || String(zs.last_sync).trim() === '') {
        return '<span class="mono-sm text-dim">Last synced: never</span>';
    }
    const sec = zs.freshness_seconds != null ? Number(zs.freshness_seconds) : null;
    if (sec == null || !Number.isFinite(sec)) {
        return '<span class="mono-sm text-dim">Last synced: ' + esc(String(zs.last_sync)) + '</span>';
    }
    if (sec < 75) {
        return '<span class="mono-sm text-dim">Last synced: just now</span>';
    }
    const m = Math.floor(sec / 60);
    if (m < 120) {
        return '<span class="mono-sm text-dim">Last synced: ' + m + ' minute' + (m === 1 ? '' : 's') + ' ago</span>';
    }
    const h = Math.floor(m / 60);
    return '<span class="mono-sm text-dim">Last synced: ' + h + ' hour' + (h === 1 ? '' : 's') + ' ago</span>';
}

/** @param {object|null} zs */
function stZabbixApplyEnrichmentFreshnessBanner(zs) {
    const el = document.getElementById('zb-enrich-freshness-banner');
    const toolsWrap = document.getElementById('st-zabbix-enrich-tools-wrap');
    if (!el) return;
    if (!stRoleIsAdmin() || !toolsWrap || toolsWrap.style.display === 'none') {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
    }
    if (!zs || !zs.tables_ready || !zs.configured || !zs.enabled) {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
    }
    const badge = '<span class="' + stZabbixFreshnessBadgeClass(zs) + '">' + esc(stZabbixFreshnessBadgeLabel(zs)) + '</span>';
    const line = stZabbixLastSyncLineHtml(zs);
    let hint = '';
    const st = String(zs.freshness_state || '');
    if (st === 'stale' || st === 'outdated') {
        hint = '<p class="hint-micro text-dim mb0 mt6">Zabbix data may be stale. Run sync to refresh.</p>';
    }
    el.innerHTML = '<div class="row-wrap gap8" style="align-items:center;flex-wrap:wrap">' + badge + line + '</div>' + hint;
    el.style.display = '';
}

function stZabbixEnrichToolsLsIsOpen() {
    try {
        return localStorage.getItem(ST_LS_ZB_ENRICH_TOOLS_OPEN) === '1';
    } catch (e) {
        return false;
    }
}

function stZabbixEnrichToolsLsSet(open) {
    try {
        localStorage.setItem(ST_LS_ZB_ENRICH_TOOLS_OPEN, open ? '1' : '0');
    } catch (e) {}
}

function stZabbixEnrichIsConfigured(z) {
    if (!z || !z.ok) return false;
    const c = z.connector || {};
    return String(c.api_url || '').trim() !== '' && !!c.api_token_set;
}

function stZabbixEnrichHasSyncedData(z) {
    if (!z || !z.ok) return false;
    if (z.zabbix_status && z.zabbix_status.hosts_cached != null) {
        const hc = parseInt(String(z.zabbix_status.hosts_cached), 10);
        if (Number.isFinite(hc)) return hc > 0;
    }
    const h = z.stats && z.stats.hosts != null ? parseInt(String(z.stats.hosts), 10) : 0;
    return Number.isFinite(h) && h > 0;
}

function stZabbixEnrichToolsPanelIsOpen() {
    const panel = document.getElementById('zb-enrich-tools-panel');
    return !!(panel && !panel.classList.contains('hide'));
}

function stZabbixEnrichToolsApplyDomOpen(open, opts) {
    const o = opts || {};
    const panel = document.getElementById('zb-enrich-tools-panel');
    const innerToggle = document.getElementById('btn-zb-enrich-tools-toggle');
    const cta = document.getElementById('enrich-zbx-tools-cta');
    const preview = document.getElementById('zb-enrich-tools-preview');
    if (panel) {
        if (open) panel.classList.remove('hide');
        else panel.classList.add('hide');
    }
    if (innerToggle) {
        innerToggle.textContent = open ? 'Close tools' : 'Open tools';
        innerToggle.setAttribute('aria-expanded', open ? 'true' : 'false');
    }
    if (cta && cta.style.display !== 'none') {
        cta.textContent = open ? 'Close tools' : 'Open tools';
        cta.setAttribute('aria-expanded', open ? 'true' : 'false');
        cta.setAttribute('aria-controls', 'zb-enrich-tools-panel');
    }
    if (preview) {
        preview.style.display = open ? 'none' : '';
    }
    if (!o.skipLs) {
        stZabbixEnrichToolsLsSet(open);
    }
}

function stZabbixEnrichToolsToggle() {
    const wrap = document.getElementById('st-zabbix-enrich-tools-wrap');
    if (!wrap || wrap.style.display === 'none') return;
    const wasOpen = stZabbixEnrichToolsPanelIsOpen();
    stZabbixEnrichToolsApplyDomOpen(!wasOpen, { skipLs: false });
    if (!wasOpen) wrap.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

/**
 * Updates the Enrichment tab Zabbix overview card and tools panel visibility.
 * @param {object|null} resp Result of GET /api/zabbix.php?status=1 (or full admin GET which includes zabbix_status).
 */
function stEnrichmentRefreshZabbixOverview(resp) {
    const detailsEl = document.getElementById('enrich-zbx-overview-details');
    const toolsWrap = document.getElementById('st-zabbix-enrich-tools-wrap');
    const cta = document.getElementById('enrich-zbx-tools-cta');
    const syncBtn = document.getElementById('enrich-zbx-sync-btn');
    const toolsPreview = document.getElementById('zb-enrich-tools-preview');
    const connectorEl = document.getElementById('enrich-zbx-connector');
    const statusLineEl = document.getElementById('enrich-zbx-status-line');
    if (!detailsEl || !toolsWrap) return;

    const setZabbixSuiteConnector = (show) => {
        if (connectorEl) {
            connectorEl.style.display = show ? '' : 'none';
        }
    };

    const showCta = (show) => {
        if (cta) {
            cta.style.display = show ? '' : 'none';
            if (!show) cta.removeAttribute('aria-expanded');
        }
    };
    const showSync = (show) => {
        if (syncBtn) syncBtn.style.display = show ? '' : 'none';
    };
    showCta(false);
    showSync(false);

    const zs = resp && resp.zabbix_status ? resp.zabbix_status : null;
    if (!resp || !resp.ok || !zs) {
        if (statusLineEl) statusLineEl.textContent = 'Zabbix: Error · Last sync failed';
        const err = (resp && resp.error) ? esc(String(resp.error)) : 'Could not load Zabbix status.';
        detailsEl.innerHTML = '<p class="hint-micro mb6">Zabbix enrichment is unavailable.</p>'
            + '<p class="hint-micro text-dim mb0">' + err + '</p>';
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        stZabbixApplyEnrichmentFreshnessBanner(null);
        return;
    }

    if (!zs.tables_ready) {
        if (statusLineEl) statusLineEl.textContent = 'Zabbix integration is not configured.';
        detailsEl.innerHTML = '<p class="hint-micro text-dim mb0">Zabbix tables are not installed. Run database migrations.</p>';
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        stZabbixApplyEnrichmentFreshnessBanner(null);
        return;
    }

    if (!zs.configured) {
        if (statusLineEl) statusLineEl.textContent = 'Zabbix integration is not configured.';
        detailsEl.innerHTML = '<p class="hint-micro mb6">Zabbix is not configured.</p>'
            + '<p class="hint-micro text-dim mb0">Set API URL and token under <strong>Integrations → Zabbix</strong>, then return here.</p>';
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        stZabbixApplyEnrichmentFreshnessBanner(null);
        return;
    }

    if (!zs.enabled) {
        if (statusLineEl) statusLineEl.textContent = 'Zabbix integration is not configured.';
        detailsEl.innerHTML = '<p class="hint-micro mb6">Zabbix enrichment is disabled.</p>'
            + '<p class="hint-micro text-dim mb0">Enable it under <strong>Integrations → Zabbix</strong>.</p>';
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        stZabbixApplyEnrichmentFreshnessBanner(null);
        return;
    }

    if (toolsPreview) toolsPreview.style.display = '';
    if (statusLineEl) {
        const syncRaw = zs.last_sync_status != null ? String(zs.last_sync_status).toLowerCase() : '';
        const isErr = syncRaw === 'failed' || syncRaw === 'error' || !!zs.last_error;
        const frState = String(zs.freshness_state || '');
        if (isErr) {
            statusLineEl.textContent = 'Zabbix: Error · Last sync failed';
        } else if (frState === 'stale' || frState === 'outdated') {
            statusLineEl.textContent = 'Zabbix: Degraded · Last sync ' + stZabbixFormatAgeSeconds(zs.freshness_seconds);
        } else {
            statusLineEl.textContent = 'Zabbix: Connected · Last sync ' + stZabbixFormatAgeSeconds(zs.freshness_seconds);
        }
    }

    const badge = '<span class="' + stZabbixFreshnessBadgeClass(zs) + '">' + esc(stZabbixFreshnessBadgeLabel(zs)) + '</span>';
    const line = stZabbixLastSyncLineHtml(zs);
    let schedHint = '';
    if (stRoleIsAdmin() && zs.sync_schedule_enabled && zs.next_sync_at) {
        schedHint = '<p class="hint-micro text-dim mb6">Next scheduled pull: <span class="mono-sm">' + esc(String(zs.next_sync_at)) + '</span></p>';
    }
    let html = '<div class="row-wrap gap8 mb8" style="align-items:center;flex-wrap:wrap">' + badge + line + '</div>'
        + schedHint
        + '<p class="hint-micro text-dim mb8" style="margin-bottom:10px">Sync updates cached monitoring data. No automatic changes are applied.</p>';
    if (stRoleIsAdmin() && resp.connector) {
        const c0 = resp.connector || {};
        html += '<div class="help-box mb8"><div class="hint-micro"><strong>Zabbix output (SurveyTrace → Zabbix)</strong></div>'
            + '<div class="hint-micro mt4"><span class="badge-mini ' + (c0.output_enabled ? 'badge-on' : 'badge-off') + '">'
            + (c0.output_enabled ? 'Enabled' : 'Disabled') + '</span>'
            + ' · last push: ' + esc(String(c0.last_output_push_at || '—'))
            + ' · result: ' + esc(String(c0.last_output_push_status || '—')) + '</div>'
            + '<p class="hint-micro text-dim mb0 mt4">SurveyTrace sends health and security summary metrics to Zabbix. No alerts are created by default.</p></div>';
    }

    const hostsCached = zs.hosts_cached != null ? parseInt(String(zs.hosts_cached), 10) : 0;
    const synced = Number.isFinite(hostsCached) && hostsCached > 0;

    if (stRoleIsAdmin() && resp.connector && resp.stats) {
        const c = resp.connector || {};
        const matched = resp.stats.matched_pairs != null ? resp.stats.matched_pairs : 0;
        const unmd = resp.stats.hosts_unmatched != null ? resp.stats.hosts_unmatched : 0;
        html += '<div class="hint-micro mb6"><span class="badge-mini ' + (c.enabled ? 'badge-on' : 'badge-off') + '">'
            + (c.enabled ? 'enabled' : 'disabled') + '</span></div>'
            + '<div class="hint-micro mb6">Matched links: <strong>' + esc(String(matched)) + '</strong>'
            + ' · Unmatched Zabbix hosts: <strong>' + esc(String(unmd)) + '</strong></div>';
        if (resp.zabbix_cache_status) {
            const fm = stZabbixFmtCacheStatusMessage(resp.zabbix_cache_status);
            if (fm.warn || fm.detail) {
                html += '<div id="zb-overview-diagnostics-row" class="mb6">'
                    + '<button type="button" class="tbtn btn-sm" id="btn-zb-overview-diagnostics-toggle" onclick="stZabbixOverviewDiagnosticsToggle()" aria-expanded="false" aria-controls="zb-overview-diagnostics-panel">Diagnostics</button>'
                    + '<div id="zb-overview-diagnostics-panel" class="hide mt6" role="region" aria-labelledby="btn-zb-overview-diagnostics-toggle">';
                if (fm.warn) {
                    html += '<div class="help-box mb6"><span class="hstate-warn">' + esc(fm.warn) + '</span></div>';
                }
                if (fm.detail) {
                    html += '<div class="hint-micro mono-sm text-dim">' + esc(fm.detail) + '</div>';
                }
                html += '</div></div>';
            }
        }
    }

    if (!synced) {
        html += '<div class="help-box mb6"><strong>No cached hosts yet.</strong> Run a sync (button below or Integrations → Zabbix).</div>';
        detailsEl.innerHTML = html;
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        showCta(false);
        if (stRoleIsAdmin() && zs.enabled && zs.configured) showSync(true);
        stZabbixApplyEnrichmentFreshnessBanner(zs);
        return;
    }

    detailsEl.innerHTML = html;
    if (stRoleIsAdmin()) {
        toolsWrap.style.display = '';
        setZabbixSuiteConnector(true);
        showCta(true);
        showSync(true);
        const wantOpen = stZabbixEnrichToolsLsIsOpen();
        stZabbixEnrichToolsApplyDomOpen(!!wantOpen, { skipLs: true });
    } else {
        toolsWrap.style.display = 'none';
        setZabbixSuiteConnector(false);
        if (toolsPreview) toolsPreview.style.display = 'none';
        showCta(false);
        showSync(false);
    }
    stZabbixApplyEnrichmentFreshnessBanner(zs);
}

/** Scan scopes for Zabbix rule dropdowns (Enrichment tab tools); mirrored on GET /api/zabbix.php as `scopes`. */
var zbScopeOptions = [];
/** Synced group / tag catalog for scope-map rules; from GET /api/zabbix.php `scope_map_catalog`. */
var zbScopeMapCatalog = { groups: [], tags: [] };

function stZabbixCatalogGroupListed(pat) {
    const p = String(pat || '').trim();
    if (!p) {
        return false;
    }
    const pl = p.toLowerCase();
    return (zbScopeMapCatalog.groups || []).some((g) => String(g).trim().toLowerCase() === pl);
}

/** @returns {{ mode: string, entry: object, value?: string }|null} */
function stZabbixCatalogTagMetaForPattern(pat) {
    const raw = String(pat || '').trim();
    if (!raw) {
        return null;
    }
    const tags = zbScopeMapCatalog.tags || [];
    if (!raw.includes('=')) {
        const pl = raw.toLowerCase();
        const entry = tags.find((t) => String(t.tag || '').trim().toLowerCase() === pl);
        return entry ? { mode: 'any', entry } : null;
    }
    const eq = raw.indexOf('=');
    const tk = raw.slice(0, eq).trim();
    const tv = raw.slice(eq + 1);
    const tvl = tv.trim().toLowerCase();
    const entry = tags.find((t) => String(t.tag || '').trim().toLowerCase() === tk.toLowerCase());
    if (!entry) {
        return null;
    }
    const vals = entry.values || [];
    const hit = vals.find((v) => String(v).trim().toLowerCase() === tvl);
    return hit !== undefined ? { mode: 'value', entry, value: hit } : null;
}

function zbScopeLabel(sid) {
    const id = parseInt(String(sid ?? '0'), 10);
    if (!id) return '—';
    const o = (zbScopeOptions || []).find((s) => parseInt(String(s.id), 10) === id);
    const raw = o ? String(o.name || '') : '';
    return raw ? esc(raw) : ('#' + id);
}

function zbScopeSelectHtml(selectedId, rule) {
    const sel = parseInt(String(selectedId || '0'), 10);
    const r = rule || {};
    const missing = !!(r.scope_missing === 1 || r.scope_missing === true || r.scope_missing === '1');
    let o = '<select class="finp zb-r-scope" style="min-width:140px" onchange="stZabbixRefreshScopeRuleButtons()">';
    o += '<option value="0">— scope —</option>';
    if (missing && sel > 0) {
        o += `<option value="${sel}" selected>${esc('(deleted scope) #' + sel)}</option>`;
    }
    (zbScopeOptions || []).forEach((s) => {
        const id = parseInt(String(s.id), 10);
        const lab = esc(s.name || ('#' + id));
        o += `<option value="${id}"${id === sel ? ' selected' : ''}>${lab}</option>`;
    });
    o += '</select>';
    return o;
}

/** Build `pattern` for save/preview: must match api/lib_zabbix.php (tag = key only, or key=value with first '='). */
function stZabbixRuleRowPatternFromDom(row) {
    const legacy = row.querySelector('.zb-r-pattern');
    if (legacy) {
        return String(legacy.value || '').trim();
    }
    const type = (row.querySelector('.zb-r-type') || {}).value || 'group';
    if (type === 'group') {
        const gmode = row.querySelector('.zb-r-gmode');
        if (!gmode || gmode.value === 'custom') {
            return String((row.querySelector('.zb-r-pattern-custom') || {}).value || '').trim();
        }
        const gs = row.querySelector('.zb-r-group-sel');
        return gs ? String(gs.value || '').trim() : '';
    }
    const tmode = row.querySelector('.zb-r-tmode');
    if (!tmode || tmode.value === 'custom') {
        return String((row.querySelector('.zb-r-pattern-custom') || {}).value || '').trim();
    }
    const key = String((row.querySelector('.zb-r-tag-key') || {}).value || '').trim();
    if (!key) {
        return '';
    }
    const vsel = row.querySelector('.zb-r-tag-val');
    if (!vsel) {
        return key;
    }
    const vv = vsel.value;
    // __ANY__ is UI-only; persisted pattern is tag key alone (backend: any value).
    if (vv === '__ANY__') {
        return key;
    }
    return key + '=' + vv;
}

function stZabbixTagValPopulate(valSel, tagEntry, selectedVal) {
    while (valSel.firstChild) {
        valSel.removeChild(valSel.firstChild);
    }
    const anyO = document.createElement('option');
    anyO.value = '__ANY__';
    anyO.textContent = '(any value)';
    valSel.appendChild(anyO);
    const vals = (tagEntry && tagEntry.values) ? tagEntry.values : [];
    vals.forEach((v) => {
        const o = document.createElement('option');
        o.value = v;
        o.textContent = v === '' ? '(empty)' : String(v);
        valSel.appendChild(o);
    });
    if (arguments.length < 3) {
        anyO.selected = true;
        return;
    }
    if (selectedVal === '__ANY__') {
        anyO.selected = true;
        return;
    }
    let set = false;
    [...valSel.options].forEach((op) => {
        if (!set && op.value !== '__ANY__' && String(op.value) === String(selectedVal)) {
            op.selected = true;
            set = true;
        }
    });
    if (!set) {
        const c = document.createElement('option');
        c.value = String(selectedVal);
        c.textContent = String(selectedVal) === '' ? '(empty)' : String(selectedVal);
        c.selected = true;
        valSel.appendChild(c);
    }
}

function stZabbixOnTagKeyChange(keySel) {
    const row = keySel.closest('.zb-rule-row');
    const valSel = row.querySelector('.zb-r-tag-val');
    if (!valSel) {
        return;
    }
    const tags = zbScopeMapCatalog.tags || [];
    const tk = String(keySel.value || '').trim();
    const trow = tags.find((t) => String(t.tag || '') === tk);
    stZabbixTagValPopulate(valSel, trow || { values: [] }, '__ANY__');
    stZabbixRefreshScopeRuleButtons();
}

function stZabbixOnRuleTypeChange(sel) {
    const row = sel.closest('.zb-rule-row');
    const prev = stZabbixRuleRowPatternFromDom(row);
    stZabbixRenderRulePatternUi(row, { rule_type: sel.value, pattern: prev });
    stZabbixRefreshScopeRuleButtons();
}

function stZabbixRenderRulePatternUi(row, seed) {
    const ui = row.querySelector('.zb-r-pattern-ui');
    if (!ui) {
        return;
    }
    const type = (seed && seed.rule_type) || (row.querySelector('.zb-r-type') || {}).value || 'group';
    const p = seed && Object.prototype.hasOwnProperty.call(seed, 'pattern')
        ? String(seed.pattern || '')
        : stZabbixRuleRowPatternFromDom(row);
    ui.innerHTML = '';
    ui.className = 'zb-r-pattern-ui row-wrap gap6 flex-1';
    ui.style.minWidth = '260px';
    ui.style.alignItems = 'flex-end';

    if (type === 'group') {
        const grp = zbScopeMapCatalog.groups || [];
        if (!grp.length) {
            const h = document.createElement('div');
            h.className = 'hint-micro text-dim';
            h.style.flex = '1';
            h.style.minWidth = '140px';
            h.textContent = 'No Zabbix groups found yet. Run a Zabbix sync first.';
            ui.appendChild(h);
        }
        const inList = grp.length > 0 && stZabbixCatalogGroupListed(p);
        const gmode = document.createElement('select');
        gmode.className = 'finp zb-r-gmode';
        gmode.style.minWidth = '170px';
        if (grp.length > 0) {
            const oa = document.createElement('option');
            oa.value = 'catalog';
            oa.textContent = 'From synced groups';
            gmode.appendChild(oa);
            const ob = document.createElement('option');
            ob.value = 'custom';
            ob.textContent = 'Advanced: custom value…';
            gmode.appendChild(ob);
            gmode.value = inList || p.trim() === '' ? 'catalog' : 'custom';
        } else {
            const ox = document.createElement('option');
            ox.value = 'custom';
            ox.textContent = 'Custom value';
            gmode.appendChild(ox);
            gmode.value = 'custom';
            gmode.style.display = 'none';
        }
        ui.appendChild(gmode);

        let groupSelWrap = null;
        let gs = null;
        if (grp.length > 0) {
            groupSelWrap = document.createElement('div');
            groupSelWrap.className = 'row-wrap gap6';
            groupSelWrap.style.flex = '1';
            gs = document.createElement('select');
            gs.className = 'finp zb-r-group-sel';
            gs.style.minWidth = '220px';
            gs.style.flex = '1';
            const ph = document.createElement('option');
            ph.value = '';
            ph.textContent = '— select group —';
            gs.appendChild(ph);
            grp.forEach((g) => {
                const o = document.createElement('option');
                o.value = g;
                o.textContent = g;
                gs.appendChild(o);
            });
            const pl = p.trim().toLowerCase();
            [...gs.options].forEach((op) => {
                if (op.value && String(op.value).trim().toLowerCase() === pl) {
                    op.selected = true;
                }
            });
            gs.onchange = () => stZabbixRefreshScopeRuleButtons();
            groupSelWrap.appendChild(gs);
            ui.appendChild(groupSelWrap);
        }

        const inp = document.createElement('input');
        inp.type = 'text';
        inp.className = 'finp zb-r-pattern-custom';
        inp.style.minWidth = '200px';
        inp.style.flex = '1';
        inp.placeholder = 'Host group name (exact match, case-insensitive)';
        inp.value = gmode.value === 'custom' ? p : '';
        inp.oninput = () => stZabbixRefreshScopeRuleButtons();
        ui.appendChild(inp);

        const applyG = () => {
            const cat = grp.length > 0 && gmode.value === 'catalog';
            if (groupSelWrap) {
                groupSelWrap.style.display = cat ? '' : 'none';
            }
            inp.style.display = cat ? 'none' : '';
        };
        applyG();
        gmode.onchange = () => {
            applyG();
            if (gmode.value === 'custom' && gs && gs.value) {
                inp.value = gs.value;
            }
            if (gmode.value === 'catalog' && gs && inp.value.trim()) {
                const hit = [...gs.options].find(
                    (o) => o.value && o.value.trim().toLowerCase() === inp.value.trim().toLowerCase()
                );
                if (hit) {
                    hit.selected = true;
                }
            }
            stZabbixRefreshScopeRuleButtons();
        };
    } else {
        const tags = zbScopeMapCatalog.tags || [];
        if (!tags.length) {
            const h = document.createElement('div');
            h.className = 'hint-micro text-dim';
            h.style.flex = '1';
            h.style.minWidth = '140px';
            h.textContent = 'No Zabbix tags found yet. Run a Zabbix sync first.';
            ui.appendChild(h);
        }
        const meta = stZabbixCatalogTagMetaForPattern(p);
        const inCat = !!meta;
        const tmode = document.createElement('select');
        tmode.className = 'finp zb-r-tmode';
        tmode.style.minWidth = '170px';
        if (tags.length > 0) {
            const oa = document.createElement('option');
            oa.value = 'catalog';
            oa.textContent = 'From synced tags';
            tmode.appendChild(oa);
            const ob = document.createElement('option');
            ob.value = 'custom';
            ob.textContent = 'Advanced: custom value…';
            tmode.appendChild(ob);
            tmode.value = inCat || p.trim() === '' ? 'catalog' : 'custom';
        } else {
            const ox = document.createElement('option');
            ox.value = 'custom';
            ox.textContent = 'Custom value';
            tmode.appendChild(ox);
            tmode.value = 'custom';
            tmode.style.display = 'none';
        }
        ui.appendChild(tmode);

        let catWrap = null;
        let keySel = null;
        let valSel = null;
        if (tags.length > 0) {
            catWrap = document.createElement('div');
            catWrap.className = 'row-wrap gap6';
            catWrap.style.flex = '1';
            keySel = document.createElement('select');
            keySel.className = 'finp zb-r-tag-key';
            keySel.style.minWidth = '140px';
            const phk = document.createElement('option');
            phk.value = '';
            phk.textContent = '— tag —';
            keySel.appendChild(phk);
            tags.forEach((t) => {
                const o = document.createElement('option');
                o.value = t.tag;
                o.textContent = t.tag;
                keySel.appendChild(o);
            });
            valSel = document.createElement('select');
            valSel.className = 'finp zb-r-tag-val';
            valSel.style.minWidth = '160px';
            let selKey = '';
            let selVal = '__ANY__';
            if (meta) {
                selKey = meta.entry.tag;
                selVal = meta.mode === 'any' ? '__ANY__' : meta.value;
            } else if (!p.includes('=')) {
                selKey = p.trim();
            } else {
                const eq = p.indexOf('=');
                selKey = p.slice(0, eq).trim();
                selVal = p.slice(eq + 1);
            }
            [...keySel.options].forEach((op) => {
                if (op.value && op.value.trim().toLowerCase() === String(selKey).trim().toLowerCase()) {
                    op.selected = true;
                }
            });
            const effKey = keySel.value || selKey;
            const trow = tags.find((t) => String(t.tag || '').trim().toLowerCase() === String(effKey).trim().toLowerCase());
            stZabbixTagValPopulate(valSel, trow || { values: [] }, selVal);
            keySel.onchange = () => stZabbixOnTagKeyChange(keySel);
            valSel.onchange = () => stZabbixRefreshScopeRuleButtons();
            catWrap.appendChild(keySel);
            catWrap.appendChild(valSel);
            ui.appendChild(catWrap);
        }

        const inpT = document.createElement('input');
        inpT.type = 'text';
        inpT.className = 'finp zb-r-pattern-custom';
        inpT.style.minWidth = '200px';
        inpT.style.flex = '1';
        inpT.placeholder = 'e.g. Environment or Environment=prod';
        inpT.value = tmode.value === 'custom' ? p : '';
        inpT.oninput = () => stZabbixRefreshScopeRuleButtons();
        ui.appendChild(inpT);

        const applyT = () => {
            const cat = tags.length > 0 && tmode.value === 'catalog';
            if (catWrap) {
                catWrap.style.display = cat ? '' : 'none';
            }
            inpT.style.display = cat ? 'none' : '';
        };
        applyT();
        tmode.onchange = () => {
            applyT();
            if (tmode.value === 'custom' && keySel && valSel && keySel.value) {
                if (valSel.value === '__ANY__') {
                    inpT.value = keySel.value;
                } else {
                    inpT.value = keySel.value + '=' + valSel.value;
                }
            }
            stZabbixRefreshScopeRuleButtons();
        };
    }
}

function stZabbixAddRuleRow(rule, skipRefresh) {
    const wrap = document.getElementById('zb-rules-wrap');
    if (!wrap) return;
    const r = rule || {};
    const rt = (r.rule_type === 'tag') ? 'tag' : 'group';
    const sid = parseInt(String(r.scope_id || '0'), 10);
    const en = r.enabled ? ' checked' : '';
    const div = document.createElement('div');
    div.className = 'zb-rule-row row-wrap gap6 mb6 flex-wrap';
    div.innerHTML = `
      <select class="finp zb-r-type" style="min-width:140px" onchange="stZabbixOnRuleTypeChange(this)">
        <option value="group"${rt === 'group' ? ' selected' : ''}>Host group (exact name)</option>
        <option value="tag"${rt === 'tag' ? ' selected' : ''}>Host tag</option>
      </select>
      <div class="zb-r-pattern-ui"></div>
      ${zbScopeSelectHtml(sid, r)}
      <label class="text-micro chk" style="align-self:center;display:flex;align-items:center;gap:6px"><input type="checkbox" class="zb-r-en chk-input"${en} aria-label="Rule enabled"><span class="chk-label">enabled</span></label>
      <button type="button" class="tbtn btn-xs" onclick="this.closest('.zb-rule-row').remove();stZabbixRefreshScopeRuleButtons();">Remove</button>`;
    wrap.appendChild(div);
    stZabbixRenderRulePatternUi(div, { rule_type: rt, pattern: String(r.pattern || '') });
    if (!skipRefresh) stZabbixRefreshScopeRuleButtons();
}

function stZabbixRowReferencesDeletedScope(row) {
    const sel = row.querySelector('.zb-r-scope');
    if (!sel) return false;
    const opt = sel.options[sel.selectedIndex];
    return !!(opt && String(opt.textContent || '').indexOf('(deleted scope)') !== -1);
}

/** Every rule row is sent to the server (no silent drops). */
function stZabbixRulesFromDomForSave() {
    const out = [];
    let rowNum = 0;
    document.querySelectorAll('.zb-rule-row').forEach((row) => {
        ++rowNum;
        const type = (row.querySelector('.zb-r-type') || {}).value || 'group';
        const pattern = stZabbixRuleRowPatternFromDom(row);
        const scopeSel = row.querySelector('.zb-r-scope');
        const scope_id = parseInt(String(scopeSel && scopeSel.value ? scopeSel.value : '0'), 10);
        const enabled = !!(row.querySelector('.zb-r-en') || {}).checked;
        out.push({ rule_type: type, pattern: pattern.trim(), scope_id, enabled, _row: rowNum });
    });
    return out;
}

function stZabbixRefreshScopeRuleButtons() {
    const n = (zbScopeOptions || []).length;
    let hasStaleRule = false;
    document.querySelectorAll('.zb-rule-row').forEach((row) => {
        if (stZabbixRowReferencesDeletedScope(row)) hasStaleRule = true;
    });
    const dis = n === 0 || hasStaleRule;
    ['zb-save-rules-btn', 'zb-preview-rules-btn', 'zb-apply-plan-btn', 'zb-apply-exec-btn', 'zb-add-rule-btn'].forEach((id) => {
        const b = document.getElementById(id);
        if (b) {
            b.disabled = dis;
            b.classList.toggle('is-disabled', dis);
        }
    });
    const ban = document.getElementById('zb-scope-prereq-banner');
    if (!ban) return;
    if (n === 0) {
        ban.style.display = '';
        ban.innerHTML = '<strong>No scan scopes exist yet.</strong> Create one to enable Zabbix scope mapping (catalog only — no automatic asset assignment). '
            + '<div class="row-wrap gap6 mt6">'
            + '<button type="button" class="btnp btn-xs" onclick="openStCreateScopeModal(\'enrich\')">Create scope</button>'
            + '<button type="button" class="tbtn btn-xs" onclick="goTab(\'report\');hiNav(\'nreport\')">Reports &amp; Analysis</button>'
            + '</div>';
    } else if (hasStaleRule) {
        ban.style.display = '';
        ban.innerHTML = '<strong>Stale rule:</strong> at least one row references a deleted scan scope. Fix or remove it before saving, previewing, or applying. '
            + '<button type="button" class="tbtn btn-xs mt6" onclick="goTab(\'report\');hiNav(\'nreport\')">Open Reports &amp; Analysis</button>';
    } else {
        ban.style.display = 'none';
    }
}

async function loadZabbixFromApi() {
    return api('/api/zabbix.php', { quiet: true });
}

function stZabbixApplyIntegrationPanel(z) {
    if (!stRoleIsAdmin()) return;
    const nameEl = document.getElementById('zb-name');
    if (!nameEl) return;
    const stEl = document.getElementById('zb-status');
    const gateEl = document.getElementById('zb-schedule-gate');
    const secEl = document.getElementById('zb-schedule-section');
    if (!z || !z.ok) {
        if (stEl) stEl.textContent = (z && z.error) ? z.error : 'Zabbix API unavailable (migrations or role).';
        if (gateEl) {
            gateEl.style.display = 'none';
            gateEl.textContent = '';
        }
        if (secEl) secEl.style.display = 'none';
        return;
    }
    const c = z.connector || {};
    const urlEl = document.getElementById('zb-url');
    const tokEl = document.getElementById('zb-token');
    const enEl = document.getElementById('zb-enabled');
    const outEnEl = document.getElementById('zb-output-enabled');
    const outSenderHostEl = document.getElementById('zb-output-sender-host');
    const outSenderPortEl = document.getElementById('zb-output-sender-port');
    const outHostEl = document.getElementById('zb-output-host');
    const outPrefEl = document.getElementById('zb-output-prefix');
    const statsEl = document.getElementById('zb-stats');
    const outStatusEl = document.getElementById('zb-output-status');
    if (nameEl) nameEl.value = c.name || 'Zabbix';
    if (urlEl) urlEl.value = c.api_url || '';
    if (tokEl) tokEl.value = '';
    if (enEl) enEl.checked = !!c.enabled;
    if (outEnEl) outEnEl.checked = !!c.output_enabled;
    if (outSenderHostEl) outSenderHostEl.value = c.output_sender_host || '';
    if (outSenderPortEl) {
        const pp = c.output_sender_port != null ? parseInt(String(c.output_sender_port), 10) : 10051;
        outSenderPortEl.value = String(Number.isFinite(pp) && pp > 0 ? pp : 10051);
    }
    if (outHostEl) outHostEl.value = c.output_host || '';
    if (outPrefEl) outPrefEl.value = c.output_key_prefix || 'surveytrace.';
    if (stEl) {
        const err = c.last_error ? (' · last error: ' + esc(c.last_error)) : '';
        let frHtml = '';
        if (z.zabbix_status) {
            const zs = z.zabbix_status;
            frHtml = ' · cache <span class="' + stZabbixFreshnessBadgeClass(zs) + '">' + esc(stZabbixFreshnessBadgeLabel(zs)) + '</span>';
        }
        stEl.innerHTML = 'Last sync: ' + esc(String(c.last_sync_at || '—'))
            + ' · status: ' + esc(String(c.last_sync_status || '—')) + err + frHtml;
    }
    if (statsEl) {
        const s = z.stats || {};
        statsEl.textContent = `Hosts synced: ${s.hosts || 0} · matched links: ${s.matched_pairs || 0} · unmatched Zabbix hosts: ${s.hosts_unmatched || 0}`;
    }
    if (outStatusEl) {
        const pushErr = c.last_output_push_error ? (' · last error: ' + esc(c.last_output_push_error)) : '';
        const pushState = c.output_enabled ? 'enabled' : 'disabled';
        outStatusEl.innerHTML = 'Zabbix output: <span class="badge-mini '
            + (c.output_enabled ? 'badge-on' : 'badge-off') + '">' + pushState + '</span>'
            + ' · last push: ' + esc(String(c.last_output_push_at || '—'))
            + ' · result: ' + esc(String(c.last_output_push_status || '—'))
            + ' · sent: ' + esc(String(c.last_output_push_count != null ? c.last_output_push_count : 0))
            + pushErr;
    }
    const configured = String(c.api_url || '').trim() !== '' && !!c.api_token_set;
    if (gateEl && secEl) {
        if (!configured) {
            gateEl.style.display = '';
            gateEl.textContent = 'Zabbix enrichment is not configured. Configure API URL and token first.';
            secEl.style.display = 'none';
        } else {
            secEl.style.display = '';
            gateEl.style.display = c.enabled ? 'none' : '';
            gateEl.textContent = c.enabled ? '' : 'Zabbix enrichment is disabled. Enable the connector above for sync or schedule to run.';
        }
    }
    const schedEnEl = document.getElementById('zb-sync-sched-enabled');
    const schedIntEl = document.getElementById('zb-sync-interval-min');
    const schedStatEl = document.getElementById('zb-schedule-status');
    if (configured && schedEnEl && schedIntEl && schedStatEl) {
        const sch = z.schedule || {};
        const fr = z.freshness || {};
        schedEnEl.checked = !!sch.sync_schedule_enabled;
        const iv = sch.sync_interval_minutes != null ? parseInt(String(sch.sync_interval_minutes), 10) : 60;
        schedIntEl.value = String(Number.isFinite(iv) ? Math.min(1440, Math.max(5, iv)) : 60);
        const zsFr = { last_sync: fr.last_sync_at, freshness_seconds: fr.last_sync_age_seconds, freshness_state: fr.freshness_state };
        const badgeSched = '<span class="' + stZabbixFreshnessBadgeClass(zsFr) + '">' + esc(stZabbixFreshnessBadgeLabel(zsFr)) + '</span>';
        const stLine = fr.last_sync_status != null ? String(fr.last_sync_status) : String(c.last_sync_status || '—');
        schedStatEl.innerHTML = 'Last pull: <span class="mono-sm">' + esc(String(fr.last_sync_at || '—')) + '</span>'
            + ' · age: ' + esc(stZabbixFormatAgeSeconds(fr.last_sync_age_seconds))
            + ' · next: <span class="mono-sm">' + esc(String(sch.next_sync_at || '—')) + '</span>'
            + ' · ' + badgeSched
            + ' · status: ' + esc(stLine)
            + (fr.last_error ? (' · error: ' + esc(String(fr.last_error))) : '');
    }
}

function stZabbixApplyEnrichmentPanel(z) {
    if (!stRoleIsAdmin()) return;
    const rulesWrap = document.getElementById('zb-rules-wrap');
    if (!rulesWrap) return;
    if (!z || !z.ok) return;
    zbScopeOptions = Array.isArray(z.scopes) && z.scopes.length
        ? z.scopes
        : zbScopeOptions;
    zbScopeMapCatalog =
        z.scope_map_catalog && typeof z.scope_map_catalog === 'object'
            ? {
                groups: Array.isArray(z.scope_map_catalog.groups) ? z.scope_map_catalog.groups : [],
                tags: Array.isArray(z.scope_map_catalog.tags) ? z.scope_map_catalog.tags : [],
            }
            : { groups: [], tags: [] };
    stZabbixApplyCacheStatusHint(z);
    if (!zbScopeOptions.length) {
        void api('/api/scopes.php', { quiet: true }).then((sc) => {
            if (sc && sc.ok && Array.isArray(sc.scopes)) zbScopeOptions = sc.scopes;
            stZabbixRefreshScopeRuleButtons();
        });
    }
    rulesWrap.innerHTML = '';
    const rules = z.scope_rules || [];
    if (rules.length) {
        rules.forEach((r) => stZabbixAddRuleRow(r, true));
    }
    const zbSc = document.getElementById('zb-scope-apply-block');
    if (zbSc) zbSc.style.display = (z.workflow && z.workflow.asset_scope_apply) ? 'block' : 'none';
    const scopeFilterSel = document.getElementById('zb-apply-scope-filter');
    if (scopeFilterSel) {
        const prev = String(scopeFilterSel.value || '0');
        scopeFilterSel.innerHTML = '<option value="0">All target scopes</option>' + (zbScopeOptions || []).map((s) => {
            const id = parseInt(String(s.id), 10);
            return `<option value="${id}">${esc(String(s.name || ('#' + id)))}</option>`;
        }).join('');
        scopeFilterSel.value = [...scopeFilterSel.options].some((o) => o.value === prev) ? prev : '0';
    }
    stZabbixRefreshScopeRuleButtons();
}

async function loadZabbixIntegrationOnly() {
    if (!stRoleIsAdmin()) return;
    const [z, zsR] = await Promise.all([
        loadZabbixFromApi(),
        api('/api/zabbix.php?status=1', { quiet: true }),
    ]);
    stZabbixApplyIntegrationPanel(z);
    stEnrichmentRefreshZabbixOverview(z && z.ok ? z : zsR);
    stZabbixApplyEnrichmentFreshnessBanner(
        z && z.ok && z.zabbix_status ? z.zabbix_status : (zsR && zsR.zabbix_status ? zsR.zabbix_status : null)
    );
}

async function loadZabbixEnrichmentPanel() {
    const zsR = await api('/api/zabbix.php?status=1', { quiet: true });
    if (stRoleIsAdmin()) {
        const z = await loadZabbixFromApi();
        stEnrichmentRefreshZabbixOverview(z && z.ok ? z : zsR);
        stZabbixApplyIntegrationPanel(z);
        stZabbixApplyEnrichmentPanel(z);
        stZabbixApplyEnrichmentFreshnessBanner(
            z && z.ok && z.zabbix_status ? z.zabbix_status : (zsR && zsR.zabbix_status ? zsR.zabbix_status : null)
        );
    } else {
        stEnrichmentRefreshZabbixOverview(zsR);
        stZabbixApplyEnrichmentFreshnessBanner(null);
    }
}

async function stZabbixSyncFromEnrichment() {
    if (!stRoleIsAdmin()) return;
    await stZabbixSync();
}

async function loadZabbixConnector() {
    await loadZabbixEnrichmentPanel();
}

async function stZabbixSave() {
    if (!stRoleIsAdmin()) return;
    const body = {
        action: 'save_connector',
        name: (document.getElementById('zb-name') || {}).value || '',
        api_url: (document.getElementById('zb-url') || {}).value || '',
        enabled: !!(document.getElementById('zb-enabled') || {}).checked,
        output_enabled: !!(document.getElementById('zb-output-enabled') || {}).checked,
        output_sender_host: ((document.getElementById('zb-output-sender-host') || {}).value || '').trim(),
        output_sender_port: (function () {
            const el = document.getElementById('zb-output-sender-port');
            const raw = el && el.value != null ? String(el.value).trim() : '';
            if (raw === '') return 10051;
            const n = parseInt(raw, 10);
            return Number.isFinite(n) ? n : 10051;
        })(),
        output_host: ((document.getElementById('zb-output-host') || {}).value || '').trim(),
        output_key_prefix: ((document.getElementById('zb-output-prefix') || {}).value || '').trim(),
    };
    const tok = (document.getElementById('zb-token') || {}).value || '';
    if (tok.trim() !== '') body.api_token = tok.trim();
    const r = await apiPost('/api/zabbix.php', body);
    if (r && r.ok) {
        toast('Zabbix connector saved', 'ok');
        await loadZabbixIntegrationOnly();
        await loadZabbixEnrichmentPanel();
    } else {
        toast((r && r.error) ? r.error : 'Save failed', 'err');
    }
}

