/** Last scope apply plan from `preview_scope_apply` (same indices as checkboxes in #zb-apply-plan-body). */
var __stZabbixScopePlan = [];

function stZabbixScopePlanCapturePrevSelection() {
    const plan = __stZabbixScopePlan || [];
    const keys = new Set();
    document.querySelectorAll('#zb-apply-plan-body .zb-plan-chk').forEach((el) => {
        if (el.disabled || !el.checked) return;
        const i = parseInt(el.getAttribute('data-i') || '-1', 10);
        const p = plan[i];
        if (!p) return;
        keys.add(String(p.asset_id) + '|' + String(parseInt(String(p.suggested_scope_id || '0'), 10)));
    });
    return keys;
}

function stZabbixScopePlanRestoreSelection(keys, plan) {
    if (!keys || keys.size === 0 || !plan.length) return;
    plan.forEach((p, i) => {
        const k = String(p.asset_id) + '|' + String(parseInt(String(p.suggested_scope_id || '0'), 10));
        if (!keys.has(k)) return;
        const ch = document.querySelector(`#zb-apply-plan-body .zb-plan-chk[data-i="${i}"]`);
        if (ch && !ch.disabled) ch.checked = true;
    });
}

function stZabbixScopePlanUpdateCount() {
    const el = document.getElementById('zb-plan-select-count');
    if (!el) return;
    let eligible = 0;
    let checked = 0;
    document.querySelectorAll('#zb-apply-plan-body .zb-plan-chk').forEach((c) => {
        if (c.disabled) return;
        eligible++;
        if (c.checked) checked++;
    });
    el.textContent = String(checked) + ' of ' + String(eligible) + ' selected';
    const hdr = document.getElementById('zb-plan-header-chk');
    if (hdr) {
        hdr.disabled = eligible === 0;
        hdr.checked = eligible > 0 && checked === eligible;
        hdr.indeterminate = checked > 0 && checked < eligible;
    }
}

function stZabbixScopePlanSelectAll(on) {
    document.querySelectorAll('#zb-apply-plan-body .zb-plan-chk:not(:disabled)').forEach((c) => {
        c.checked = !!on;
    });
    stZabbixScopePlanUpdateCount();
}

function stZabbixScopePlanHeaderClick(ev) {
    if (ev) ev.preventDefault();
    const eligible = [...document.querySelectorAll('#zb-apply-plan-body .zb-plan-chk:not(:disabled)')];
    if (!eligible.length) return false;
    const allOn = eligible.every((c) => c.checked);
    eligible.forEach((c) => {
        c.checked = !allOn;
    });
    stZabbixScopePlanUpdateCount();
    return false;
}

function stZabbixFormatSkipReasons(sr) {
    if (!sr || typeof sr !== 'object') return '';
    const labels = {
        already_target_scope: 'already at target scope',
        stale_old_scope: 'stale current scope (refresh plan)',
        stale_suggestion: 'rules changed (refresh plan)',
        invalid_row: 'invalid row',
        invalid_new_scope: 'invalid target scope',
        asset_not_found: 'asset not found',
        not_linked: 'not linked',
        hostname_locked: 'hostname locked',
        already_set: 'hostname already set',
        stale_current_hostname: 'stale hostname (refresh plan)',
        no_zabbix_name: 'no Zabbix name',
        stale_preview: 'stale preview',
        not_selected: 'invalid selection',
    };
    const parts = [];
    Object.keys(sr).forEach((k) => {
        const n = sr[k];
        if (typeof n === 'number' && n > 0) parts.push(String(n) + ' ' + (labels[k] || k));
    });
    return parts.join(', ');
}

function stZabbixFormatScopeApplyToast(r) {
    const applied = r.applied != null ? r.applied : 0;
    const skipped = r.skipped != null ? r.skipped : 0;
    const sr = r.skip_reasons || {};
    if (applied > 0) {
        let m = 'Applied ' + String(applied) + ' update' + (applied === 1 ? '' : 's') + '.';
        if (skipped > 0) {
            const sum = stZabbixFormatSkipReasons(sr);
            if (sum) m += ' Skipped: ' + sum + '.';
        }
        return m;
    }
    if (skipped > 0 && sr.already_target_scope === skipped) {
        return 'No changes needed. ' + String(skipped) + ' asset' + (skipped === 1 ? '' : 's') + ' already matched the target scope.';
    }
    if (skipped > 0) {
        const sum = stZabbixFormatSkipReasons(sr);
        return sum ? ('No updates applied. Skipped: ' + sum + '.') : 'No updates applied.';
    }
    return 'No updates applied.';
}

function stZabbixFormatIdentityApplyToast(r) {
    const applied = r.applied != null ? r.applied : 0;
    const skipped = r.skipped != null ? r.skipped : 0;
    const sr = r.skip_reasons || {};
    if (applied > 0) {
        let m = 'Applied ' + String(applied) + ' hostname update' + (applied === 1 ? '' : 's') + '.';
        if (skipped > 0) {
            const sum = stZabbixFormatSkipReasons(sr);
            if (sum) m += ' Skipped: ' + sum + '.';
        }
        return m;
    }
    if (skipped > 0) {
        const sum = stZabbixFormatSkipReasons(sr);
        return sum ? ('No updates applied. Skipped: ' + sum + '.') : 'No updates applied.';
    }
    return 'No updates applied.';
}

async function stZabbixLoadApplyPlan() {
    if (!stRoleIsAdmin()) return;
    const el = document.getElementById('zb-apply-plan-body');
    if (!el) return;
    const prevKeys = stZabbixScopePlanCapturePrevSelection();
    el.textContent = 'Loading plan…';
    const scopeFilterEl = document.getElementById('zb-apply-scope-filter');
    const scopeFilter = scopeFilterEl ? parseInt(String(scopeFilterEl.value || '0'), 10) : 0;
    const payload = { action: 'preview_scope_apply' };
    if (scopeFilter > 0) payload.scope_id = scopeFilter;
    const r = await apiPost('/api/zabbix.php', payload);
    if (!r || !r.ok) {
        el.textContent = (r && r.error) ? r.error : 'Plan failed';
        return;
    }
    const plan = r.plan || [];
    __stZabbixScopePlan = plan;
    const scopeFilterLabel = (() => {
        if (!(scopeFilter > 0)) return 'All scopes';
        const hit = (zbScopeOptions || []).find((s) => parseInt(String(s.id), 10) === scopeFilter);
        return hit ? ('Filtered to scope: ' + String(hit.name || ('#' + scopeFilter))) : ('Filtered to scope #' + scopeFilter);
    })();
    if (!plan.length) {
        el.innerHTML = '<p class="hint-micro mb2"><strong>' + esc(scopeFilterLabel) + '</strong></p>'
            + '<p class="hint-micro mb2">' + esc(r.note || 'No scope updates needed.') + '</p>'
            + '<p class="text-dim text-micro mb0">No saved enabled rules produced changes, or no linked assets matched those rules.</p>';
        return;
    }
    const planLim = 25;
    const rowOne = (p, i, hide) => {
        const cur = p.current_scope_id != null && p.current_scope_id !== '' ? parseInt(String(p.current_scope_id), 10) : null;
        const sug = parseInt(String(p.suggested_scope_id || '0'), 10);
        const chg = (cur || 0) !== (sug || 0);
        const checked = chg ? ' checked' : '';
        const dis = chg ? '' : ' disabled';
        const status = chg
            ? '<span class="text-micro">Will change</span>'
            : '<span class="text-dim text-micro">No change needed</span>';
        const hid = hide ? ' class="zb-mr-extra zb-mr-extra-plan" style="display:none"' : '';
        return `<tr${hid}>
          <td><input type="checkbox" class="zb-plan-chk chk-input" data-i="${i}" data-eligible="${chg ? '1' : '0'}"${checked}${dis} onchange="stZabbixScopePlanUpdateCount()"></td>
          <td class="mono-sm">${esc(String(p.asset_id))}</td>
          <td class="mono-sm">${esc(p.ip || '')}</td>
          <td>${zbScopeLabel(cur)}</td>
          <td>${zbScopeLabel(sug)}</td>
          <td class="text-micro">${esc(p.rule_type || '')}:${esc(p.pattern || '')}</td>
          <td class="text-micro">${status}</td>
        </tr>`;
    };
    const rows = plan.map((p, i) => rowOne(p, i, i >= planLim)).join('');
    const morePlan = plan.length > planLim
        ? `<button type="button" class="tbtn btn-xs mt6" id="zb-mr-more-plan" onclick="stZabbixMrShowAll('plan')">Show all ${plan.length}</button>`
        : '';
    let eligibleN = 0;
    let noChg = 0;
    plan.forEach((p) => {
        const cur = p.current_scope_id != null && p.current_scope_id !== '' ? parseInt(String(p.current_scope_id), 10) : 0;
        const sug = parseInt(String(p.suggested_scope_id || '0'), 10) || 0;
        if ((cur || 0) !== (sug || 0)) {
            eligibleN++;
        } else {
            noChg++;
        }
    });
    let sumP = '';
    if (eligibleN === 0) {
        sumP = '<p class="hint-micro mb4"><strong>' + esc(scopeFilterLabel) + '</strong></p>'
            + '<p class="hint-micro mb6">No scope updates needed — every row is already at the suggested scope.</p>';
    } else {
        sumP = '<p class="hint-micro mb4"><strong>' + esc(scopeFilterLabel) + '</strong></p>'
            + '<p class="hint-micro mb6">' + esc(String(eligibleN)) + ' row(s) can be applied'
            + (noChg > 0 ? ' · ' + esc(String(noChg)) + ' already at target (disabled)' : '')
            + '.</p>';
    }
    el.innerHTML = sumP
        + `<div class="row-wrap gap6 mb8" style="align-items:center;flex-wrap:wrap">
      <button type="button" class="tbtn btn-xs" onclick="stZabbixScopePlanSelectAll(true)">Select all</button>
      <button type="button" class="tbtn btn-xs" onclick="stZabbixScopePlanSelectAll(false)">Clear all</button>
      <span class="hint-micro" id="zb-plan-select-count">0 of 0 selected</span>
    </div>
    <div class="tbl-wrap"><table class="tbl"><thead><tr>
      <th style="width:36px"><input type="checkbox" class="chk-input" id="zb-plan-header-chk" title="Select all eligible rows" aria-label="Select all eligible rows" onclick="stZabbixScopePlanHeaderClick(event)"></th>
      <th>Asset</th><th>IP</th><th>Current scope</th><th>New scope</th><th>Rule</th><th>Status</th>
    </tr></thead><tbody>${rows}</tbody></table></div>${morePlan}
    <p class="hint-micro mt4">Only checked, eligible rows are sent on apply.</p>`;
    stZabbixScopePlanRestoreSelection(prevKeys, plan);
    stZabbixScopePlanUpdateCount();
}

async function stZabbixApplyPlanSelection() {
    if (!stRoleIsAdmin()) return;
    const c = document.getElementById('zb-apply-confirm');
    if (!c || !c.checked) {
        toast('Check the confirmation box first', 'err');
        return;
    }
    const plan = __stZabbixScopePlan || [];
    const apply = [];
    document.querySelectorAll('.zb-plan-chk:checked').forEach((el) => {
        const i = parseInt(el.getAttribute('data-i') || '-1', 10);
        const p = plan[i];
        if (!p) return;
        const curRaw = p.current_scope_id;
        const oldScope = (curRaw !== null && curRaw !== undefined && String(curRaw) !== '')
            ? parseInt(String(curRaw), 10)
            : null;
        apply.push({
            asset_id: parseInt(String(p.asset_id), 10),
            old_scope_id: oldScope,
            new_scope_id: parseInt(String(p.suggested_scope_id), 10),
        });
    });
    if (!apply.length) {
        toast('Select at least one row to apply', 'err');
        return;
    }
    if (!(await showConfirmModal(
        `Apply scan scope updates to ${apply.length} asset(s)? Changes are logged in the audit trail.`,
        { title: 'Apply scope map', okText: 'Apply updates', cancelText: 'Cancel' }
    ))) return;
    const r = await apiPost('/api/zabbix.php', { action: 'apply_scope_map', confirm: true, apply });
    if (r && r.ok) {
        let msg = stZabbixFormatScopeApplyToast(r);
        if (r.errors && r.errors.length) msg += ' Details: ' + r.errors.join('; ');
        const sr0 = r.skip_reasons || {};
        const sk = r.skipped != null ? r.skipped : 0;
        const ap = r.applied != null ? r.applied : 0;
        const benign = ap === 0 && sk > 0 && sr0.already_target_scope === sk;
        toast(msg, (ap > 0 || benign) ? 'ok' : 'err');
        document.getElementById('zb-apply-confirm').checked = false;
        await stZabbixLoadApplyPlan();
        await loadZabbixEnrichmentPanel();
    } else {
        toast((r && r.error) ? r.error : 'Apply failed', 'err');
    }
}

/** Last identity hostname plan from `preview_identity_apply` (indices match `.zb-id-chk`). */
var __stZabbixIdentityPlan = [];

function stZabbixIdentityPlanCapturePrevSelection() {
    const plan = __stZabbixIdentityPlan || [];
    const keys = new Set();
    document.querySelectorAll('#zb-identity-plan-body .zb-id-chk').forEach((el) => {
        if (el.disabled || !el.checked) return;
        const i = parseInt(el.getAttribute('data-i') || '-1', 10);
        const p = plan[i];
        if (!p) return;
        const sug = p.suggested_hostname != null ? String(p.suggested_hostname) : '';
        keys.add(String(p.asset_id) + '\0' + sug);
    });
    return keys;
}

function stZabbixIdentityPlanRestoreSelection(keys, plan) {
    if (!keys || keys.size === 0 || !plan.length) return;
    plan.forEach((p, i) => {
        const sug = p.suggested_hostname != null ? String(p.suggested_hostname) : '';
        const k = String(p.asset_id) + '\0' + sug;
        if (!keys.has(k)) return;
        const ch = document.querySelector(`#zb-identity-plan-body .zb-id-chk[data-i="${i}"]`);
        if (ch && !ch.disabled) ch.checked = true;
    });
}

function stZabbixIdentityPlanUpdateCount() {
    const el = document.getElementById('zb-id-select-count');
    if (!el) return;
    let eligible = 0;
    let checked = 0;
    document.querySelectorAll('#zb-identity-plan-body .zb-id-chk').forEach((c) => {
        if (c.disabled) return;
        eligible++;
        if (c.checked) checked++;
    });
    el.textContent = String(checked) + ' of ' + String(eligible) + ' selected';
    const hdr = document.getElementById('zb-id-header-chk');
    if (hdr) {
        hdr.disabled = eligible === 0;
        hdr.checked = eligible > 0 && checked === eligible;
        hdr.indeterminate = checked > 0 && checked < eligible;
    }
}

function stZabbixIdentityPlanSelectAll(on) {
    document.querySelectorAll('#zb-identity-plan-body .zb-id-chk:not(:disabled)').forEach((c) => {
        c.checked = !!on;
    });
    stZabbixIdentityPlanUpdateCount();
}

function stZabbixIdentityPlanHeaderClick(ev) {
    if (ev) ev.preventDefault();
    const eligible = [...document.querySelectorAll('#zb-identity-plan-body .zb-id-chk:not(:disabled)')];
    if (!eligible.length) return false;
    const allOn = eligible.every((c) => c.checked);
    eligible.forEach((c) => {
        c.checked = !allOn;
    });
    stZabbixIdentityPlanUpdateCount();
    return false;
}

async function stZabbixLoadIdentityPlan() {
    if (!stRoleIsAdmin()) return;
    const el = document.getElementById('zb-identity-plan-body');
    if (!el) return;
    const prevKeys = stZabbixIdentityPlanCapturePrevSelection();
    el.textContent = 'Loading plan…';
    const r = await apiPost('/api/zabbix.php', { action: 'preview_identity_apply' });
    if (!r || !r.ok) {
        el.textContent = (r && r.error) ? r.error : 'Plan failed';
        return;
    }
    const plan = r.plan || [];
    __stZabbixIdentityPlan = plan;
    if (!plan.length) {
        el.innerHTML = '<p class="hint-micro mb2">' + esc(r.note || 'No identity suggestions right now.') + '</p>'
            + '<p class="text-dim text-micro mb0">Linked assets already have hostnames, have locked hostnames, or Zabbix has no usable name.</p>';
        return;
    }
    const idLim = 25;
    const rowId = (p, i, hide) => {
        const curH = p.current_hostname != null ? String(p.current_hostname) : '';
        const sug = p.suggested_hostname != null ? String(p.suggested_hostname) : '';
        const zdn = p.zabbix_display_name != null ? String(p.zabbix_display_name) : '';
        const conf = p.confidence != null ? Number(p.confidence).toFixed(2) : '—';
        const eligible = sug.trim() !== '';
        const dis = eligible ? '' : ' disabled';
        const checked = eligible ? ' checked' : '';
        const hid = hide ? ' class="zb-mr-extra zb-mr-extra-idplan" style="display:none"' : '';
        return `<tr${hid}>
          <td><input type="checkbox" class="zb-id-chk chk-input" data-i="${i}" data-eligible="${eligible ? '1' : '0'}"${checked}${dis} onchange="stZabbixIdentityPlanUpdateCount()"></td>
          <td class="mono-sm">${esc(String(p.asset_id))}</td>
          <td class="mono-sm">${esc(p.ip || '')}</td>
          <td class="mono-sm">${esc(curH || '—')}</td>
          <td class="mono-sm">${esc(zdn)}</td>
          <td class="text-micro">${esc(String(p.match_method || ''))}</td>
          <td class="mono-sm">${esc(conf)}</td>
          <td class="mono-sm">${esc(sug)}</td>
        </tr>`;
    };
    const rows = plan.map((p, i) => rowId(p, i, i >= idLim)).join('');
    const moreId = plan.length > idLim
        ? `<button type="button" class="tbtn btn-xs mt6" id="zb-mr-more-idplan" onclick="stZabbixMrShowAll('idplan')">Show all ${plan.length}</button>`
        : '';
    el.innerHTML = `<div class="row-wrap gap6 mb8" style="align-items:center;flex-wrap:wrap">
      <button type="button" class="tbtn btn-xs" onclick="stZabbixIdentityPlanSelectAll(true)">Select all</button>
      <button type="button" class="tbtn btn-xs" onclick="stZabbixIdentityPlanSelectAll(false)">Clear all</button>
      <span class="hint-micro" id="zb-id-select-count">0 of 0 selected</span>
    </div>
    <div class="tbl-wrap"><table class="tbl"><thead><tr>
      <th style="width:36px"><input type="checkbox" class="chk-input" id="zb-id-header-chk" title="Select all eligible rows" aria-label="Select all eligible rows" onclick="stZabbixIdentityPlanHeaderClick(event)"></th>
      <th>Asset</th><th>IP</th><th>Current hostname</th><th>Zabbix host</th><th>Match</th><th>Conf.</th><th>Suggested hostname</th>
    </tr></thead><tbody>${rows}</tbody></table></div>${moreId}
    <p class="hint-micro mt4">Only checked, eligible rows are sent on apply.</p>`;
    stZabbixIdentityPlanRestoreSelection(prevKeys, plan);
    stZabbixIdentityPlanUpdateCount();
}

async function stZabbixApplyIdentitySelection() {
    if (!stRoleIsAdmin()) return;
    const c = document.getElementById('zb-identity-confirm');
    if (!c || !c.checked) {
        toast('Check the confirmation box first', 'err');
        return;
    }
    const plan = __stZabbixIdentityPlan || [];
    const apply = [];
    document.querySelectorAll('.zb-id-chk:checked').forEach((el) => {
        const i = parseInt(el.getAttribute('data-i') || '-1', 10);
        const p = plan[i];
        if (!p) return;
        apply.push({
            asset_id: parseInt(String(p.asset_id), 10),
            current_hostname: p.current_hostname != null ? String(p.current_hostname) : '',
            suggested_hostname: p.suggested_hostname != null ? String(p.suggested_hostname) : '',
        });
    });
    if (!apply.length) {
        toast('Select at least one row to apply', 'err');
        return;
    }
    if (!(await showConfirmModal(
        `Apply Zabbix-suggested hostname to ${apply.length} asset(s)? Only blank hostnames are updated; changes are logged in the audit trail.`,
        { title: 'Apply identity updates', okText: 'Apply', cancelText: 'Cancel' }
    ))) return;
    const r = await apiPost('/api/zabbix.php', { action: 'apply_identity', confirm: true, apply });
    if (r && r.ok) {
        toast(stZabbixFormatIdentityApplyToast(r), (r.applied > 0) ? 'ok' : 'err');
        document.getElementById('zb-identity-confirm').checked = false;
        await stZabbixLoadIdentityPlan();
        await stZabbixMatchReviewRefresh();
        if (currentTab === 'assets') loadAssets(typeof assetPage === 'number' ? assetPage : 1);
    } else {
        toast((r && r.error) ? r.error : 'Apply failed', 'err');
    }
}

function stZabbixFormatConfidenceCell(v) {
    if (v === null || v === undefined || v === '') {
        return '—';
    }
    const n = Number(v);
    if (!Number.isFinite(n)) {
        return esc(String(v));
    }
    return esc(n.toFixed(2));
}

function stZabbixFormatManualCell(v) {
    if (v === true || v === 1 || v === '1') {
        return 'Yes';
    }
    if (v === false || v === 0 || v === '0') {
        return 'No';
    }
    const n = parseInt(String(v ?? ''), 10);
    if (n === 1) {
        return 'Yes';
    }
    if (n === 0) {
        return 'No';
    }
    return '—';
}

function stZabbixMrCell(row, col) {
    if (!row || !col) {
        return '';
    }
    if (col.fmt === 'conf') {
        return stZabbixFormatConfidenceCell(row.confidence);
    }
    if (col.fmt === 'yesno') {
        return stZabbixFormatManualCell(row.is_manual);
    }
    const raw = row[col.key] != null ? row[col.key] : '';
    return esc(String(raw));
}

/** @param {string} kind safe id fragment for Show all / extra row classes */
function stZabbixMatchLinkedTableHtml(title, rows, cols, kind) {
    if (!rows || !rows.length) {
        return title
            ? '<div class="mb6"><span class="text-dim">' + esc(title) + ' — none</span></div>'
            : '<p class="text-dim text-micro mb0">None</p>';
    }
    const lim = 25;
    const hdr = cols.map((c) => `<th class="tbl-th-no-sort">${esc(c.label)}</th>`).join('');
    const bodyV = rows.slice(0, lim).map((row) => '<tr>'
        + cols.map((c) => `<td class="mono-sm tbl-cell-mono tbl-cell-muted">${stZabbixMrCell(row, c)}</td>`).join('') + '</tr>').join('');
    const bodyH = rows.slice(lim).map((row) => '<tr class="zb-mr-extra zb-mr-extra-' + kind + '" style="display:none">'
        + cols.map((c) => `<td class="mono-sm tbl-cell-mono tbl-cell-muted">${stZabbixMrCell(row, c)}</td>`).join('') + '</tr>').join('');
    const more = rows.length > lim
        ? `<button type="button" class="tbtn btn-xs mt6" id="zb-mr-more-${kind}" onclick="stZabbixMrShowAll('${kind}')">Show all ${rows.length}</button>`
        : '';
    const ttl = title ? `<div class="text-strong mb4">${esc(title)} <span class="text-dim">(${rows.length})</span></div>` : '';
    return '<div class="mb10">' + ttl + `<div class="tbl-wrap tbl-wrap--data zb-mr-tbl-wrap"><table class="tbl tbl--data"><thead><tr>${hdr}</tr></thead><tbody>${bodyV}${bodyH}</tbody></table></div>${more}</div>`;
}

async function stZabbixMatchReviewRefresh() {
    if (!stRoleIsAdmin()) return;
    const el = document.getElementById('zb-match-review-body');
    if (!el) return;
    el.innerHTML = '<p class="tbl-empty-inline">Loading match review…</p>';
    const z = await api('/api/zabbix.php?match_review=1', { quiet: true });
    if (!z || !z.ok) {
        el.textContent = (z && z.error) ? z.error : 'Could not load match review';
        return;
    }
    const mr = z.match_review || {};
    const hi = mr.high_confidence || [];
    const near = mr.near_threshold || [];
    const uh = mr.unmatched_zabbix_hosts || [];
    const ua = mr.unmatched_assets || [];
    const MR_LINK_COLS = [
        { key: 'asset_id', label: 'Asset ID' },
        { key: 'ip', label: 'IP' },
        { key: 'hostname', label: 'Asset host' },
        { key: 'zabbix_display_name', label: 'Zabbix host' },
        { key: 'zabbix_hostid', label: 'Zabbix hostid' },
        { key: 'match_method', label: 'Method' },
        { key: 'confidence', label: 'Confidence', fmt: 'conf' },
        { key: 'is_manual', label: 'Manual?', fmt: 'yesno' },
    ];
    const MR_UH_COLS = [
        { key: 'hostid', label: 'Zabbix hostid' },
        { key: 'zabbix_display_name', label: 'Display' },
        { key: 'visible_name', label: 'Visible name' },
        { key: 'tech_name', label: 'Technical name' },
        { key: 'monitored', label: 'Monitored' },
        { key: 'available', label: 'Availability' },
    ];
    const MR_UA_COLS = [
        { key: 'asset_id', label: 'Asset ID' },
        { key: 'ip', label: 'IP' },
        { key: 'hostname', label: 'Asset host' },
    ];
    const nHi = hi.length;
    const nNear = near.length;
    const nUh = uh.length;
    const nUa = ua.length;
    const cardParts = [
        ['High confidence links', nHi],
        ['Near threshold candidates', nNear],
        ['Unmatched Zabbix hosts', nUh],
        ['Assets without Zabbix link', nUa],
    ].map(([t, n]) => '<div class="card" style="padding:10px 14px;min-width:152px">'
        + `<div class="text-micro text-dim">${esc(t)}</div><div class="text-strong mono-sm">${esc(String(n))}</div></div>`).join('');
    const summaryCards = '<div class="row-wrap gap8 mb10" style="flex-wrap:wrap">' + cardParts + '</div>';
    const hiBlock = stZabbixMatchLinkedTableHtml('High confidence (≥ 0.9)', hi, MR_LINK_COLS, 'mr-hi');
    const nearBlock = stZabbixMatchLinkedTableHtml('Near threshold (0.75–0.9)', near, MR_LINK_COLS, 'mr-near');
    let uhBlock = '';
    if (nUh === 0) {
        uhBlock = '<p class="text-micro text-dim mb8">Unmatched Zabbix hosts: none</p>';
    } else {
        uhBlock = '<details class="mb10"><summary class="text-strong" style="cursor:pointer">Unmatched Zabbix hosts ('
            + esc(String(nUh)) + ')</summary><div class="mt6">'
            + stZabbixMatchLinkedTableHtml('', uh, MR_UH_COLS, 'mr-uh')
            + '</div></details>';
    }
    let uaBlock = '';
    if (nUa === 0) {
        uaBlock = '<p class="text-micro text-dim mb8">Assets without Zabbix link: none</p>';
    } else {
        const uaOpen = nUa <= 20 ? ' open' : '';
        uaBlock = '<details class="mb8"' + uaOpen + '><summary class="text-strong" style="cursor:pointer">Assets without Zabbix link ('
            + esc(String(nUa)) + ')</summary>'
            + '<p class="hint-micro text-dim mb6">Usually expected unless every asset is monitored by Zabbix.</p><div class="mt6">'
            + stZabbixMatchLinkedTableHtml('', ua, MR_UA_COLS, 'mr-ua')
            + '</div></details>';
    }
    el.innerHTML = summaryCards + hiBlock + nearBlock + uhBlock + uaBlock;
}

async function stZabbixManualLink() {
    if (!stRoleIsAdmin()) return;
    const asset_id = parseInt(String((document.getElementById('zb-link-aid') || {}).value || '0'), 10);
    const zabbix_hostid = String((document.getElementById('zb-link-hid') || {}).value || '').trim();
    const match_method = String((document.getElementById('zb-link-method') || {}).value || 'manual').trim() || 'manual';
    const confidence = parseFloat(String((document.getElementById('zb-link-conf') || {}).value || '1'));
    if (asset_id <= 0 || !zabbix_hostid) {
        toast('Asset id and Zabbix hostid required', 'err');
        return;
    }
    const r = await apiPost('/api/zabbix.php', {
        action: 'link_manual',
