function feedSyncConflictReason(target) {
    const r = feedSyncRunning;
    if (target === 'nvd' && r.nvd && !r.all) return 'NVD sync is already running.';
    if (target === 'oui' && r.oui && !r.all) return 'OUI sync is already running.';
    if (target === 'webfp' && r.webfp && !r.all) return 'WebFP sync is already running.';
    if (target === 'cve_intel' && r.cve_intel && !r.all) return 'CVE intel sync is already running.';
    if (target === 'all' && r.all) return 'A full feed sync is already running.';
    const any = r.nvd || r.oui || r.webfp || r.cve_intel || r.all;
    if (any) return 'A feed sync is already running. Wait for it to finish.';
    return null;
}

function refreshFeedSyncButtons() {
    const ra = feedSyncRunning;
    const any = ra.nvd || ra.oui || ra.webfp || ra.cve_intel || ra.all;
    const cfg = {
        'btn-sync-nvd': { disabled: !!any, busy: ra.nvd && !ra.all },
        'btn-sync-oui': { disabled: !!any, busy: ra.oui && !ra.all },
        'btn-sync-webfp': { disabled: !!any, busy: ra.webfp && !ra.all },
        'btn-sync-cve-intel': { disabled: !!any, busy: ra.cve_intel && !ra.all },
        'btn-sync-all': { disabled: !!any, busy: !!ra.all },
    };
    FEED_SYNC_BTN_IDS.forEach(id => {
        const b = document.getElementById(id);
        if (!b) return;
        const c = cfg[id];
        b.disabled = c.disabled;
        b.classList.toggle('btn-busy', !!c.busy);
        b.textContent = c.busy ? 'Syncing…' : (FEED_SYNC_BTN_LABELS[id] || b.textContent);
    });
    const cancelFeed = document.getElementById('btn-cancel-feed-sync');
    if (cancelFeed) {
        cancelFeed.disabled = !any;
    }
}

function markFeedSyncStart(target) {
    if (target === 'cve_intel' || target === 'all') {
        cveIntelSyncHadError = false;
    }
    const hadFp = feedSyncRunning.oui || feedSyncRunning.webfp || feedSyncRunning.all;
    if ((target === 'oui' || target === 'webfp' || target === 'all') && !hadFp) {
        fpSyncHadError = false;
    }
    if (target === 'all') {
        feedSyncRunning.all = true;
        feedSyncStartedAt.all = Date.now();
    } else {
        feedSyncRunning[target] = true;
        feedSyncStartedAt[target] = Date.now();
    }
    refreshFeedSyncButtons();
    ensureFeedSyncUiTimer();
}

function markFeedSyncEnd(target) {
    if (target === 'all') {
        feedSyncRunning.all = false;
        feedSyncStartedAt.all = 0;
    } else {
        feedSyncRunning[target] = false;
        feedSyncStartedAt[target] = 0;
    }
    refreshFeedSyncButtons();
    stopFeedSyncUiTimerIfIdle();
    const anyLeft = feedSyncRunning.nvd || feedSyncRunning.oui || feedSyncRunning.webfp || feedSyncRunning.cve_intel || feedSyncRunning.all;
    if (!anyLeft) stopFeedSyncStatePolling();
}

function feedSyncTouchesNvd(t) { return t === 'nvd' || t === 'all'; }
function feedSyncTouchesFp(t) { return t === 'oui' || t === 'webfp' || t === 'all'; }
function feedSyncTouchesCveIntel(t) { return t === 'cve_intel' || t === 'all'; }

function refreshNvdStatusLineAfterEnd(target, errText, okText) {
    const el = document.getElementById('sync-status-nvd');
    if (!el || !feedSyncTouchesNvd(target)) return;
    const still = feedSyncRunning.nvd || feedSyncRunning.all;
    if (still) {
        tickFeedSyncStatusLines();
        return;
    }
    el.className = errText ? 'sync-status err' : 'sync-status ok';
    el.textContent = errText || okText || 'Sync complete.';
}

function refreshFpStatusLineAfterEnd(target, errText, okText) {
    const el = document.getElementById('sync-status-fp');
    if (!el || !feedSyncTouchesFp(target)) return;
    const still = feedSyncRunning.oui || feedSyncRunning.webfp || feedSyncRunning.all;
    if (still) {
        tickFeedSyncStatusLines();
        return;
    }
    const useErr = errText || fpSyncHadError;
    el.className = useErr ? 'sync-status err' : 'sync-status ok';
    el.textContent = useErr
        ? (errText || 'One or more fingerprint feeds had errors. See output.')
        : (okText || 'Sync complete.');
    fpSyncHadError = false;
}

function refreshCveIntelStatusLineAfterEnd(target, errText, okText) {
    const el = document.getElementById('sync-status-cveintel');
    if (!el || !feedSyncTouchesCveIntel(target)) return;
    const still = feedSyncRunning.cve_intel || feedSyncRunning.all;
    if (still) {
        tickFeedSyncStatusLines();
        return;
    }
    const useErr = errText || cveIntelSyncHadError;
    el.className = useErr ? 'sync-status err' : 'sync-status ok';
    el.textContent = useErr
        ? (errText || 'CVE intel sync had errors. See output.')
        : (okText || 'Sync complete.');
    cveIntelSyncHadError = false;
}

async function requestFeedSyncCancel() {
    const r = await apiPost('/api/feeds.php?cancel=1', {});
    if (r && r.ok) {
        toast('Stop requested — long-running sync scripts should stop within a few seconds.', 'ok');
    } else {
        toast((r && r.error) ? String(r.error).slice(0, 140) : 'Cancel failed', 'err');
    }
}

function resetFeedSyncClientAfterServerClear() {
    feedSyncRunning = { nvd: false, oui: false, webfp: false, cve_intel: false, all: false };
    feedSyncStartedAt = { nvd: 0, oui: 0, webfp: 0, cve_intel: 0, all: 0 };
    stopFeedSyncStatePolling();
    stopFeedSyncUiTimerIfIdle();
    refreshFeedSyncButtons();
    tickFeedSyncStatusLines();
    renderFeedSyncOutputPanel();
}

async function requestFeedSyncClearStuckState() {
    if (!(await showConfirmModal(
        'This removes the server “sync running” flag and the cancel marker. '
            + 'Use only when no feed sync is actually running (for example after you killed sync scripts on the server). '
            + 'If a sync is still running, stop it first or use Cancel sync.',
        { title: 'Reset sync lock', okText: 'Clear server state' }
    ))) return;
    const r = await apiPost('/api/feeds.php?clear_sync_state=1', {});
    if (r && r.ok) {
        resetFeedSyncClientAfterServerClear();
        toast('Feed sync lock cleared. You can start a new sync.', 'ok');
    } else {
        toast((r && r.error) ? String(r.error).slice(0, 140) : 'Reset failed', 'err');
    }
}

async function runFeedSync(target) {
    const conflict = feedSyncConflictReason(target);
    if (conflict) {
        toast(conflict, 'err');
        return;
    }
    markFeedSyncStart(target);

    toast('Starting ' + target + ' feed sync…', 'ok');
    feedSyncLastOutput = `[client] ${new Date().toISOString()} — starting ${target} feed sync...`;
    const r = await apiPost('/api/feeds.php?sync=1', {target});

    if (!r) {
        markFeedSyncEnd(target);
        if (feedSyncTouchesFp(target)) fpSyncHadError = true;
        if (feedSyncTouchesCveIntel(target)) cveIntelSyncHadError = true;
        feedSyncLastOutput = '[client] Feed sync request failed (no response)';
        toast('Feed sync request failed', 'err');
        refreshNvdStatusLineAfterEnd(target, 'Sync failed (no response).', null);
        refreshFpStatusLineAfterEnd(target, 'Sync failed (no response).', null);
        refreshCveIntelStatusLineAfterEnd(target, 'Sync failed (no response).', null);
        return;
    }
    if (!r.ok) {
        markFeedSyncEnd(target);
        if (feedSyncTouchesFp(target)) fpSyncHadError = true;
        if (feedSyncTouchesCveIntel(target)) cveIntelSyncHadError = true;
        const msg = (r.results && r.results.find(x => !x.ok)?.output) || r.error || 'Sync failed';
        toast(String(msg).slice(0, 120), 'err');
        refreshNvdStatusLineAfterEnd(target, 'Sync failed. See output for details.', null);
        refreshFpStatusLineAfterEnd(target, 'Sync failed. See output for details.', null);
        refreshCveIntelStatusLineAfterEnd(target, 'Sync failed. See output for details.', null);
        openFeedSyncOutput();
        return;
    }

    if (r.async && r.started) {
        toast('Feed sync running on the server — NVD can take several minutes. Status updates below.', 'ok');
        startFeedSyncStatePolling();
        return;
    }

    appendFeedSyncResultToOutput(target, r);

    markFeedSyncEnd(target);

    refreshNvdStatusLineAfterEnd(target, null, 'Sync complete.');
    refreshFpStatusLineAfterEnd(target, null, 'Sync complete.');
    refreshCveIntelStatusLineAfterEnd(target, null, 'Sync complete.');

    const names = (r.results || []).map(x => x.script.replace('.py', '')).join(', ');
    toast('Feed sync complete: ' + names, 'ok');
    await loadDashboard();
    openFeedSyncOutput();
}

function openFeedSyncOutput() {
    const bg = document.getElementById('fsync-bg');
    if (!bg) return;
    renderFeedSyncOutputPanel();
    bg.style.display = 'flex';
}

function closeFeedSyncOutput() {
    const bg = document.getElementById('fsync-bg');
    if (bg) bg.style.display = 'none';
}

// ==========================================================================
// Schedules
// ==========================================================================
function collectorDisplayName(c) {
    const id = Number(c && c.id || 0);
    const n = String((c && c.name) || '').trim();
    return n ? `${n} (#${id})` : `Collector #${id}`;
}

function refreshCollectorSelectors() {
    const selectors = ['sc-collector', 'sched-collector', 'hr-collector'].map(id => document.getElementById(id)).filter(Boolean);
    if (!selectors.length) return;
    const options = ['<option value="0">Master scanner (local)</option>'];
    (collectorsCache || []).forEach(c => {
        let rangeHint = '';
        try {
            const arr = JSON.parse(String(c.allowed_cidrs_json || '[]'));
            if (Array.isArray(arr) && arr.length) {
                rangeHint = ' | ' + arr.join(',');
            }
        } catch (e) {}
        options.push(`<option value="${Number(c.id || 0)}">${esc(collectorDisplayName(c) + rangeHint)}</option>`);
    });
    selectors.forEach(sel => {
        const prev = String(sel.value || '0');
        sel.innerHTML = options.join('');
        sel.value = options.some(o => o.includes(`value="${prev}"`)) ? prev : '0';
    });
}

function scanSourceFilterValue() {
    const el = document.getElementById('scan-source-filter');
    const raw = String(el && el.value ? el.value : 'any').toLowerCase();
    return ['any', 'master', 'collector'].includes(raw) ? raw : 'any';
}

async function loadCollectorsOverview() {
    const tbody = document.getElementById('collector-overview-tbody');
    const stats = document.getElementById('collector-overview-stats');
    let d = null;
    try {
        d = await api('/api/collectors.php', {quiet:true});
    } catch (e) {
        d = null;
    }
    if (!d || !d.ok) {
        if (tbody) tbody.innerHTML = '<tr><td colspan="8" class="loading tbl-empty st-collectors-empty">Could not load collectors</td></tr>';
        if (stats) stats.textContent = 'Collectors unavailable';
        return;
    }
    collectorsCache = Array.isArray(d.collectors) ? d.collectors : [];
    collectorSchedulesCache = Array.isArray(d.schedules) ? d.schedules : [];
    refreshCollectorSelectors();
    if (stats) {
        const total = collectorsCache.length;
        const online = collectorsCache.filter(c => Number(c.online_recent_2m || 0) === 1).length;
        const stale = collectorsCache.filter(c => Number(c.online_recent_2m || 0) !== 1).length;
        stats.textContent = `Collectors: ${total} total | ${online} online (<=2m) | ${stale} stale/offline`;
    }
    if (!tbody) return;
    if (!collectorsCache.length) {
        tbody.innerHTML = '<tr><td colspan="8" class="loading tbl-empty st-collectors-empty">No remote collectors registered. <strong>Master-only</strong> deployments are valid — collectors are optional for extra sites. After an agent registers and checks in, it appears in this table. Use <strong>Settings</strong> to create install tokens.</td></tr>';
        return;
    }
    tbody.innerHTML = collectorsCache.map(c => {
        const id = Number(c.id || 0);
        const st = String(c.status || 'active');
        const pending = Number(c.pending_chunks || 0);
        const failed = Number(c.failed_chunks || 0);
        const seen = c.last_seen_at ? relTime(c.last_seen_at) : 'never';
        const ip = c.last_ip ? esc(String(c.last_ip)) : '—';
        const online = Number(c.online_recent_2m || 0) === 1;
        const rowCls = online ? 'st-collectors-row st-collectors-row--online' : 'st-collectors-row st-collectors-row--stale';
        const chunkWarn = failed > 0 ? ' st-collectors-row--chunks-warn' : '';
        let ranges = 'any';
        try {
            const arr = JSON.parse(String(c.allowed_cidrs_json || '[]'));
            if (Array.isArray(arr) && arr.length) ranges = arr.join(', ');
        } catch (e) {}
        const assignedSchedules = (collectorSchedulesCache || []).filter(s => Number(s.collector_id || 0) === id);
        const schedSummary = assignedSchedules.length
            ? assignedSchedules.map(s => String(s.name || ('#' + Number(s.id || 0)))).slice(0, 2).join(', ')
                + (assignedSchedules.length > 2 ? ` (+${assignedSchedules.length - 2} more)` : '')
            : 'None';
        return `<tr class="${rowCls}${chunkWarn}">
          <td class="mono">#${id}</td>
          <td class="text-primary">${esc(collectorDisplayName(c))}<div class="text-micro text-dim">ranges: ${esc(ranges)}</div><div class="text-micro text-dim">schedules: ${esc(schedSummary)}</div></td>
          <td class="mono-sm">${esc(st)}</td>
          <td class="mono-sm">${seen}</td>
          <td class="mono-sm">${ip}</td>
          <td class="mono-sm">${pending}</td>
          <td class="mono-sm">${failed}</td>
          <td class="row-actions st-collectors-row-actions">
            <button type="button" class="tbtn btn-xxs" onclick="setCollectorAllowedCidrs(${id})">Set ranges</button>
            <button type="button" class="tbtn btn-xxs" onclick="goTab('sched')">Manage in schedules</button>
            <button type="button" class="tbtn btn-xxs st-collectors-action-rotate" onclick="rotateCollectorToken(${id})">Rotate token</button>
            <button type="button" class="tbtn btn-xxs st-collectors-action-revoke" style="color:var(--red)" onclick="revokeCollector(${id})">Revoke</button>
          </td>
        </tr>`;
    }).join('');
}

async function setCollectorAllowedCidrs(id) {
    const collector = (collectorsCache || []).find(c => Number(c.id || 0) === Number(id || 0));
    if (!collector) {
        toast('Collector not found', 'err');
        return;
    }
    let current = '';
    try {
        const arr = JSON.parse(String(collector.allowed_cidrs_json || '[]'));
        if (Array.isArray(arr)) current = arr.join(', ');
    } catch (e) {}
    const raw = await openCollectorRangesModal(current);
    if (raw === null) return;
    const r = await apiPost('/api/collectors.php', {
        action: 'set_allowed_cidrs',
        collector_id: Number(id || 0),
        allowed_cidrs: String(raw || ''),
    });
    if (r && r.ok) {
        toast('Collector ranges updated', 'ok');
        await loadCollectorsOverview();
    } else {
        toast((r && r.error) || 'Update failed', 'err');
    }
}

async function rotateCollectorToken(id) {
    if (!(await showConfirmModal('Rotate this collector token now?', {title:'Rotate collector token', okText:'Rotate'}))) return;
    const r = await apiPost('/api/collectors.php', {action:'rotate_token', collector_id: Number(id || 0)});
    if (r && r.ok) {
        toast('Collector token rotated', 'ok');
        if (r.token) {
            await stCopyTextToClipboard(String(r.token));
            toast('New token copied to clipboard', 'ok');
        }
        loadCollectorsOverview();
    } else {
        toast((r && r.error) || 'Rotate failed', 'err');
    }
}

async function revokeCollector(id) {
    if (!(await showConfirmModal('Revoke this collector and all of its tokens?', {title:'Revoke collector', okText:'Revoke'}))) return;
    const r = await apiPost('/api/collectors.php', {action:'revoke', collector_id: Number(id || 0)});
    if (r && r.ok) {
        toast('Collector revoked', 'ok');
        loadCollectorsOverview();
    } else {
        toast((r && r.error) || 'Revoke failed', 'err');
    }
}

const REPORTING_DEBUG_JSON_MAX = 14000;
const REPORTING_COUNT_METRICS_MAX = 72;

function reportingUserErrorMessage(d, fallback) {
    if (d && typeof d === 'object' && typeof d.error === 'string' && d.error.trim()) {
        return d.error.trim();
    }
    return fallback;
}

function reportingToastApiError(context, d, fallback) {
    const msg = reportingUserErrorMessage(d, fallback);
    const short = msg.length > 280 ? msg.slice(0, 280) + '…' : msg;
    toast(context + ': ' + short, 'err');
}

function reportingTruncateJsonDisplay(obj) {
    const s = JSON.stringify(obj, null, 2);
    if (s.length <= REPORTING_DEBUG_JSON_MAX) return s;
    return s.slice(0, REPORTING_DEBUG_JSON_MAX) + '\n… (' + (s.length - REPORTING_DEBUG_JSON_MAX) + ' more characters truncated)';
}

const REPORTING_SCOPE_LS_KEY = 'st_report_scope_id';
const REPORTING_SCOPE_MODE_LS_KEY = 'st_report_scope_mode';
/** null = all scopes (omit API scope_id, legacy universe); 0 = unscoped only; positive int = named scope */
var reportingScopeApiFilter = null;
/** @type {'job'|'inventory'} */
var reportingScopeMode = 'job';
var reportingScopesList = [];
var stScopesForFormsCache = null;
var stScopesMeta = {
    default_scope_id: 0,
    scoping_enabled: false,
    scope_catalog_unavailable: false,
    asset_counts: {},
    job_counts: {},
    job_done_counts: {},
    schedule_counts: {},
};

function reportingScopeQuery() {
    const f = reportingScopeApiFilter;
    if (f === null || f === undefined) {
        return '';
    }
    return '&scope_id=' + encodeURIComponent(String(f));
}

function reportingIsInventoryMode() {
    return reportingScopeMode === 'inventory';
}

function reportingScopeModePersistRead() {
    try {
        const raw = localStorage.getItem(REPORTING_SCOPE_MODE_LS_KEY);
        reportingScopeMode = raw === 'inventory' ? 'inventory' : 'job';
    } catch (_e) {
        reportingScopeMode = 'job';
    }
}

function reportingScopeModePersistWrite() {
    try {
        localStorage.setItem(REPORTING_SCOPE_MODE_LS_KEY, reportingScopeMode === 'inventory' ? 'inventory' : 'job');
    } catch (_e) {}
}

function applyReportingScopeModeUi() {
    const inv = reportingIsInventoryMode();
    document.querySelectorAll('.report-job-only').forEach((el) => {
        el.style.display = inv ? 'none' : '';
    });
    const invCard = document.getElementById('report-inventory-summary-card');
    if (invCard) {
        invCard.style.display = inv ? '' : 'none';
    }
    const lbl = document.getElementById('report-scope-bucket-label');
    if (lbl) {
        lbl.textContent = inv ? 'Inventory bucket' : 'Which completed scans';
    }
}

function onReportingScopeModeChange() {
    const sel = document.getElementById('report-scope-mode-select');
    reportingScopeMode = sel && String(sel.value) === 'inventory' ? 'inventory' : 'job';
    reportingScopeModePersistWrite();
    applyReportingScopeModeUi();
    updateReportingScopeDetail();
    updateReportScopeCoverageBanner();
    void loadReportingTab();
}

/**
 * @param {Record<string, unknown>} inv
 * @returns {string}
 */
function reportingRenderInventorySummaryHtml(inv) {
    if (!inv || typeof inv !== 'object') {
        return '<div class="hstate-warn">Invalid inventory summary response.</div>';
    }
    const note = inv.note != null ? String(inv.note) : '';
    if (note && !inv.assets_scope_column) {
        return '<div class="hstate-warn">' + esc(note) + '</div>';
    }
    const scopeLabel =
        inv.scope_name != null && String(inv.scope_name).trim()
            ? esc(String(inv.scope_name).trim())
            : reportingScopeApiFilter === null
              ? 'All scopes'
              : reportingScopeApiFilter === 0
                ? 'Unscoped inventory'
                : 'Scope filter';
    const parts = [];
    if (note) {
        parts.push('<div class="hint-micro mb8 hstate-warn">' + esc(note) + '</div>');
    }
    const at = parseInt(String(inv.assets_total ?? 0), 10) || 0;
    const openTot = parseInt(String(inv.open_findings_total ?? 0), 10) || 0;
    const oc = parseInt(String(inv.open_critical ?? 0), 10) || 0;
    const oh = parseInt(String(inv.open_high ?? 0), 10) || 0;
    parts.push(
        '<div class="hint-micro mb8 text-dim"><strong>Bucket:</strong> ' +
            scopeLabel +
            ' · <strong>Assets:</strong> ' +
            esc(String(at)) +
            ' · <strong>Open findings:</strong> ' +
            esc(String(openTot)) +
            ' <span class="text-dim">(critical ' +
            esc(String(oc)) +
            ', high ' +
            esc(String(oh)) +
            ')</span></div>'
    );
    parts.push('<div class="report-card-title" style="margin-top:10px;font-size:13px">At a glance</div>');
    parts.push(
        '<div class="row-wrap gap8" style="align-items:stretch;margin-top:6px">' +
            '<div class="card" style="flex:1;min-width:120px;padding:10px 12px"><div class="text-dim" style="font-size:11px">Assets</div><div style="font-size:22px;font-weight:600">' +
            esc(String(at)) +
            '</div></div>' +
            '<div class="card" style="flex:1;min-width:120px;padding:10px 12px"><div class="text-dim" style="font-size:11px">Open findings</div><div style="font-size:22px;font-weight:600">' +
            esc(String(openTot)) +
            '</div></div>' +
            '<div class="card" style="flex:1;min-width:120px;padding:10px 12px"><div class="text-dim" style="font-size:11px">Critical</div><div style="font-size:22px;font-weight:600">' +
            esc(String(oc)) +
            '</div></div>' +
            '<div class="card" style="flex:1;min-width:120px;padding:10px 12px"><div class="text-dim" style="font-size:11px">High</div><div style="font-size:22px;font-weight:600">' +
            esc(String(oh)) +
            '</div></div>' +
            '</div>'
    );
    parts.push('<div class="report-card-title" style="margin-top:14px;font-size:13px">Current findings (by severity)</div>');
    const bySev = inv.open_findings_by_severity && typeof inv.open_findings_by_severity === 'object' ? inv.open_findings_by_severity : {};
    const order = ['critical', 'high', 'medium', 'low', 'info', 'unknown'];
    const rows = [];
    order.forEach((k) => {
        const c = parseInt(String(bySev[k] ?? 0), 10) || 0;
        if (c > 0) {
            rows.push('<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(String(c)) + '</td></tr>');
        }
    });
    Object.keys(bySev).forEach((k) => {
        if (order.indexOf(k) >= 0) {
            return;
        }
        const c = parseInt(String(bySev[k] ?? 0), 10) || 0;
        if (c > 0) {
            rows.push('<tr><td class="mono-sm">' + esc(String(k)) + '</td><td>' + esc(String(c)) + '</td></tr>');
        }
    });
    if (!rows.length) {
        parts.push('<div class="hint-micro text-dim mt6">No open findings for assets in this bucket.</div>');
    } else {
        parts.push(
            '<div class="tbl-wrap mt6"><table class="tbl"><thead><tr><th>Severity</th><th>Open</th></tr></thead><tbody>' +
                rows.join('') +
                '</tbody></table></div>'
        );
    }
    parts.push('<div class="report-card-title" style="margin-top:14px;font-size:13px">Asset lifecycle (coverage)</div>');
    const lc = inv.lifecycle_counts && typeof inv.lifecycle_counts === 'object' ? inv.lifecycle_counts : {};
    const lk = Object.keys(lc);
    if (!lk.length) {
        parts.push('<div class="hint-micro text-dim mt6">No assets in this bucket (or lifecycle not recorded).</div>');
    } else {
        lk.sort();
        const lrows = lk.map((k) => {
            const c = parseInt(String(lc[k] ?? 0), 10) || 0;
            return '<tr><td>' + esc(String(k)) + '</td><td>' + esc(String(c)) + '</td></tr>';
        });
        parts.push(
            '<div class="tbl-wrap mt6"><table class="tbl"><thead><tr><th>Lifecycle</th><th>Assets</th></tr></thead><tbody>' +
                lrows.join('') +
                '</tbody></table></div>'
        );
    }
    const top = Array.isArray(inv.top_assets) ? inv.top_assets : [];
    parts.push('<div class="report-card-title" style="margin-top:14px;font-size:13px">Top affected assets</div>');
    if (!top.length) {
        parts.push('<div class="hint-micro text-dim mt6">No assets in this bucket.</div>');
    } else {
        const trows = top.map((a) => {
            const row = /** @type {Record<string, unknown>} */ (a || {});
            const id = parseInt(String(row.id ?? 0), 10) || 0;
            const ip = row.ip != null ? String(row.ip) : '';
            const hn = row.hostname != null ? String(row.hostname) : '';
            const th = row.trusted_hostname != null && String(row.trusted_hostname).trim()
                && stTrustedMeetsOperationalUiPref(row.trusted_hostname_confidence)
                ? String(row.trusted_hostname).trim() : '';
            const cat = row.category != null ? String(row.category) : '';
            const life = row.lifecycle_status != null ? String(row.lifecycle_status) : '';
            const nf = parseInt(String(row.open_findings ?? 0), 10) || 0;
            const cv = row.top_cvss;
            const cvTxt = cv != null && cv !== '' && Number.isFinite(Number(cv)) ? String(Number(cv).toFixed(1)) : '—';
            const label = (th || hn || ip || '—').slice(0, 80);
            return (
                '<tr><td class="mono-sm">#' +
                esc(String(id)) +
                '</td><td>' +
                esc(label) +
                '</td><td class="text-dim">' +
                esc(cat.slice(0, 24)) +
                '</td><td class="text-dim">' +
                esc(life.slice(0, 16)) +
                '</td><td>' +
                esc(String(nf)) +
                '</td><td>' +
                esc(cvTxt) +
                '</td></tr>'
            );
        });
        parts.push(
            '<div class="tbl-wrap mt6"><table class="tbl"><thead><tr><th>ID</th><th>Host / IP</th><th>Cat</th><th>Life</th><th>Open</th><th>Top CVSS</th></tr></thead><tbody>' +
                trows.join('') +
                '</tbody></table></div>'
        );
    }
    return parts.join('');
}

async function loadReportingInventorySummary() {
    const body = document.getElementById('report-inventory-body');
    if (!body) {
        return;
    }
    body.innerHTML = '<span class="text-dim">Loading inventory summary…</span>';
    const url = '/api/reporting.php?action=inventory_scope_summary' + reportingScopeQuery();
    if (typeof window !== 'undefined' && stRoleIsAdmin()) {
        window.__stReportingDiag = Object.assign({}, window.__stReportingDiag || {}, {
            lastInventoryScopeUrl: url,
            lastInventoryScopeAt: Date.now(),
        });
    }
    const d = await api(url, { quiet: true });
    if (!d || !d.ok) {
        const msg = esc(reportingUserErrorMessage(d, 'Could not load inventory summary.'));
        body.innerHTML = '<div class="hstate-warn">' + msg + '</div>';
        reportingToastApiError('Inventory summary', d, 'Could not load inventory summary.');
        return;
    }
    const inv = d.inventory_scope_summary;
    body.innerHTML = reportingRenderInventorySummaryHtml(inv && typeof inv === 'object' ? inv : {});
}

/** Extra copy when a named report scope has no matching finished jobs (inventory vs job scope). */
function reportingNoJobsForScopeHintHtml() {
    const sid = reportingScopeApiFilter;
    if (sid == null || !Number.isFinite(sid) || sid <= 0) {
        return '';
    }
    const jk = String(sid);
    const djRaw =
        stScopesMeta.job_done_counts && typeof stScopesMeta.job_done_counts === 'object'
            ? stScopesMeta.job_done_counts[jk]
            : null;
    const dj = djRaw != null ? parseInt(String(djRaw), 10) : NaN;
    const acRaw =
        stScopesMeta.asset_counts && typeof stScopesMeta.asset_counts === 'object'
            ? stScopesMeta.asset_counts[jk]
            : null;
    const ac = parseInt(String(acRaw ?? 0), 10) || 0;
    if (ac > 0 && (!Number.isFinite(dj) || dj === 0)) {
        return (
            '<div class="hint-micro mt6" style="line-height:1.5">' +
            '<strong>Inventory vs report scope:</strong> ' +
            esc(String(ac)) +
            ' asset(s) are tagged with this catalog scope, but there are <strong>no finished scan jobs</strong> with <code class="code-accent">scan_jobs.scope_id</code> = ' +
            esc(String(sid)) +
            '. In <strong>Job scope</strong> mode, charts use the scope stored when each job was queued (Scan tab / schedule), not live <code class="code-accent">assets.scope_id</code> tags.<br><br>' +
            '<strong>Tip:</strong> switch <strong>Report mode</strong> to <strong>Inventory scope reports</strong> to summarize current assets and open findings for this scope.</div>'
        );
    }
    return '';
}

function updateReportScopeCoverageBanner() {
    const el = document.getElementById('report-scope-coverage-banner');
    if (!el) {
        return;
    }
    if (reportingIsInventoryMode()) {
        el.style.display = '';
        el.className = 'hint-micro mt8 text-dim report-scope-coverage-banner';
        const sid = reportingScopeApiFilter;
        if (sid == null || !Number.isFinite(sid)) {
            el.innerHTML =
                '<strong>Inventory mode:</strong> summary includes <strong>all assets</strong> (any <code class="code-accent">assets.scope_id</code>). Open findings are joined to those rows — not filtered by <code class="code-accent">scan_jobs.scope_id</code>.';
            return;
        }
        if (sid === 0) {
            el.innerHTML =
                '<strong>Inventory mode:</strong> only assets with <strong>no inventory scope tag</strong> (<code class="code-accent">scope_id</code> null or 0).';
            return;
        }
        const jk = String(sid);
        const ac = parseInt(String(stScopesMeta.asset_counts[jk] ?? 0), 10) || 0;
        el.innerHTML =
            '<strong>Inventory mode:</strong> live assets where <code class="code-accent">assets.scope_id</code> = ' +
            esc(String(sid)) +
            '. Catalog count for this tag: <strong>' +
            esc(String(ac)) +
            '</strong> asset(s) (same as dropdown).';
        return;
    }
    const sid = reportingScopeApiFilter;
    if (sid == null || !Number.isFinite(sid) || sid <= 0) {
        el.style.display = 'none';
        el.innerHTML = '';
        el.className = 'report-scope-coverage-banner';
        return;
    }
    const jk = String(sid);
    const ac = parseInt(String(stScopesMeta.asset_counts[jk] ?? 0), 10) || 0;
    const djRaw =
        stScopesMeta.job_done_counts && typeof stScopesMeta.job_done_counts === 'object'
            ? stScopesMeta.job_done_counts[jk]
            : null;
    const dj = djRaw != null ? parseInt(String(djRaw), 10) : 0;
    el.style.display = '';
    if (dj > 0) {
        el.className = 'hint-micro mt8 text-dim report-scope-coverage-banner';
        el.innerHTML =
            '<strong>Coverage for this report scope:</strong> Assets in scope: <strong>' +
            esc(String(ac)) +
            '</strong> · Completed scan jobs in scope: <strong>' +
            esc(String(dj)) +
            '</strong> <span class="text-dim">(finished scans with <code class="code-accent">scan_jobs.scope_id</code> = ' +
            esc(String(sid)) +
            ')</span>';
        return;
    }
    if (ac > 0) {
        el.className = 'help-box mt8 report-scope-coverage-banner';
        el.innerHTML =
            '<strong>This scope has inventory assets, but no completed scan jobs.</strong> In <strong>Job scope</strong> mode, drift and trends need finished scans whose job tag matches — asset tags alone do not create job history.<br><br>' +
            'Assets in scope: <strong>' +
            esc(String(ac)) +
            '</strong> · Completed scan jobs in scope: <strong>0</strong><br>' +
            '<span class="hint-micro">Queue scans with this report scope selected on the <strong>Scan</strong> tab or set scope on a <strong>Schedule</strong> so <code class="code-accent">scan_jobs.scope_id</code> matches.</span>' +
            '<div class="hint-micro mt8" style="line-height:1.5"><strong>Tip:</strong> switch <strong>Report mode</strong> to <strong>Inventory scope reports</strong> to see current assets and open findings for this scope without completed jobs.</div>';
        return;
    }
    el.className = 'help-box mt8 report-scope-coverage-banner';
    el.innerHTML =
        '<strong>No inventory assets or completed scan jobs exist for this scope yet.</strong><br>' +
        '<span class="hint-micro">Assets in scope: <strong>0</strong> · Completed scan jobs in scope: <strong>0</strong></span>';
}

function updateReportScopeAdminDiag() {
    const wrap = document.getElementById('report-scope-diag-details');
    const pre = document.getElementById('report-scope-diag-pre');
    if (!wrap || !pre) {
