        'lastBaselineUrl: ' + (d.lastBaselineUrl || '—'),
        'lastTrendsUrl: ' + (d.lastTrendsUrl || '—'),
        'lastInventoryScopeUrl: ' + (d.lastInventoryScopeUrl || '—'),
    ].join('\n');
