function reportingScopePersistWrite() {
    try {
        if (reportingScopeApiFilter === null) {
            localStorage.setItem(REPORTING_SCOPE_LS_KEY, 'all');
        } else {
            localStorage.setItem(REPORTING_SCOPE_LS_KEY, String(reportingScopeApiFilter));
        }
    } catch (_e) {}
}

/** @returns {0|number} scope bucket for matching (0 = unscoped / unknown) */
function reportingTrendsRowScopeKey(row) {
    if (!row || row.scope_id == null) {
        return 0;
    }
    const n = parseInt(String(row.scope_id), 10);
    return Number.isFinite(n) && n > 0 ? n : 0;
}

/**
 * Legacy rows share scope_id 0 but are not one network. Mirrors {@see st_reporting_unscoped_jobs_compatible} in api/lib_reporting.php.
 * @param {Record<string, unknown>} a
 * @param {Record<string, unknown>} b
 */
function reportingUnscopedJobsCompatible(a, b) {
    if (!a || !b) {
        return false;
    }
    const schedA = parseInt(String(a.schedule_id != null ? a.schedule_id : 0), 10) || 0;
    const schedB = parseInt(String(b.schedule_id != null ? b.schedule_id : 0), 10) || 0;
    if (schedA > 0 && schedA === schedB) {
        return true;
    }
    const batchA = parseInt(String(a.batch_id != null ? a.batch_id : 0), 10) || 0;
    const batchB = parseInt(String(b.batch_id != null ? b.batch_id : 0), 10) || 0;
    if (batchA > 0 && batchA === batchB) {
        return true;
    }
    const cidrA = String(a.target_cidr != null ? a.target_cidr : '').trim();
    const cidrB = String(b.target_cidr != null ? b.target_cidr : '').trim();
    if (cidrA !== '' && cidrA === cidrB) {
        return true;
    }
    const normLabel = (lab) => {
        lab = String(lab != null ? lab : '').trim();
        if (!lab) {
            return '';
        }
        const seps = [' — ', ' | ', ' - ', ' / '];
        for (let s = 0; s < seps.length; s++) {
            const sep = seps[s];
            const p = lab.indexOf(sep);
            if (p >= 3) {
                return lab.slice(0, p).toLowerCase();
            }
        }
        return lab.length >= 4 ? lab.toLowerCase() : '';
    };
    const la = normLabel(a.label);
    const lb = normLabel(b.label);
    if (la !== '' && la === lb && la.length >= 4) {
        return true;
    }
    const colA = parseInt(String(a.collector_id != null ? a.collector_id : 0), 10) || 0;
    const colB = parseInt(String(b.collector_id != null ? b.collector_id : 0), 10) || 0;
    if (colA > 0 && colA === colB) {
        if (
            (schedA > 0 && schedA === schedB) ||
            (batchA > 0 && batchA === batchB) ||
            (cidrA !== '' && cidrA === cidrB) ||
            (la !== '' && la === lb && la.length >= 4)
        ) {
            return true;
        }
    }
    return false;
}

function fillStScopeOptionSelects(scopes) {
    const pairs = [
        ['sc-scope-id', 'None — unscoped job'],
        ['sched-scope-id', 'None — unscoped jobs from this schedule'],
    ];
    pairs.forEach(([id, zlbl]) => {
        const el = document.getElementById(id);
        if (!el) {
            return;
        }
        const prev = el.value;
        el.innerHTML = '<option value="0">' + zlbl + '</option>';
        (scopes || []).forEach((sc) => {
            const o = document.createElement('option');
            o.value = String(sc.id);
            o.textContent = (sc.name || 'Scope #' + sc.id).slice(0, 120);
            el.appendChild(o);
        });
        if (prev && [...el.options].some((opt) => opt.value === prev)) {
            el.value = prev;
        }
    });
}

async function ensureStScopeSelects(force) {
    const anyEl =
        document.getElementById('sc-scope-id') ||
        document.getElementById('sched-scope-id') ||
        document.getElementById('report-scope-select') ||
        document.getElementById('st-bulk-scope-sel') ||
        document.getElementById('st-asset-scope-sel');
    if (!anyEl) {
        return;
    }
    if (!force && stScopesForFormsCache !== null && !stScopesMeta.scope_catalog_unavailable) {
        fillStScopeOptionSelects(stScopesForFormsCache);
        return;
    }
    let d = null;
    try {
        const r = await fetch('/api/scopes.php', { credentials: 'same-origin' });
        const txt = await r.text();
        if (txt && txt.trim()) {
            try {
                d = JSON.parse(txt);
            } catch (_e) {
                d = null;
            }
        }
        if (!r.ok || !d || typeof d !== 'object') {
            d = { ok: false };
        }
    } catch (_e) {
        d = { ok: false };
    }
    const catalogOk = !!(d && d.ok === true && Array.isArray(d.scopes));
    stScopesMeta.scope_catalog_unavailable = !catalogOk;
    if (catalogOk) {
        stScopesForFormsCache = d.scopes;
        stScopesMeta.asset_counts = d.asset_counts && typeof d.asset_counts === 'object' ? d.asset_counts : {};
        stScopesMeta.job_counts = d.job_counts && typeof d.job_counts === 'object' ? d.job_counts : {};
        stScopesMeta.job_done_counts =
            d.job_done_counts && typeof d.job_done_counts === 'object' ? d.job_done_counts : {};
        stScopesMeta.schedule_counts = d.schedule_counts && typeof d.schedule_counts === 'object' ? d.schedule_counts : {};
        stScopesMeta.default_scope_id =
            d.default_scope_id != null && parseInt(String(d.default_scope_id), 10) > 0
                ? parseInt(String(d.default_scope_id), 10)
                : 0;
        stScopesMeta.scoping_enabled = !!d.scoping_enabled;
    } else {
        stScopesForFormsCache = [];
        stScopesMeta.asset_counts = {};
        stScopesMeta.job_counts = {};
        stScopesMeta.job_done_counts = {};
        stScopesMeta.schedule_counts = {};
        stScopesMeta.default_scope_id = 0;
        stScopesMeta.scoping_enabled = false;
    }
    fillStScopeOptionSelects(stScopesForFormsCache);
}

function updateReportingScopeDetail() {
    const detailEl = document.getElementById('report-scope-detail');
    const warnEl = document.getElementById('report-scope-unscoped-warn');
    if (reportingIsInventoryMode()) {
        if (warnEl) {
            warnEl.style.display = 'none';
        }
        if (!detailEl) {
            return;
        }
        if (stScopesMeta.scope_catalog_unavailable) {
            detailEl.innerHTML =
                '<span class="hstate-warn">Scope support unavailable</span> — the scope list API did not return usable data (missing deploy, HTTP error, or non-JSON). Reporting stays on <strong>All scopes</strong>. Ask your admin to deploy <span class="mono-sm">api/scopes.php</span>, <span class="mono-sm">api/scan_scopes.php</span>, and <span class="mono-sm">api/lib_scan_scopes.php</span>, then run <span class="mono-sm">bash deploy.sh</span> (or open the app once so migrations run).';
            return;
        }
        if (reportingScopeApiFilter === null) {
            detailEl.innerHTML =
                '<strong>All scopes (inventory)</strong> — includes every asset row regardless of <code class="code-accent">assets.scope_id</code>. Use a named bucket or <strong>Unscoped only</strong> to narrow to one inventory tag.';
            return;
        }
        if (reportingScopeApiFilter === 0) {
            detailEl.innerHTML =
                '<strong>Unscoped inventory</strong> — assets whose inventory tag is missing or zero (<code class="code-accent">scope_id</code> NULL / 0). This is <strong>not</strong> “one network”; it is “no catalog scope assigned”.';
            return;
        }
        const sc = reportingScopesList.find((x) => parseInt(String(x.id), 10) === reportingScopeApiFilter);
        if (!sc) {
            detailEl.textContent = 'Scope #' + reportingScopeApiFilter;
            return;
        }
        let cidrTxt = '';
        try {
            const arr = JSON.parse(String(sc.cidrs || '[]'));
            if (Array.isArray(arr) && arr.length) {
                cidrTxt = arr.slice(0, 8).join(', ') + (arr.length > 8 ? ' …' : '');
            }
        } catch (_e) {
            cidrTxt = '';
        }
        const env = sc.environment != null && String(sc.environment).trim() ? esc(String(sc.environment).trim()) : 'unknown';
        detailEl.innerHTML =
            '<strong>Inventory — ' +
            esc(String(sc.name || 'Scope')) +
            '</strong> — live assets tagged <code class="code-accent">assets.scope_id</code> = ' +
            esc(String(sc.id)) +
            (cidrTxt ? ' · CIDRs: <span class="mono-sm">' + esc(cidrTxt) + '</span>' : '') +
            ' · Environment: <strong>' +
            env +
            '</strong>';
        return;
    }
    if (warnEl) {
        warnEl.style.display =
            reportingScopeApiFilter === 0 && stScopesMeta.scoping_enabled && !stScopesMeta.scope_catalog_unavailable
                ? ''
                : 'none';
    }
    if (!detailEl) {
        return;
    }
    if (stScopesMeta.scope_catalog_unavailable) {
        detailEl.innerHTML =
            '<span class="hstate-warn">Scope support unavailable</span> — the scope list API did not return usable data (missing deploy, HTTP error, or non-JSON). Reporting stays on <strong>All scopes</strong>. Ask your admin to deploy <span class="mono-sm">api/scopes.php</span>, <span class="mono-sm">api/scan_scopes.php</span>, and <span class="mono-sm">api/lib_scan_scopes.php</span>, then run <span class="mono-sm">bash deploy.sh</span> (or open the app once so migrations run).';
        return;
    }
    if (reportingScopeApiFilter === null) {
        detailEl.innerHTML =
            '<strong>All scopes (overview)</strong> — lists every completed scan. This mode is <em>not</em> a single comparison universe: there is no one baseline for all networks here. Unscoped jobs are <strong>scope-unknown</strong>, not one bucket; automatic drift does not pair unrelated unscoped scans without a compatibility signal. Use a named scope or Unscoped only to set or inspect baselines.';
        return;
    }
    if (reportingScopeApiFilter === 0) {
        detailEl.innerHTML =
            '<strong>Unscoped only</strong> — jobs with no scope tag (NULL / 0). <strong>Unscoped means scope unknown</strong>, not one shared environment. Use this to audit legacy scans separately from named networks; drift uses a prior scan only when schedule, batch, target CIDR, or label prefix matches.';
        return;
    }
    const sc = reportingScopesList.find((x) => parseInt(String(x.id), 10) === reportingScopeApiFilter);
    if (!sc) {
        detailEl.textContent = 'Scope #' + reportingScopeApiFilter;
        return;
    }
    let cidrTxt = '';
    try {
        const arr = JSON.parse(String(sc.cidrs || '[]'));
        if (Array.isArray(arr) && arr.length) {
            cidrTxt = arr.slice(0, 8).join(', ') + (arr.length > 8 ? ' …' : '');
        }
    } catch (_e) {
        cidrTxt = '';
    }
    const env = sc.environment != null && String(sc.environment).trim() ? esc(String(sc.environment).trim()) : 'unknown';
    detailEl.innerHTML =
        '<strong>' +
        esc(String(sc.name || 'Scope')) +
        '</strong>' +
        (cidrTxt ? ' · CIDRs: <span class="mono-sm">' + esc(cidrTxt) + '</span>' : '') +
        ' · Environment: <strong>' +
        env +
        '</strong>';
}

/** Where the create-scope modal was opened from (report | enrich | scopes). */
var stCreateScopeOpenedFrom = 'report';

function openStCreateScopeModal(from) {
    if (!stRoleCanManageScans()) {
        toast('Scan editor or admin role required to create scopes.', 'err');
        return;
    }
    stCreateScopeOpenedFrom = from === 'enrich' ? 'enrich' : from === 'scopes' ? 'scopes' : 'report';
    const nm = document.getElementById('st-scope-create-name');
    const ds = document.getElementById('st-scope-create-desc');
    const en = document.getElementById('st-scope-create-env');
    const cd = document.getElementById('st-scope-create-cidrs');
    const er = document.getElementById('st-scope-create-err');
    if (nm) nm.value = '';
    if (ds) ds.value = '';
    if (en) en.value = '';
    if (cd) cd.value = '';
    if (er) {
        er.textContent = '';
        er.style.display = 'none';
    }
    const bg = document.getElementById('st-create-scope-bg');
    if (bg) bg.style.display = 'flex';
    if (nm) nm.focus();
}

function closeStCreateScopeModal() {
    const bg = document.getElementById('st-create-scope-bg');
    if (bg) bg.style.display = 'none';
}

async function submitStCreateScope() {
    const errEl = document.getElementById('st-scope-create-err');
    if (errEl) {
        errEl.textContent = '';
        errEl.style.display = 'none';
    }
    const name = String((document.getElementById('st-scope-create-name') || {}).value || '').trim();
    if (!name) {
        if (errEl) {
            errEl.textContent = 'Name is required';
            errEl.style.display = '';
        }
        return;
    }
    const desc = String((document.getElementById('st-scope-create-desc') || {}).value || '').trim();
    const env = String((document.getElementById('st-scope-create-env') || {}).value || '').trim();
    const cidrBlob = String((document.getElementById('st-scope-create-cidrs') || {}).value || '');
    const cidrs = cidrBlob.split(/\r?\n/).map((s) => s.trim()).filter(Boolean);
    const btn = document.getElementById('st-scope-create-submit');
    if (btn) btn.disabled = true;
    const r = await apiPost('/api/scopes.php?action=create', {
        name,
        description: desc,
        environment: env || 'unknown',
        cidrs,
        scope_type: 'network',
    });
    if (btn) btn.disabled = false;
    if (!r || !r.ok) {
        if (errEl) {
            errEl.textContent = (r && r.error) ? r.error : 'Save failed';
            errEl.style.display = '';
        }
        return;
    }
    toast('Scan scope created', 'ok');
    closeStCreateScopeModal();
    stScopesForFormsCache = null;
    await ensureStScopeSelects(true);
    await loadReportingScopeSelector(true);
    const sel = document.getElementById('report-scope-select');
    if (sel && r.scope && r.scope.id) {
        const sid = String(r.scope.id);
        if ([...sel.options].some((o) => o.value === sid)) {
            sel.value = sid;
            syncReportingScopeApiFilterFromSelect(sel);
            reportingScopePersistWrite();
            updateReportingScopeDetail();
            updateReportScopeCoverageBanner();
        }
    }
    if (currentTab === 'report') {
        void loadReportingTab();
    }
    await loadZabbixEnrichmentPanel();
    if (stCreateScopeOpenedFrom === 'enrich') {
        goTab('enrich');
        hiNav('nenrich');
    } else if (stCreateScopeOpenedFrom === 'scopes') {
        goTab('scopes');
        hiNav('nscopes');
        void loadScopesTab();
    }
}

async function loadReportingScopeSelector(forceRefresh) {
    await ensureStScopeSelects(!!forceRefresh);
    const sel = document.getElementById('report-scope-select');
    if (!sel) {
        return;
    }
    const scopes = stScopesForFormsCache || [];
    reportingScopesList = scopes;
    const apiF = reportingScopeApiFilter;
    const desiredFromMemory =
        apiF === null || apiF === undefined ? null : apiF === 0 ? '0' : String(apiF);
    const keepVal = forceRefresh ? (desiredFromMemory === null ? 'all' : desiredFromMemory) : null;
    sel.innerHTML =
        '<option value="all">All scopes (default)</option>' +
        '<option value="0" title="Unscoped means scope unknown, not one shared environment.">Unscoped only</option>';
    const ac = stScopesMeta.asset_counts || {};
    const jdc = stScopesMeta.job_done_counts && typeof stScopesMeta.job_done_counts === 'object' ? stScopesMeta.job_done_counts : {};
    scopes.forEach((sc) => {
        const o = document.createElement('option');
        o.value = String(sc.id);
        const nm = (sc.name || 'Scope #' + sc.id).slice(0, 100);
        const cnt = parseInt(String(ac[String(sc.id)] ?? 0), 10) || 0;
        const dj = parseInt(String(jdc[String(sc.id)] ?? 0), 10) || 0;
        o.textContent = nm + ' (' + cnt + ' assets · ' + dj + ' done)';
        sel.appendChild(o);
    });
    const optOk = (val) => [...sel.options].some((opt) => opt.value === val);
    if (keepVal !== null && optOk(keepVal)) {
        sel.value = keepVal;
    } else if (!forceRefresh && desiredFromMemory !== null && optOk(desiredFromMemory)) {
        sel.value = desiredFromMemory;
    } else {
        let persist = 'all';
        try {
            const raw = localStorage.getItem(REPORTING_SCOPE_LS_KEY);
            if (raw !== null && raw !== '') {
                persist = raw;
            }
        } catch (_e) {}
        if (persist === 'all') {
            sel.value = 'all';
        } else if (persist === '0') {
            sel.value = '0';
        } else {
            const idn = parseInt(persist, 10);
            if (Number.isFinite(idn) && idn > 0 && scopes.some((s) => parseInt(String(s.id), 10) === idn)) {
                sel.value = String(idn);
            } else {
                sel.value = 'all';
            }
        }
    }
    if (!optOk(sel.value)) {
        sel.value = 'all';
    }
    if (stScopesMeta.scope_catalog_unavailable) {
        sel.value = 'all';
        reportingScopeApiFilter = null;
    }
    const refBtn = document.getElementById('report-scope-refresh-btn');
    if (refBtn) {
        refBtn.title = stScopesMeta.scope_catalog_unavailable
            ? 'Retry after redeploying api/scopes.php, api/scan_scopes.php, and api/lib_scan_scopes.php'
            : '';
    }
    syncReportingScopeApiFilterFromSelect(sel);
    reportingScopePersistWrite();
    reportingScopeModePersistRead();
    const modeSelNode = document.getElementById('report-scope-mode-select');
    if (modeSelNode) {
        modeSelNode.value = reportingScopeMode === 'inventory' ? 'inventory' : 'job';
    }
    applyReportingScopeModeUi();
    updateReportingScopeDetail();
    updateReportScopeCoverageBanner();
}

function syncReportingScopeApiFilterFromSelect(sel) {
    const v = sel ? String(sel.value).trim() : 'all';
    if (v === '' || v === 'all') {
        reportingScopeApiFilter = null;
        return;
    }
    const n = parseInt(v, 10);
    reportingScopeApiFilter = Number.isFinite(n) ? n : null;
}

function onReportingScopeChange() {
    const sel = document.getElementById('report-scope-select');
    if (!sel) {
        return;
    }
    syncReportingScopeApiFilterFromSelect(sel);
    reportingScopePersistWrite();
    updateReportingScopeDetail();
    updateReportScopeCoverageBanner();
    void loadReportingTab();
}

function reportingJobSelectScopeTag(h) {
    if (!h || h.scope_id == null) {
        return '';
    }
    const sid = parseInt(String(h.scope_id), 10);
    if (!Number.isFinite(sid) || sid <= 0) {
        return ' [unscoped]';
    }
    const sc = (reportingScopesList || []).find((x) => parseInt(String(x.id), 10) === sid);
    const nm = sc && sc.name ? String(sc.name).trim().slice(0, 48) : '';
    return nm ? ' [' + nm + ']' : ' [scope #' + sid + ']';
}

function reportingFillJobSelect(selectId, rows) {
    const el = document.getElementById(selectId);
    if (!el) return;
    el.innerHTML = '';
    const o0 = document.createElement('option');
    o0.value = '';
    o0.textContent = '— select job —';
    el.appendChild(o0);
    for (const h of rows) {
        const o = document.createElement('option');
        o.value = String(h.id);
        const lab = (h.label != null && String(h.label)) ? String(h.label) : '';
        const tgt = (h.target_cidr != null) ? String(h.target_cidr) : '';
        const sc = reportingJobSelectScopeTag(h);
        o.textContent = ('#' + h.id + ' ' + lab + ' — ' + tgt + sc).slice(0, 240);
        el.appendChild(o);
    }
}

function reportingMergeJobRowsForPickers(histResp, trendsResp) {
    const byId = new Map();
    const add = (row) => {
        if (!row || row.id == null) {
            return;
        }
        const id = parseInt(String(row.id), 10);
        if (!Number.isFinite(id) || id <= 0) {
            return;
        }
        if (byId.has(id)) {
            return;
        }
        const st = String(row.status != null ? row.status : '').toLowerCase();
        if (st !== 'done') {
            return;
        }
        byId.set(id, {
            id,
            status: 'done',
            label: row.label != null ? String(row.label) : '',
            target_cidr: row.target_cidr != null ? String(row.target_cidr) : '',
            scope_id: row.scope_id,
        });
    };
    if (histResp && histResp.ok && Array.isArray(histResp.history)) {
        histResp.history.forEach(add);
    }
    if (trendsResp && trendsResp.ok && Array.isArray(trendsResp.trends_summary)) {
        trendsResp.trends_summary.forEach((r) => {
            const jid = parseInt(String(r.job_id != null ? r.job_id : 0), 10);
            if (!Number.isFinite(jid) || jid <= 0) {
                return;
            }
            add({
                id: jid,
                status: 'done',
                label: r.label,
                target_cidr: r.target_cidr,
                scope_id: r.scope_id,
            });
        });
    }
    return Array.from(byId.values()).sort((a, b) => b.id - a.id);
}

async function populateReportingJobSelects() {
    const q = reportingScopeQuery();
    const histUrl = '/api/scan_history.php?limit=200&view=active' + q;
    const trendUrl = '/api/reporting.php?action=trends_summary&limit=50' + q;
    const [d, tr] = await Promise.all([api(histUrl, {quiet: true}), api(trendUrl, {quiet: true})]);
    const ids = ['report-baseline-job', 'report-cmp-a', 'report-cmp-b', 'report-compliance-job'];
    const histOk = !!(d && d.ok && Array.isArray(d.history));
    const trendsOk = !!(tr && tr.ok && Array.isArray(tr.trends_summary));
    if (!histOk && !trendsOk) {
        ids.forEach((id) => {
            const el = document.getElementById(id);
            if (!el) {
                return;
            }
            el.innerHTML = '';
            const o0 = document.createElement('option');
            o0.value = '';
            o0.textContent = reportingUserErrorMessage(d || tr, '— could not load job list —');
            el.appendChild(o0);
        });
        if (currentTab === 'report') {
            reportingToastApiError('Reports & Analysis', d || tr, 'Could not load completed scans for pickers.');
        }
        return;
    }
    const done = reportingMergeJobRowsForPickers(d, tr);
    reportingFillJobSelect('report-baseline-job', done);
    reportingFillJobSelect('report-cmp-a', done);
    reportingFillJobSelect('report-cmp-b', done);
    reportingFillJobSelect('report-compliance-job', done);
}

function reportingRenderCountsTable(counts, fe) {
    const rows = [];
    if (counts && typeof counts === 'object') {
        const keys = Object.keys(counts).sort();
        const extra = keys.length - REPORTING_COUNT_METRICS_MAX;
        const use = extra > 0 ? keys.slice(0, REPORTING_COUNT_METRICS_MAX) : keys;
        use.forEach((k) => {
            rows.push('<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(String(counts[k])) + '</td></tr>');
        });
        if (extra > 0) {
            rows.push(
                '<tr><td colspan="2" class="text-dim">Showing first ' +
                    REPORTING_COUNT_METRICS_MAX +
                    ' metrics; +' +
                    extra +
                    ' omitted for display.</td></tr>'
            );
        }
    }
    let feHtml = '';
    if (fe && typeof fe === 'object') {
        feHtml = '<div class="sth" style="margin-top:10px;font-size:12px">Finding events</div><table class="tbl mt4"><tbody>';
        Object.keys(fe).sort().forEach((k) => {
            feHtml += '<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(String(fe[k])) + '</td></tr>';
        });
        feHtml += '</tbody></table>';
    }
    if (!rows.length && !feHtml) return '<span class="text-dim">No counts returned.</span>';
    return '<table class="tbl"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody>' + rows.join('') + '</tbody></table>' + feHtml;
}

/** @returns {Record<string, number>} */
function reportingCompareNormalizeCounts(counts, finding_events) {
    const c = counts && typeof counts === 'object' ? counts : {};
    const fe = finding_events && typeof finding_events === 'object' ? finding_events : {};
    const num = (v) => {
        if (v == null || v === '') {
            return 0;
        }
        const n = parseInt(String(v), 10);
        return Number.isFinite(n) ? n : 0;
    };
    const openAbsentFe = num(fe.open_in_a_absent_in_b_snapshots);
    const openAbsentC = num(c.open_in_a_absent_in_b);
    return {
        assets_a: num(c.assets_a),
        assets_b: num(c.assets_b),
        assets_only_in_a: num(c.assets_only_in_a) || num(c.removed_hosts),
        assets_only_in_b: num(c.assets_only_in_b) || num(c.new_hosts),
        new_findings_rows: num(c.new_findings_rows) || num(c.findings_only_in_b),
        marked_resolved_in_b: num(fe.marked_resolved_in_b) || num(c.marked_resolved_in_b),
        reopened_in_b: num(fe.reopened_in_b) || num(c.reopened_in_b),
        open_in_a_absent_in_b: openAbsentFe || openAbsentC,
        hosts_with_port_delta: num(c.hosts_with_port_delta),
    };
}

function reportingCompareIsSignificant(nc) {
    if (!nc) {
        return false;
    }
    if (nc.new_findings_rows > 0 || nc.reopened_in_b > 0 || nc.assets_only_in_a > 0 || nc.assets_only_in_b > 0) {
        return true;
    }
    if (nc.marked_resolved_in_b > 0 || nc.open_in_a_absent_in_b > 0 || nc.hosts_with_port_delta > 0) {
        return true;
    }
    return nc.assets_a !== nc.assets_b;
}

/** Open high + critical counts from one trends_summary row (snapshot), or null if row invalid. */
function reportingTrendsOpenHighCritical(row) {
    if (!row || typeof row !== 'object') {
        return null;
    }
    const by =
        row.open_findings_by_severity && typeof row.open_findings_by_severity === 'object'
            ? row.open_findings_by_severity
            : {};
    const c = parseInt(String(by.critical != null ? by.critical : 0), 10);
    const h = parseInt(String(by.high != null ? by.high : 0), 10);
    const cc = Number.isFinite(c) ? c : 0;
    const hh = Number.isFinite(h) ? h : 0;
    return cc + hh;
}

function reportingTrendsRowByJobId(ts, jobId) {
    if (!Array.isArray(ts)) {
        return null;
    }
    const want = parseInt(String(jobId), 10);
    for (let i = 0; i < ts.length; i++) {
        const j = parseInt(String(ts[i].job_id), 10);
        if (j === want) {
            return ts[i];
        }
    }
    return null;
}

/**
 * @returns {{ html: string, badgeKey: string, badgeLabel: string, badgeEmoji: string }}
 */
function reportingCompareRiskClassification(nc, deltaHc, hasTrendPair) {
    const sig = reportingCompareIsSignificant(nc);
    const dh = deltaHc == null || !Number.isFinite(deltaHc) ? 0 : deltaHc;
    const highHc = hasTrendPair && dh > 0;
    const newRows = nc.new_findings_rows > 0;
    const reopened = nc.reopened_in_b > 0;
    if (highHc) {
        return {
            html:
                '<span class="report-risk-badge report-risk-high" title="Open high or critical findings increased between these two completed scans">🔴 HIGH RISK</span>',
            badgeKey: 'high',
            badgeLabel: 'HIGH RISK',
            badgeEmoji: '🔴',
        };
    }
    if (reopened || (newRows && !hasTrendPair)) {
        return {
            html:
                '<span class="report-risk-badge report-risk-warn" title="Reopened findings or new finding rows in the current snapshot">🟠 WARNING</span>',
            badgeKey: 'warn',
            badgeLabel: 'WARNING',
            badgeEmoji: '🟠',
        };
    }
    if (newRows && hasTrendPair) {
        return {
            html:
                '<span class="report-risk-badge report-risk-warn" title="New finding rows in current snapshot — review severities in Vulnerabilities">🟠 WARNING</span>',
            badgeKey: 'warn',
            badgeLabel: 'WARNING',
            badgeEmoji: '🟠',
        };
    }
    if (
        sig &&
        nc.marked_resolved_in_b > 0 &&
        nc.new_findings_rows === 0 &&
        nc.reopened_in_b === 0 &&
        !(hasTrendPair && dh > 0) &&
        nc.assets_only_in_a === 0 &&
        nc.assets_only_in_b === 0 &&
        nc.hosts_with_port_delta === 0 &&
        nc.open_in_a_absent_in_b === 0
    ) {
        return {
            html:
                '<span class="report-risk-badge report-risk-ok" title="Findings moved to resolved with no new or reopened rows in this diff">🟢 IMPROVED</span>',
            badgeKey: 'improved',
            badgeLabel: 'IMPROVED',
            badgeEmoji: '🟢',
        };
    }
    if (!sig) {
        return {
            html:
                '<span class="report-risk-badge report-risk-stable" title="No material deltas in snapshot counters for this pair">⚪ STABLE</span>',
            badgeKey: 'stable',
            badgeLabel: 'STABLE',
            badgeEmoji: '⚪',
        };
    }
    return {
        html:
            '<span class="report-risk-badge report-risk-warn" title="Inventory or port changes — review callouts below">🟠 WARNING</span>',
        badgeKey: 'warn',
        badgeLabel: 'WARNING',
        badgeEmoji: '🟠',
    };
}

function reportingCompareAttentionCalloutsHtml(nc, deltaHc, hasTrendPair) {
    const items = [];
    const dh = deltaHc == null || !Number.isFinite(deltaHc) ? 0 : deltaHc;
    if (nc.assets_only_in_a > 0) {
        const n = nc.assets_only_in_a;
        items.push(
            '<li><strong>Hosts removed</strong> — ' +
                esc(String(n)) +
                ' ' +
                (n === 1 ? 'host is' : 'hosts are') +
                ' no longer detected in the current scan — verify whether that is expected (scope, coverage, or retirement).</li>'
        );
    }
    if (nc.assets_only_in_b > 0) {
        const n = nc.assets_only_in_b;
        items.push(
            '<li><strong>New assets</strong> — ' +
                esc(String(n)) +
                ' new ' +
                (n === 1 ? 'asset was' : 'assets were') +
                ' detected in the current scan.</li>'
        );
    }
    if (nc.reopened_in_b > 0) {
        items.push(
            '<li><strong>Reopened findings</strong> — previously resolved issues have reappeared in the current snapshot.</li>'
        );
    }
    if (hasTrendPair && dh > 0) {
        items.push(
            '<li><strong>New high-risk vulnerabilities detected</strong> — open high or critical findings increased by ' +
                esc(String(dh)) +
                ' between these two completed scans.</li>'
        );
    } else if (nc.new_findings_rows > 0 && !(hasTrendPair && dh > 0)) {
        items.push(
            '<li><strong>New findings</strong> — new open finding rows appeared in the current snapshot; review severity in <strong>Vulnerabilities</strong>.</li>'
        );
    }
    if (!items.length) {
        return '';
    }
    return (
        '<ul class="hint-micro report-snapshot-callouts" style="margin:8px 0 0;padding-left:18px;line-height:1.5">' +
        items.join('') +
        '</ul>'
    );
}

/**
 * @param {object} [narrativeOpts]
 * @param {boolean} [narrativeOpts.softReferenceHostWording] softer snapshot phrasing for reference-only hosts (unscoped-compatible drift)
 */
function reportingCompareNarrativeParagraph(refId, curId, nc, deltaHc, hasTrendPair, narrativeOpts) {
    narrativeOpts = narrativeOpts || {};
    const softHost = !!narrativeOpts.softReferenceHostWording;
    const r = parseInt(String(refId), 10);
    const c = parseInt(String(curId), 10);
    const sig = reportingCompareIsSignificant(nc);
    const dh = deltaHc == null || !Number.isFinite(deltaHc) ? 0 : deltaHc;
    const parts = [];
    parts.push(
        'Compared to <strong>reference scan #' +
            esc(String(r)) +
            '</strong>, <strong>current scan #' +
            esc(String(c)) +
            '</strong>'
    );
    if (!sig) {
        parts.push(' shows <strong>no material change</strong> in snapshot counters (assets, findings, and port deltas).');
        return '<p class="hint-micro report-snapshot-narrative" style="line-height:1.55;margin:0 0 8px">' + parts.join('') + '</p>';
    }
    let tone = 'shows a <strong>mixed picture</strong>';
    const bad =
        nc.reopened_in_b > 0 ||
        nc.new_findings_rows > 0 ||
        (hasTrendPair && dh > 0) ||
        nc.assets_only_in_a > 0 ||
        nc.assets_only_in_b > 0;
    const good = nc.marked_resolved_in_b > 0 || (hasTrendPair && dh < 0);
    if (good && !bad) {
        tone = 'shows <strong>a slight improvement</strong>';
    } else if (bad && !good) {
        tone = 'shows <strong>increased exposure or drift</strong>';
    } else if (good && bad) {
        tone = 'shows <strong>a mixed picture</strong>';
    } else {
        tone = 'shows <strong>measurable drift</strong>';
    }
    parts.push(' ' + tone + '.');
    const detail = [];
    if (nc.assets_only_in_a === 1) {
        detail.push(
            softHost
                ? '1 host from the reference scan was not seen in the current scan.'
                : 'One host is no longer detected'
        );
    } else if (nc.assets_only_in_a > 1) {
        detail.push(
            softHost
                ? nc.assets_only_in_a + ' hosts from the reference scan were not seen in the current scan.'
                : nc.assets_only_in_a + ' hosts are no longer detected'
        );
    }
    if (nc.assets_only_in_b === 1) {
        detail.push('One new asset appears in the current scan');
    } else if (nc.assets_only_in_b > 1) {
        detail.push(nc.assets_only_in_b + ' new assets appear in the current scan');
    }
    if (nc.marked_resolved_in_b === 1) {
        detail.push('One finding was not detected in the current scan');
    } else if (nc.marked_resolved_in_b > 1) {
        detail.push(nc.marked_resolved_in_b + ' findings were not detected in the current scan');
    }
    if (nc.reopened_in_b > 0) {
        detail.push(
            nc.reopened_in_b === 1
                ? 'One finding reopened'
                : nc.reopened_in_b + ' findings reopened'
        );
    }
    if (nc.new_findings_rows > 0) {
        detail.push(
            nc.new_findings_rows === 1
                ? 'One new finding row appears in the current snapshot'
                : nc.new_findings_rows + ' new finding rows appear in the current snapshot'
        );
    }
    if (hasTrendPair && dh > 0) {
        detail.push('Open high or critical findings increased by ' + dh);
    } else if (hasTrendPair && dh < 0) {
        detail.push('Open high or critical findings decreased by ' + Math.abs(dh));
    }
    if (nc.hosts_with_port_delta > 0) {
        detail.push(
            'Open ports changed on ' +
                nc.hosts_with_port_delta +
                ' host' +
                (nc.hosts_with_port_delta === 1 ? '' : 's')
        );
    }
    if (detail.length) {
        parts.push(' ' + detail.slice(0, 6).join('. ') + '.');
    }
    const tail = [];
    if (nc.new_findings_rows === 0 && nc.reopened_in_b === 0 && !(hasTrendPair && dh > 0)) {
        tail.push('No new or reopened risks were flagged in this snapshot diff.');
    }
    if (tail.length) {
        parts.push(' ' + tail.join(' '));
    }
    return '<p class="hint-micro report-snapshot-narrative" style="line-height:1.55;margin:0 0 8px">' + parts.join('') + '</p>';
}

function reportingCompareSummaryCardsHtml(nc, cardOpts) {
    cardOpts = cardOpts || {};
    const cross = !!(cardOpts.crossScope || cardOpts.unscopedUncertain);
    const dAssets = nc.assets_b - nc.assets_a;
    const dShow = dAssets > 0 ? '+' + dAssets : String(dAssets);
    const card = (title, value, sub, tone) => {
        const toneClass =
            tone === 'good' ? 'hstate-ok' : tone === 'bad' ? 'hstate-err' : tone === 'warn' ? 'hstate-warn' : 'hstate-unk';
        return (
            '<div class="card" style="padding:10px 12px;min-width:120px;flex:1 1 120px;border:1px solid var(--border)">' +
            '<div class="hint-micro text-dim" style="margin-bottom:4px">' +
            esc(title) +
            '</div>' +
            '<div class="' +
            toneClass +
            '" style="font-size:20px;line-height:1.2">' +
            esc(String(value)) +
            '</div>' +
            (sub ? '<div class="hint-micro text-dim mt4">' + esc(sub) + '</div>' : '') +
            '</div>'
        );
    };
    let assetSub = cross
        ? 'Raw counter delta — not a reliable “hosts removed” signal across scopes'
        : 'Snapshot host rows (current − reference)';
    if (!cross) {
        if (dAssets < 0) {
            assetSub = 'Fewer hosts in current snapshot';
        } else if (dAssets > 0) {
            assetSub = 'More hosts in current snapshot';
        } else {
            assetSub = 'Same host count';
        }
    }
    const assetTone = cross ? 'unk' : dAssets !== 0 || nc.assets_only_in_a > 0 ? 'warn' : 'unk';
    const newFindTone = nc.new_findings_rows > 0 ? 'warn' : 'unk';
    const reopenTone = nc.reopened_in_b > 0 ? 'bad' : 'unk';
    const resolvedTone = nc.marked_resolved_in_b > 0 ? 'good' : 'unk';
    const portTone = nc.hosts_with_port_delta > 0 ? 'warn' : 'unk';
    let h = '<div class="row-wrap gap8 mb6" style="align-items:stretch">';
    h += card('Asset change (Δ)', dShow, assetSub, assetTone);
    h += card('New findings', String(nc.new_findings_rows), 'New open rows in current snapshot', newFindTone);
    h += card('Resolved findings', String(nc.marked_resolved_in_b), 'Marked resolved in current', resolvedTone);
    h += card('Reopened findings', String(nc.reopened_in_b), 'Were resolved, open again', reopenTone);
    h += card('Port changes', String(nc.hosts_with_port_delta), 'Hosts with port deltas', portTone);
    h += '</div>';
    if (!cross && (nc.assets_only_in_b > 0 || nc.assets_only_in_a > 0)) {
        const invParts = [];
        if (nc.assets_only_in_b > 0) {
            invParts.push(
                esc(String(nc.assets_only_in_b)) +
                    ' new asset row' +
                    (nc.assets_only_in_b === 1 ? '' : 's') +
                    ' only in current'
            );
        }
        if (nc.assets_only_in_a > 0) {
            invParts.push(
                esc(String(nc.assets_only_in_a)) +
                    ' asset row' +
                    (nc.assets_only_in_a === 1 ? '' : 's') +
                    ' in reference missing from current'
            );
        }
        h +=
            '<div class="hint-micro text-dim mb8">' +
            '<span class="hstate-warn" style="font-weight:600">Inventory</span> — ' +
            invParts.join('; ') +
            '.' +
            '</div>';
    }
    return h;
}

function reportingHumanizeFindingEventKey(k) {
    const m = {
        marked_resolved_in_b: 'Findings resolved in current scan',
        reopened_in_b: 'Findings reopened',
        open_in_a_absent_in_b_snapshots: 'Open in reference, absent in current snapshot',
    };
    return m[k] || reportingHumanizeRuleKey(k);
}

function reportingRenderCompareAdvancedDetails(counts, finding_events) {
    const c = counts && typeof counts === 'object' ? counts : {};
    const fe = finding_events && typeof finding_events === 'object' ? finding_events : {};
    const num = (v) => {
        if (v == null || v === '') {
            return 0;
        }
        const n = parseInt(String(v), 10);
        return Number.isFinite(n) ? n : 0;
    };
    const rows = [];
    const push = (label, val) => {
        rows.push('<tr><td>' + esc(label) + '</td><td>' + esc(String(val)) + '</td></tr>');
    };
    push('Assets in reference scan', num(c.assets_a));
    push('Assets in current scan', num(c.assets_b));
    push('Assets missing from current scan', num(c.assets_only_in_a) || num(c.removed_hosts));
    push('New assets in current scan', num(c.assets_only_in_b) || num(c.new_hosts));
    push('Hosts with port changes', num(c.hosts_with_port_delta));
    push('New finding rows in current scan', num(c.new_findings_rows) || num(c.findings_only_in_b));
    push('Finding rows only in reference snapshot', num(c.findings_absent_in_b) || num(c.findings_only_in_a));
    push('Findings resolved in current scan', num(fe.marked_resolved_in_b) || num(c.marked_resolved_in_b));
    push('Findings reopened', num(fe.reopened_in_b) || num(c.reopened_in_b));
    push(
        'Previously open findings not seen in current snapshot',
        num(fe.open_in_a_absent_in_b_snapshots) || num(c.open_in_a_absent_in_b)
    );
    push('Resolution changes (total rows)', num(c.resolution_changes));
    const shown = new Set([
        'assets_a',
        'assets_b',
        'assets_only_in_a',
        'assets_only_in_b',
        'removed_hosts',
        'new_hosts',
        'hosts_with_port_delta',
        'new_findings_rows',
        'findings_only_in_b',
        'findings_absent_in_b',
        'findings_only_in_a',
        'marked_resolved_in_b',
        'reopened_in_b',
        'open_in_a_absent_in_b',
        'resolution_changes',
    ]);
    const extra = [];
    Object.keys(c)
        .sort()
        .forEach((k) => {
            if (shown.has(k)) {
                return;
            }
            extra.push('<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(String(c[k])) + '</td></tr>');
        });
    let feRows = '';
    Object.keys(fe)
        .sort()
        .forEach((k) => {
            feRows +=
                '<tr><td>' +
                esc(reportingHumanizeFindingEventKey(k)) +
                '</td><td>' +
                esc(String(fe[k])) +
                '</td></tr>';
        });
    let extraBlock = '';
    if (extra.length) {
        extraBlock =
            '<div class="hint-micro text-dim mt8 mb4">Additional server counters (internal keys)</div><table class="tbl"><tbody>' +
            extra.join('') +
            '</tbody></table>';
    }
    let h =
        '<table class="tbl"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody>' +
        rows.join('') +
        feRows +
        '</tbody></table>' +
        extraBlock;
    if (!rows.length && !extra.length && !feRows) {
        h = '<span class="text-dim">No counter data.</span>';
    }
    return h;
}

function reportingRenderCompareExecutiveSummary(s, opts) {
    opts = opts || {};
    const showCards = opts.cards !== false;
    const jobRef = s.job_a;
    const jobCur = s.job_b;
    const nc = reportingCompareNormalizeCounts(s.counts, s.finding_events);
    const align = s.scope_alignment;
    const unscopedPairUncertain = !!(opts.unscopedPairUncertain || s.unscoped_pair_uncertain);
    const crossScope = !!(opts.crossScope || (align && align.comparable === false));
    const lowConfidence = crossScope || unscopedPairUncertain;
    const warnList = Array.isArray(s.warnings) ? s.warnings.slice(0, 24) : [];
    const warns =
        warnList.length > 0
            ? '<div class="hint-micro mt8 hstate-warn">' +
              warnList.map((w) => esc(String(w))).join('<br>') +
              (Array.isArray(s.warnings) && s.warnings.length > 24
                  ? '<br><span class="text-dim">(' + (s.warnings.length - 24) + ' more warnings omitted)</span>'
                  : '') +
              '</div>'
            : '';
    let deltaHc = opts.trendDeltaHc;
    if (deltaHc == null || !Number.isFinite(deltaHc)) {
        deltaHc = 0;
    }
    const hasTrendPair = !!opts.trendHasPair;
    if (lowConfidence) {
        const unscopedOnlyUncertain = unscopedPairUncertain && !crossScope;
        const warnBody = unscopedOnlyUncertain
            ? '<strong>Low-confidence comparison</strong> — both scans are unscoped; comparison may be unreliable. ' +
              'Raw counters are shown below; do not read asset deltas as “hosts disappeared” without verifying the same network.'
            : '<strong>Low-confidence comparison</strong> — scopes differ or one job is unscoped. ' +
              'Raw counters are shown below; do not read asset deltas as “hosts disappeared” across networks.';
        const narrativeBody = unscopedOnlyUncertain
            ? 'Assign jobs to a <strong>named scope</strong> when you need like-for-like drift, or pick a reference scan that shares schedule, batch, target CIDR, or label lineage with the current job.'
            : 'Use this pair for manual inspection only. Prefer the <strong>Reports</strong> scope selector and two jobs from the same scope for production drift review.';
        const head =
            '<div class="hint-micro mb8">' +
            '<strong>Reference scan</strong> <span class="mono-sm">#' +
            esc(String(jobRef)) +
            '</span> · <strong>Current scan</strong> <span class="mono-sm">#' +
            esc(String(jobCur)) +
            '</span> <span class="text-dim">(frozen per-scan snapshots)</span></div>' +
            '<div class="hint-micro mb8 hstate-warn" style="line-height:1.5">' +
            warnBody +
            '</div>';
        const narrative =
            '<p class="hint-micro report-snapshot-narrative" style="line-height:1.55;margin:0 0 8px">' +
            narrativeBody +
            '</p>';
        const badgeRow =
            '<div class="row-wrap gap10 mb8" style="align-items:center"><span class="hstate-unk" style="font-weight:600">' +
            (unscopedOnlyUncertain ? 'Unscoped pair (unverified network)' : 'Cross-scope / unscoped mix') +
            '</span></div>';
        const cards = showCards
            ? reportingCompareSummaryCardsHtml(nc, { crossScope: true, unscopedUncertain: unscopedOnlyUncertain })
            : '';
        const adv =
            '<details class="mt10 report-snapshot-advanced" style="border:1px solid var(--border);border-radius:6px;padding:8px 10px">' +
            '<summary class="hint-micro" style="cursor:pointer;font-weight:600">Advanced details</summary>' +
            '<div class="hint-micro text-dim mt6 mb6">Counter table for this scan pair (technical).</div>' +
            reportingRenderCompareAdvancedDetails(s.counts, s.finding_events) +
            '</details>';
        return head + narrative + badgeRow + cards + warns + adv;
    }
    const risk = reportingCompareRiskClassification(nc, deltaHc, hasTrendPair);
    const narrative = reportingCompareNarrativeParagraph(jobRef, jobCur, nc, deltaHc, hasTrendPair, {
        softReferenceHostWording: !!opts.softReferenceHostWording,
    });
    const callouts = reportingCompareAttentionCalloutsHtml(nc, deltaHc, hasTrendPair);
    const head =
        '<div class="hint-micro mb8">' +
        '<strong>Reference scan</strong> <span class="mono-sm">#' +
        esc(String(jobRef)) +
        '</span> · <strong>Current scan</strong> <span class="mono-sm">#' +
        esc(String(jobCur)) +
        '</span> <span class="text-dim">(frozen per-scan snapshots, not live inventory)</span></div>';
    const badgeRow =
        '<div class="row-wrap gap10 mb8" style="align-items:center">' + risk.html + '</div>';
    const cards = showCards ? reportingCompareSummaryCardsHtml(nc, {}) : '';
    const adv =
        '<details class="mt10 report-snapshot-advanced" style="border:1px solid var(--border);border-radius:6px;padding:8px 10px">' +
        '<summary class="hint-micro" style="cursor:pointer;font-weight:600">Advanced details</summary>' +
        '<div class="hint-micro text-dim mt6 mb6">Counter table for this scan pair (technical). Expanded fields use server-internal keys for support/debug.</div>' +
        reportingRenderCompareAdvancedDetails(s.counts, s.finding_events) +
        '</details>';
    return head + narrative + badgeRow + callouts + cards + warns + adv;
}

function reportingHumanizeRuleKey(k) {
    return String(k || '').replace(/_/g, ' ');
}

/** Best-effort critical count from compliance rule detail (no new API). */
function reportingComplianceExtractCriticalCount(rules) {
    const r = rules && typeof rules === 'object' ? rules.no_critical_open : null;
    if (!r || r.pass || !r.detail) {
        return null;
    }
    const m = String(r.detail).match(/(\d+)/);
    if (!m) {
        return null;
    }
    const n = parseInt(m[1], 10);
    return Number.isFinite(n) ? n : null;
}

function reportingComplianceFriendlySummaryLine(c) {
    const pass = !!(c && c.overall_pass);
    const rules = c && c.rules && typeof c.rules === 'object' ? c.rules : {};
    if (pass) {
        return 'No critical or baseline regressions detected.';
    }
    const critN = reportingComplianceExtractCriticalCount(rules);
    if (critN != null && critN > 0) {
        return 'Critical vulnerabilities are still present (' + critN + ' detected).';
    }
    return 'One or more policy checks failed on this completed scan.';
}

function reportingRenderComplianceArtifactCard(cs) {
    if (!cs || typeof cs !== 'object' || !Object.keys(cs).length) {
        return '';
    }
    const pass = !!cs.overall_pass;
    const badge = pass
        ? '<span style="color:var(--green);font-weight:600">PASS</span>'
        : '<span style="color:var(--amber);font-weight:600">FAIL</span>';
    let h =
        '<div class="card" style="padding:10px;margin-bottom:14px;border:1px solid var(--border);border-radius:6px">';
    h +=
        '<div class="row-between mb8" style="align-items:center;flex-wrap:wrap;gap:8px"><span class="sth" style="margin:0;font-size:13px">Compliance (saved in artifact)</span>' +
        badge +
        '</div>';
    h += '<table class="tbl"><tbody>';
    h += '<tr><td class="mono-sm">job_id</td><td>' + esc(String(cs.job_id != null ? cs.job_id : '—')) + '</td></tr>';
    h +=
        '<tr><td class="mono-sm">baseline_job_id</td><td>' +
        esc(String(cs.baseline_job_id != null ? cs.baseline_job_id : '—')) +
        '</td></tr>';
    h += '</tbody></table>';
    h +=
        '<div class="hint-micro mt6">Stored artifacts only keep pass/fail and ids. Use <strong>Compliance detail</strong> (Reports &amp; Analysis → Analysis &amp; tools) with the same job for full rule text.</div>';
    h += '</div>';
    return h;
}

function reportingRenderComplianceFull(c) {
    if (!c || typeof c !== 'object') {
        return '<div class="text-dim">No compliance data returned.</div>';
    }
    const pass = !!c.overall_pass;
    const badge = pass
        ? '<span style="color:var(--green);font-weight:600">PASS</span>'
        : '<span style="color:var(--amber);font-weight:600">FAIL</span>';
    const friendly = reportingComplianceFriendlySummaryLine(c);
    let h =
        '<div class="card mb10" style="padding:12px 14px;border:1px solid var(--border)">' +
        '<div class="hint-micro" style="font-size:14px;line-height:1.45;margin:0 0 8px">' +
        esc(friendly) +
        '</div>' +
        '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap"><span class="text-secondary">Overall</span>' +
        badge +
        '</div></div>';
    h += '<div class="sth mb6" style="font-size:12px">Evaluation context</div>';
    h += '<table class="tbl mb10"><tbody>';
    h += '<tr><td>Scan evaluated</td><td class="mono-sm">' + esc(String(c.job_id != null ? c.job_id : '—')) + '</td></tr>';
    const beff = c.baseline_job_id != null ? c.baseline_job_id : c.baseline_effective;
    h +=
        '<tr><td>Baseline used for rules</td><td class="mono-sm">' +
        esc(String(beff != null && beff !== '' ? beff : '—')) +
        '</td></tr>';
    const bcfg = c.baseline_config_job_id != null ? c.baseline_config_job_id : c.baseline_config_id;
    h +=
        '<tr><td>Configured baseline id</td><td class="mono-sm">' +
        esc(String(bcfg != null && bcfg !== '' ? bcfg : '—')) +
        '</td></tr>';
    h += '</tbody></table>';
    const rules = c.rules && typeof c.rules === 'object' ? c.rules : {};
    const ruleKeys = Object.keys(rules);
    if (!ruleKeys.length) {
        h += '<div class="text-dim">No compliance rules in response.</div>';
        return h;
    }
    let passN = 0;
    let failN = 0;
    const fails = [];
    ruleKeys.forEach((k) => {
        const r = rules[k];
        if (r && r.pass) {
            passN++;
        } else {
            failN++;
            if (r && !r.pass) {
                fails.push({ k: k, detail: String(r.detail || '') });
            }
        }
    });
    h +=
        '<div class="hint-micro mb8">Checks: <strong>' +
        passN +
        '</strong> passed, <strong>' +
        failN +
        '</strong> failed <span class="text-dim">(of ' +
        ruleKeys.length +
        ')</span></div>';
    if (fails.length) {
        h += '<div class="sth mb4" style="font-size:12px">Failed rules</div><ul class="hint-micro" style="margin:0;padding-left:18px;max-width:100%">';
        fails.slice(0, 8).forEach(({ k, detail }) => {
            const det = detail.length > 220 ? detail.slice(0, 220) + '…' : detail;
            h += '<li style="margin-bottom:4px"><strong>' + esc(reportingHumanizeRuleKey(k)) + '</strong> — ' + esc(det) + '</li>';
        });
        if (fails.length > 8) {
            h += '<li class="text-dim">(' + (fails.length - 8) + ' more failures omitted)</li>';
        }
        h += '</ul>';
    } else {
        h += '<div class="hint-micro text-dim">All evaluated rules passed.</div>';
    }
    return h;
}

async function loadReportingCompliancePanel() {
    const sel = document.getElementById('report-compliance-job');
    const out = document.getElementById('report-compliance-out');
    const vs = document.getElementById('report-compliance-vs-baseline');
    const jid = sel ? parseInt(String(sel.value), 10) : 0;
    if (!jid) {
        toast('Select a completed scan job', 'err');
        if (out) {
            out.innerHTML = '<span class="text-dim">Select a job to evaluate compliance rules.</span>';
        }
        return;
    }
    if (out) out.innerHTML = '<span class="text-dim">Loading…</span>';
    const vsB = vs && vs.checked ? 1 : 0;
    const d = await api(
        '/api/reporting.php?action=compliance&job_id=' +
            jid +
            '&vs_baseline=' +
            vsB +
            reportingScopeQuery(),
        {quiet: true}
    );
    if (!d || !d.ok) {
        const msg = esc(reportingUserErrorMessage(d, 'Could not load compliance.'));
        if (out) out.innerHTML = '<div class="text-dim">' + msg + '</div>';
        reportingToastApiError('Compliance', d, 'Compliance request failed');
        return;
    }
    const c = d.compliance;
    if (!c || typeof c !== 'object') {
        if (out) out.innerHTML = '<div class="text-dim">No compliance data in response.</div>';
        return;
    }
    if (out) out.innerHTML = reportingRenderComplianceFull(c);
}

var reportingTabBaseline = null;

async function loadReportingAtGlance() {
    const kpiEl = document.getElementById('report-at-glance-kpis');
    const cmpEl = document.getElementById('report-at-glance-compliance');
    if (kpiEl) {
        kpiEl.innerHTML = '<span class="text-dim">Loading…</span>';
    }
    if (cmpEl) {
        cmpEl.innerHTML = '<span class="text-dim">Loading compliance…</span>';
    }
    const dash = await api('/api/dashboard.php?trend_days=14', {quiet: true});
    if (dash && dash.ok) {
        const ex = dash.executive && typeof dash.executive === 'object' ? dash.executive : {};
        const kpis = ex.kpis || {};
        const total = dash.assets != null && dash.assets.total != null ? dash.assets.total : kpis.assets_total;
        const openF =
            dash.findings != null && dash.findings.open != null ? dash.findings.open : kpis.open_findings;
        const bySev = (dash.findings && dash.findings.by_severity) || {};
        const crit = bySev.critical != null ? bySev.critical : kpis.critical_open || 0;
        const high = bySev.high != null ? bySev.high : kpis.high_open || 0;
        const card = (title, val, sub, tone) => {
            const tc = tone === 'bad' ? 'hstate-err' : tone === 'warn' ? 'hstate-warn' : '';
            return (
                '<div class="card" style="padding:10px 14px;flex:1 1 130px;border:1px solid var(--border)">' +
                '<div class="hint-micro text-dim" style="margin-bottom:4px">' +
                esc(title) +
                '</div>' +
                '<div class="' +
                tc +
                '" style="font-size:22px;font-weight:600;line-height:1.1">' +
                esc(String(val)) +
                '</div>' +
                (sub ? '<div class="hint-micro text-dim mt4">' + esc(sub) + '</div>' : '') +
                '</div>'
            );
        };
        const hiCrit = (Number(crit) || 0) + (Number(high) || 0);
        const sevTone = hiCrit > 0 ? 'warn' : '';
        if (kpiEl) {
            kpiEl.innerHTML =
                '<div class="row-wrap gap8" style="align-items:stretch">' +
                card('Assets (inventory)', total != null ? total : '—', 'Live — same as Dashboard', '') +
                card('Open findings', openF != null ? openF : '—', 'Live — unresolved CVE rows', '') +
                card('High + critical (open)', String(hiCrit), 'Live — severity split', sevTone) +
                '</div>';
        }
    } else if (kpiEl) {
        kpiEl.innerHTML =
            '<div class="hint-micro text-dim">Live KPIs could not load. Snapshot sections below still work once scan data is available.</div>';
    }
    if (!cmpEl) {
        return;
    }
    const tr = await api('/api/reporting.php?action=trends_summary&limit=1' + reportingScopeQuery(), {
        quiet: true,
    });
    const jid =
        tr && tr.ok && Array.isArray(tr.trends_summary) && tr.trends_summary[0]
            ? parseInt(String(tr.trends_summary[0].job_id), 10)
            : 0;
    if (!jid) {
        const named = reportingScopeApiFilter != null && reportingScopeApiFilter > 0;
        cmpEl.innerHTML =
            '<div class="hint-micro text-dim"><strong>Compliance (snapshot)</strong> — unavailable: ' +
            (named
                ? 'no completed scan jobs exist for this report scope in the recent snapshot window.'
                : 'no completed scan in the recent snapshot list. Run a scan or open <strong>Compliance detail</strong> below.') +
            '</div>' +
            (named ? reportingNoJobsForScopeHintHtml() : '');
        return;
    }
    const comp = await api(
        '/api/reporting.php?action=compliance&job_id=' + jid + '&vs_baseline=1' + reportingScopeQuery(),
        {quiet: true}
    );
    if (!comp || !comp.ok) {
        cmpEl.innerHTML =
            '<div class="hint-micro text-dim"><strong>Compliance (snapshot) for latest completed scan #' +
            esc(String(jid)) +
            '</strong> — temporarily unavailable. Use <strong>Compliance detail</strong> below to retry.</div>';
        return;
    }
    const c = comp.compliance;
    const pass = !!(c && c.overall_pass);
    const badge = pass
        ? '<span class="hstate-ok" style="font-weight:600">PASS</span>'
        : '<span class="hstate-warn" style="font-weight:600">FAIL</span>';
    const line = c && typeof c === 'object' ? reportingComplianceFriendlySummaryLine(c) : '';
    cmpEl.innerHTML =
        '<div><strong>Compliance (snapshot) — latest completed scan #' +
        esc(String(jid)) +
        '</strong> <span class="text-dim">(vs baseline rules)</span></div>' +
        '<div class="hint-micro mt6" style="line-height:1.45">' +
        esc(line) +
        ' <span class="text-dim">' +
        badge +
        ' — full rule text under <strong>Compliance detail</strong>.</span></div>';
}

async function loadReportingChangeSince() {
    const out = document.getElementById('report-change-since');
    if (!out) {
        return;
    }
    out.innerHTML = '<span class="text-dim">Loading snapshot drift…</span>';
    const driftLimit = 30;
    const tr = await api(
        '/api/reporting.php?action=trends_summary&limit=' + driftLimit + reportingScopeQuery(),
        {quiet: true}
    );
    if (!tr || !tr.ok) {
        out.innerHTML =
            '<div class="hint-micro text-dim">Snapshot drift could not load (recent scans unavailable). Other sections may still work.</div>';
        return;
    }
    const ts = tr.trends_summary;
    if (!Array.isArray(ts) || ts.length < 1) {
        let emptyMsg =
            'No completed scans yet — snapshot drift appears after at least one job finishes.';
        if (reportingScopeApiFilter != null && reportingScopeApiFilter > 0) {
            emptyMsg =
                'No completed scan jobs exist for this report scope in the recent window. Run a finished scan with this scope selected when queuing, switch to All scopes, or use Compare two scans (below).';
        } else if (reportingScopeApiFilter === 0) {
            emptyMsg =
                'No unscoped completed scans in the recent window (jobs need no scope tag). Try All scopes if you expect legacy data here.';
        }
        out.innerHTML =
            '<div class="hint-micro text-dim">' + esc(emptyMsg) + '</div>' + reportingNoJobsForScopeHintHtml();
        return;
    }
    if (ts.length === 1 && reportingScopeApiFilter !== null && reportingScopeApiFilter !== undefined) {
        out.innerHTML =
            '<div class="hint-micro text-dim">Only <strong>one</strong> completed scan matches this scope filter in the recent window. Drift needs a second finished job in the same scope, a valid baseline for that scope, or switch to <strong>All scopes</strong> / use <strong>Compare two scans</strong> (below).</div>';
        return;
    }
    const newest = parseInt(String(ts[0].job_id), 10);
    if (!newest) {
        out.innerHTML = '<div class="hint-micro text-dim">No valid latest scan id for drift.</div>';
        return;
    }
    const modeAll = reportingScopeApiFilter === null;
    const bl = reportingTabBaseline;
    const eff = bl && bl.ok && bl.baseline_job_id != null ? parseInt(String(bl.baseline_job_id), 10) : 0;
    const cfg = bl && bl.ok && bl.baseline_config_job_id != null ? parseInt(String(bl.baseline_config_job_id), 10) : 0;
    const unavail = !!(bl && bl.ok && bl.baseline_unavailable);
    let jobA = 0;
    let labelMode = 'none';
    if (modeAll) {
        const sk = reportingTrendsRowScopeKey(ts[0]);
        let picked = false;
        if (sk > 0) {
            const bxs = await api('/api/reporting.php?action=baseline&scope_id=' + encodeURIComponent(String(sk)), {
                quiet: true,
            });
            const effS =
                bxs && bxs.ok && bxs.scope_baseline_job_id != null
                    ? parseInt(String(bxs.scope_baseline_job_id), 10)
                    : 0;
            if (effS > 0 && effS !== newest) {
                jobA = effS;
                labelMode = 'scope_baseline_latest_network';
                picked = true;
            }
        }
        if (!picked && sk === 0 && bl && bl.ok) {
            const us = bl.unscoped_comparison_baseline_job_id;
            const usEff = us != null ? parseInt(String(us), 10) : 0;
            if (usEff > 0 && usEff !== newest) {
                jobA = usEff;
                labelMode = 'legacy_unscoped_global_all';
                picked = true;
            }
        }
        if (!picked) {
            for (let i = 1; i < ts.length; i++) {
                if (reportingTrendsRowScopeKey(ts[i]) === sk) {
                    if (sk === 0 && !reportingUnscopedJobsCompatible(ts[0], ts[i])) {
                        continue;
                    }
                    const cand = parseInt(String(ts[i].job_id), 10);
                    if (cand > 0 && cand !== newest) {
                        jobA = cand;
                        labelMode = sk === 0 ? 'unscoped_compatible_prior_all' : 'same_scope_prior_all';
                        break;
                    }
                }
            }
        }
        if (!jobA) {
            if (sk === 0) {
                const baselineNote =
                    bl && bl.ok && bl.legacy_global_points_to_named_scope
                        ? ' <span class="text-dim">(Legacy global baseline points at a named-scope job, so it is not used for unscoped drift here.)</span>'
                        : '';
                out.innerHTML =
                    '<div class="hint-micro text-dim hstate-warn" style="line-height:1.5">This scan is unscoped, so Reports cannot safely choose a previous scan for drift. Assign it to a scope or use <strong>Compare two scans</strong> (below).' +
                    baselineNote +
                    '</div>';
                return;
            }
            const scopeLabel = 'scope #' + sk + ' (named network)';
            const baselineNote =
                sk > 0
                    ? ' (No scoped baseline set for that network, or it matches the latest scan.)'
                    : '';
            out.innerHTML =
                '<div class="hint-micro text-dim">Latest completed scan is <span class="mono-sm">#' +
                esc(String(newest)) +
                '</span> (' +
                esc(scopeLabel) +
                '). <strong>No comparable reference</strong> in that same scope in the last ' +
                esc(String(driftLimit)) +
                ' finished jobs — add another scan in this scope, set a scoped baseline for that network, or use <strong>Compare two scans</strong> (below).' +
                esc(baselineNote) +
                '</div>';
            return;
        }
    } else {
        const unscopedOnly = reportingScopeApiFilter === 0;
        if (eff > 0 && eff !== newest) {
            jobA = eff;
            labelMode = 'baseline';
        } else {
            for (let i = 1; i < ts.length; i++) {
                const cand = parseInt(String(ts[i].job_id), 10);
                if (cand <= 0 || cand === newest) {
                    continue;
                }
                if (unscopedOnly && !reportingUnscopedJobsCompatible(ts[0], ts[i])) {
                    continue;
                }
                jobA = cand;
                break;
            }
            if (jobA) {
                if (eff > 0 && eff === newest) {
                    labelMode = 'prior_latest_is_baseline';
                } else if (unavail && cfg > 0) {
                    labelMode = 'fallback_unusable_baseline';
                } else {
                    labelMode = unscopedOnly ? 'unscoped_compatible_prior_filter' : 'prior_only';
                }
            }
        }
    }
    if (!jobA || jobA === newest) {
        if (reportingScopeApiFilter === 0) {
            out.innerHTML =
                '<div class="hint-micro text-dim hstate-warn" style="line-height:1.5">Unscoped-only mode: no <strong>compatible</strong> prior scan was found in this list (same schedule, batch, target CIDR, or matching label prefix). Automatic snapshot drift is not shown — history charts below still list unscoped jobs. Set a baseline for this bucket, assign scans to a named scope, or use <strong>Compare two scans</strong> (below).</div>';
            return;
        }
        const narrow =
            reportingScopeApiFilter !== null && reportingScopeApiFilter !== undefined
                ? ' At least two completed scans in this filter, or a baseline that differs from the latest scan, are needed.'
                : '';
        out.innerHTML =
            '<div class="hint-micro text-dim">Drift cannot be shown for this pair: the reference scan is missing or the same as the latest.' +
            esc(narrow) +
            ' If a baseline is configured but deleted or invalid, set a new one or wait for another finished job.</div>';
        return;
    }
    const d = await api(
        '/api/reporting.php?action=compare_summary&job_a=' +
            jobA +
            '&job_b=' +
            newest +
            reportingScopeQuery(),
        {quiet: true}
    );
    if (!d || !d.ok) {
        out.innerHTML =
            '<div class="hint-micro text-dim">' +
            esc(reportingUserErrorMessage(d, 'Snapshot drift could not be computed for these jobs.')) +
            '</div>';
        return;
    }
    const ds = d.diff_summary;
    if (!ds || typeof ds !== 'object') {
        out.innerHTML = '<div class="hint-micro text-dim">No drift summary returned.</div>';
        return;
    }
    let hintText = '';
    if (labelMode === 'same_scope_prior_all') {
        hintText =
            'All scopes — reference: most recent prior completed scan in the same named scope (scan #' +
            jobA +
            ') vs latest scan #' +
            newest +
            ' — snapshot tables only (not live inventory).';
    } else if (labelMode === 'unscoped_compatible_prior_all') {
        hintText =
            'All scopes — reference: prior unscoped scan #' +
            jobA +
            ' vs latest #' +
            newest +
            ' — chosen only because they share a compatibility signal (same schedule, batch, target CIDR, or label prefix); snapshots only.';
    } else if (labelMode === 'scope_baseline_latest_network') {
        hintText =
            'All scopes — reference: baseline for the latest scan’s network (scan #' +
            jobA +
            ') vs latest scan #' +
            newest +
            ' — snapshots only.';
    } else if (labelMode === 'legacy_unscoped_global_all') {
        hintText =
            'All scopes — reference: legacy global baseline (operator-chosen unscoped job, scan #' +
            jobA +
            ') vs latest unscoped scan #' +
            newest +
            ' — snapshots only; verify both jobs target the same network.';
    } else if (labelMode === 'baseline') {
        hintText =
            (reportingScopeApiFilter > 0
                ? 'Named scope — reference: '
                : 'Unscoped filter — reference: ') +
            'configured baseline (scan #' +
            jobA +
            ') vs current scan #' +
            newest +
            ' — snapshot tables only (not live inventory).';
    } else if (labelMode === 'prior_latest_is_baseline') {
        hintText =
            'Your latest completed scan is the effective baseline; reference: prior completed scan #' +
            jobA +
            ' vs current scan #' +
            newest +
            ' — snapshots only.';
    } else if (labelMode === 'fallback_unusable_baseline') {
        hintText =
            'Configured baseline is not usable for snapshots; reference: prior completed scan #' +
            jobA +
            ' vs current scan #' +
            newest +
            ' — snapshots only.';
    } else if (labelMode === 'unscoped_compatible_prior_filter') {
        hintText =
            'Unscoped filter — reference: prior scan #' +
            jobA +
            ' vs latest #' +
            newest +
            ' — compatible signal only (schedule, batch, target CIDR, or label prefix); snapshots only.';
    } else {
        hintText =
            'No separate baseline for drift; reference: prior completed scan #' +
            jobA +
            ' vs current scan #' +
            newest +
            ' — snapshots only.';
    }
    const hint =
        '<div class="hint-micro mb8 text-dim"><strong>How this comparison was chosen</strong> — ' +
        esc(hintText) +
        '</div>';
    const refRow = reportingTrendsRowByJobId(ts, jobA);
    const curRow = ts[0];
    let trendDeltaHc = 0;
    let trendHasPair = false;
    if (refRow && curRow) {
        const hr = reportingTrendsOpenHighCritical(refRow);
        const hc = reportingTrendsOpenHighCritical(curRow);
        if (hr !== null && hc !== null) {
            trendDeltaHc = hc - hr;
            trendHasPair = true;
        }
    }
    const align = ds.scope_alignment;
    const crossScope = !!(align && align.comparable === false);
    const unscopedPairUncertain = !!ds.unscoped_pair_uncertain;
    const softRefHost =
        labelMode === 'unscoped_compatible_prior_all' || labelMode === 'unscoped_compatible_prior_filter';
    out.innerHTML =
        hint +
        reportingRenderCompareExecutiveSummary(ds, {
            cards: false,
            trendDeltaHc: trendDeltaHc,
            trendHasPair: trendHasPair,
            crossScope: crossScope,
            unscopedPairUncertain: unscopedPairUncertain,
            softReferenceHostWording: softRefHost,
        });
}

function reportingTrendsChronological(points) {
    if (!Array.isArray(points)) {
        return [];
    }
    return points.slice().reverse();
}

/** Simple SVG line chart for snapshot trends (oldest → newest, left to right). */
function reportingTrendSnapshotLineChart(values, title, colorCss) {
    const n = values.length;
    if (n < 2) {
        return (
            '<div class="mb10"><div class="hint-micro mb4" style="font-weight:600">' +
            esc(title) +
            '</div><span class="text-dim">Not enough points</span></div>'
        );
    }
    const W = 340;
    const H = 118;
    const padL = 36;
    const padR = 10;
    const padT = 12;
    const padB = 26;
    const iw = W - padL - padR;
    const ih = H - padT - padB;
    let minV = values[0];
    let maxV = values[0];
    for (let i = 1; i < n; i++) {
        if (values[i] < minV) {
            minV = values[i];
        }
        if (values[i] > maxV) {
            maxV = values[i];
        }
    }
    if (minV === maxV) {
        minV -= 1;
        maxV += 1;
    }
    const pts = [];
    for (let i = 0; i < n; i++) {
        const x = padL + (i / (n - 1)) * iw;
        const y = padT + (1 - (values[i] - minV) / (maxV - minV)) * ih;
        pts.push(x.toFixed(1) + ',' + y.toFixed(1));
    }
    const stroke = colorCss || 'currentColor';
    const yMax = padT + ih;
    return (
        '<div class="mb12" style="max-width:100%">' +
        '<div class="hint-micro mb4" style="font-weight:600">' +
        esc(title) +
        '</div>' +
        '<svg width="' +
        W +
        '" height="' +
        H +
        '" viewBox="0 0 ' +
        W +
        ' ' +
        H +
        '" xmlns="http://www.w3.org/2000/svg" class="report-trend-line-chart" role="img" aria-label="' +
        esc(title) +
        '">' +
        '<line x1="' +
        padL +
        '" y1="' +
        yMax +
        '" x2="' +
        (W - padR) +
        '" y2="' +
        yMax +
        '" stroke="var(--border)" stroke-width="1"/>' +
        '<line x1="' +
        padL +
        '" y1="' +
        padT +
        '" x2="' +
        padL +
        '" y2="' +
        yMax +
        '" stroke="var(--border)" stroke-width="1"/>' +
        '<text x="' +
        padL +
        '" y="' +
        (H - 6) +
        '" font-size="10" fill="currentColor" opacity="0.55">Older</text>' +
        '<text x="' +
        (W - padR - 40) +
        '" y="' +
        (H - 6) +
        '" font-size="10" fill="currentColor" opacity="0.55">Newer</text>' +
        '<text x="' +
        (padL + 2) +
        '" y="' +
        (padT + 10) +
        '" font-size="10" fill="currentColor" opacity="0.55">' +
        esc(String(maxV)) +
        '</text>' +
        '<text x="' +
        (padL + 2) +
        '" y="' +
        yMax +
        '" font-size="10" fill="currentColor" opacity="0.55" dominant-baseline="ideographic">' +
        esc(String(minV)) +
        '</text>' +
        '<polyline fill="none" stroke="' +
        stroke +
        '" stroke-width="2" points="' +
        pts.join(' ') +
        '"/>' +
        '</svg></div>'
    );
}

function reportingTrendsCollectSeverityKeys(rows) {
    const s = new Set();
    rows.forEach((r) => {
        const o = r.open_findings_by_severity;
        if (o && typeof o === 'object') {
            Object.keys(o).forEach((k) => s.add(k));
        }
    });
    const order = ['critical', 'high', 'medium', 'low', 'info', ''];
    const keys = [];
    order.forEach((k) => {
        if (s.has(k)) {
            keys.push(k);
            s.delete(k);
        }
    });
    Array.from(s)
        .sort()
        .forEach((k) => keys.push(k));
    return keys;
}

function reportingTrendsSevLabel(k) {
    if (k === '') {
        return '(unset)';
    }
    return k;
}

function reportingRenderTrendsSummaryHtml(chrono) {
    if (!chrono.length) {
        return '<div class="hint-micro text-dim">No completed scan jobs with a finish time were found. Run scans and return here after jobs complete.</div>';
    }
    let h =
        '<div class="hint-micro text-dim mb8">Each row is one <strong>completed scan</strong> (snapshot tables only; not live inventory).</div>';
    h +=
        '<div class="hint-micro text-dim mb10"><strong>Snapshot-based trend (not real-time)</strong> — up to 50 most recent finished jobs, oldest on the left.</div>';
    const assetVals = chrono.map((r) => (r.asset_count != null ? r.asset_count : 0));
    const findVals = chrono.map((r) => (r.open_findings_total != null ? r.open_findings_total : 0));
    const hcVals = chrono.map((r) => {
        const by =
            r.open_findings_by_severity && typeof r.open_findings_by_severity === 'object'
                ? r.open_findings_by_severity
                : {};
        const c = parseInt(String(by.critical != null ? by.critical : 0), 10) || 0;
        const hi = parseInt(String(by.high != null ? by.high : 0), 10) || 0;
        return c + hi;
    });
    h += '<div class="row-wrap gap10 mb10" style="align-items:flex-start">';
    h += reportingTrendSnapshotLineChart(assetVals, 'Asset count over time', 'var(--blue)');
    h += reportingTrendSnapshotLineChart(findVals, 'Open findings over time', 'var(--amber)');
    h += reportingTrendSnapshotLineChart(hcVals, 'High + critical (open) over time', 'var(--red)');
    h += '</div>';

    h +=
        '<div class="sth" style="font-size:12px;margin-bottom:6px">Assets over time <span class="text-dim">(oldest → newest)</span></div>';
    h += '<div class="tbl-wrap mb12"><table class="tbl"><thead><tr><th>Finished</th><th>Scan #</th><th>Label</th><th>Asset count</th></tr></thead><tbody>';
    chrono.forEach((r) => {
        h +=
            '<tr><td>' +
            esc(String(r.timestamp || '—')) +
            '</td><td class="mono-sm">' +
            esc(String(r.job_id)) +
            '</td><td>' +
            esc(String(r.label || '')) +
            '</td><td>' +
            esc(String(r.asset_count != null ? r.asset_count : 0)) +
            '</td></tr>';
    });
    h += '</tbody></table></div>';

    const sevKeys = reportingTrendsCollectSeverityKeys(chrono);
    h +=
        '<div class="sth" style="font-size:12px;margin-bottom:6px">Findings over time <span class="text-dim">(open in snapshot, by severity)</span></div>';
    h += '<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Finished</th><th>Scan #</th><th>Total open</th>';
    sevKeys.forEach((k) => {
        h += '<th>' + esc(reportingTrendsSevLabel(k)) + '</th>';
    });
    h += '</tr></thead><tbody>';
    chrono.forEach((r) => {
        const by =
            r.open_findings_by_severity && typeof r.open_findings_by_severity === 'object'
                ? r.open_findings_by_severity
                : {};
        h +=
            '<tr><td>' +
            esc(String(r.timestamp || '—')) +
            '</td><td class="mono-sm">' +
            esc(String(r.job_id)) +
            '</td><td>' +
            esc(String(r.open_findings_total != null ? r.open_findings_total : 0)) +
            '</td>';
        sevKeys.forEach((k) => {
            const v = by[k];
            h += '<td>' + esc(String(v != null ? v : 0)) + '</td>';
        });
        h += '</tr>';
    });
    h += '</tbody></table></div>';
    return h;
}

async function loadReportingTrendsSummary(silentFail) {
    const sel = document.getElementById('report-trends-limit');
    const out = document.getElementById('report-trends-out');
    const limRaw = sel ? parseInt(String(sel.value), 10) : 30;
    const lim = Math.min(50, Math.max(1, limRaw || 30));
    if (out) {
        out.innerHTML = '<span class="text-dim">Loading…</span>';
    }
    const trendUrl = '/api/reporting.php?action=trends_summary&limit=' + lim + reportingScopeQuery();
    const d = await api(trendUrl, {quiet: true});
    if (typeof window !== 'undefined' && stRoleIsAdmin()) {
        window.__stReportingDiag = Object.assign({}, window.__stReportingDiag || {}, {
            lastTrendsUrl: trendUrl,
            lastTrendsOk: !!(d && d.ok),
        });
    }
    if (!d || !d.ok) {
        const msg = esc(reportingUserErrorMessage(d, 'Could not load scan history.'));
        if (out) {
            out.innerHTML =
                '<div class="hint-micro text-dim">' +
                msg +
                (silentFail
                    ? ' Live KPIs and snapshot drift above may still be useful.'
                    : '') +
                '</div>';
        }
        if (!silentFail) {
            reportingToastApiError('Trends', d, 'Trends request failed');
        }
        return;
    }
    const pts = d.trends_summary;
    if (!Array.isArray(pts)) {
        if (out) {
            out.innerHTML = '<div class="text-dim">Invalid trends response.</div>';
        }
        return;
    }
    const chrono = reportingTrendsChronological(pts);
    if (out) {
        if (!chrono.length) {
            let why =
                '<div class="hint-micro text-dim">No completed scans match this scope filter in the recent window.</div>';
            if (reportingScopeApiFilter === null) {
                why =
                    '<div class="hint-micro text-dim">No finished jobs with snapshots appeared in the last ' +
                    esc(String(lim)) +
                    ' completed scans. Run a scan and return after it completes.</div>';
            } else if (reportingScopeApiFilter === 0) {
                why =
                    '<div class="hint-micro text-dim"><strong>Unscoped only</strong> — no completed jobs without a scope tag in this list. Legacy scans may still be tagged; try <strong>All scopes</strong> to confirm data exists.</div>';
            } else {
                why =
                    '<div class="hint-micro text-dim"><strong>No completed scan jobs exist for this report scope</strong> in the last ' +
                    esc(String(lim)) +
                    ' finished jobs. Pick another scope, or queue scans with this scope selected on the <strong>Scan</strong> tab (job scope is stored at queue time).</div>' +
                    reportingNoJobsForScopeHintHtml();
            }
            out.innerHTML = why;
            out.className = 'report-trends-out text-dim';
        } else {
            let trendBody = reportingRenderTrendsSummaryHtml(chrono);
            if (reportingScopeApiFilter === null) {
                trendBody =
                    '<div class="hint-micro mb8 text-dim">All scopes trend includes mixed scan scopes. For cleaner per-network trends, select a named scope.</div>' +
                    trendBody;
            }
            out.innerHTML = trendBody;
            out.className = 'report-trends-out';
        }
    }
}

async function loadReportingTab() {
    if (typeof window !== 'undefined' && !stRoleIsAdmin()) {
        try {
            delete window.__stReportingDiag;
        } catch (_e) {}
    }
    try {
        await loadReportingScopeSelector(false);
    } catch (_e) {}
    if (reportingIsInventoryMode()) {
        try {
            await loadReportingInventorySummary();
        } catch (_e) {}
        updateReportScopeAdminDiag();
        return;
    }
    const baseEl = document.getElementById('report-baseline-status');
    const valEl = document.getElementById('report-baseline-validation');
    const setWrap = document.getElementById('report-baseline-set-wrap');
    const dbgWrap = document.getElementById('report-baseline-debug-wrap');
    const cmpDbgWrap = document.getElementById('report-cmp-debug-wrap');
    const dbgOut = document.getElementById('report-baseline-debug-out');
    const cmpDbgOut = document.getElementById('report-cmp-debug-out');
    if (dbgOut) {
        dbgOut.style.display = 'none';
        dbgOut.textContent = '';
    }
    if (cmpDbgOut) {
        cmpDbgOut.style.display = 'none';
        cmpDbgOut.textContent = '';
    }
    if (baseEl) baseEl.textContent = 'Loading…';
    if (valEl) {
        valEl.style.display = 'none';
        valEl.textContent = '';
    }
    const trendsOut = document.getElementById('report-trends-out');
    if (trendsOut) {
        trendsOut.innerHTML = '<span class="text-dim">Loading scan history (snapshots)…</span>';
        trendsOut.className = 'report-trends-out text-dim';
    }
    // Baseline first so a failure loading scan history (job pickers) does not block baseline or artifacts.
    const baselineUrl = '/api/reporting.php?action=baseline' + reportingScopeQuery();
    const d = await api(baselineUrl, {quiet: true});
    if (typeof window !== 'undefined' && stRoleIsAdmin()) {
        window.__stReportingDiag = Object.assign({}, window.__stReportingDiag || {}, {
            lastBaselineUrl: baselineUrl,
            lastBaselineAt: Date.now(),
            lastBaselineOk: !!(d && (d.ok !== false || d.baseline_soft_error)),
        });
    }
    reportingTabBaseline = d && d.ok !== false ? d : null;
    const lblEl = document.getElementById('report-baseline-set-label');
    const setHintEl = document.getElementById('report-baseline-set-hint');
    const overviewMode = reportingScopeApiFilter === null;
    const namedMode = reportingScopeApiFilter !== null && reportingScopeApiFilter > 0;
    const unscopedMode = reportingScopeApiFilter !== null && reportingScopeApiFilter === 0;
    if (!d) {
        if (baseEl) {
            baseEl.innerHTML =
                '<div class="hstate-warn">Baseline status could not be loaded (network, session, or non-JSON response). Charts and trends below may still work after sign-in.</div>';
        }
        if (valEl) {
            valEl.style.display = 'none';
            valEl.textContent = '';
        }
    } else if (d.baseline_soft_error) {
        if (baseEl) {
            baseEl.innerHTML =
                '<div class="hstate-warn">' +
                esc(String(d.baseline_soft_error)) +
                '</div><div class="hint-micro mt6 text-dim">If this persists, check the server <strong>error_log</strong> for <span class="mono-sm">reporting baseline</span>.</div>';
        }
        if (valEl) {
            valEl.style.display = 'none';
            valEl.textContent = '';
        }
    } else {
        const cfg = d.baseline_config_job_id;
        const eff = d.baseline_job_id;
        const un = !!d.baseline_unavailable;
        const gScope = d.global_baseline_job_scope_id;
        const gScopeTxt =
            gScope != null && parseInt(String(gScope), 10) > 0
                ? 'named scope #' + esc(String(gScope))
                : 'unscoped / legacy';
        const unscopedEff = d.unscoped_comparison_baseline_job_id;
        const legNamed = !!d.legacy_global_points_to_named_scope;
        const upePool = d.unscoped_pool_baseline_job_id;
        if (baseEl) {
            let html = '';
            if (overviewMode) {
                html +=
                    '<div class="hint-micro mb10" style="line-height:1.5">' +
                    '<strong>Baselines are per scope.</strong> With <em>All scopes</em>, trends include every finished job; automatic drift only compares within the latest job’s own scope. ' +
                    'The <strong>legacy global</strong> row is a special-case reference for unscoped jobs — not one baseline for every network on this page. ' +
                    'Pick a <strong>named scope</strong> or <strong>Unscoped only</strong> to view or set that bucket’s baseline.</div>';
            }
            html +=
                '<div class="text-dim" style="font-size:11px;margin-bottom:4px"><strong>Legacy global baseline</strong> (<span class="mono-sm">config.phase13_baseline_job_id</span>) — optional reference for unscoped comparisons; see technical details in Advanced (admin).</div>' +
                '<div><strong>Configured id:</strong> ' +
                (cfg == null ? '— none —' : esc(String(cfg))) +
                '</div><div><strong>Effective job:</strong> ' +
                (eff == null ? '— none —' : esc(String(eff))) +
                (d.scoping_enabled ? ' <span class="text-dim">(scope: ' + gScopeTxt + ')</span>' : '') +
                '</div><div><strong>Usable as drift reference:</strong> ' +
                (un ? '<span class="hstate-warn">No — see note below</span>' : '<span class="text-dim">Yes</span>') +
                '</div>';
            if (d.scoping_enabled) {
                html +=
                    '<div class="mt8"><strong>Unscoped comparison baseline:</strong> ' +
                    (unscopedEff == null ? '— none —' : esc(String(unscopedEff))) +
                    ' <span class="text-dim">(only when the legacy global baseline job is itself unscoped)</span></div>';
            }
            if (namedMode) {
                const scfg = d.scope_baseline_config_job_id;
                const seff = d.scope_baseline_job_id;
                const sun = !!d.scope_baseline_unavailable;
                html +=
                    '<div class="mt8"><strong>Named scope baseline (saved id):</strong> ' +
                    (scfg == null ? '— none —' : esc(String(scfg))) +
                    '</div><div><strong>Named scope effective:</strong> ' +
                    (seff == null ? '— none —' : esc(String(seff))) +
                    '</div><div><strong>Baseline usable for this scope:</strong> ' +
                    (sun ? '<span class="hstate-warn">No — see note below</span>' : '<span class="text-dim">Yes</span>') +
                    '</div>';
                {
                    const scfgNum = scfg != null && String(scfg) !== '' ? parseInt(String(scfg), 10) : 0;
                    if (!(scfgNum > 0) && !sun) {
                        html +=
                            '<div class="hint-micro mt6 text-dim">No baseline saved for this scope yet. Choose a completed scan in this scope from <strong>Set baseline</strong> below.</div>';
                    }
                }
            }
            if (unscopedMode) {
                const upc = d.unscoped_pool_config_job_id;
                const upe = d.unscoped_pool_baseline_job_id;
                html +=
                    '<div class="mt8"><strong>Unscoped pool — configured (legacy global):</strong> ' +
                    (upc == null ? '— none —' : esc(String(upc))) +
                    '</div><div><strong>Unscoped pool — effective:</strong> ' +
                    (upe == null ? '— none —' : esc(String(upe))) +
                    '</div>';
            }
            baseEl.innerHTML = html;
        }
        if (valEl) {
            const parts = [];
            if (un) {
                parts.push(
                    'Baseline not available: the configured reference scan is missing, not finished, in trash, or has no asset snapshots. Set a different baseline from a valid completed job.'
                );
            }
            if (namedMode && d.scope_baseline_config_job_id != null && parseInt(String(d.scope_baseline_config_job_id), 10) > 0 && d.scope_baseline_unavailable) {
                parts.push('Baseline not available for this named scope: the saved reference scan cannot be used. Choose another completed scan in this scope and set baseline again.');
            }
            if (overviewMode && legNamed) {
                parts.push(
                    'Global baseline points at a named-scope scan, so it is not used as a single “all networks” reference. For unscoped drift, set the global baseline to an unscoped completed job or switch to a named scope.'
                );
            }
            if (unscopedMode && legNamed) {
                parts.push(
                    'Unscoped comparisons cannot use a baseline that points at a named-scope scan. Set baseline from an unscoped completed job, or select a named report scope.'
                );
            }
            if (unscopedMode && (upePool == null || upePool === '') && !legNamed) {
                parts.push('No baseline set yet for unscoped jobs. Pick a finished unscoped scan in the list below and use Set baseline.');
            }
            if (parts.length) {
                valEl.style.display = '';
                valEl.textContent = parts.join(' ');
            } else {
                valEl.style.display = 'none';
                valEl.textContent = '';
            }
        }
    }
    if (setWrap) {
        const canSet = stRoleCanManageScans();
        if (!canSet) {
            setWrap.style.display = 'none';
        } else if (overviewMode) {
            setWrap.style.display = 'none';
        } else {
            setWrap.style.display = '';
            if (lblEl) {
                lblEl.innerHTML =
                    namedMode
                        ? 'Set baseline for <strong>this named scope</strong> (<span class="mono-sm">scan_scope_baselines</span>)'
                        : 'Set <strong>legacy global</strong> baseline (applies to unscoped comparisons; writes <span class="mono-sm">config.phase13_baseline_job_id</span>)';
            }
            if (setHintEl) {
                setHintEl.innerHTML = namedMode
                    ? 'The selected job must belong to this scope and have asset snapshots.'
                    : 'Pick a <strong>completed</strong> job with <strong>no scope tag</strong> (unscoped) so legacy comparisons stay meaningful.';
            }
        }
    }
    const advRegion = document.getElementById('report-advanced-region');
    if (advRegion) {
        advRegion.style.display = stRoleIsAdmin() ? '' : 'none';
    }
    try {
        await loadReportingAtGlance();
    } catch (_e) {}
    try {
        await loadReportingChangeSince();
    } catch (_e) {}
    try {
        await populateReportingJobSelects();
    } catch (_e) {}
    const artH = document.getElementById('report-artifacts-heading');
    const artW = document.getElementById('report-artifacts-wrap');
    if (artH) artH.style.display = '';
    if (artW) artW.style.display = '';
    try {
        await loadReportingArtifacts();
    } catch (_e) {}
    try {
        await loadReportingTrendsSummary(true);
    } catch (_e) {}
    updateReportScopeAdminDiag();
}

async function saveReportingBaseline() {
    if (!stRoleCanManageScans()) {
        toast('Scan editor or admin role required to set baseline.', 'err');
        return;
    }
    const sel = document.getElementById('report-baseline-job');
    const jid = sel ? parseInt(String(sel.value), 10) : 0;
    if (!jid) {
        toast('Select a completed scan', 'err');
        return;
    }
    const body = { job_id: jid };
    if (reportingScopeApiFilter !== null && reportingScopeApiFilter > 0) {
        body.scope_id = reportingScopeApiFilter;
    }
    const r = await apiPost('/api/reporting.php?action=set_baseline', body);
    if (r && r.ok) {
        toast('Baseline updated', 'ok');
        await loadReportingTab();
    } else {
        reportingToastApiError('Set baseline', r, 'Failed to set baseline');
    }
}

async function runReportingCompareSummary() {
    const a = parseInt(String(document.getElementById('report-cmp-a') && document.getElementById('report-cmp-a').value), 10);
    const b = parseInt(String(document.getElementById('report-cmp-b') && document.getElementById('report-cmp-b').value), 10);
    const out = document.getElementById('report-cmp-out');
    if (!a || !b) {
        toast('Select a reference scan and a current scan', 'err');
        return;
    }
    if (a === b) {
        toast('Reference and current scans must be different jobs', 'err');
        return;
    }
    if (out) out.innerHTML = '<span class="text-dim">Loading…</span>';
    const d = await api(
        '/api/reporting.php?action=compare_summary&job_a=' + a + '&job_b=' + b + reportingScopeQuery(),
        {quiet: true}
    );
    if (!d || !d.ok) {
        const msg = esc(reportingUserErrorMessage(d, 'Could not compare jobs (network or server error).'));
        if (out) out.innerHTML = '<div class="text-dim">' + msg + '</div>';
        reportingToastApiError('Compare', d, 'Could not load compare summary.');
        return;
    }
    const s = d.diff_summary || {};
    const align = s.scope_alignment;
    const crossScope = !!(align && align.comparable === false);
    const unscopedPairUncertain = !!s.unscoped_pair_uncertain;
    if (out) {
        out.className = 'report-snapshot-drift-out';
        out.innerHTML = reportingRenderCompareExecutiveSummary(s, {
            crossScope: crossScope,
            unscopedPairUncertain: unscopedPairUncertain,
        });
    }
}

async function loadReportingBaselineDebug() {
    if (!stRoleIsAdmin()) {
        toast('Admin role required for baseline_debug.', 'err');
        return;
    }
    const pre = document.getElementById('report-baseline-debug-out');
    if (!pre) return;
    pre.style.display = '';
    pre.textContent = 'Loading…';
    const d = await api('/api/reporting.php?action=baseline_debug', {quiet: true});
    if (!d || !d.ok) {
        pre.textContent = reportingUserErrorMessage(d, 'Request failed (forbidden or server error).');
        reportingToastApiError('baseline_debug', d, 'Could not load debug detail.');
        return;
    }
    pre.textContent = reportingTruncateJsonDisplay(d.baseline || d);
}

async function runReportingCompareDebug() {
    if (!stRoleIsAdmin()) {
        toast('Admin role required for compare_debug.', 'err');
        return;
    }
    const pre = document.getElementById('report-cmp-debug-out');
    if (!pre) return;
    const a = parseInt(String(document.getElementById('report-cmp-a') && document.getElementById('report-cmp-a').value), 10);
    const b = parseInt(String(document.getElementById('report-cmp-b') && document.getElementById('report-cmp-b').value), 10);
    if (!a || !b) {
        toast('Select reference and current scans first', 'err');
        return;
    }
    if (a === b) {
        toast('Reference and current scans must differ', 'err');
        return;
    }
    pre.style.display = '';
    pre.textContent = 'Loading…';
    const d = await api(
        '/api/reporting.php?action=compare_debug&job_a=' +
            a +
            '&job_b=' +
            b +
            '&sample_limit=12' +
            reportingScopeQuery(),
        {quiet: true}
    );
    if (!d || !d.ok) {
        pre.textContent = reportingUserErrorMessage(d, 'Request failed (forbidden or server error).');
        reportingToastApiError('compare_debug', d, 'Could not load debug samples.');
        return;
    }
    pre.textContent = reportingTruncateJsonDisplay(d.compare_debug || d);
}

async function loadReportingArtifacts() {
    const tbody = document.getElementById('report-artifacts-tbody');
    if (!tbody) return;
    tbody.innerHTML = '<tr><td colspan="7" class="text-dim">Loading…</td></tr>';
    const artUrl = '/api/reporting.php?action=artifacts&limit=40';
    const d = await api(artUrl, {quiet: true});
    if (typeof window !== 'undefined' && stRoleIsAdmin()) {
        window.__stReportingDiag = Object.assign({}, window.__stReportingDiag || {}, {
            lastArtifactsUrl: artUrl,
            lastArtifactsAt: Date.now(),
            lastArtifactsOk: !!(d && d.ok !== false),
        });
    }
    if (!d) {
        tbody.innerHTML =
            '<tr><td colspan="7" class="text-dim">Could not load saved reports (network or session). Sign in again if needed.</td></tr>';
        return;
    }
    if (!d.ok) {
        const hint = reportingUserErrorMessage(d, 'Saved reports could not be loaded.');
        tbody.innerHTML = '<tr><td colspan="7" class="text-dim">' + esc(hint) + '</td></tr>';
        return;
    }
    if (d.artifacts_soft_error) {
        tbody.innerHTML =
            '<tr><td colspan="7" class="text-dim">' +
            esc(String(d.artifacts_soft_error)) +
            '</td></tr>';
        return;
    }
    const rows = d.artifacts || [];
    if (!rows.length) {
        tbody.innerHTML =
            '<tr><td colspan="7" class="text-dim">No saved reports yet. Scheduled <strong>report</strong> runs create rows here (scan editor or admin).</td></tr>';
        return;
    }
    tbody.innerHTML = rows
        .map((r) => {
            const rid = esc(String(r.id));
            return (
                '<tr><td class="mono-sm">' +
                rid +
                '</td><td>' +
                esc(String(r.created_at || '')) +
                '</td><td>' +
                esc(String(r.schedule_id != null ? r.schedule_id : '')) +
                '</td><td>' +
                esc(String(r.compare_job_id != null ? r.compare_job_id : '')) +
                '</td><td>' +
                esc(String(r.baseline_job_id != null ? r.baseline_job_id : '')) +
                '</td><td>' +
                esc(String(r.title || '')) +
                '</td><td>' +
                (stRoleCanManageScans()
                    ? '<button type="button" class="tbtn btn-xs" onclick="openReportArtifactSummary(' +
                      parseInt(String(r.id), 10) +
                      ')">Details</button>'
                    : '<span class="text-dim" title="Details require scan editor or admin">—</span>') +
                '</td></tr>'
            );
        })
        .join('');
}

var reportArtifactDetailId = 0;
var reportArtifactSummaryLoading = false;

function reportingRenderArtifactSummaryBody(s) {
    if (!s || typeof s !== 'object') {
        return '<p class="text-dim">No data.</p>';
    }
    let h = '<div class="sth mb6">Metadata</div><table class="tbl mb10"><tbody>';
    const metaRows = [
        ['artifact_id', s.artifact_id],
        ['created_at', s.created_at],
        ['schedule_id', s.schedule_id],
        ['schedule_name', s.schedule_name],
        ['title', s.title],
        ['kind', s.kind],
        ['job_id', s.job_id],
        ['compare_job_id', s.compare_job_id],
        ['baseline_job_id', s.baseline_job_id],
        ['baseline_config_job_id', s.baseline_config_job_id],
        ['baseline_unavailable', s.baseline_unavailable],
        ['generated_at', s.generated_at],
        ['schema_version', s.schema_version],
    ];
    metaRows.forEach(([k, v]) => {
        let disp = v === null || v === undefined || v === '' ? '—' : String(v);
        if ((k === 'title' || k === 'schedule_name') && disp.length > 400) {
            disp = disp.slice(0, 400) + '…';
        }
        h += '<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(disp) + '</td></tr>';
    });
    h += '</tbody></table>';
    const _csArt = s.compliance_summary;
    if (_csArt && typeof _csArt === 'object' && Object.keys(_csArt).length) {
        h += reportingRenderComplianceArtifactCard(_csArt);
    }
    if (s.error) {
        h += '<div class="hint-micro mb8 hstate-warn">' + esc(String(s.error)) + '</div>';
    }
    if (s.payload_warning) {
        h += '<div class="hint-micro mb8 hstate-warn">' + esc(String(s.payload_warning).slice(0, 500)) + '</div>';
    }
    const sum = s.summary && typeof s.summary === 'object' ? s.summary : {};
    h += '<div class="sth mb6">Summary</div><table class="tbl mb10"><tbody>';
    h +=
        '<tr><td class="mono-sm">job_id</td><td>' +
        esc(String(sum.job_id != null ? sum.job_id : s.job_id != null ? s.job_id : '—')) +
        '</td></tr>';
    h +=
        '<tr><td class="mono-sm">asset_snapshots</td><td>' +
        esc(String(sum.asset_snapshots != null ? sum.asset_snapshots : '—')) +
        '</td></tr>';
    h +=
        '<tr><td class="mono-sm">open_findings_total</td><td>' +
        esc(String(sum.open_findings_total != null ? sum.open_findings_total : '—')) +
        '</td></tr>';
    const bySev = sum.open_findings_by_severity;
    if (bySev && typeof bySev === 'object') {
        Object.keys(bySev)
            .sort()
            .forEach((sev) => {
                h +=
                    '<tr><td class="mono-sm">open_' +
                    esc(sev) +
                    '</td><td>' +
                    esc(String(bySev[sev])) +
                    '</td></tr>';
            });
    }
    h += '</tbody></table>';
    if (s.delta && typeof s.delta === 'object' && Object.keys(s.delta).length) {
        h += '<div class="sth mb6">Delta</div><table class="tbl mb10"><tbody>';
        Object.keys(s.delta)
            .sort()
            .forEach((k) => {
                const dv = s.delta[k];
                let cell = dv !== null && typeof dv === 'object' ? JSON.stringify(dv) : String(dv);
                if (cell.length > 400) {
                    cell = cell.slice(0, 400) + '…';
                }
                h += '<tr><td class="mono-sm">' + esc(k) + '</td><td>' + esc(cell) + '</td></tr>';
            });
        h += '</tbody></table>';
    }
    const ds = s.diff_summary;
    if (!ds || typeof ds !== 'object') {
        h += '<div class="sth mb6">Diff summary</div><div class="text-dim">None stored for this artifact.</div>';
    } else if (ds.error) {
        h += '<div class="sth mb6">Diff summary</div><div class="text-dim">' + esc(String(ds.error)) + '</div>';
    } else {
        h += '<div class="sth mb6">Diff summary</div>';
        h += reportingRenderCompareExecutiveSummary(ds);
    }
    return h;
}

function closeReportArtifactModal() {
    const bg = document.getElementById('report-artifact-bg');
    if (bg) bg.style.display = 'none';
    reportArtifactDetailId = 0;
    const rawCb = document.getElementById('report-artifact-raw-toggle');
    const rawPre = document.getElementById('report-artifact-raw-pre');
    if (rawCb) rawCb.checked = false;
    if (rawPre) {
        rawPre.style.display = 'none';
        rawPre.textContent = '';
    }
}

async function openReportArtifactSummary(id) {
    if (!stRoleCanManageScans()) {
        toast('Scan editor or admin role required to open report details.', 'err');
        return;
    }
    const aid = parseInt(String(id), 10);
    if (!aid) {
        toast('Invalid artifact id', 'err');
        return;
    }
    if (reportArtifactSummaryLoading) {
        return;
    }
    reportArtifactSummaryLoading = true;
    reportArtifactDetailId = aid;
    const bg = document.getElementById('report-artifact-bg');
    const title = document.getElementById('report-artifact-title');
    const body = document.getElementById('report-artifact-body');
    const rawWrap = document.getElementById('report-artifact-raw-wrap');
    const rawCb = document.getElementById('report-artifact-raw-toggle');
    const rawPre = document.getElementById('report-artifact-raw-pre');
    if (!bg || !body) {
        reportArtifactSummaryLoading = false;
        return;
    }
    if (rawCb) rawCb.checked = false;
    if (rawPre) {
        rawPre.style.display = 'none';
        rawPre.textContent = '';
    }
    if (rawWrap) {
        rawWrap.style.display = stRoleIsAdmin() ? 'block' : 'none';
        rawWrap.setAttribute('aria-hidden', stRoleIsAdmin() ? 'false' : 'true');
    }
    body.innerHTML = '<span class="text-dim">Loading…</span>';
    if (title) title.textContent = 'Report artifact #' + aid;
    bg.style.display = 'flex';
    try {
        const d = await api('/api/reporting.php?action=artifact_summary&id=' + aid, {quiet: true});
        if (!d || !d.ok) {
            const msg = reportingUserErrorMessage(d, 'Could not load artifact.');
            body.innerHTML = '<div class="text-dim">' + esc(msg) + '</div>';
            reportingToastApiError('Artifact', d, 'Could not load artifact summary.');
            return;
        }
        body.innerHTML = reportingRenderArtifactSummaryBody(d.artifact_summary || {});
    } finally {
        reportArtifactSummaryLoading = false;
    }
}

async function toggleReportArtifactRawJson() {
    const cb = document.getElementById('report-artifact-raw-toggle');
    const pre = document.getElementById('report-artifact-raw-pre');
    if (!cb || !pre) return;
    if (!stRoleIsAdmin()) {
        cb.checked = false;
        toast('Raw JSON preview is admin-only.', 'err');
        return;
    }
    if (!cb.checked) {
        pre.style.display = 'none';
        pre.textContent = '';
        return;
    }
    const id = reportArtifactDetailId;
    if (!id) return;
    pre.style.display = 'block';
    pre.textContent = 'Loading…';
    const d = await api('/api/reporting.php?action=artifact_payload_preview&id=' + id, {quiet: true});
    if (!d || !d.ok) {
        pre.textContent = reportingUserErrorMessage(d, 'Could not load preview.');
        reportingToastApiError('Raw JSON preview', d, 'Preview failed');
        return;
    }
    const txt = typeof d.preview === 'string' ? d.preview : '';
    pre.textContent = txt.length > REPORTING_DEBUG_JSON_MAX ? txt.slice(0, REPORTING_DEBUG_JSON_MAX) + '\n… (truncated)' : txt;
}

async function loadSchedules() {
    const d = await api('/api/schedules.php');
    if (!d) return;

    const statColor = {done:'var(--green)',failed:'var(--red)',aborted:'var(--amber)'};
    const tbody = document.getElementById('sched-tbody');
    if (!d.schedules || !d.schedules.length) {
        tbody.innerHTML = '<tr><td colspan="12" class="loading tbl-empty st-sched-empty"><div class="st-sched-empty-inner"><strong>Optional automation.</strong> No recurring scans are defined yet — one-off scans from <strong>Scan control</strong> still work. Use <strong>+ New schedule</strong> to add a cadence with a target, profile, and cron. After you save, the row appears here with <strong>next run</strong> and <strong>ON</strong> / <strong>Pause</strong> state.</div></td></tr>';
        return;
    }

    tbody.innerHTML = d.schedules.map(s => {
        const pol = (s.missed_run_policy || 'run_once');
        const missedLbl = pol === 'skip_no_run'
            ? 'Skip'
            : pol === 'run_all'
                ? `All ≤${parseInt(s.missed_run_max, 10) || 5}`
                : 'Once';
        const isPaused = !!(parseInt(s.paused, 10) || 0);
        const isOn = !!(parseInt(s.enabled, 10) || 0);
        const pausedTag = isPaused
            ? '<span class="paused-chip st-sched-paused-chip">Paused</span>'
            : '';

        const rowStateCls = !isOn
            ? 'st-sched-row--off'
            : (isPaused ? 'st-sched-row--paused' : 'st-sched-row--active');

        // next_run is stored as UTC — display as local browser time
        let nextRun = '<span class="pending">pending</span>';
        if (s.next_run) {
            const nr = new Date(s.next_run + 'Z');  // append Z to treat as UTC
            const secs = s.secs_until_next;
            const timeStr = nr.toLocaleString([], {month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});
            if (secs <= 0) {
                nextRun = '<span class="due-now">due now</span>';
            } else if (secs < 3600) {
                nextRun = `<span title="${timeStr}">${Math.floor(secs/60)}m</span>`;
            } else if (secs < 86400) {
                nextRun = `<span title="${timeStr}">${Math.floor(secs/3600)}h</span>`;
            } else {
                nextRun = `<span title="${timeStr}">${Math.floor(secs/86400)}d · ${timeStr}</span>`;
            }
        }

        const lastRun   = s.last_run   ? relTime(s.last_run)   : '—';
        const lastStat  = s.last_job_status
            ? `<span class="status-text" style="color:${statColor[s.last_job_status]||'var(--tx2)'}">${s.last_job_status}</span>`
              + (s.last_hosts_found ? ` <span class="status-text">${s.last_hosts_found} hosts</span>` : '')
            : '—';

        const pauseResume = isOn
            ? (isPaused
                ? `<button type="button" class="tbtn btn-xxs" onclick="resumeSchedule(${s.id})" title="Resume schedule">Resume</button>`
                : `<button type="button" class="tbtn btn-xxs" onclick="pauseSchedule(${s.id})" title="Pause without deleting">Pause</button>`)
            : '';

        const scn = s.scope_name && String(s.scope_name).trim()
            ? esc(String(s.scope_name).slice(0, 80))
            : (parseInt(String(s.scope_id || 0), 10) > 0 ? '<span class="text-dim">#' + esc(String(s.scope_id)) + '</span>' : '—');
        return `<tr class="${rowStateCls}">
          <td class="text-primary">${esc(s.name)}${pausedTag}</td>
          <td class="mono">${esc(s.target_cidr)}</td>
          <td class="status-text">${scn}</td>
          <td class="status-text">${esc((s.profile||'').replace(/_/g,' '))}</td>
          <td class="mono">${esc(s.cron_expr)}</td>
          <td class="mono-sm">${s.collector_id ? esc(s.collector_name || ('#' + String(s.collector_id))) : 'master'}</td>
          <td class="status-text" title="Catch-up when overdue">${missedLbl}</td>
          <td class="status-text">${nextRun}</td>
          <td class="status-text">${lastRun}</td>
          <td>${lastStat}</td>
          <td>
            <button type="button" class="tbtn btn-xs st-sched-toggle ${isOn ? 'toggle-on' : 'toggle-off'}"
              onclick="toggleSchedule(${s.id})"
              title="${isOn ? 'Click to disable' : 'Click to enable'}">
              ${isOn ? '● ON' : '○ OFF'}
            </button>
          </td>
          <td class="row-actions st-sched-row-actions">
            <button type="button" class="tbtn btn-xxs" onclick="openSchedHist(${s.id})" title="Run history">Hist</button>
            ${pauseResume}
            <button type="button" class="tbtn btn-xs" onclick="runSchedNow(${s.id})" title="Run now">&#9654;</button>
            <button type="button" class="tbtn btn-xs" onclick="editSchedule(${s.id})">&#9998;</button>
            <button type="button" class="tbtn btn-xs st-sched-action-delete" style="color:var(--red)" onclick="deleteSchedule(${s.id})">&#10005;</button>
          </td>
        </tr>`;
    }).join('');
}

function parseSchedEnrichmentIds(s) {
    if (!s) return null;
    const raw = s.enrichment_source_ids;
    if (raw === undefined || raw === null || raw === '') return null;
    if (Array.isArray(raw)) return raw;
    try {
        const j = JSON.parse(String(raw));
        return Array.isArray(j) ? j : null;
    } catch (e) {
        return null;
    }
}

async function refreshSchedEnrichmentPicker(selectedIds) {
    const wrap = document.getElementById('sched-enrichment-wrap');
    if (!wrap) return;
    wrap.dataset.ready = '0';
    wrap.innerHTML = '<div class="hint-micro">Loading…</div>';
    let data;
    try {
        data = await api('/api/enrichment.php', {quiet:true});
    } catch (e) {
        wrap.innerHTML = '<div class="hint-micro">Could not load enrichment sources</div>';
        return;
    }
    const srcs = (data && data.sources) ? data.sources : [];
    if (!srcs.length) {
        wrap.innerHTML = '<div class="hint-micro">No sources configured — add them under Enrichment.</div>';
        wrap.dataset.ready = '1';
        return;
    }
    const parts = [];
    for (const src of srcs) {
        const en = parseInt(src.enabled, 10) === 1;
        const id = parseInt(src.id, 10);
        const label = esc(src.label || src.source_type || '');
        const typ = esc(src.source_type || '');
        let checked = true;
        if (en) {
            if (selectedIds === null) checked = true;
            else if (Array.isArray(selectedIds) && selectedIds.length === 0) checked = false;
            else if (Array.isArray(selectedIds)) checked = selectedIds.includes(id);
            parts.push(`<div class="tr2"><div><div class="tl">${label}</div><div class="tsubl">${typ}</div></div><label class="chk tr2-check"><input type="checkbox" class="chk-input" data-enr-id="${id}" ${checked ? 'checked' : ''} aria-label="Include enrichment source for scheduled runs"></label></div>`);
        } else {
            parts.push(`<div class="tr2" style="opacity:0.55"><div><div class="tl">${label}</div><div class="tsubl">${typ} (disabled in Enrichment)</div></div><label class="chk tr2-check"><input type="checkbox" class="chk-input" disabled aria-label="Enrichment source disabled in settings"></label></div>`);
        }
    }
    wrap.innerHTML = parts.join('');
    wrap.dataset.ready = '1';
}

function schedEnrichmentPayloadField() {
    const wrap = document.getElementById('sched-enrichment-wrap');
    if (!wrap || wrap.dataset.ready !== '1') return undefined;
    const enabledBoxes = wrap.querySelectorAll('input[data-enr-id]');
    if (!enabledBoxes.length) return undefined;
    const checked = [];
    enabledBoxes.forEach(cb => { if (cb.checked) checked.push(parseInt(cb.dataset.enrId, 10)); });
    if (checked.length === enabledBoxes.length) return undefined;
    return checked;
}

async function openSchedModal(s) {
    if (!collectorsCache.length) {
        await loadCollectorsOverview();
    } else {
        refreshCollectorSelectors();
    }
    document.getElementById('sched-id').value    = s ? s.id : '';
    document.getElementById('sched-title').textContent = s ? 'Edit schedule' : 'New schedule';
    document.getElementById('sched-name').value  = s ? s.name : '';
    document.getElementById('sched-cidr').value  = s ? s.target_cidr : '';
    document.getElementById('sched-cron').value  = s ? s.cron_expr : '0 3 * * 0';
    document.getElementById('sched-collector').value = s ? String(parseInt(s.collector_id, 10) || 0) : '0';
    document.getElementById('sched-profile').value = s ? (s.profile||'standard_inventory') : 'standard_inventory';
    document.getElementById('sched-mode').value  = s ? (s.scan_mode||'auto') : 'auto';
    document.getElementById('sched-excl').value  = s ? (s.exclusions||'') : '';
    document.getElementById('sched-notes').value = s ? (s.notes||'') : '';
    const polEl = document.getElementById('sched-missed-pol');
    if (polEl) polEl.value = s ? (s.missed_run_policy || 'run_once') : 'run_once';
    const mxEl = document.getElementById('sched-missed-max');
    if (mxEl) mxEl.value = s ? (parseInt(s.missed_run_max, 10) || 5) : 5;
    const enCb = document.getElementById('sched-en');
    if (enCb) enCb.checked = s ? !!(parseInt(s.enabled, 10) || 0) : true;
    const pz = document.getElementById('sched-paused');
    if (pz) pz.value = s ? (parseInt(s.paused, 10) || 0) : 0;
    const tzSel = document.getElementById('sched-tz');
    if (tzSel) {
        const browserTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        tzSel.value = s ? (s.timezone||'UTC') : (browserTz||'UTC');
        if (tzSel.value !== (s ? (s.timezone||'UTC') : (browserTz||'UTC'))) {
            const opt = document.createElement('option');
            opt.value = browserTz;
            opt.textContent = browserTz;
            tzSel.appendChild(opt);
            tzSel.value = browserTz;
        }
    }

    document.getElementById('sched-priority').value = String(s ? (parseInt(s.priority, 10) || 20) : 20);

    if (!s) {
        applySchedProfileDefaults(document.getElementById('sched-profile').value);
    } else {
        const rp = parseInt(s.rate_pps, 10) || 5;
        document.getElementById('sched-pps').value = String(Math.max(1, Math.min(50, rp)));
        document.getElementById('sched-pps-val').textContent = document.getElementById('sched-pps').value + ' pps';
        const idel = parseInt(s.inter_delay, 10) || 200;
        document.getElementById('sched-delay').value = String(Math.max(0, Math.min(2000, idel)));
        document.getElementById('sched-delay-val').textContent = document.getElementById('sched-delay').value + ' ms';

        const defPh = ['passive','icmp','banner','fingerprint','cve'];
        let pArr = defPh;
        if (s.phases) {
            try {
                pArr = typeof s.phases === 'string' ? JSON.parse(s.phases) : (Array.isArray(s.phases) ? s.phases : defPh);
            } catch (e) {
                pArr = defPh;
            }
        }
        if (!Array.isArray(pArr)) pArr = defPh;
        ['passive','icmp','banner','fingerprint','snmp','ot','cve'].forEach(p => {
            const el = document.getElementById('sched-ph-' + p);
            if (el) el.checked = pArr.includes(p);
        });
        const prof = document.getElementById('sched-profile').value;
        updateSchedProfileHelp(prof);
        updateSchedProfileWarn(prof);
        syncSchedScanStepRowOpacityFromProfile();
    }

    await refreshSchedEnrichmentPicker(parseSchedEnrichmentIds(s));
    updateCronDesc();
    await ensureStScopeSelects(false);
    const ss = document.getElementById('sched-scope-id');
    if (ss) {
        const sid = s && s.scope_id != null ? parseInt(String(s.scope_id), 10) || 0 : 0;
        ss.value = sid > 0 ? String(sid) : '0';
    }
    const schedBg = document.getElementById('sched-bg');
    schedBg.style.display = 'flex';
    const schedCard = schedBg.querySelector('.modal-card');
    if (schedCard) {
        const top = () => { schedCard.scrollTop = 0; };
        top();
        requestAnimationFrame(top);
    }
}

function closeSchedModal() {
    document.getElementById('sched-bg').style.display = 'none';
}

function setCron(expr) {
    document.getElementById('sched-cron').value = expr;
    updateCronDesc();
}

function _cronPlural(n, one, many) {
    return `${n} ${n === 1 ? one : many}`;
}

function _cronOrd(n) {
    const v = Math.abs(Number(n)) % 100;
    if (v >= 11 && v <= 13) return `${n}th`;
    const d = v % 10;
    if (d === 1) return `${n}st`;
    if (d === 2) return `${n}nd`;
    if (d === 3) return `${n}rd`;
    return `${n}th`;
}

function _cronJoin(list) {
    if (!list.length) return '';
    if (list.length === 1) return list[0];
    if (list.length === 2) return `${list[0]} and ${list[1]}`;
    return `${list.slice(0, -1).join(', ')}, and ${list[list.length - 1]}`;
}

function _cronDescribeMinute(field) {
    if (field === '*') return 'every minute';
    let m = field.match(/^\*\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[1]), 'minute', 'minutes')}`;
    m = field.match(/^(\d{1,2})$/);
    if (m) return `minute ${m[1].padStart(2, '0')}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})$/);
    if (m) return `every minute from ${m[1].padStart(2, '0')} through ${m[2].padStart(2, '0')}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[3]), 'minute', 'minutes')} from ${m[1].padStart(2, '0')} through ${m[2].padStart(2, '0')}`;
    if (field.includes(',')) {
        const vals = field.split(',').map(v => v.trim()).filter(Boolean).map(v => v.padStart(2, '0'));
        return `minute ${_cronJoin(vals)}`;
    }
    return '';
}

function _cronDescribeHour(field) {
    if (field === '*') return 'every hour';
    let m = field.match(/^\*\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[1]), 'hour', 'hours')}`;
    m = field.match(/^(\d{1,2})$/);
    if (m) return `hour ${m[1].padStart(2, '0')}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})$/);
    if (m) return `every hour from ${m[1].padStart(2, '0')} through ${m[2].padStart(2, '0')}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[3]), 'hour', 'hours')} from ${m[1].padStart(2, '0')} through ${m[2].padStart(2, '0')}`;
    if (field.includes(',')) {
        const vals = field.split(',').map(v => v.trim()).filter(Boolean).map(v => v.padStart(2, '0'));
        return `hour ${_cronJoin(vals)}`;
    }
    return '';
}

function _cronDescribeDom(field) {
    if (field === '*') return 'every day-of-month';
    let m = field.match(/^\*\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[1]), 'day', 'days')} of the month`;
    m = field.match(/^(\d{1,2})$/);
    if (m) return `day-of-month ${_cronOrd(Number(m[1]))}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})$/);
    if (m) return `day-of-month ${_cronOrd(Number(m[1]))} through ${_cronOrd(Number(m[2]))}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})\/(\d{1,2})$/);
    if (m) return `every ${_cronPlural(Number(m[3]), 'day', 'days')} from day-of-month ${_cronOrd(Number(m[1]))} through ${_cronOrd(Number(m[2]))}`;
    if (field.includes(',')) {
        const vals = field.split(',').map(v => v.trim()).filter(Boolean).map(v => _cronOrd(Number(v)));
        return `day-of-month ${_cronJoin(vals)}`;
    }
    return '';
}

function _cronDescribeMonth(field) {
    const names = [null, 'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    if (field === '*') return 'every month';
    let m = field.match(/^(\d{1,2})$/);
    if (m) return `in ${names[Number(m[1])] || m[1]}`;
    m = field.match(/^(\d{1,2})-(\d{1,2})$/);
    if (m) return `from ${names[Number(m[1])] || m[1]} through ${names[Number(m[2])] || m[2]}`;
    if (field.includes(',')) {
        const vals = field.split(',').map(v => v.trim()).filter(Boolean).map(v => names[Number(v)] || v);
        return `in ${_cronJoin(vals)}`;
    }
    return '';
}

function _cronDescribeDow(field) {
    const names = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    if (field === '*') return 'every day-of-week';
    let m = field.match(/^(\d)$/);
    if (m) return `on ${names[Number(m[1])]}`;
    m = field.match(/^(\d)-(\d)$/);
    if (m) return `on ${names[Number(m[1])]} through ${names[Number(m[2])]}`;
    m = field.match(/^\*\/(\d)$/);
    if (m) return `every ${_cronPlural(Number(m[1]), 'day', 'days')} of week`;
    if (field.includes(',')) {
        const vals = field.split(',').map(v => v.trim()).filter(Boolean).map(v => names[Number(v)] || v);
        return `on ${_cronJoin(vals)}`;
    }
    return '';
}

function _cronDescribe(expr) {
    const parts = expr.trim().split(/\s+/);
    if (parts.length !== 5) return '';
    const [minF, hrF, domF, monF, dowF] = parts;
    if (/^\d{1,2}$/.test(minF) && /^\d{1,2}$/.test(hrF) && domF === '*' && monF === '*' && dowF === '*') {
        return `At ${hrF.padStart(2, '0')}:${minF.padStart(2, '0')}.`;
    }
    const mDesc = _cronDescribeMinute(minF);
    const hDesc = _cronDescribeHour(hrF);
    const domDesc = _cronDescribeDom(domF);
    const monDesc = _cronDescribeMonth(monF);
    const dowDesc = _cronDescribeDow(dowF);
    if (!mDesc || !hDesc || !domDesc || !monDesc || !dowDesc) return '';
    return `At ${mDesc} past ${hDesc} on ${domDesc}, ${monDesc}, and ${dowDesc}.`;
}

function _cronHumanText(expr) {
    const descs = {
        '@daily':'Every day at midnight','@weekly':'Every Sunday at midnight',
        '@monthly':'First of every month at midnight','@hourly':'Every hour',
        '@yearly':'Every year on Jan 1st','@annually':'Every year on Jan 1st',
        '@midnight':'Every day at midnight',
    };
    if (descs[expr]) return descs[expr];
    const parts = expr.split(/\s+/);
    if (parts.length === 5) return _cronDescribe(expr) || ('Custom: ' + expr);
    return 'Format: minute hour day-of-month month day-of-week';
}

function updateCronDesc() {
    const expr = document.getElementById('sched-cron').value.trim();
    const el = document.getElementById('sched-cron-desc');
    const txt = _cronHumanText(expr);
    const parts = expr.split(/\s+/);
    el.textContent = txt;
    el.style.color = (parts.length === 5 || expr.startsWith('@')) ? 'var(--tx2)' : 'var(--tx3)';
}

document.getElementById('sched-cron')?.addEventListener('input', updateCronDesc);

function updateDbBackupCronDesc() {
    const expr = String(document.getElementById('st-db-backup-cron')?.value || '').trim();
    const el = document.getElementById('st-db-backup-cron-desc');
    if (!el) return;
    const txt = _cronHumanText(expr);
    const parts = expr.split(/\s+/);
    el.textContent = txt;
    el.style.color = (parts.length === 5 || expr.startsWith('@')) ? 'var(--tx2)' : 'var(--tx3)';
}

document.getElementById('st-db-backup-cron')?.addEventListener('input', updateDbBackupCronDesc);

async function editSchedule(id) {
    const d = await api('/api/schedules.php');
    if (!d) return;
    const s = d.schedules.find(s => s.id === id);
    if (s) await openSchedModal(s);
}

async function saveSchedule() {
    const id      = document.getElementById('sched-id').value;
    let mx = parseInt(document.getElementById('sched-missed-max')?.value || '5', 10);
    if (mx < 1) mx = 1;
    if (mx > 100) mx = 100;
    const schedPhKeys = ['passive','icmp','banner','fingerprint','snmp','ot','cve'];
    const phases = [];
    schedPhKeys.forEach(p => {
        if (document.getElementById('sched-ph-' + p)?.checked) phases.push(p);
    });
    if (!phases.length) { toast('Select at least one scan step', 'err'); return; }

    let pr = parseInt(document.getElementById('sched-priority')?.value || '20', 10);
    if (pr < 1) pr = 1;
    if (pr > 100) pr = 100;

    const payload = {
        id:          id ? parseInt(id) : 0,
        name:        document.getElementById('sched-name').value.trim(),
        target_cidr: document.getElementById('sched-cidr').value.trim(),
        cron_expr:   document.getElementById('sched-cron').value.trim(),
        profile:     document.getElementById('sched-profile').value,
        scan_mode:   document.getElementById('sched-mode').value,
        exclusions:  document.getElementById('sched-excl').value.trim(),
        notes:       document.getElementById('sched-notes').value.trim(),
        timezone:    document.getElementById('sched-tz')?.value || 'UTC',
        enabled:     document.getElementById('sched-en')?.checked ? 1 : 0,
        paused:      parseInt(document.getElementById('sched-paused')?.value || '0', 10) || 0,
        missed_run_policy: document.getElementById('sched-missed-pol')?.value || 'run_once',
        missed_run_max: mx,
        phases:      phases,
        rate_pps:    parseInt(document.getElementById('sched-pps')?.value || '5', 10) || 5,
        inter_delay: parseInt(document.getElementById('sched-delay')?.value || '200', 10) || 0,
        priority:    pr,
        collector_id: parseInt(document.getElementById('sched-collector')?.value || '0', 10) || 0,
        scope_id:    parseInt(String(document.getElementById('sched-scope-id')?.value || '0'), 10) || 0,
    };
    const enrSel = schedEnrichmentPayloadField();
    if (enrSel !== undefined) payload.enrichment_source_ids = enrSel;

    const profileVal = payload.profile;
    if (['deep_scan', 'full_tcp', 'ot_careful'].includes(profileVal)) {
        const ok = await showConfirmModal(
            `Profile "${profileVal}" can generate significant network traffic and is meant for controlled use.\n\n` +
            `You are saving a recurring schedule — each run will repeat with these settings until you change or disable it.\n\n` +
            `Save this schedule?`,
            {title: 'Confirm high-impact scheduled scan', okText: 'Save schedule'}
        );
        if (!ok) return;
        payload.confirmed = true;
    }

    if (!payload.name)        { toast('Name is required', 'err'); return; }
    if (!payload.target_cidr) { toast('Target CIDR is required', 'err'); return; }
    if (!payload.cron_expr)   { toast('Cron expression is required', 'err'); return; }

    const r = await apiPost('/api/schedules.php', payload);
    if (r && r.ok) {
        toast(id ? 'Schedule updated' : 'Schedule created', 'ok');
        closeSchedModal();
        loadSchedules();
    } else {
        toast((r && r.error) || 'Save failed', 'err');
    }
}

async function toggleSchedule(id) {
    const r = await apiPost('/api/schedules.php?toggle=1', {id});
    if (r && r.ok) loadSchedules();
    else toast('Toggle failed', 'err');
}

async function runSchedNow(id) {
    const r = await apiPost('/api/schedules.php?run_now=1', {id});
    if (r && r.ok) {
        toast('Job #' + r.job_id + ' queued', 'ok');
        loadSchedules();
        loadScanStatus();
    } else {
        toast((r && r.error) || 'Failed to queue job', 'err');
    }
}

async function deleteSchedule(id) {
    if (!(await showConfirmModal(
        'Delete this schedule? This cannot be undone.',
        {title: 'Delete schedule', okText: 'Delete'}
    ))) return;
    const r = await fetch(`/api/schedules.php?id=${id}`, {
        method: 'DELETE',
        credentials: 'same-origin',
        headers: csrfToken ? {'X-CSRF-Token': csrfToken} : {}
    });
    if (r.ok) { toast('Schedule deleted', 'ok'); loadSchedules(); }
    else toast('Delete failed', 'err');
}

function closeSchedHistModal() {
    const el = document.getElementById('sched-hist-bg');
    if (el) el.style.display = 'none';
}

function openJobFromHist(jobId) {
    if (!stRoleCanManageScans()) {
        toast('You do not have permission to access Scan control.', 'err');
        return;
    }
    closeSchedHistModal();
    goTab('scan');
    hiNav('nscan');
    activeJobId = jobId;
    showScanRunning(jobId);
    startPoll(jobId);
    pollJob(jobId);
    loadScanHistory();
}

async function openSchedHist(id) {
    const bg = document.getElementById('sched-hist-bg');
    const tb = document.getElementById('sched-hist-tbody');
    const title = document.getElementById('sched-hist-title');
    if (!bg || !tb) return;
    let name = 'Schedule #' + id;
    const list = await api('/api/schedules.php');
    if (list && list.schedules) {
        const row = list.schedules.find(x => x.id === id);
        if (row) name = row.name;
    }
    title.textContent = 'Run history — ' + name;
    tb.innerHTML = '<tr><td colspan="6" class="loading">Loading…</td></tr>';
    bg.style.display = 'flex';
    const d = await api('/api/schedules.php?history=1&id=' + encodeURIComponent(id) + '&limit=25');
    if (!d || !d.runs) {
        tb.innerHTML = '<tr><td colspan="6" class="loading">Could not load history</td></tr>';
        return;
    }
    if (!d.runs.length) {
        tb.innerHTML = '<tr><td colspan="6" class="loading">No jobs linked to this schedule yet</td></tr>';
        return;
    }
    const toLoc = (ts) => {
        if (!ts) return '—';
        const iso = String(ts).replace(' ', 'T');
        const dt = new Date(/Z|[+-]\d{2}:?\d{2}$/.test(iso) ? iso : iso + 'Z');
        return isNaN(dt.getTime()) ? esc(ts) : dt.toLocaleString([], {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit'});
    };
    tb.innerHTML = d.runs.map(r => {
        const hosts = (r.hosts_found != null && r.hosts_found !== '')
            ? `${parseInt(r.hosts_scanned, 10) || 0}/${parseInt(r.hosts_found, 10) || 0}`
            : '—';
        return `<tr>
          <td class="mono font11"><a href="#" onclick="openJobFromHist(${r.id});return false">${r.id}</a></td>
          <td class="status-text">${esc(r.status || '')}</td>
          <td class="text-secondary font11">${esc(r.label || '')}</td>
          <td class="status-text">${hosts}</td>
          <td class="status-text">${toLoc(r.created_at)}</td>
          <td class="status-text">${toLoc(r.finished_at)}</td>
        </tr>`;
    }).join('');
}

async function pauseSchedule(id) {
    const r = await apiPost('/api/schedules.php?pause=1', {id});
    if (r && r.ok) { toast('Schedule paused', 'ok'); loadSchedules(); }
    else toast((r && r.error) || 'Pause failed', 'err');
}

async function resumeSchedule(id) {
    const r = await apiPost('/api/schedules.php?resume=1', {id});
    if (r && r.ok) { toast('Schedule resumed', 'ok'); loadSchedules(); }
    else toast((r && r.error) || 'Resume failed', 'err');
}

// ==========================================================================
// Export findings (CVEs) with current filters
// ==========================================================================
function exportFindings(format) {
    const cve   = document.getElementById('vf-cve')?.value   || '';
    const ip    = document.getElementById('vf-ip')?.value    || '';
    const sev   = document.getElementById('vf-sev')?.value   || '';
    const cat   = document.getElementById('vf-cat')?.value   || '';
    const res   = document.getElementById('vf-resolved')?.value || '0';
    const miny  = document.getElementById('vf-minyear')?.value || '';
    const conf  = document.getElementById('vf-confidence')?.value || '';

    const params = new URLSearchParams({
        format,
        cve_id:    cve,
        ip:        ip,
        severity:  sev,
        category:  cat,
        resolved:  res,
        min_year:  miny,
        confidence: conf,
        per_page:  9999,
    });

    const a = document.createElement('a');
    a.href     = `/api/findings_export.php?${params}`;
    a.download = `surveytrace_cves_${new Date().toISOString().slice(0,10)}.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    toast(`Exporting CVEs as ${format.toUpperCase()}…`, 'ok');
}

// ==========================================================================
// Reclassify modal
// ==========================================================================
function openReclassify(id, ip, hostname, category, vendor, notes, owner, businessUnit, criticality, environment, hl, cl, vl) {
    if (!stRoleCanManageScans()) {
        toast('Requires scan editor or admin role.', 'err');
        return;
    }
    document.getElementById('modal-asset-id').value  = id;
    document.getElementById('modal-ip').textContent  = ip;
    document.getElementById('modal-hostname').value  = hostname;
    document.getElementById('modal-vendor').value    = vendor;
    document.getElementById('modal-notes').value     = notes;
    const hle = document.getElementById('modal-hl');
    const cle = document.getElementById('modal-cl');
    const vle = document.getElementById('modal-vl');
    if (hle) hle.value = hl ? 1 : 0;
    if (cle) cle.value = cl ? 1 : 0;
    if (vle) vle.value = vl ? 1 : 0;
    const mo = document.getElementById('modal-owner');
    const mb = document.getElementById('modal-business-unit');
    const mc = document.getElementById('modal-criticality');
    const me = document.getElementById('modal-environment');
    if (mo) mo.value = owner || '';
    if (mb) mb.value = businessUnit || '';
    if (mc) {
        const c0 = (criticality || 'medium').toLowerCase();
        mc.value = ['low', 'medium', 'high', 'critical'].includes(c0) ? c0 : 'medium';
    }
    if (me) me.value = environment || '';
    const sel = document.getElementById('modal-cat');
    for (let i = 0; i < sel.options.length; i++) {
        sel.options[i].selected = (sel.options[i].value === category);
    }
    window._reclassifyOrig = {
        category: category || 'unk',
        hostname: hostname || '',
        vendor: vendor || '',
    };
    const bg = document.getElementById('modal-bg');
    bg.style.display = 'flex';
    modalRefreshLockUi();
    document.getElementById('modal-hostname').focus();
    void hydrateAssetModalZabbix(id);
}

function stZabbixUiTruncate(str, maxLen) {
    const s = String(str || '');
    if (s.length <= maxLen) return s;
    return s.slice(0, Math.max(0, maxLen - 16)) + '… (truncated)';
}

async function hydrateAssetModalZabbix(assetId) {
    const wrap = document.getElementById('modal-zabbix-wrap');
    const body = document.getElementById('modal-zabbix-body');
    if (!wrap || !body) return;
    wrap.classList.add('hide');
    body.textContent = '';
    const r = await api('/api/assets.php?id=' + encodeURIComponent(String(assetId)), { quiet: true });
    if (!r || !r.asset) return;
    const fs = r.asset.zabbix_enrichment_status;
    if (!fs || !fs.tables_ready || !fs.configured || !fs.enabled) {
        wrap.classList.add('hide');
        return;
    }
    if (!('zabbix' in r.asset)) return;
    const z = r.asset.zabbix;
    wrap.classList.remove('hide');
    if (!z || !z.linked) {
        body.innerHTML = '<span class="text-dim">No Zabbix host linked (sync the Zabbix connector under Integrations).</span>';
        return;
    }
    const inv = z.inventory || {};
    const tags = stZabbixUiTruncate((z.tags || []).map((t) => esc((t.tag || '') + (t.value !== '' && t.value !== undefined ? '=' + t.value : ''))).filter(Boolean).join(', '), 2400);
    const gr = stZabbixUiTruncate((z.host_groups || []).map((g) => esc(g)).join(', '), 2400);
    const tm = stZabbixUiTruncate((z.templates || []).map((t) => esc(t)).join(', '), 2400);
    const ra = r.asset || {};
    const den = (ra.monitored_by_zabbix === true || ra.monitored_by_zabbix === false)
        ? `<div class="mt4 text-micro text-dim">Asset denorm: monitored_by_zabbix=${ra.monitored_by_zabbix ? 'yes' : 'no'} · zabbix_availability=${esc(String(ra.zabbix_availability || '—'))} · zabbix_problem_count=${esc(String(ra.zabbix_problem_count != null ? ra.zabbix_problem_count : '—'))}</div>`
        : '';
    const man = (z.match && z.match.manual) ? ' <span class="text-dim">(manual)</span>' : '';
    body.innerHTML =
        '<div><strong>Monitored</strong>: ' + (z.monitored ? 'yes' : 'no') +
        ' · <strong>Availability</strong>: ' + esc(z.availability || '—') +
        ' · <strong>Open problems</strong>: ' + esc(String(z.open_problem_count != null ? z.open_problem_count : '—')) + '</div>' +
        den +
        '<div class="mt4"><strong>Match</strong>: ' + esc((z.match && z.match.method) || '') + ' (confidence ' +
        (z.match && z.match.confidence != null ? Number(z.match.confidence).toFixed(2) : '—') + ')' + man + '</div>' +
        (gr ? '<div class="mt4"><strong>Groups</strong>: ' + gr + '</div>' : '') +
        (tm ? '<div class="mt4"><strong>Templates</strong>: ' + tm + '</div>' : '') +
        (tags ? '<div class="mt4"><strong>Tags</strong>: ' + tags + '</div>' : '') +
        '<div class="mt4"><strong>Inventory</strong>: owner ' + esc(inv.owner || '—') +
        ' · location ' + esc(inv.location || '—') +
        ' · environment ' + esc(inv.environment || '—') + '</div>' +
        '<p class="hint-micro mt4 text-dim">Zabbix does not silently overwrite hostname, category, or vendor. Operators can assign <strong>scan scope</strong> from enabled rules under Integrations after preview + confirmation (audited).</p>';
}

function modalRefreshLockUi() {
    const hl = parseInt(document.getElementById('modal-hl')?.value || '0', 10) ? 1 : 0;
    const cl = parseInt(document.getElementById('modal-cl')?.value || '0', 10) ? 1 : 0;
    const vl = parseInt(document.getElementById('modal-vl')?.value || '0', 10) ? 1 : 0;
    const rh = document.getElementById('modal-host-lock-row');
    const rc = document.getElementById('modal-cat-lock-row');
    const rv = document.getElementById('modal-vendor-lock-row');
    if (rh) rh.classList.toggle('hide', !hl);
    if (rc) rc.classList.toggle('hide', !cl);
    if (rv) rv.classList.toggle('hide', !vl);
}

async function unlockAssetField(field) {
    const id = document.getElementById('modal-asset-id')?.value;
    if (!id) return;
    const headers = {'Content-Type': 'application/json'};
    if (csrfToken) headers['X-CSRF-Token'] = csrfToken;
    const r = await fetch(`/api/assets.php?id=${id}`, {
        method: 'PUT',
        headers: headers,
        body: JSON.stringify({ unlock: [field] }),
        credentials: 'same-origin'
    });
    let data = {};
    try { data = await r.json(); } catch (e) {}
    if (!data.ok) {
        toast(data.error || 'Unlock failed', 'err');
        return;
    }
    if (field === 'hostname') {
        const h = document.getElementById('modal-hl');
        if (h) h.value = '0';
    } else if (field === 'category') {
        const c = document.getElementById('modal-cl');
        if (c) c.value = '0';
    } else if (field === 'vendor') {
        const v = document.getElementById('modal-vl');
        if (v) v.value = '0';
    }
    modalRefreshLockUi();
    toast('Unlocked — the next scan can refresh this field from discovery', 'ok');
}

function closeModal() {
    document.getElementById('modal-bg').style.display = 'none';
}

async function saveReclassify() {
    const id       = document.getElementById('modal-asset-id').value;
    const hostname = document.getElementById('modal-hostname').value.trim();
    const category = document.getElementById('modal-cat').value;
    const vendor   = document.getElementById('modal-vendor').value.trim();
    const notes    = document.getElementById('modal-notes').value.trim();
    const owner    = document.getElementById('modal-owner') ? document.getElementById('modal-owner').value.trim() : '';
    const bu       = document.getElementById('modal-business-unit') ? document.getElementById('modal-business-unit').value.trim() : '';
    const crit     = document.getElementById('modal-criticality') ? document.getElementById('modal-criticality').value : 'medium';
    const env      = document.getElementById('modal-environment') ? document.getElementById('modal-environment').value.trim() : '';

    const o = window._reclassifyOrig || {};
    const body = {};
    if (category !== (o.category || 'unk')) {
        body.category = category;
    }
    if (hostname !== (o.hostname || '')) {
        body.hostname = hostname;
    }
    if (vendor !== (o.vendor || '')) {
        body.vendor = vendor;
    }
    if (notes !== undefined) body.notes = notes;
    body.owner = owner;
    body.business_unit = bu;
    body.criticality = crit;
    body.environment = env || 'unknown';

    // Sync lock state when hostname is unchanged so we never override PHP's
    // auto-lock on hostname edits (which would send hostname_locked: 0 from an unlocked modal).
    const hle = document.getElementById('modal-hl');
    if (hle && body.hostname === undefined) {
        const hl = parseInt(String(hle.value), 10);
        if (!Number.isNaN(hl)) {
            body.hostname_locked = hl ? 1 : 0;
        }
    }

    const headers = {'Content-Type': 'application/json'};
    if (csrfToken) headers['X-CSRF-Token'] = csrfToken;
    const r = await fetch(`/api/assets.php?id=${id}`, {
        method: 'PUT',
        headers: headers,
        body: JSON.stringify(body),
        credentials: 'same-origin'
    });
    const data = await r.json();
    if (data.ok) {
        toast('Asset updated', 'ok');
        closeModal();
        loadAssets(assetPage);
        if (currentTab === 'dash') loadDashboard();
    } else {
        toast(data.error || 'Save failed', 'err');
    }
}

// Close modal on background click
