// ==========================================================================
// Host detail — friendly port labels (title + common homelab stacks)
// ==========================================================================
function extractBracketTitles(text) {
    const s = String(text || '');
    const out = [];
    const re = /\[([^\]]+)\]/g;
    let m;
    while ((m = re.exec(s)) !== null) {
        const t = m[1].trim();
        if (t && !out.includes(t)) out.push(t);
    }
    return out;
}

function firstHttpTitle(rawBanner, httpProbe) {
    for (const t of extractBracketTitles(rawBanner)) {
        if (/^https?$/i.test(t)) continue;
        return t;
    }
    for (const t of extractBracketTitles(httpProbe)) {
        if (/^https?$/i.test(t)) continue;
        return t;
    }
    return '';
}

/**
 * NPM (Nginx Proxy Manager) — only label when evidence is strong.
 * Avoid: generic "Default Site" titles, bare OpenResty, or plain nginx (false positives).
 */
function likelyNpmReverseProxy(allPorts, raw, probe) {
    const set = new Set((allPorts || []).map(Number));
    const blob = (String(raw || '') + '\n' + String(probe || '')).toLowerCase();
    // NPM exposes admin on 81 by default — strongest signal with other ports.
    if (set.has(81)) return true;
    // Explicit product strings from NPM UI / docs / responses
    if (/nginx[-\s]?proxy[-\s]?manager|nginxproxymanager|nginx proxy manager/.test(blob)) return true;
    return false;
}

function buildFriendlyOpenPortLine(port, rawBanner, httpProbe, allPorts) {
    const raw = String(rawBanner || '');
    const probe = String(httpProbe || '');
    const low = raw.toLowerCase();
    const title = firstHttpTitle(raw, probe);
    const npm = likelyNpmReverseProxy(allPorts, raw, probe);

    if (port === 80) {
        if (npm) {
            const t = title ? `HTTP (${title})` : 'HTTP';
            return t + ' — NPM reverse proxy';
        }
        return title ? `HTTP (${title})` : (raw ? raw : 'HTTP');
    }
    if (port === 443) {
        if (npm) {
            const t = title ? `HTTPS (${title})` : 'HTTPS';
            return t + ' — NPM reverse proxy';
        }
        return title ? `HTTPS (${title})` : (raw ? raw : 'HTTPS');
    }
    if (port === 81) {
        return likelyNpmReverseProxy(allPorts, raw, probe)
            ? 'NPM Proxy Manager (admin UI)'
            : 'HTTP — port 81';
    }

    if (port === 445) return 'SMB — Windows file sharing';
    if (port === 3389) return 'RDP — Remote Desktop';

    if (port === 3000) {
        const t = firstHttpTitle(raw, probe);
        if (/karakeep/i.test(raw + probe + t)) return 'Karakeep (bookmarks / hoarder)';
        if (/homarr/i.test(raw + probe + t)) return 'Homarr (dashboard)';
        if (/homepage/i.test(raw + probe + t)) return 'Homepage (dashboard)';
        if (/grafana/i.test(raw + probe + t)) return 'Grafana';
        return 'Web dashboard (Homarr / Grafana / dev)';
    }

    if (port === 5000 && /werkzeug/i.test(low)) return 'Python app (Werkzeug)';
    if (port === 8080) {
        const t = firstHttpTitle(raw, probe);
        if (/open\s*webui|openwebui/i.test(raw + probe + t)) return 'Open WebUI (LLM chat UI)';
        if (/it tools/i.test(raw + probe + t)) return 'IT Tools (developer utilities)';
    }
    if (port === 8089) {
        const t = firstHttpTitle(raw, probe);
        if (/channels/i.test(raw + probe + t)) return 'Channels';
    }
    if (port === 8888) {
        const t = firstHttpTitle(raw, probe);
        if (/web check/i.test(raw + probe + t)) return 'Web Check';
    }

    if (port === 9000) return 'Portainer (HTTP)';
    if (port === 9443) return 'Portainer (HTTPS)';

    if (port === 53 && /\bpi[- ]hole\b|\bpihole\b/i.test(low)) return 'DNS — Pi-hole (dnsmasq)';

    const parts = raw.split(' ');
    const proto = parts[0] || '';
    const rest = parts.slice(1).join(' ');
    if (rest) return rest;
    return proto || 'open';
}

function collectDetectedServiceChips(ports, banners, httpProbe) {
    const chips = new Set();
    const probe = String(httpProbe || '');
    const all = ports || [];
    for (const p of all) {
        const raw = String((banners || {})[String(p)] || '');
        const low = raw.toLowerCase();
        if (p === 80 || p === 443 || p === 81) {
            if (likelyNpmReverseProxy(all, raw, probe)) chips.add('NPM');
        }
        if (p === 3389) chips.add('RDP');
        if (p === 445) chips.add('SMB');
        if (p === 3000) {
            const t = firstHttpTitle(raw, probe);
            if (/karakeep/i.test(raw + probe + t)) chips.add('Karakeep');
            else if (/homarr/i.test(raw + probe + t)) chips.add('Homarr');
            else if (/homepage/i.test(raw + probe + t)) chips.add('Homepage');
            else if (/grafana/i.test(raw + probe + t)) chips.add('Grafana');
        }
        if (p === 5000 && /werkzeug/i.test(low)) chips.add('Werkzeug');
        if (p === 8080) {
            const t = firstHttpTitle(raw, probe);
            if (/open\s*webui|openwebui/i.test(raw + probe + t)) chips.add('Open WebUI');
            else if (/it tools/i.test(raw + probe + t)) chips.add('IT Tools');
        }
        if (p === 8089) {
            const t = firstHttpTitle(raw, probe);
            if (/channels/i.test(raw + probe + t)) chips.add('Channels');
        }
        if (p === 8888) {
            const t = firstHttpTitle(raw, probe);
            if (/web check/i.test(raw + probe + t)) chips.add('Web Check');
        }
        if (p === 9000 || p === 9443) chips.add('Portainer');
        if (/splunk/i.test(raw + probe) && (p === 8088 || p === 8089 || p === 8000)) chips.add('Splunk');
        if (/jupyter/i.test(raw + probe)) chips.add('Jupyter');
        if (/minio/i.test(raw + probe)) chips.add('MinIO');
    }
    if (/portainer/i.test(probe)) chips.add('Portainer');

    const blob = all.map(pr => String((banners || {})[String(pr)] || '')).join('\n') + '\n' + probe;
    const EXTRA_SIGS = [
        ['Zabbix', /zabbix/i], ['ntfy', /\bntfy\b/i],
        ['Kasm Workspaces', /\bkasm(web|vnc)?\b|kasmtechnologies/i],
        ['Proxmox VE', /proxmox|pve\.|pve-/i],
        ['VMware', /\bvmware\s+esxi\b|\besxi\b|\bvcenter\b|vsphere\s*(web\s*)?client|\bvmware\s+vsphere\b|\bvmware\s+vcenter\b/i],
        ['Hyper-V', /\bhyper[- ]?v\b|\bhyperv\b|\bmicrosoft\s+hyper[- ]?v\b/i],
        ['Docker Engine', /\bdocker engine\b|docker\/v|\bdockerd\b/i],
        ['Jellyfin', /jellyfin/i], ['Gitea', /\bgitea\b/i], ['Nextcloud', /nextcloud/i],
        ['Mastodon', /mastodon/i], ['OpenObserve', /openobserve/i],
        ['Uptime Kuma', /uptime.?kuma/i], ['InfluxDB', /\binfluxdb?\b/i],
        ['Pi-hole', /\bpi[- ]hole\b|\bpihole\b|dnsmasq[^\n]{0,80}pi[- ]hole/i],
        ['Karakeep', /\bkarakeep\b/i],
        ['Open WebUI', /\bopen\s*webui\b|\bopenwebui\b/i],
    ];
    for (const [name, rx] of EXTRA_SIGS) {
        if (rx.test(blob)) chips.add(name);
    }
    return Array.from(chips).sort();
}

// ==========================================================================
// Host detail panel (centered modal)
// ==========================================================================
/** @returns {boolean} */
function stIsHostPanelOpen() {
    const hp = document.getElementById('host-panel');
    return !!(hp && hp.style.display && hp.style.display !== 'none');
}

let stHostPanelReturnFocusEl = null;

/** True if any `.modal-bg` overlay is visible (flex), or auth gate is shown — excludes host panel itself. */
function stAnyModalBgOpen() {
    const nodes = document.querySelectorAll('.modal-bg');
    for (let i = 0; i < nodes.length; i++) {
        const el = nodes[i];
        try {
            if (el.style.display === 'flex') return true;
            if (window.getComputedStyle(el).display === 'flex') return true;
        } catch (_e) {}
    }
    const gate = document.getElementById('st-auth-gate');
    if (gate && !gate.classList.contains('hide')) return true;
    return false;
}

function stHostPanelAttachEsc() {
    if (window.__stHostPanelEscHandler) return;
    window.__stHostPanelEscHandler = function (ev) {
        if (ev.key !== 'Escape') return;
        if (!stIsHostPanelOpen()) return;
        if (stAnyModalBgOpen()) return;
        ev.preventDefault();
        ev.stopPropagation();
        closeHostPanel();
    };
    document.addEventListener('keydown', window.__stHostPanelEscHandler, true);
}

function stHostPanelDetachEsc() {
    if (!window.__stHostPanelEscHandler) return;
    document.removeEventListener('keydown', window.__stHostPanelEscHandler, true);
    window.__stHostPanelEscHandler = null;
}

/** Read-only Zabbix summary for the host Details side panel (no actions). */
function renderHostPanelZabbixBlock(a) {
    const f = a && a.zabbix_enrichment_status;
    if (!f || !f.tables_ready || !f.configured || !f.enabled) {
        return '';
    }
    const z = a && a.zabbix;
    if (!z || typeof z !== 'object') {
        return '';
    }
    const linked = !!z.linked;
    let monLabel = '—';
    if (linked) {
        monLabel = z.monitored === true ? 'yes' : z.monitored === false ? 'no' : '—';
    } else if (a.monitored_by_zabbix === true || a.monitored_by_zabbix === false) {
        monLabel = a.monitored_by_zabbix ? 'yes' : 'no';
    } else {
        monLabel = 'no';
    }
    const avail = linked
        ? esc(String(z.availability != null && z.availability !== '' ? z.availability : '—'))
        : esc(String(a.zabbix_availability != null && a.zabbix_availability !== '' ? a.zabbix_availability : '—'));
    let prob = '—';
    if (linked && z.open_problem_count != null) {
        prob = esc(String(z.open_problem_count));
    } else if (a.zabbix_problem_count != null) {
        prob = esc(String(a.zabbix_problem_count));
    }
    const tagsJoined = stZabbixUiTruncate((z.tags || []).map((t) => {
        const tag = t.tag || '';
        const v = t.value;
        return esc(tag + (v !== '' && v !== undefined ? '=' + v : ''));
    }).filter(Boolean).join(', '), 1200);
    const gr = stZabbixUiTruncate((z.host_groups || []).map((g) => esc(g)).join(', '), 1200);
    const tm = stZabbixUiTruncate((z.templates || []).map((t) => esc(t)).join(', '), 1200);
    const zbxHostLabel = linked
        ? esc(String(
            (z.display_name != null && String(z.display_name).trim() !== '')
                ? z.display_name
                : (z.visible_name != null && String(z.visible_name).trim() !== '')
                    ? z.visible_name
                    : (z.tech_name != null && String(z.tech_name).trim() !== '')
                        ? z.tech_name
                        : (z.zabbix_hostid || '—'),
        ))
        : '—';
    const m = z.match;
    let matchHtml = '<span class="text-dim">—</span>';
    if (m && linked) {
        const conf = m.confidence != null ? Number(m.confidence).toFixed(2) : '—';
        const man = m.manual ? ' · <span class="text-dim">manual link</span>' : ' · <span class="text-dim">automatic</span>';
        matchHtml = `${esc(m.method || '—')} · confidence ${esc(conf)}${man}`;
    }
    const unlinkNote = linked
        ? ''
        : '<p class="hint-micro text-dim mt6" style="margin-bottom:0">No Zabbix host linked. After the connector syncs, matching links hosts by IP, hostname, MAC, or visible name.</p>';
    const fr = f.freshness_state ? String(f.freshness_state) : 'never_synced';
    const zbxFreshRow = '<tr><td class="hp-meta-key">Zabbix cache</td><td class="hp-meta-val-dim">'
        + stZabbixLastSyncLineHtml(f)
        + ' <span class="' + stZabbixFreshnessBadgeClass(f) + '">' + esc(stZabbixFreshnessBadgeLabel(f)) + '</span></td></tr>';
    const zbxOutdatedNote = fr === 'outdated'
        ? '<p class="hp-zbx-freshness-warn" style="margin-bottom:0">Zabbix data may be outdated.</p>'
        : '';
    return `
      <div class="hp-head">
        Zabbix
        <span class="text-dim mono-sm" style="font-weight:normal;margin-left:6px">enrichment (read-only)</span>
        <div class="hp-head-line"></div>
      </div>
      <div class="mb14 host-inner-surface">
        <table class="hp-meta-table">
          ${zbxFreshRow}
          <tr><td class="hp-meta-key">Zabbix host</td><td class="hp-meta-val-dim">${zbxHostLabel}</td></tr>
          <tr><td class="hp-meta-key">Monitored</td><td class="hp-meta-val-dim">${esc(monLabel)}</td></tr>
          <tr><td class="hp-meta-key">Availability</td><td class="hp-meta-val-dim">${avail}</td></tr>
          <tr><td class="hp-meta-key">Open problems</td><td class="hp-meta-val-dim">${prob}</td></tr>
          <tr><td class="hp-meta-key">Groups</td><td class="hp-meta-val-dim cpe-break">${gr || '<span class="text-dim">—</span>'}</td></tr>
          <tr><td class="hp-meta-key">Tags</td><td class="hp-meta-val-dim cpe-break">${tagsJoined || '<span class="text-dim">—</span>'}</td></tr>
          <tr><td class="hp-meta-key">Templates</td><td class="hp-meta-val-dim cpe-break">${tm || '<span class="text-dim">—</span>'}</td></tr>
          <tr><td class="hp-meta-key">Match</td><td class="hp-meta-val-dim">${matchHtml}</td></tr>
        </table>
        ${zbxOutdatedNote}
        ${unlinkNote}
      </div>`;
}

const ST_HOST_TAB_ORDER = ['overview', 'enrichment', 'ports', 'vulns', 'history', 'ai'];

function stHostSetTab(tab) {
    try {
        const body = document.getElementById('hp-body');
        if (!body || !body.querySelector('.host-tablist')) {
            return;
        }
        let t = tab;
        if (!ST_HOST_TAB_ORDER.includes(t)) {
            t = 'overview';
        }
        body.querySelectorAll('.host-tab-btn').forEach((btn) => {
            const isSel = btn.getAttribute('data-tab') === t;
            btn.classList.toggle('active', isSel);
            btn.setAttribute('aria-selected', isSel ? 'true' : 'false');
            btn.setAttribute('tabindex', isSel ? '0' : '-1');
        });
        body.querySelectorAll('.host-tab-panel').forEach((panel) => {
            const show = panel.getAttribute('data-tab') === t;
            if (show) {
                panel.removeAttribute('hidden');
            } else {
                panel.setAttribute('hidden', '');
            }
        });
        const panelsRoot = body.querySelector('.host-tab-panels');
        if (panelsRoot) {
            panelsRoot.scrollTop = 0;
        }
    } catch (e) {
        console.error('stHostSetTab', e);
    }
}

/** @param {KeyboardEvent} ev @param {Element} [listEl] tablist root (use when delegating from #host-panel) */
function stHostTablistKeydown(ev, listEl) {
    if (!ev || (ev.key !== 'ArrowRight' && ev.key !== 'ArrowLeft' && ev.key !== 'Home' && ev.key !== 'End')) {
        return;
    }
    const list = listEl || ev.currentTarget;
    if (!list || !list.classList || !list.classList.contains('host-tablist')) {
        return;
    }
    const body = document.getElementById('hp-body');
    if (!body) {
        return;
    }
    const btns = [...body.querySelectorAll('.host-tab-btn')];
    if (!btns.length) {
        return;
    }
    let idx = btns.findIndex((b) => b.getAttribute('aria-selected') === 'true');
    if (idx < 0) {
        idx = 0;
    }
    let next = idx;
    if (ev.key === 'ArrowRight') {
        next = (idx + 1) % btns.length;
    } else if (ev.key === 'ArrowLeft') {
        next = (idx - 1 + btns.length) % btns.length;
    } else if (ev.key === 'Home') {
        next = 0;
    } else if (ev.key === 'End') {
        next = btns.length - 1;
    }
    const btn = btns[next];
    if (!btn) {
        return;
    }
    ev.preventDefault();
    const t = btn.getAttribute('data-tab') || 'overview';
    stHostSetTab(t);
    try {
        btn.focus();
    } catch (_e) {}
}

window.stHostSetTab = stHostSetTab;
window.stHostTablistKeydown = stHostTablistKeydown;

async function openHostPanel(id, ip) {
    closeDevicePanel();
    stHostPanelReturnFocusEl = document.activeElement instanceof HTMLElement ? document.activeElement : null;
    const hpEl = document.getElementById('host-panel');
    const hpBody = document.getElementById('hp-body');
    const hpBadges = document.getElementById('hp-header-badges');
    if (!hpEl || !hpBody) {
        return;
    }
    const hpBg = document.getElementById('host-panel-bg');
    const hpTitle = document.getElementById('hp-title');
    hpEl.style.display = 'flex';
    if (hpBg) hpBg.style.display = 'block';
    stHostPanelAttachEsc();
    hpEl.dataset.hpAssetId = String(id);
    if (hpTitle) hpTitle.textContent = ip;
    if (hpBadges) hpBadges.innerHTML = '';
    hpBody.classList.remove('host-modal-body--tabbed');
    hpBody.innerHTML = '<div class="loading">Loading…</div>';
    syncHostPanelExplainBusyUi();

    const [assetData, openFindingsData, acceptedFindingsData] = await Promise.all([
        api('/api/assets.php?id=' + id),
        api('/api/findings.php?asset_id=' + id + '&resolved=0&per_page=50&sort=cvss&order=desc'),
        api('/api/findings.php?asset_id=' + id + '&resolved=1&lifecycle=accepted&per_page=50&sort=cvss&order=desc', { quiet: true }),
    ]);

    if (!assetData || !assetData.asset) {
        hpBody.classList.remove('host-modal-body--tabbed');
        hpBody.innerHTML = '<div class="loading">Failed to load</div>';
        if (hpBadges) hpBadges.innerHTML = '';
        delete hpEl.dataset.hpAssetId;
        syncHostPanelExplainBusyUi();
        queueMicrotask(() => {
            const c = document.querySelector('#host-panel .host-modal-close');
            if (c && typeof c.focus === 'function') c.focus();
        });
        return;
    }

    const a = assetData.asset;
    const scopeAssignable = !!(assetData && assetData.asset_scope_assignable);
    try {
        if (typeof assetData.asset_scope_assignable === 'boolean') {
            window.__stAssetsScopeColumn = assetData.asset_scope_assignable;
        }
    } catch (_e) {}
    const openFindings = openFindingsData && openFindingsData.findings ? openFindingsData.findings : [];
    const acceptedFindings = acceptedFindingsData && acceptedFindingsData.findings ? acceptedFindingsData.findings : [];
    const ports = a.open_ports || [];
    const banners = a.banners || {};
    const httpProbe = String(banners._http || '');
    const discoverySources = Array.isArray(a.discovery_sources) ? a.discovery_sources : [];
    const aiInfluenced = discoverySources.includes('ai_local_inference');

    const hn = String(a.hostname || '').trim();
    const trustedHn = assetData.trusted_hostname != null && String(assetData.trusted_hostname).trim()
        && stTrustedMeetsOperationalUiPref(assetData.trusted_hostname_confidence)
        ? String(assetData.trusted_hostname).trim() : '';
    const titleHostname = trustedHn || hn || '—';
    const hnTrustChip = (() => {
        const bits = [];
        if (trustedHn && (!hn || hn.toLowerCase() !== trustedHn.toLowerCase())) {
            bits.push('<span class="hp-chip st-trusted-pref-chip" title="Reconciled canonical hostname (trusted data, medium+ confidence). Stored hostname remains in Identity &amp; inventory.">Trusted</span>');
        }
        if (Number(a.hostname_locked || 0)) {
            bits.push('<span class="hp-chip" title="Hostname is locked — scans will not overwrite it">Locked</span>');
        }
        const ic = a.identity_confidence != null ? Number(a.identity_confidence) : null;
        if (ic != null && ic >= 0.75) {
            bits.push('<span class="hp-chip" title="High identity confidence (manual edit or enrichment)">Operator-approved</span>');
        }
        return bits.join(' ');
    })();
    if (hpTitle) hpTitle.textContent = (hn || trustedHn) ? `${titleHostname} · ${a.ip}` : String(a.ip);
    const trustedOs = assetData.trusted_os_platform != null && String(assetData.trusted_os_platform).trim()
        && stTrustedMeetsOperationalUiPref(assetData.trusted_os_confidence)
        ? String(assetData.trusted_os_platform).trim() : '';
    const osGuessRaw = String(a.os_guess || '').trim();
    const osPrimaryHtml = trustedOs
        ? `${esc(trustedOs)} <span class="text-dim mono-sm" title="Reconciled OS/platform (${esc(String(assetData.trusted_os_confidence || ''))})">· trusted</span>`
        : esc(a.os_guess || '—');
    const osStoredRow = trustedOs && osGuessRaw && osGuessRaw !== trustedOs
        ? `<tr class="st-host-meta-secondary"><td class="hp-meta-key">OS (scan)</td><td class="hp-meta-val-dim">${esc(osGuessRaw)}</td></tr>`
        : '';
    const hnStoredRow = trustedHn && hn && hn.toLowerCase() !== trustedHn.toLowerCase()
        ? `<tr><td class="hp-meta-key">Hostname (stored)</td><td class="hp-meta-val">${esc(hn)}</td></tr>`
        : '';
    if (hpBadges) {
        let badgeHtml = `<span class="cat ${esc(a.category || 'unk')}">${esc(a.category || 'unk')}</span>${lifecycleBadgeHtml(a)}`;
        if (aiInfluenced) {
            badgeHtml += '<span class="hp-chip" title="Category was adjusted by local AI enrichment">AI-assisted</span>';
        }
        if (scopeAssignable) {
            const sn = a.scope_name != null && String(a.scope_name).trim() ? String(a.scope_name) : '—';
            badgeHtml += `<span class="host-modal-scope-wrap"><span class="text-dim text-micro">Scope</span> <span class="mono-sm">${esc(sn)}</span></span>`;
        }
        hpBadges.innerHTML = badgeHtml;
    }

    const serviceChips = collectDetectedServiceChips(ports, banners, httpProbe);

    const portRows = ports.length ? ports.map(p => {
        const rawBanner = banners[String(p)] || '';
        const friendly = buildFriendlyOpenPortLine(p, rawBanner, httpProbe, ports);

        return `<div class="hp-port-row">
          <span class="hp-port-num">${p}</span>
          <div class="minw0 grow">
            <div class="hp-port-text">
              <span class="hp-arrow">→</span>
              ${esc(friendly)}
            </div>
            ${rawBanner ? `<details class="mt4"><summary class="hp-raw-summary">raw banner</summary>
              <div class="hp-raw-body">${esc(rawBanner)}</div>
            </details>` : ''}
          </div>
        </div>`;
    }).join('') : '<div class="hp-empty st-host-empty">No open ports on record. Run a scan to discover listening services.</div>';

    const serviceRows = serviceChips.length
        ? `<div class="hp-chips">${
            serviceChips.map(s =>
                `<span class="hp-chip">${esc(s)}</span>`
            ).join('')
          }</div>`
        : `<div class="hp-empty st-host-empty">No service fingerprints yet. Banners and probes populate after discovery runs.</div>`;

    const findingRows = openFindings.length ? openFindings.map(f => `
        <div class="hp-block">
          <div class="hp-row">
            <span class="sev ${sevClass(f.cvss)} hp-sev-chip">${f.cvss != null ? esc(f.cvss) : '?'} ${esc((f.severity||'').toUpperCase())}</span>
            <span class="hp-cve">${esc(f.cve_id)}</span>
            <span class="hp-date">${localDate(f.published)}</span>
          </div>
          <div class="hp-desc">${esc(f.description||'').slice(0,180)}${(f.description||'').length>180?'…':''}</div>
          ${formatHpFindingTriage(f)}
          ${!f.resolved
              ? (stRoleCanManageScans()
                  ? `<div class="row-wrap mt4" style="gap:4px"><button type="button" class="tbtn btn-xs" onclick="resolveFinding(${f.id},this);openHostPanel(${id},'${esc(ip)}')">Resolve</button><button type="button" class="tbtn btn-xs" onclick="acceptFindingRisk(${f.id},this);openHostPanel(${id},'${esc(ip)}')">Accept risk</button></div>`
                  : '')
              : '<span class="status-text" style="color:var(--green)">resolved</span>'}
        </div>`).join('') : '<div class="hp-empty st-host-empty">No open CVEs matched for this host. Rescan to refresh NVD correlation.</div>';

    const acceptedFindingRows = acceptedFindings.length ? acceptedFindings.map(f => `
        <div class="hp-block" style="border-left:3px solid var(--border);padding-left:10px;opacity:0.95">
          <div class="hp-row">
            <span class="sev ${sevClass(f.cvss)} hp-sev-chip">${f.cvss != null ? esc(f.cvss) : '?'} ${esc((f.severity||'').toUpperCase())}</span>
            <span class="hp-cve">${esc(f.cve_id)}</span>
            <span class="hp-chip" title="Acknowledged risk — scanner will not raise new alerts for this CVE while accepted">Accepted risk</span>
            ${f.accepted_at ? `<span class="hp-date">${localDate(f.accepted_at)}</span>` : ''}
          </div>
          <div class="hp-desc text-dim">${esc(f.description||'').slice(0,180)}${(f.description||'').length>180?'…':''}</div>
          ${formatHpFindingTriage(f)}
          ${stRoleCanManageScans() ? `<div class="mt4"><button type="button" class="tbtn btn-xs" onclick="unacceptFindingRisk(${f.id}, ${id}, '${esc(ip)}')" title="Return this CVE to the open vulnerabilities list">Unaccept risk</button></div>` : ''}
        </div>`).join('') : '<div class="hp-empty st-host-empty">No accepted-risk CVEs on this host.</div>';

    const scanHistoryRows = (assetData.asset.scan_history || []).length
        ? (assetData.asset.scan_history || []).map(h => {
            const ch = h.changes || {};
            const plusPorts = (ch.new_ports || []).slice(0, 6).join(', ');
            const minusPorts = (ch.closed_ports || []).slice(0, 6).join(', ');
            const plusCves = (ch.new_cves || []).slice(0, 4).join(', ');
            const minusCves = (ch.resolved_cves || []).slice(0, 4).join(', ');
            const portsTotal = Array.isArray(h.ports) ? h.ports.length : 0;
            const when = h.finished_at || h.started_at || h.created_at;
            return `<div class="hp-history-row">
              <span class="hp-history-ts">#${h.job_id} · ${esc(localDate(when))}</span>
              <span class="hp-history-ports">${portsTotal} ports · ${h.open_findings || 0} open CVEs</span>
              ${(plusPorts || minusPorts || plusCves || minusCves) ? `
                <div class="status-text" style="margin-top:2px">
                  ${plusPorts ? `+ports ${esc(plusPorts)} ` : ''}${minusPorts ? `-ports ${esc(minusPorts)} ` : ''}${plusCves ? `+CVEs ${esc(plusCves)} ` : ''}${minusCves ? `resolved ${esc(minusCves)}` : ''}
                </div>` : ''}
            </div>`;
        }).join('')
        : '<div class="hp-empty st-host-empty">No scan-to-scan deltas yet. Repeat scans build this timeline.</div>';

    const reconEvidenceHtml = stHostReconciliationEvidenceHtml(assetData);
    const softwareInventoryHtml = stHostSoftwareInventoryHtml(assetData);
    const identityEvidenceHtml = stHostIdentityEvidenceHtml(assetData);
    const credHostSummaryHtml = stHostCredentialedChecksHtml(assetData);

    const hpActionsHtml = (stRoleCanManageScans() || (openFindings.length || acceptedFindings.length))
        ? `<div class="hp-actions hp-actions-host-primary mt14 st-host-actionbar">
        ${stRoleCanManageScans() ? `<button type="button" class="btnp btn-xs" onclick='void queueHostRescan(${JSON.stringify(a.ip)}, this)' title="Rescan: profile, collector target, scan steps, rates, discovery, exclusions, enrichment; Scan tab syncs after a successful queue">&#8635; Rescan host</button>
        <button type="button" class="btnp btn-xs" onclick="openReclassify(${a.id},'${esc(a.ip)}','${esc(a.hostname||'')}','${esc(a.category||'unk')}','${esc(a.vendor||'')}','${esc(a.notes||'')}','${esc(a.owner||'')}','${esc(a.business_unit||'')}','${esc(a.criticality||'medium')}','${esc(a.environment||'unknown')}',${Number(a.hostname_locked||0)},${Number(a.category_locked||0)},${Number(a.vendor_locked||0)})">&#9998; Edit</button>` : ''}
        ${(openFindings.length || acceptedFindings.length) ? `<button type="button" class="tbtn btn-xs" onclick="filterVulnsByIP('${esc(a.ip)}');closeHostPanel()">See all CVEs</button>` : ''}
      </div>`
        : '';

    const zbxHtml = renderHostPanelZabbixBlock(a);
    const enrichmentBody = zbxHtml
        ? `<section class="host-section host-section--zbx" aria-label="Zabbix enrichment">${zbxHtml}</section>`
        : `<section class="host-section" aria-label="Zabbix enrichment"><div class="hp-empty st-host-empty">No Zabbix enrichment for this address. Connect Zabbix under Integrations if you monitor this host there.</div></section>`;
    const hostVendorSummary = stVendorSummaryForAsset(a);
    const scanHistList = Array.isArray(assetData.asset.scan_history) ? assetData.asset.scan_history : [];
    const latestScan = scanHistList.length ? scanHistList[0] : null;
    const latestScanWhen = latestScan ? (latestScan.finished_at || latestScan.started_at || latestScan.created_at) : '';
    const latestScanLabel = latestScanWhen ? localDate(latestScanWhen) : '—';
    const enrichmentState = zbxHtml ? 'Linked / cached' : 'Not linked';
    const lifecycleState = String(a.lifecycle_state || 'active');
    const scopeLabel = scopeAssignable
        ? esc(a.scope_name != null && String(a.scope_name).trim() ? String(a.scope_name) : '—')
        : '—';
    const deviceLinkHtml = a.device_id != null && a.device_id !== ''
        ? `<span class="click-ip" onclick="openDevicePanel(${a.device_id})" title="Logical device overview">${esc(String(a.device_id))}</span>`
        : '—';
    const deviceSummaryHtml = a.device_id != null && a.device_id !== ''
        ? `<span class="click-ip" onclick="openDevicePanel(${a.device_id})" title="Open logical device overview">${esc(String(a.device_id))}</span>`
        : '<span class="text-dim">No linked device</span>';

    try {
    hpBody.innerHTML = `
      <div class="host-tab-shell">
        <div class="host-tablist" role="tablist" aria-label="Host detail sections">
          <button type="button" role="tab" class="host-tab-btn active" data-tab="overview" id="hp-tab-overview" aria-selected="true" aria-controls="hp-panel-overview" tabindex="0" onclick="stHostSetTab('overview')">Overview</button>
