function closeHostPanel() {
    const hpEl = document.getElementById('host-panel');
    if (!hpEl) {
        return;
    }
    const hpBody = document.getElementById('hp-body');
    if (hpBody) {
        hpBody.classList.remove('host-modal-body--tabbed');
    }
    const hpBadges = document.getElementById('hp-header-badges');
    stHostPanelDetachEsc();
    hpEl.style.display = 'none';
    const hpBg = document.getElementById('host-panel-bg');
    if (hpBg) hpBg.style.display = 'none';
    delete hpEl.dataset.hpAssetId;
    if (hpBadges) hpBadges.innerHTML = '';
    syncHostPanelExplainBusyUi();
    const ret = stHostPanelReturnFocusEl;
    stHostPanelReturnFocusEl = null;
    if (ret && typeof ret.focus === 'function' && !stAnyModalBgOpen()) {
        try {
            ret.focus();
        } catch (_e) {}
    }
}

// ==========================================================================
// Device detail panel
// ==========================================================================
async function openDevicePanel(deviceId) {
    closeHostPanel();
    const did = parseInt(String(deviceId), 10);
    if (!did) return;

    document.getElementById('device-panel').style.display = 'block';
    document.getElementById('device-panel-bg').style.display = 'block';
    document.getElementById('dp-body').innerHTML = '<div class="loading">Loading…</div>';

    const data = await api('/api/devices.php?id=' + encodeURIComponent(String(did)));
    if (!data || !data.device) {
        document.getElementById('dp-body').innerHTML = '<div class="loading">Device not found</div>';
        return;
    }

    const d = data.device;
    const assets = data.assets || [];
    const deviceScanHistory = data.scan_history || [];
    const mac = d.primary_mac_norm ? esc(d.primary_mac_norm) : '—';
    const label = d.label ? esc(d.label) : '—';

    const assetRows = assets.length
        ? assets.map(a => {
            const cv = a.top_cvss != null && a.top_cvss !== '' ? esc(String(a.top_cvss)) : '—';
            return `<tr class="dp-asset-row" onclick="openHostPanel(${a.id},'${esc(a.ip)}')" title="Open host detail">
              <td class="mono mono-sm">${esc(a.ip)}</td>
              <td>${esc(a.hostname || '—')}</td>
              <td><span class="cat ${esc(a.category || 'unk')}">${esc(a.category || 'unk')}</span></td>
              <td class="mono mono-sm">${cv}</td>
              <td class="mono mono-sm">${relTime(a.last_seen)}</td>
            </tr>`;
        }).join('')
        : '<tr><td colspan="5" class="text-secondary" style="padding:10px 0">No linked addresses</td></tr>';

    const scanHistoryRows = deviceScanHistory.length
        ? deviceScanHistory.map(h => {
            const ch = h.changes || {};
            const plusPorts = (ch.new_ports || []).slice(0, 6).join(', ');
            const minusPorts = (ch.closed_ports || []).slice(0, 6).join(', ');
            const plusCves = (ch.new_cves || []).slice(0, 4).join(', ');
            const minusCves = (ch.resolved_cves || []).slice(0, 4).join(', ');
            const when = h.finished_at || h.started_at || h.created_at;
            const pCount = Array.isArray(h.ports) ? h.ports.length : 0;
            return `<div class="hp-history-row">
              <span class="hp-history-ts">#${h.job_id} · ${esc(localDate(when))}</span>
              <span class="hp-history-ports">${h.asset_count || 0} assets · ${pCount} ports · ${h.open_findings || 0} open CVEs</span>
              <button type="button" class="tbtn btn-xs" style="margin-top:3px" onclick="openScanDetailFromDeviceHistory(${h.job_id})">View run details</button>
              ${(plusPorts || minusPorts || plusCves || minusCves) ? `
                <div class="status-text" style="margin-top:2px">
                  ${plusPorts ? `+ports ${esc(plusPorts)} ` : ''}${minusPorts ? `-ports ${esc(minusPorts)} ` : ''}${plusCves ? `+CVEs ${esc(plusCves)} ` : ''}${minusCves ? `resolved ${esc(minusCves)}` : ''}
                </div>` : ''}
            </div>`;
        }).join('')
        : '<div class="hp-empty" style="padding:4px 0">No device scan history yet</div>';

    document.getElementById('dp-body').innerHTML = `
      <div class="hp-meta st-devices-panel-meta">
        <div class="hp-meta-title">
          <span class="mono mono-sm">#${did}</span>
          <span class="hp-meta-host" style="margin-left:8px">${assets.length} address${assets.length === 1 ? '' : 'es'}</span>
        </div>
        <table class="hp-meta-table">
          <tr><td class="hp-meta-key">MAC (norm)</td><td class="hp-meta-val mono">${mac}</td></tr>
          <tr><td class="hp-meta-key">Label</td><td class="hp-meta-val">${label}</td></tr>
          <tr><td class="hp-meta-key">Created</td><td class="hp-meta-val-dim">${localTime(d.created_at)}</td></tr>
          <tr><td class="hp-meta-key">Updated</td><td class="hp-meta-val-dim">${localTime(d.updated_at)}</td></tr>
        </table>
      </div>
      <div class="hp-actions st-devices-panel-actions" style="margin-top:12px;margin-bottom:14px">
        <button type="button" class="btnp btn-xs" onclick="viewDeviceAssets(${did});closeDevicePanel()">View in Assets</button>
      </div>
      <div class="st-devices-merge-well">
        <div class="hp-head st-devices-panel-merge-title" style="margin-top:16px">Merge other devices into this one</div>
        <p class="text-secondary st-devices-merge-lede" style="font-size:12px;line-height:1.45;margin:0 0 10px">Operator-reviewed action: all assets on the devices you list are reassigned to <strong>#${did}</strong>; merged device rows are removed. A line is written to the <strong>audit log</strong>. Cannot be undone — confirm IDs before proceeding.</p>
        <div class="st-devices-merge-row" style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:14px">
          <input type="text" class="finp st-devices-merge-input" id="dp-merge-ids" placeholder="Other device ids, e.g. 12, 18" autocomplete="off" style="min-width:0;flex:1;max-width:280px">
          <button type="button" class="tbtn st-devices-merge-btn" onclick="requestDeviceMerge(${did})">Merge…</button>
        </div>
      </div>
      <div class="hp-head st-devices-panel-assets-hd">
        Linked addresses
        <div class="hp-head-line"></div>
      </div>
      <div class="tbl-wrap st-devices-panel-tbl-wrap" style="margin-bottom:12px">
        <table class="tbl st-devices-panel-assets-tbl">
          <thead><tr>
            <th>IP</th><th>Hostname</th><th>Type</th><th>CVSS</th><th>Last seen</th>
          </tr></thead>
          <tbody>${assetRows}</tbody>
        </table>
      </div>
      <div class="hp-head st-devices-panel-history-hd">
        Device scan history
        <div class="hp-head-line"></div>
      </div>
      <div class="mb12 st-devices-panel-history-body">${scanHistoryRows}</div>
      <p class="text-secondary st-devices-panel-foot" style="font-size:12px;margin:0">Click a row for full host detail (ports, CVEs, history).</p>`;

    const hnHint = (assets[0] && assets[0].hostname) ? String(assets[0].hostname) : '';
    document.getElementById('dp-title').textContent = hnHint
        ? `Device #${did} — ${esc(hnHint)}`
        : `Device #${did}`;
}

function closeDevicePanel() {
    const p = document.getElementById('device-panel');
    const bg = document.getElementById('device-panel-bg');
    if (p) p.style.display = 'none';
    if (bg) bg.style.display = 'none';
}

function openScanDetailFromDeviceHistory(jobId) {
    const jid = parseInt(String(jobId), 10);
    if (!jid) return;
    const title = document.getElementById('dp-title')?.textContent || '';
    const m = title.match(/Device #(\d+)/);
    scanDetailReturnDeviceId = m ? parseInt(m[1], 10) : 0;
    closeDevicePanel();
    goTab('scanhist');
    hiNav('nscanhist');
    // Open after tab switch/render settles.
    setTimeout(() => { void openScanHistDetail(jid); }, 0);
}

async function requestDeviceMerge(survivorId) {
    const sid = parseInt(String(survivorId), 10);
    if (!sid) return;
    const raw = (document.getElementById('dp-merge-ids')?.value || '').trim();
    const mergeIds = [...new Set(
        raw.split(/[\s,]+/).map(s => parseInt(s, 10)).filter(n => n > 0 && n !== sid)
    )];
    if (!mergeIds.length) {
        toast('Enter one or more other device ids (comma or space separated).', 'err');
        return;
    }
    const ok = await showConfirmModal(
        'Merge devices ' + mergeIds.join(', ') + ' into device ' + sid + '?\n\n'
        + 'All assets on those devices will be reassigned here. The merged device rows will be deleted. This cannot be undone.',
        { title: 'Merge devices', okText: 'Merge' }
    );
    if (!ok) return;
    const res = await apiPost('/api/devices.php', {
        action: 'merge',
        survivor_id: sid,
        merge_ids: mergeIds,
    });
    if (res && res.ok === true) {
        toast('Merged ' + res.merged_count + ' device(s); ' + res.assets_updated + ' asset(s) updated.', 'ok');
        if (mergeIds.includes(assetDeviceFilter)) {
            assetDeviceFilter = sid;
        }
        closeDevicePanel();
        if (currentTab === 'devices') loadDevices(typeof devicePage === 'number' ? devicePage : 1);
        if (currentTab === 'assets') loadAssets(typeof assetPage === 'number' ? assetPage : 1);
        return;
    }
    toast((res && res.error) ? res.error : 'Merge failed', 'err');
}

// close on Escape key
document.addEventListener('keydown', e => {
    if (e.key !== 'Escape') return;
    const colRg = document.getElementById('collector-ranges-bg');
    if (colRg && colRg.style.display === 'flex') {
        closeCollectorRangesModal(false);
        return;
    }
    const prBg = document.getElementById('st-prompt-bg');
    if (prBg && prBg.style.display === 'flex') {
        closeStPromptModal(false);
        return;
    }
    const confBg = document.getElementById('confirm-bg');
    if (confBg && confBg.style.display === 'flex') {
        closeConfirmModal(false);
        return;
    }
    const rotBg = document.getElementById('st-int-rotate-confirm-bg');
    if (rotBg && rotBg.style.display === 'flex') {
        stIntegrationRotateConfirmClose();
        return;
    }
    const intTokBg = document.getElementById('st-int-pull-token-bg');
    if (intTokBg && intTokBg.style.display === 'flex') {
        stIntegrationPullTokenModalClose();
        return;
    }
    const hResBg = document.getElementById('host-rescan-bg');
    if (hResBg && hResBg.style.display === 'flex') {
        closeHostRescanModal(null);
        return;
    }
    const rclBg = document.getElementById('modal-bg');
    if (rclBg && rclBg.style.display === 'flex') {
        closeModal();
        return;
    }
    const scopeAssetBg = document.getElementById('st-asset-scope-bg');
    if (scopeAssetBg && scopeAssetBg.style.display === 'flex') {
        closeStAssetScopeModal();
        return;
    }
    const scanHistDetailBg = document.getElementById('scan-hist-detail-bg');
    if (scanHistDetailBg && scanHistDetailBg.style.display === 'flex') {
        closeScanHistDetailModal(false);
        return;
    }
    closeDevicePanel();
    closeHostPanel();
    closeProfileModal();
    closeMfaDisableModal();
    closePasswordChangeModal();
    closeUserPasswordModal();
});

// ==========================================================================
// Export
// ==========================================================================
function exportAssets(format) {
    const q    = document.getElementById('af-q').value;
    const cat  = document.getElementById('af-cat').value;
    const sev  = document.getElementById('af-sev').value;
    const life = document.getElementById('af-life')?.value || '';
    const lifeQ = life ? `&lifecycle_status=${enc(life)}` : '';
    const incf = document.getElementById('af-findings')?.checked ? '1' : '0';
    const devQ = assetDeviceFilter > 0 ? `&device_id=${encodeURIComponent(String(assetDeviceFilter))}` : '';
    const zbxOk = !!window.__stAssetsZabbixFiltersAvailable;
    const zMon = zbxOk ? (document.getElementById('af-zbx-monitored')?.value || '') : '';
    const zUn = zbxOk && document.getElementById('af-zbx-unavail')?.checked ? '1' : '';
    const zPr = zbxOk && document.getElementById('af-zbx-problems')?.checked ? '1' : '';
    const zGr = zbxOk ? (document.getElementById('af-zbx-group')?.value || '').trim() : '';
    const zTg = zbxOk ? (document.getElementById('af-zbx-tag')?.value || '').trim() : '';
    let zbxQ = '';
    if (zbxOk) {
        if (zMon === '0' || zMon === '1') zbxQ += `&zabbix_monitored=${enc(zMon)}`;
        if (zUn) zbxQ += '&zabbix_unavailable=1';
        if (zPr) zbxQ += '&zabbix_has_problems=1';
        if (zGr) zbxQ += `&zabbix_group=${enc(zGr)}`;
        if (zTg) zbxQ += `&zabbix_tag=${enc(zTg)}`;
    }
    const aiRev = !!window.__stAiNeedsReviewFilterAvailable && !!document.getElementById('af-ai-review')?.checked;
    const aiQ = aiRev ? '&ai_review=1' : '';
    const aiSumOn = !!window.__stAiSummaryFilterAvailable && !!document.getElementById('af-ai-summary')?.checked;
    const aiSumQ = aiSumOn ? '&ai_summary=1' : '';
    const sfE = document.getElementById('af-scope-filter');
    const scopeQ = (window.__stAssetsScopeColumn && sfE && sfE.style.display !== 'none' && sfE.value !== '')
        ? `&scope_id=${encodeURIComponent(sfE.value)}`
        : '';
    const url  = `/api/export.php?format=${format}&q=${enc(q)}&category=${enc(cat)}&severity=${enc(sev)}&findings=${incf}${devQ}${lifeQ}${aiQ}${aiSumQ}${scopeQ}${zbxQ}`;
    // Trigger download
    const a = document.createElement('a');
    a.href = url;
    a.download = `surveytrace_assets_${new Date().toISOString().slice(0,10)}.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    toast(`Exporting assets as ${format.toUpperCase()}…`, 'ok');
}

// ==========================================================================
// Init
// ==========================================================================
async function initAuthMode() {
    const r = await api('/api/auth.php?status=1');
    if (!r) return;
    authMode = r.auth_mode || 'basic';
    csrfToken = r.csrf_token || '';
    breakglassEnabled = !!r.breakglass_enabled;
    breakglassUsername = r.breakglass_username || 'admin';
    currentUser = r.user || null;
    currentUserRole = (currentUser && currentUser.role) ? currentUser.role : 'admin';
    currentUserMfaEnabled = !!r.current_mfa_enabled;
    currentUserAuthSource = r.current_auth_source || 'local';
    currentProfileDisplayName = (r.profile && r.profile.display_name) ? r.profile.display_name : '';
    currentProfileEmail = (r.profile && r.profile.email) ? r.profile.email : '';
    updateMfaActionButtons();
    const accountWrap = document.getElementById('bar-account-wrap');
    if (accountWrap) {
        const showAccount = !!(currentUser && currentUser.id > 0);
        accountWrap.style.display = showAccount ? '' : 'none';
    }
    applyRoleAwareUi();
    if ((authMode === 'session' || authMode === 'oidc') && r.requires_auth && !r.authed) {
        loginRequired = true;
        openLoginModal(authMode === 'session' ? 'Session sign-in required.' : 'Single sign-on required.');
        return;
    }
    loginRequired = false;
    document.body.classList.remove('st-auth-locked');
    document.getElementById('st-auth-gate')?.classList.add('hide');
    if (r.authed || !r.requires_auth) {
        lastSessionExpiredToastAt = 0;
    }
    if (currentUser && currentUser.must_change_password) {
        openPasswordChangeModal(true);
    }
}

function readThemeModePref() {
    try {
        const raw = localStorage.getItem('st_theme_mode');
        if (raw === 'light' || raw === 'dark') return raw;
        if (raw === 'auto') return 'auto';
    } catch (e) {}
    return 'auto';
}

function systemPrefersDark() {
    return !!(window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches);
}

function effectiveTheme() {
    const mode = readThemeModePref();
    if (mode === 'auto') return systemPrefersDark() ? 'dark' : 'light';
    return mode;
}

function applyThemeMode(mode) {
    const effective = (mode === 'auto') ? (systemPrefersDark() ? 'dark' : 'light') : mode;
    document.body.classList.toggle('light-mode', effective === 'light');
}

/** Sync Theme menuitemradio aria-checked from localStorage (light / dark / auto). */
function syncBarAccountThemeRadios() {
    const pref = readThemeModePref();
    ['light', 'dark', 'auto'].forEach((m) => {
        const el = document.getElementById('bar-theme-' + m);
        if (el) el.setAttribute('aria-checked', pref === m ? 'true' : 'false');
    });
}

function updateThemeToggleLabel() {
    syncBarAccountThemeRadios();
}

function stSetThemeMode(mode) {
    if (mode !== 'light' && mode !== 'dark' && mode !== 'auto') return;
    try { localStorage.setItem('st_theme_mode', mode); } catch (e) {}
    applyThemeMode(mode);
    syncBarAccountThemeRadios();
    closeBarAccountMenu(false);
}

var stBarAccountReturnEl = null;

function openBarAccountMenu() {
    document.removeEventListener('click', onBarAccountOutsideClick, true);
    document.removeEventListener('keydown', onBarAccountEscape, true);
    const btn = document.getElementById('bar-account-btn');
    const menu = document.getElementById('bar-account-menu');
    if (!btn || !menu) return;
    stBarAccountReturnEl = btn;
    menu.classList.remove('hide');
    btn.setAttribute('aria-expanded', 'true');
    menu.setAttribute('aria-hidden', 'false');
    syncBarAccountThemeRadios();
    queueMicrotask(() => {
        document.addEventListener('click', onBarAccountOutsideClick, true);
        document.addEventListener('keydown', onBarAccountEscape, true);
    });
}

/** @param {boolean} [restoreFocus=true] Return focus to Account when true (Escape / outside click). */
function closeBarAccountMenu(restoreFocus) {
    if (restoreFocus === undefined) restoreFocus = true;
    const btn = document.getElementById('bar-account-btn');
    const menu = document.getElementById('bar-account-menu');
    document.removeEventListener('click', onBarAccountOutsideClick, true);
    document.removeEventListener('keydown', onBarAccountEscape, true);
    if (menu) {
        menu.classList.add('hide');
        menu.setAttribute('aria-hidden', 'true');
    }
    if (btn) btn.setAttribute('aria-expanded', 'false');
    const rf = restoreFocus ? stBarAccountReturnEl : null;
    stBarAccountReturnEl = null;
    if (rf && typeof rf.focus === 'function') {
        try { rf.focus(); } catch (_e) {}
    }
}

function onBarAccountOutsideClick(ev) {
    const w = document.getElementById('bar-account-wrap');
    if (w && !w.contains(ev.target)) closeBarAccountMenu(true);
}

function onBarAccountEscape(ev) {
    if (ev.key !== 'Escape') return;
    const menu = document.getElementById('bar-account-menu');
    if (!menu || menu.classList.contains('hide')) return;
    ev.preventDefault();
    ev.stopPropagation();
    closeBarAccountMenu(true);
}

function toggleBarAccountMenu(ev) {
    if (ev) {
        ev.preventDefault();
        ev.stopPropagation();
    }
    const menu = document.getElementById('bar-account-menu');
    const btn = document.getElementById('bar-account-btn');
    if (!menu || !btn) return;
    if (menu.classList.contains('hide')) {
        openBarAccountMenu();
    } else {
        stBarAccountReturnEl = btn;
        closeBarAccountMenu(true);
    }
}

/** Legacy name: cycle light/dark (no auto). Prefer Account menu theme choices. */
function toggleThemeOverride() {
    const next = effectiveTheme() === 'light' ? 'dark' : 'light';
    stSetThemeMode(next);
}

function setupSystemThemeWatcher() {
    if (!window.matchMedia) return;
    themeMediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    themeMediaListener = () => {
        if (readThemeModePref() === 'auto') {
            applyThemeMode('auto');
            updateThemeToggleLabel();
        }
    };
    if (themeMediaQuery.addEventListener) {
        themeMediaQuery.addEventListener('change', themeMediaListener);
    } else if (themeMediaQuery.addListener) {
        themeMediaQuery.addListener(themeMediaListener);
    }
}

async function initApp() {
    await initAuthMode();
    const mode = readThemeModePref();
    applyThemeMode(mode);
    updateThemeToggleLabel();
    setupSystemThemeWatcher();

    if (loginRequired && (authMode === 'session' || authMode === 'oidc')) {
        return;
    }

    const execMode = (() => {
        try { return localStorage.getItem('st_exec_mode') === '1'; }
        catch (e) { return false; }
    })();
    document.body.classList.toggle('exec-mode', execMode);
    applyExecutiveModeUI(execMode);
    const mb = document.getElementById('dash-mode-btn');
    if (mb) mb.textContent = 'Dashboard mode: ' + (execMode ? 'on' : 'off');
    // Always load dashboard data first to populate sidebar badges
    await loadDashboard();
    await hydrateFeedSyncFromServer();
    await hydrateFeedSyncLastOutputFromServer();
}

function toggleDashMode() {
    const on = !document.body.classList.contains('exec-mode');
    document.body.classList.toggle('exec-mode', on);
    stApplyNavItemTitles();
    if (!on) {
        stNavQuickTipHide();
    }
    applyExecutiveModeUI(on);
    try { localStorage.setItem('st_exec_mode', on ? '1' : '0'); } catch (e) {}
    const mb = document.getElementById('dash-mode-btn');
    if (mb) mb.textContent = 'Dashboard mode: ' + (on ? 'on' : 'off');
    const navMap = {dash:'ndash',assets:'nassets',devices:'ndevices',vulns:'nvulns',logs:'nlogs',scan:'nscan',scanhist:'nscanhist',report:'nreport',enrich:'nenrich',health:'nhealth',access:'naccess',settings:'nsettings',sched:'nsched',scopes:'nscopes',integrations:'nintegrations',alerts:'nalerts',collectors:'ncollectors'};

    if (on) {
        // Remember where the user was, then switch to dashboard presentation.
        execPreviousTab = currentTab !== 'dash' ? currentTab : null;
        goTab('dash');
        hiNav('ndash');
        return;
    }

    // Restore prior tab when exiting executive mode.
    const restore = (execPreviousTab && document.getElementById('t-' + execPreviousTab))
        ? execPreviousTab
        : 'dash';
    goTab(restore);
    if (navMap[restore]) hiNav(navMap[restore]);
    execPreviousTab = null;
}

initApp();

// Restore last active tab from session storage (skip when session sign-in is still required)
(function bootAfterAuth() {
    if (loginRequired && (authMode === 'session' || authMode === 'oidc')) return;
const lastTab = (() => { try { return sessionStorage.getItem('st_tab'); } catch(e) { return null; } })();
stSettingsInitSubtabs();
stApplyNavItemTitles();
stNavQuickTipBind();
document.addEventListener('keydown', (ev) => {
    if (ev.key === 'Escape') {
        stNavQuickTipHide();
    }
});
if (lastTab && document.getElementById('t-' + lastTab)) {
    goTab(lastTab);
    const navMap = {
        dash:'ndash',assets:'nassets',devices:'ndevices',vulns:'nvulns',logs:'nlogs',scan:'nscan',scanhist:'nscanhist',
        report:'nreport',enrich:'nenrich',health:'nhealth',access:'naccess',settings:'nsettings',sched:'nsched',scopes:'nscopes',
        integrations:'nintegrations',alerts:'nalerts',collectors:'ncollectors',
    };
    const navKey = currentTab;
    const navId = navMap[navKey];
    if (navId) {
        const navEl = document.getElementById(navId);
        if (navEl && navEl.style.display !== 'none') hiNav(navId);
    }
} else {
    goTab('dash');
    hiNav('ndash');
}
loadEnrichment();  // Pre-load so enrichment tab is ready immediately
loadScanStatus();
    startDashTimerIfNeeded();
})();
</script>
</body>
</html>
